function normalizeDecorKey(decorKey = "") {
  const key = String(decorKey || "").trim();
  if (!key) {
    return "";
  }

  return DECOR_KEY_ALIASES[key] || DECOR_KEY_ALIASES[key.toLowerCase()] || key;
}

