function renderTipsOverlay() {
  const suggestions = buildCurrentTankCareSuggestions(Date.now());
  if (!suggestions.length) {
    return `<div class="empty-state">No care issues are being suggested for this tank right now.</div>`;
  }

  return suggestions.map((suggestion) => `
    <label class="checklist-row ${suggestion.fulfilled ? "is-fulfilled" : ""}">
      <input type="checkbox" disabled ${suggestion.fulfilled ? "checked" : ""} />
      <span>${suggestion.label}</span>
    </label>
  `).join("");
}

function renderDailyBonusOverlay() {
  const summary = state.dailyBonus?.summary;
  if (!summary) {
    return `<div class="empty-state">No daily bonus is waiting right now.</div>`;
  }

  return `
    <div class="summary-grid bonus-summary-grid">
      <div class="summary-row"><span>Meals Fed</span><strong>${summary.mealsFed}</strong></div>
      <div class="summary-row"><span>Average Comfort</span><strong>${summary.averageComfort}%</strong></div>
      <div class="summary-row"><span>Fish Count</span><strong>${summary.fishCount}</strong></div>
      <div class="summary-row"><span>Decor Count</span><strong>${summary.decorCount}</strong></div>
      <div class="summary-row"><span>Reward</span><strong>${summary.reward} coins</strong></div>
    </div>
  `;
}

function renderTankSetupOverlay() {
  const tank = getCurrentTank();
  if (!tank) {
    return `<div class="empty-state">No aquarium is selected.</div>`;
  }

  return `
    <div class="compact-heading">
      <p>${getTankLabel(tank)} is ready to use.</p>
    </div>
  `;
}

function getCareCategoryLabel(category) {
  switch (String(category || "").toLowerCase()) {
    case "caves":
      return "A Cave";
    case "plants":
      return "A Plant";
    case "ornaments":
      return "An Ornament";
    default:
      return `More ${titleFromFile(category)}`;
  }
}

function buildCurrentTankCareSuggestions(now = Date.now()) {
  const tank = getCurrentTank();
  if (!tank) {
    return [];
  }

  const livingFish = tank.fish.filter((fish) => !isFishDead(fish));
  if (!livingFish.length) {
    return [];
  }

  const decorCategories = new Set(
    tank.placedDecor.flatMap((item) => {
      const decor = runtime.decorMap.get(item.decorKey) || runtime.decorMeta[item.decorKey];
      return Array.isArray(decor?.categories) && decor.categories.length
        ? decor.categories
        : deriveDecorCategories(item.decorKey);
    })
  );
  const countsBySpecies = new Map();
  for (const fish of livingFish) {
    countsBySpecies.set(fish.speciesId, (countsBySpecies.get(fish.speciesId) || 0) + 1);
  }

  const suggestions = new Map();
  const putSuggestion = (key, label, fulfilled) => {
    const existing = suggestions.get(key);
    if (existing) {
      existing.fulfilled = existing.fulfilled && fulfilled;
      return;
    }
    suggestions.set(key, { key, label, fulfilled });
  };

  for (const fish of livingFish) {
    const species = getSpeciesForFish(fish);
    if (!species) {
      continue;
    }

    for (const category of species.needs?.decor || []) {
      putSuggestion(
        `decor:${category}`,
        getCareCategoryLabel(category),
        decorCategories.has(category)
      );
    }

    const friendNeed = species.needs?.friends;
    if (friendNeed?.min > 0) {
      const friendCount = friendNeed.alikeOnly ? (countsBySpecies.get(fish.speciesId) || 0) : livingFish.length;
      putSuggestion(
        `friends:${fish.speciesId}:${friendNeed.min}:${friendNeed.alikeOnly ? "alike" : "any"}`,
        friendNeed.alikeOnly
          ? `${species.name} need ${friendNeed.min}+ of their own kind`
          : `Keep at least ${friendNeed.min} fish together`,
        friendCount >= friendNeed.min
      );
    }

    const disliked = normalizeStringList(species.dislikedTypes)
      .filter((type) => livingFish.some((otherFish) => otherFish.id !== fish.id && otherFish.speciesId === type));
    if (disliked.length) {
      putSuggestion(
        `dislikes:${fish.speciesId}`,
        `${species.name} dislike ${disliked.map((type) => runtime.fishMap.get(type)?.name || titleFromFile(type)).join(", ")}`,
        false
      );
    }

    const comfort = getFishComfort(fish, now);
    if (comfort.value < 0.45) {
      putSuggestion(`comfort:${fish.id}`, `${species.name} comfort is low`, false);
    }
  }

  return [...suggestions.values()].sort((left, right) => Number(left.fulfilled) - Number(right.fulfilled) || left.label.localeCompare(right.label));
}

function claimDailyBonus() {
  const now = Date.now();
  const summary = state.dailyBonus?.summary;
  if (!state.dailyBonus?.available || !summary) {
    closeUtilityOverlay();
    return;
  }

  const reward = Math.max(0, Math.floor(Number(summary.reward) || 0));
  if (reward > 0) {
    state.coins += reward;
  }
  state.dailyBonus.available = false;
  state.dailyBonus.lastClaimedDayKey = summary.dayKey || state.dailyBonus.lastQualifiedDayKey || null;
  pushEvent(`Claimed a daily care bonus worth ${reward} ${pluralize("coin", reward)}.`, now);
  closeUtilityOverlay();
  saveState();
  renderUi(now);
  showToast(`Daily bonus claimed. +${reward} coins.`);
}

function renderSettingsOverlay() {
  if (!dom.settingsOverlay) {
    return;
  }

  const settings = getContentSettings();
  const uiSettings = getUiSettings();
  dom.settingsOverlay.hidden = !runtime.settingsOverlayOpen;
  dom.settingsOverlay.classList.toggle("is-open", runtime.settingsOverlayOpen);
  if (dom.violenceGoreToggleInput) {
    dom.violenceGoreToggleInput.checked = settings.violenceAndGoreEnabled;
  }
  if (dom.soundMuteToggleInput) {
    dom.soundMuteToggleInput.checked = uiSettings.soundMuted;
  }
  if (dom.tankMouseLockToggleInput) {
    dom.tankMouseLockToggleInput.checked = uiSettings.tankMouseInputLocked;
  }
  for (const input of dom.settingsOverlay.querySelectorAll("[data-toolbar-position-choice]")) {
    if (input instanceof HTMLInputElement) {
      input.checked = input.value === uiSettings.toolbarPosition;
      input.closest(".toolbar-position-option")?.classList.toggle("is-selected", input.checked);
    }
  }
  for (const input of dom.settingsOverlay.querySelectorAll("[data-display-position-choice]")) {
    if (input instanceof HTMLInputElement) {
      input.checked = input.value === uiSettings.displayPosition;
      input.closest(".display-position-option")?.classList.toggle("is-selected", input.checked);
    }
  }
}

function renderEquipmentOverlay() {
  if (!dom.equipmentOverlay) {
    return;
  }

  dom.equipmentOverlay.hidden = !runtime.equipmentOverlayOpen;
  dom.equipmentOverlay.classList.toggle("is-open", runtime.equipmentOverlayOpen);
}

function renderIntroTutorial() {
  if (!dom.introTutorialOverlay || !dom.introTutorialArrow) {
    return;
  }

  const step = getIntroTutorialStep();
  const isOpen = Boolean(step);
  dom.introTutorialOverlay.hidden = !isOpen;
  dom.introTutorialOverlay.classList.toggle("is-focus-step", isOpen && getIntroTutorialStepIndex() > 0);
  if (!isOpen) {
    dom.introTutorialArrow.hidden = true;
    dom.introTutorialArrow.className = "tutorial-arrow";
    return;
  }

  setTextIfChanged(dom.introTutorialBody, step.message);
  setTextIfChanged(
    dom.introTutorialNextButton,
    getIntroTutorialStepIndex() >= INTRO_TUTORIAL_STEPS.length - 1 ? "Finish" : "Next"
  );

  const arrowPosition = resolveIntroTutorialArrowPosition(step);
  if (!arrowPosition) {
    dom.introTutorialArrow.hidden = true;
    dom.introTutorialArrow.className = "tutorial-arrow";
    return;
  }

  dom.introTutorialArrow.hidden = false;
  dom.introTutorialArrow.className = `tutorial-arrow is-${step.arrowDirection}`;
  dom.introTutorialArrow.style.left = `${arrowPosition.x}px`;
  dom.introTutorialArrow.style.top = `${arrowPosition.y}px`;
}

function getStoredDecorEntries() {
  return Object.entries(state.decorInventory)
    .filter(([, count]) => count > 0)
    .sort(([leftKey], [rightKey]) => {
      const left = runtime.decorMap.get(leftKey)?.name || leftKey;
      const right = runtime.decorMap.get(rightKey)?.name || rightKey;
      return left.localeCompare(right);
    });
}

function getStoredDecorTrayEntryId(decorKey) {
  return `stored:${decorKey}`;
}

function getPlacedDecorTrayEntryId(placedId) {
  return `placed:${placedId}`;
}

function normalizeDecorTrayEntryId(entryId) {
  const value = String(entryId || "");
  if (value.startsWith("stored:") || value.startsWith("placed:")) {
    return value;
  }
  return value ? getStoredDecorTrayEntryId(value) : "";
}

function getDecorTrayEntryById(entryId) {
  const normalizedId = normalizeDecorTrayEntryId(entryId);
  if (!normalizedId) {
    return null;
  }

  if (normalizedId.startsWith("placed:")) {
    const placedId = normalizedId.slice("placed:".length);
    const item = state.placedDecor.find((entry) => entry.id === placedId) || null;
    if (!item) {
      return null;
    }
    const decor = runtime.decorMap.get(item.decorKey) || {
      name: titleFromFile(item.decorKey),
      path: resolveAppUrl(`assets/decor/${encodeURIComponent(item.decorKey)}`),
      cost: 0
    };
    return {
      id: normalizedId,
      type: "placed",
      decorKey: item.decorKey,
      placedId,
      item,
      decor,
      count: 1
    };
  }

  const decorKey = normalizedId.slice("stored:".length);
  const count = Math.max(0, Number(state.decorInventory[decorKey]) || 0);
  if (!decorKey || count <= 0) {
    return null;
  }
  const decor = runtime.decorMap.get(decorKey) || {
    name: titleFromFile(decorKey),
    path: resolveAppUrl(`assets/decor/${encodeURIComponent(decorKey)}`),
    cost: 0
  };
  return {
    id: normalizedId,
    type: "stored",
    decorKey,
    placedId: "",
    item: null,
    decor,
    count
  };
}

function getDecorTrayEntries() {
  const storedEntries = getStoredDecorEntries().map(([decorKey, count]) => {
    const decor = runtime.decorMap.get(decorKey) || {
      name: titleFromFile(decorKey),
      path: resolveAppUrl(`assets/decor/${encodeURIComponent(decorKey)}`),
      cost: 0
    };
    return {
      id: getStoredDecorTrayEntryId(decorKey),
      type: "stored",
      decorKey,
      placedId: "",
      item: null,
      decor,
      count
    };
  });
  const placedEntries = [...state.placedDecor]
    .sort((left, right) => {
      if (getDecorTankLayer(left) !== getDecorTankLayer(right)) {
        return getDecorTankLayer(right) - getDecorTankLayer(left);
      }
      return left.yNorm - right.yNorm;
    })
    .map((item) => {
      const decor = runtime.decorMap.get(item.decorKey) || {
        name: titleFromFile(item.decorKey),
        path: resolveAppUrl(`assets/decor/${encodeURIComponent(item.decorKey)}`),
        cost: 0
      };
      return {
        id: getPlacedDecorTrayEntryId(item.id),
        type: "placed",
        decorKey: item.decorKey,
        placedId: item.id,
        item,
        decor,
        count: 1
      };
    });
  return [...storedEntries, ...placedEntries];
}

function selectPlacedDecorFromTray(placedId, options = {}) {
  const item = setSelectedDecor(placedId, options);
  if (!item) {
    return;
  }

  runtime.placementMode = null;
  runtime.placementPreview = null;
  const decor = runtime.decorMap.get(item.decorKey);
  renderUi(Date.now());
  if (!options.additive && canConfigureDecorBubbler(item)) {
    openDecorSettings(item.id);
    return;
  }

  const selectedCount = getSelectedPlacedDecorItems().length;
  showToast(selectedCount > 1
    ? `${selectedCount} decor pieces selected.`
    : `${decor?.name || titleFromFile(item.decorKey)} selected.`);
}

function syncEditDecorTrayScrollControls() {
  if (!dom.editDecorTrayScroller || !dom.editDecorTrayPrev || !dom.editDecorTrayNext) {
    return;
  }

  const scroller = dom.editDecorTrayScroller;
  const maxScroll = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
  const visible = !dom.editDecorTray?.hidden;

  dom.editDecorTrayPrev.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft <= 2;
  dom.editDecorTrayNext.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft >= maxScroll - 2;
}

function scrollEditDecorTray(direction) {
  if (!dom.editDecorTrayScroller) {
    return;
  }

  const distance = Math.max(180, Math.round(dom.editDecorTrayScroller.clientWidth * 0.72));
  dom.editDecorTrayScroller.scrollBy({
    left: distance * direction,
    behavior: "smooth"
  });

  window.setTimeout(() => syncEditDecorTrayScrollControls(), 180);
}

function clearEditDecorTrayLongPress(pointerId = null) {
  const pressState = runtime.editDecorTrayLongPress;
  if (
    pointerId !== null
    && Number.isInteger(pressState.pointerId)
    && pressState.pointerId !== pointerId
  ) {
    return;
  }

  if (pressState.timerId) {
    window.clearTimeout(pressState.timerId);
  }

  pressState.timerId = 0;
  pressState.pointerId = null;
  pressState.decorKey = null;
  pressState.entryId = null;
  pressState.startClientX = 0;
  pressState.startClientY = 0;
}

function shouldSuppressEditDecorTrayEntryClick(entryId) {
  const normalizedId = normalizeDecorTrayEntryId(entryId);
  if (!normalizedId || runtime.suppressEditDecorTrayClickEntryId !== normalizedId) {
    return false;
  }

  runtime.suppressEditDecorTrayClickEntryId = null;
  return true;
}

function shouldSuppressEditDecorTrayPlaceClick(decorKey) {
  if (!decorKey || runtime.suppressEditDecorTrayClickDecorKey !== decorKey) {
    return false;
  }

  runtime.suppressEditDecorTrayClickDecorKey = null;
  return true;
}

function closeEditDecorTrayContextMenu(options = {}) {
  runtime.editDecorTrayContextMenuState.entryId = null;
  runtime.editDecorTrayContextMenuState.decorKey = null;
  runtime.editDecorTrayContextMenuState.anchorX = 0;
  runtime.editDecorTrayContextMenuState.anchorY = 0;

  if (options.render !== false) {
    renderEditDecorTrayContextMenu();
  }
}

function resolveEditTrayContextMenuAnchor(tray, anchor = null) {
  const trayRect = tray?.getBoundingClientRect();
  if (!trayRect) {
    return { x: 0, y: 0 };
  }

  if (anchor instanceof Element && anchor.isConnected) {
    const buttonRect = anchor.getBoundingClientRect();
    return {
      x: buttonRect.left - trayRect.left + buttonRect.width / 2,
      y: buttonRect.top - trayRect.top
    };
  }

  const clientX = Number(anchor?.clientX);
  const clientY = Number(anchor?.clientY);
  if (Number.isFinite(clientX) && Number.isFinite(clientY)) {
    return {
      x: clientX - trayRect.left,
      y: clientY - trayRect.top
    };
  }

  return {
    x: trayRect.width / 2,
    y: trayRect.height / 2
  };
}

function positionEditTrayContextMenu(tray, menu, anchorX, anchorY) {
  const trayRect = tray.getBoundingClientRect();
  menu.style.left = "0px";
  menu.style.top = "0px";
  const menuRect = menu.getBoundingClientRect();
  const maxLeft = Math.max(
    EDIT_TRAY_CONTEXT_MENU_GUTTER_PX,
    trayRect.width - menuRect.width - EDIT_TRAY_CONTEXT_MENU_GUTTER_PX
  );
  const left = clamp(
    anchorX - menuRect.width / 2,
    EDIT_TRAY_CONTEXT_MENU_GUTTER_PX,
    maxLeft
  );
  const unclampedTop = anchorY - menuRect.height - 12;
  const top = clamp(
    unclampedTop,
    8 - trayRect.top,
    window.innerHeight - menuRect.height - 8 - trayRect.top
  );
  menu.style.left = `${Math.round(left)}px`;
  menu.style.top = `${Math.round(top)}px`;
}

function openEditDecorTrayContextMenu(entryId, anchor = null) {
  const entry = getDecorTrayEntryById(entryId);
  if (!entry) {
    closeEditDecorTrayContextMenu();
    return;
  }

  const nextAnchor = resolveEditTrayContextMenuAnchor(dom.editDecorTray, anchor);
  runtime.editDecorTrayContextMenuState.entryId = entry.id;
  runtime.editDecorTrayContextMenuState.decorKey = entry.decorKey;
  runtime.editDecorTrayContextMenuState.anchorX = nextAnchor.x;
  runtime.editDecorTrayContextMenuState.anchorY = nextAnchor.y;
  renderEditDecorTrayContextMenu();
}

function renderEditDecorTrayContextMenu() {
  const tray = dom.editDecorTray;
  const scroller = dom.editDecorTrayScroller;
  const menu = dom.editDecorTrayContextMenu;
  if (!tray || !menu) {
    return;
  }

  const entry = getDecorTrayEntryById(runtime.editDecorTrayContextMenuState.entryId);
  const decorKey = entry?.decorKey || "";
  const count = entry?.count || 0;
  const decor = entry?.decor || null;
  const isVisible = Boolean(runtime.editTankMode && !tray.hidden && entry && decor);

  tray.classList.toggle("has-context-menu", isVisible);
  if (scroller) {
    for (const button of scroller.querySelectorAll("[data-decor-tray-entry-id]")) {
      button.closest(".edit-decor-tile")?.classList.toggle("is-context-open", isVisible && normalizeDecorTrayEntryId(button.dataset.decorTrayEntryId) === entry?.id);
    }
  }

  if (!isVisible || !decor) {
    menu.hidden = true;
    menu.style.left = "";
    menu.style.top = "";
    return;
  }

  const resaleValue = getResaleValue(decor.cost || 0);
  const purchaseCost = getDecorPurchaseCost(decorKey);
  const canBuyAnotherDecor = entry.type === "stored";
  const canAffordAnotherDecor = state.coins >= purchaseCost;
  const grouped = entry.type === "placed" && isPlacedDecorGrouped(entry.item);
  const detailText = entry.type === "placed"
    ? `${grouped ? "Grouped - " : ""}Layer ${getDecorTankLayer(entry.item)} - ${formatDecorScale(entry.item.scale)}`
    : `${count} in storage`;
  const markup = `
    <div class="edit-fish-tray-context-card">
      <div class="edit-fish-tray-context-copy">
        <strong>${escapeHtml(decor.name)}</strong>
        <span>${escapeHtml(detailText)}</span>
      </div>
      ${entry.type === "placed" ? `
        <button
          class="edit-fish-tray-context-action"
          type="button"
          data-tray-select-placed-decor-action="${escapeHtml(entry.placedId)}"
        >
          Select In Tank
        </button>
        <button
          class="edit-fish-tray-context-action"
          type="button"
          data-tray-edit-decor-settings="${escapeHtml(entry.placedId)}"
        >
          Edit Settings
        </button>
        ${grouped ? `
          <button
            class="edit-fish-tray-context-action"
            type="button"
            data-tray-ungroup-decor="${escapeHtml(entry.placedId)}"
          >
            Ungroup
          </button>
        ` : ""}
        <button
          class="edit-fish-tray-context-action"
          type="button"
          data-tray-store-placed-decor="${escapeHtml(entry.placedId)}"
          ${grouped ? "disabled" : ""}
        >
          Put Away
        </button>
        <button
          class="edit-fish-tray-context-action warn"
          type="button"
          data-tray-sell-placed-decor="${escapeHtml(entry.placedId)}"
          ${grouped ? "disabled" : ""}
        >
          Sell For ${resaleValue} ${pluralize("coin", resaleValue)}
        </button>
      ` : `
        <button
          class="edit-fish-tray-context-action"
          type="button"
          data-tray-place-decor-action="${escapeHtml(decorKey)}"
        >
          Place
        </button>
        ${canBuyAnotherDecor ? `
          <button
            class="edit-fish-tray-context-action buy-another"
            type="button"
            data-tray-buy-another-decor="${escapeHtml(decorKey)}"
            title="Buy Another"
            ${canAffordAnotherDecor ? "" : "disabled"}
          >
            Buy Another 🪙${purchaseCost}
          </button>
        ` : ""}
        <button
          class="edit-fish-tray-context-action warn"
          type="button"
          data-tray-sell-decor="${escapeHtml(decorKey)}"
        >
          Sell For ${resaleValue} ${pluralize("coin", resaleValue)}
        </button>
      `}
    </div>
  `;
  setMarkupIfChanged("edit-decor-tray-context-menu", menu, markup);
  menu.hidden = false;
  positionEditTrayContextMenu(
    tray,
    menu,
    runtime.editDecorTrayContextMenuState.anchorX,
    runtime.editDecorTrayContextMenuState.anchorY
  );
}

function hasInlineToolTrayOpen() {
  return runtime.editTankMode || runtime.fishEditMode || runtime.foodTrayOpen || runtime.medicineTrayOpen;
}

function syncTankTrayStageClass() {
  dom.tankStage?.classList.toggle("has-edit-decor-tray", hasInlineToolTrayOpen());
}

function renderEditDecorTray() {
  const visible = runtime.editTankMode;
  if (dom.editDecorTray) {
    dom.editDecorTray.hidden = !visible;
  }
  syncTankTrayStageClass();

  if (!visible || !dom.editDecorTrayScroller) {
    closeEditDecorTrayContextMenu({ render: false });
    renderEditDecorTrayContextMenu();
    syncEditDecorTrayScrollControls();
    return;
  }

  const trayEntries = getDecorTrayEntries();
  const dataKey = [
    runtime.editTankMode ? "1" : "0",
    isViolenceAndGoreEnabled() ? "1" : "0",
    runtime.placementMode?.decorKey || "",
    runtime.selectedDecorId || "",
    (Array.isArray(runtime.selectedDecorIds) ? runtime.selectedDecorIds : []).join(","),
    ...trayEntries.map((entry) => [
      entry.id,
      entry.decorKey,
      entry.count,
      entry.type,
      entry.placedId || "",
      entry.item ? getDecorTankLayer(entry.item) : "",
      entry.item ? Number(entry.item.scale || 1).toFixed(2) : formatDecorScale(getDecorScaleDefault(entry.decorKey)),
      entry.item && isDecorHorizontallyFlipped(entry.item) ? 1 : 0,
      entry.item?.groupId || ""
    ].join(":"))
  ].join("|");

  if (shouldRebuildRenderSection("edit-decor-tray-data", dataKey)) {
    const markup = trayEntries.length
      ? trayEntries
        .map((entry) => {
          const { decor, decorKey, count } = entry;
          const disabledByContent = entry.type === "stored" && !canUseDecorWithCurrentContentSettings(decorKey);
          const placing = entry.type === "stored" && !disabledByContent && runtime.placementMode?.decorKey === decorKey;
          const selected = entry.type === "placed" && getSelectedDecorIdSet().has(entry.placedId);
          const actionLabel = disabledByContent
            ? `${decor.name} is unavailable while Violence & Gore is off.`
            : entry.type === "placed"
              ? (selected ? `${decor.name} is selected` : `Select ${decor.name} in the tank`)
              : (placing ? `Cancel preview for ${decor.name}` : `Preview and place ${decor.name}`);
          const badge = entry.type === "placed"
            ? `${entry.item?.groupId ? "Group " : ""}Layer ${getDecorTankLayer(entry.item)}`
            : `x${count}`;
          const tileClasses = ["edit-decor-tile"];
          if (placing || selected) {
            tileClasses.push("is-active");
          }
          if (disabledByContent) {
            tileClasses.push("is-disabled");
          }
          return `
            <article class="${tileClasses.join(" ")}" data-decor-name="${escapeHtml(decor.name)}">
              <button
                class="edit-decor-tile-menu-button"
                type="button"
                data-open-decor-tray-menu="${escapeHtml(entry.id)}"
                data-decor-tray-entry-id="${escapeHtml(entry.id)}"
                aria-label="More options for ${escapeHtml(decor.name)}"
                title="More options"
              >
                ...
              </button>
              <button
                class="edit-decor-tile-primary"
                type="button"
                data-decor-tray-entry-id="${escapeHtml(entry.id)}"
                ${entry.type === "placed" ? `data-tray-select-placed-decor="${escapeHtml(entry.placedId)}"` : `data-tray-place-decor="${escapeHtml(decorKey)}"`}
                title="${escapeHtml(actionLabel)}"
                aria-label="${escapeHtml(actionLabel)}"
              >
                <span class="edit-decor-tile-surface">
                  <img class="edit-decor-tile-thumb" src="${decor.path}" alt="${escapeHtml(decor.name)}"${entry.type === "placed" && isDecorHorizontallyFlipped(entry.item) ? ` style="transform: translate(-50%, -50%) scaleX(-1);"` : ""} />
                  <span class="edit-decor-tile-count">${badge}</span>
                </span>
              </button>
            </article>
          `;
        })
        .join("")
      : `<div class="edit-decor-tray-empty">No decor is in storage or placed in the tank yet. Open the store to buy something to place.</div>`;

    setMarkupIfChanged("edit-decor-tray", dom.editDecorTrayScroller, markup);
  }

  renderEditDecorTrayContextMenu();
  syncEditDecorTrayScrollControls();
}

function getStoredFishEntries() {
  return [...state.storedFish].filter((fish) => !isFishDead(fish)).sort((left, right) => {
    const leftName = String(left.name || "").toLowerCase();
    const rightName = String(right.name || "").toLowerCase();
    return leftName.localeCompare(rightName) || left.acquiredAt - right.acquiredAt;
  });
}

function getFishTrayEntries() {
  const livingStoredFish = getStoredFishEntries().map((fish) => ({
    fish,
    inStorage: true,
    dead: false
  }));
  const deadFish = [
    ...state.fish.filter((fish) => isFishDead(fish)).map((fish) => ({ fish, inStorage: false, dead: true })),
    ...state.storedFish.filter((fish) => isFishDead(fish)).map((fish) => ({ fish, inStorage: true, dead: true }))
  ].sort((left, right) => (left.fish.deadAt || 0) - (right.fish.deadAt || 0));
  return [...livingStoredFish, ...deadFish];
}

function syncEditFishTrayScrollControls() {
  if (!dom.editFishTrayScroller || !dom.editFishTrayPrev || !dom.editFishTrayNext) {
    return;
  }

  const scroller = dom.editFishTrayScroller;
  const maxScroll = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
  const visible = !dom.editFishTray?.hidden;

  dom.editFishTrayPrev.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft <= 2;
  dom.editFishTrayNext.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft >= maxScroll - 2;
}

function scrollEditFishTray(direction) {
  if (!dom.editFishTrayScroller) {
    return;
  }

  const distance = Math.max(180, Math.round(dom.editFishTrayScroller.clientWidth * 0.72));
  dom.editFishTrayScroller.scrollBy({
    left: distance * direction,
    behavior: "smooth"
  });

  window.setTimeout(() => syncEditFishTrayScrollControls(), 180);
}

function clearEditFishTrayLongPress(pointerId = null) {
  const pressState = runtime.editFishTrayLongPress;
  if (
    pointerId !== null
    && Number.isInteger(pressState.pointerId)
    && pressState.pointerId !== pointerId
  ) {
    return;
  }

  if (pressState.timerId) {
    window.clearTimeout(pressState.timerId);
  }

  pressState.timerId = 0;
  pressState.pointerId = null;
  pressState.fishId = null;
  pressState.startClientX = 0;
  pressState.startClientY = 0;
}

function shouldSuppressEditFishTrayRestoreClick(fishId) {
  if (!fishId || runtime.suppressEditFishTrayClickFishId !== fishId) {
    return false;
  }

  runtime.suppressEditFishTrayClickFishId = null;
  return true;
}

function closeEditFishTrayContextMenu(options = {}) {
  runtime.editFishTrayContextMenuState.fishId = null;
  runtime.editFishTrayContextMenuState.anchorX = 0;
  runtime.editFishTrayContextMenuState.anchorY = 0;

  if (options.render !== false) {
    renderEditFishTrayContextMenu();
  }
}

function openEditFishTrayContextMenu(fishId, anchor = null) {
  const managed = getManagedFishById(fishId);
  if (!managed || (!managed.inStorage && !isFishDead(managed.fish))) {
    closeEditFishTrayContextMenu();
    return;
  }

  const nextAnchor = resolveEditTrayContextMenuAnchor(dom.editFishTray, anchor);
  runtime.editFishTrayContextMenuState.fishId = fishId;
  runtime.editFishTrayContextMenuState.anchorX = nextAnchor.x;
  runtime.editFishTrayContextMenuState.anchorY = nextAnchor.y;
  renderEditFishTrayContextMenu();
}

function renderEditFishTrayContextMenu() {
  const tray = dom.editFishTray;
  const scroller = dom.editFishTrayScroller;
  const menu = dom.editFishTrayContextMenu;
  if (!tray || !menu) {
    return;
  }

  const fishId = runtime.editFishTrayContextMenuState.fishId;
  const managed = fishId ? getManagedFishById(fishId) : null;
  const dead = isFishDead(managed?.fish);
  const isVisible = Boolean(runtime.fishEditMode && !tray.hidden && managed && (managed.inStorage || dead));

  tray.classList.toggle("has-context-menu", isVisible);
  if (scroller) {
    for (const button of scroller.querySelectorAll("[data-tray-restore-fish]")) {
      button.closest(".edit-decor-tile")?.classList.toggle("is-context-open", isVisible && button.dataset.trayRestoreFish === fishId);
    }
  }

  if (!isVisible) {
    menu.hidden = true;
    menu.style.left = "";
    menu.style.top = "";
    return;
  }

  const { fish } = managed;
  const species = getSpeciesForFish(fish);
  const displaySpeciesName = getFishDisplaySpeciesName(fish, species);
  const resaleValue = getResaleValue(species?.cost || 0);
  const canSell = Boolean(species) && !isFishJuvenile(fish);
  const markup = `
    <div class="edit-fish-tray-context-card">
      <div class="edit-fish-tray-context-copy">
        <strong>${escapeHtml(fish.name)}</strong>
        <span>${escapeHtml(displaySpeciesName)}</span>
      </div>
      ${dead ? `
        <button
          class="edit-fish-tray-context-action warn"
          type="button"
          data-tray-dispose-fish="${fish.id}"
        >
          Dispose Of Dead Fish
        </button>
      ` : `
        <button
          class="edit-fish-tray-context-action"
          type="button"
          data-tray-place-fish="${fish.id}"
        >
          Place In Tank
        </button>
        <button
          class="edit-fish-tray-context-action ${canSell ? "warn" : ""}"
          type="button"
          data-tray-sell-fish="${fish.id}"
          ${canSell ? "" : "disabled"}
        >
          ${canSell ? `Sell For ${resaleValue} ${pluralize("coin", resaleValue)}` : "Grow First"}
        </button>
      `}
    </div>
  `;
  setMarkupIfChanged("edit-fish-tray-context-menu", menu, markup);
  menu.hidden = false;
  positionEditTrayContextMenu(
    tray,
    menu,
    runtime.editFishTrayContextMenuState.anchorX,
    runtime.editFishTrayContextMenuState.anchorY
  );
}

function syncFoodTrayScrollControls() {
  if (!dom.foodTrayScroller || !dom.foodTrayPrev || !dom.foodTrayNext) {
    return;
  }

  const scroller = dom.foodTrayScroller;
  const maxScroll = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
  const visible = !dom.foodTray?.hidden;

  dom.foodTrayPrev.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft <= 2;
  dom.foodTrayNext.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft >= maxScroll - 2;
}

function scrollFoodTray(direction) {
  if (!dom.foodTrayScroller) {
    return;
  }

  const distance = Math.max(180, Math.round(dom.foodTrayScroller.clientWidth * 0.72));
  dom.foodTrayScroller.scrollBy({
    left: distance * direction,
    behavior: "smooth"
  });

  window.setTimeout(() => syncFoodTrayScrollControls(), 180);
}

function syncMedicineTrayScrollControls() {
  if (!dom.medicineTrayScroller || !dom.medicineTrayPrev || !dom.medicineTrayNext) {
    return;
  }

  const scroller = dom.medicineTrayScroller;
  const maxScroll = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
  const visible = !dom.medicineTray?.hidden;

  dom.medicineTrayPrev.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft <= 2;
  dom.medicineTrayNext.disabled = !visible || maxScroll <= 2 || scroller.scrollLeft >= maxScroll - 2;
}

function scrollMedicineTray(direction) {
  if (!dom.medicineTrayScroller) {
    return;
  }

  const distance = Math.max(180, Math.round(dom.medicineTrayScroller.clientWidth * 0.72));
  dom.medicineTrayScroller.scrollBy({
    left: distance * direction,
    behavior: "smooth"
  });

  window.setTimeout(() => syncMedicineTrayScrollControls(), 180);
}

function renderEditFishTray() {
  const visible = runtime.fishEditMode;
  if (dom.editFishTray) {
    dom.editFishTray.hidden = !visible;
  }
  syncTankTrayStageClass();

  if (!visible || !dom.editFishTrayScroller) {
    closeEditFishTrayContextMenu({ render: false });
    renderEditFishTrayContextMenu();
    syncEditFishTrayScrollControls();
    return;
  }

  const trayEntries = getFishTrayEntries();
  const dataKey = [
    runtime.fishEditMode ? "1" : "0",
    ...trayEntries.map(({ fish, inStorage, dead }) => [fish.id, fish.name, fish.speciesId, fish.undeadTemplateSpeciesId || "", Number(fish.scale || 1).toFixed(2), inStorage ? "storage" : "tank", dead ? "dead" : "living"].join(":"))
  ].join("|");

  if (shouldRebuildRenderSection("edit-fish-tray-data", dataKey)) {
    const markup = trayEntries.length
      ? trayEntries.map(({ fish, inStorage, dead }) => {
        const species = runtime.fishMap.get(fish.speciesId);
        const displaySpeciesName = getFishDisplaySpeciesName(fish, species);
        const label = `${fish.name}${displaySpeciesName ? ` - ${displaySpeciesName}` : ""}`;
        const actionLabel = dead
          ? `Dispose of ${fish.name}`
          : `Place ${fish.name} in the tank`;
        return `
          <article class="edit-decor-tile ${dead ? "is-dead" : ""}" data-decor-name="${label}">
            <button
              class="edit-decor-tile-menu-button"
              type="button"
              data-open-fish-tray-menu="${fish.id}"
              aria-label="More options for ${fish.name}"
              title="More options"
            >
              ...
            </button>
            <button
              class="edit-decor-tile-primary"
              type="button"
              data-tray-restore-fish="${fish.id}"
              title="${actionLabel}"
              aria-label="${actionLabel}"
            >
              <span class="edit-decor-tile-surface">
                <img class="edit-decor-tile-thumb" src="${getFishDisplayAssetPath(fish, species) || species?.asset || ""}" alt="${label}" />
                <span class="inventory-tray-label">${dead ? (inStorage ? "Dead In Storage" : "Dead In Tank") : "Storage"}</span>
              </span>
            </button>
          </article>
        `;
      }).join("")
      : `<div class="edit-decor-tray-empty">No stored or deceased fish need attention right now.</div>`;

    setMarkupIfChanged("edit-fish-tray", dom.editFishTrayScroller, markup);
  }

  renderEditFishTrayContextMenu();
  syncEditFishTrayScrollControls();
}

function renderFoodTray() {
  const visible = runtime.foodTrayOpen;
  if (dom.foodTray) {
    dom.foodTray.hidden = !visible;
  }
  syncTankTrayStageClass();

  if (!visible || !dom.foodTrayScroller) {
    syncFoodTrayScrollControls();
    return;
  }

  const items = getFoodCatalog().filter((food) => (
    Math.max(0, Number(state.foodInventory?.[food.id]) || 0) > 0
  ));
  const dataKey = [
    runtime.foodTrayOpen ? "1" : "0",
    runtime.feedingModeFoodKey || "",
    ...getFoodCatalog().map((food) => `${food.id}:${state.foodInventory?.[food.id] || 0}`)
  ].join("|");

  if (shouldRebuildRenderSection("food-tray-data", dataKey)) {
    const markup = items.length
      ? items.map((food) => {
        const quantity = Math.max(0, Number(state.foodInventory?.[food.id]) || 0);
        const active = runtime.feedingModeFoodKey === food.id;
        const label = `${food.name} • ${quantity} left`;
        return `
          <button
            class="edit-decor-tile ${active ? "is-active" : ""}"
            type="button"
            data-select-food="${food.id}"
            data-decor-name="${label}"
            title="${label}"
            aria-label="${active ? `Selected ${food.name}` : `Select ${food.name}`}"
            ${quantity > 0 ? "" : "disabled"}
            style="--tray-accent: #E0B24C;"
          >
            <span class="edit-decor-tile-surface inventory-tray-tile-surface">
              ${renderFoodAndMedImage("food", food.id, food.name, "edit-decor-tile-thumb inventory-tray-thumb")}
              <span class="inventory-tray-label">${food.name.replace(" Food", "")}</span>
              <span class="edit-decor-tile-count">x${quantity}</span>
            </span>
          </button>
        `;
      }).join("")
      : `<div class="edit-decor-tray-empty">No food is stocked yet. Open the store to buy a bottle first.</div>`;

    setMarkupIfChanged("food-tray", dom.foodTrayScroller, markup);
  }

  syncFoodTrayScrollControls();
}

function renderMedicineTray() {
  const visible = runtime.medicineTrayOpen;
  if (dom.medicineTray) {
    dom.medicineTray.hidden = !visible;
  }
  syncTankTrayStageClass();

  if (!visible || !dom.medicineTrayScroller) {
    syncMedicineTrayScrollControls();
    return;
  }

  const items = getMedicineCatalog().filter((medicine) => (
    shouldShowMedicineInStore(medicine)
    && Math.max(0, Number(state.medicineInventory?.[medicine.id]) || 0) > 0
  ));
  const dataKey = [
    runtime.medicineTrayOpen ? "1" : "0",
    runtime.medicineModeKey || "",
    ...getMedicineCatalog().map((medicine) => `${medicine.id}:${state.medicineInventory?.[medicine.id] || 0}`)
  ].join("|");

  if (shouldRebuildRenderSection("medicine-tray-data", dataKey)) {
    const markup = items.length
      ? items.map((medicine) => {
        const quantity = Math.max(0, Number(state.medicineInventory?.[medicine.id]) || 0);
        const active = runtime.medicineModeKey === medicine.id;
        const label = `${medicine.name} • ${quantity} left`;
        return `
          <button
            class="edit-decor-tile ${active ? "is-active" : ""}"
            type="button"
            data-select-medicine="${medicine.id}"
            data-decor-name="${label}"
            title="${label}"
            aria-label="${active ? `Selected ${medicine.name}` : `Select ${medicine.name}`}"
            ${quantity > 0 ? "" : "disabled"}
            style="--tray-accent: ${medicine.color};"
          >
            <span class="edit-decor-tile-surface inventory-tray-tile-surface">
              ${renderFoodAndMedImage("medicine", medicine.id, medicine.name, "edit-decor-tile-thumb inventory-tray-thumb")}
              <span class="inventory-tray-label">${medicine.name.replace(" Drops", "")}</span>
              <span class="edit-decor-tile-count">x${quantity}</span>
            </span>
          </button>
        `;
      }).join("")
      : `<div class="edit-decor-tray-empty">No medicine is stocked yet. Open the pharmacy to buy a bottle first.</div>`;

    setMarkupIfChanged("medicine-tray", dom.medicineTrayScroller, markup);
  }

  syncMedicineTrayScrollControls();
}

function renderFishList(now) {
  const currentSlot = getCurrentMealSlot(now);
  const currentFed = isMealSlotCompleteForTank(currentSlot);
  const starterSpecies = getStarterFishSpecies();
  const starterName = starterSpecies?.name || "starter fish";
  const emergencyStarter = starterSpecies ? getFishPurchaseCost(starterSpecies.id) === 0 : false;
  const starterCost = starterSpecies ? starterSpecies.cost : 1;
  const fishListDataKey = [
    currentSlot.key,
    currentFed ? 1 : 0,
    starterSpecies?.id || "",
    starterCost,
    emergencyStarter ? 1 : 0,
    runtime.collapsedSections.fishTank ? 1 : 0,
    runtime.collapsedSections.fishDead ? 1 : 0,
    runtime.collapsedSections.fishStorage ? 1 : 0,
    state.selectedFilterAsset,
    state.fish.map((fish) => [
      fish.id,
      fish.name,
      fish.speciesId,
      fish.undeadTemplateSpeciesId || "",
      fish.healthUnits,
      Number(fish.scale).toFixed(2),
      fish.acquiredAt,
      fish.growthEndsAt || "",
      fish.deadAt || "",
      fish.fedStreak || 0
    ].join(",")).join(";"),
    state.storedFish.map((fish) => [
      fish.id,
      fish.name,
      fish.speciesId,
      fish.undeadTemplateSpeciesId || "",
      fish.healthUnits,
      Number(fish.scale).toFixed(2),
      fish.acquiredAt,
      fish.growthEndsAt || "",
      fish.deadAt || "",
      fish.fedStreak || 0
    ].join(",")).join(";")
  ].join("|");
  if (!shouldRebuildRenderSection("fish-list-data", fishListDataKey)) {
    return;
  }

  const livingTankFish = state.fish.filter((fish) => !isFishDead(fish));
  const deadTankFish = state.fish.filter((fish) => isFishDead(fish));
  const deadStoredFish = state.storedFish.filter((fish) => isFishDead(fish));
  const livingStoredFish = getStoredFishEntries();
  const deadFishEntries = [
    ...deadTankFish.map((fish) => ({ fish, inStorage: false })),
    ...deadStoredFish.map((fish) => ({ fish, inStorage: true }))
  ];

  const tankCollapsed = isSidebarSectionCollapsed("fishTank");
  const deadCollapsed = deadFishEntries.length ? isSidebarSectionCollapsed("fishDead") : true;
  const storageCollapsed = isSidebarSectionCollapsed("fishStorage");

  const activeMarkup = livingTankFish.length
    ? [...livingTankFish]
      .sort((left, right) => getFishHealthRatio(left) - getFishHealthRatio(right) || left.healthUnits - right.healthUnits || left.acquiredAt - right.acquiredAt)
      .map((fish) => renderManagedFishCard(fish, now, {
        currentSlot,
        currentFed: hasFishEatenInSlot(fish, currentSlot),
        inStorage: false
      }))
      .join("")
    : `<div class="empty-state">The tank is empty. Open the cart and ${emergencyStarter ? `grab a free ${starterName} to get back on your feet.` : `grab a ${starterName} for ${starterCost} ${pluralize("coin", starterCost)} to get started.`}</div>`;

  const deadMarkup = deadFishEntries.length
    ? [...deadFishEntries]
      .sort((left, right) => (left.fish.deadAt || 0) - (right.fish.deadAt || 0))
      .map((entry) => renderManagedFishCard(entry.fish, now, {
        currentSlot,
        currentFed: hasFishEatenInSlot(entry.fish, currentSlot),
        inStorage: entry.inStorage
      }))
      .join("")
    : `<div class="empty-state">No dead fish are in the tank or storage.</div>`;

  const storedMarkup = livingStoredFish.length
    ? [...livingStoredFish]
      .sort((left, right) => left.acquiredAt - right.acquiredAt)
      .map((fish) => renderManagedFishCard(fish, now, {
        currentSlot,
        currentFed: hasFishEatenInSlot(fish, currentSlot),
        inStorage: true
      }))
      .join("")
    : `<div class="empty-state">No living fish are in storage.</div>`;

  setMarkupIfChanged("fish-list", dom.fishList, `
    <section class="info-card stack-section collapsible-section ${tankCollapsed ? "is-collapsed" : ""}" data-collapsible-section="fishTank">
      <div class="collapsible-header">
        <button
          class="collapsible-toggle"
          type="button"
          data-collapsible-toggle="fishTank"
          aria-expanded="${String(!tankCollapsed)}"
        >
          <span class="collapsible-title">In Tank</span>
          <span class="collapsible-icon" data-collapsible-icon>${tankCollapsed ? "⬇️" : "⬆️"}</span>
        </button>
        <div class="collapsible-meta">
          <strong>${livingTankFish.length}</strong>
        </div>
      </div>
      <div class="card-stack" data-collapsible-body ${tankCollapsed ? "hidden" : ""}>${activeMarkup}</div>
    </section>

    ${deadFishEntries.length ? `
      <section class="info-card stack-section collapsible-section ${deadCollapsed ? "is-collapsed" : ""}" data-collapsible-section="fishDead">
        <div class="collapsible-header">
          <button
            class="collapsible-toggle"
            type="button"
            data-collapsible-toggle="fishDead"
            aria-expanded="${String(!deadCollapsed)}"
          >
            <span class="collapsible-title">Dead Fish</span>
            <span class="collapsible-icon" data-collapsible-icon>${deadCollapsed ? "⬇️" : "⬆️"}</span>
          </button>
          <div class="collapsible-meta">
            <button class="small-button warn" data-dispose-all-dead title="Dispose of all dead fish" aria-label="Dispose of all dead fish">&#128701;</button>
            <strong>${deadFishEntries.length}</strong>
          </div>
        </div>
        <div class="card-stack" data-collapsible-body ${deadCollapsed ? "hidden" : ""}>${deadMarkup}</div>
      </section>
    ` : ""}

    <section class="info-card stack-section collapsible-section ${storageCollapsed ? "is-collapsed" : ""}" data-collapsible-section="fishStorage">
      <div class="collapsible-header">
        <button
          class="collapsible-toggle"
          type="button"
          data-collapsible-toggle="fishStorage"
          aria-expanded="${String(!storageCollapsed)}"
        >
          <span class="collapsible-title">Storage</span>
          <span class="collapsible-icon" data-collapsible-icon>${storageCollapsed ? "⬇️" : "⬆️"}</span>
        </button>
        <div class="collapsible-meta">
          <strong>${livingStoredFish.length}</strong>
        </div>
      </div>
      <div class="card-stack" data-collapsible-body ${storageCollapsed ? "hidden" : ""}>${storedMarkup}</div>
    </section>
  `);
}

function renderManagedFishCard(fish, now, options = {}) {
  const species = runtime.fishMap.get(fish.speciesId);
  if (!species) {
    return "";
  }

  const dead = isFishDead(fish);
  const juvenile = !dead && isFishJuvenile(fish, now);
  const comfort = getFishComfort(fish, now);
  const age = formatFishAge(fish.acquiredAt, now);
  const defaultScale = getFishScaleDefault(fish.speciesId);
  const usesDefaultScale = Math.abs(defaultScale - fish.scale) < 0.001;
  const inStorage = Boolean(options.inStorage);
  const displaySpeciesName = getFishDisplaySpeciesName(fish, species);
  const detritusFish = isDetritusFish(fish);
  const mealFreeFish = isMealFreeFish(fish);
  const goreEnabled = isGoreEnabled();
  const undeadFish = goreEnabled && isUndeadFish(fish);
  const zombieHunterFish = !dead && usesZombieHunterBehavior(fish);
  const zombieBittenFish = hasZombieBiteInfection(fish);
  const piranhaFish = isPiranhaSpecies(fish);
  const maxHealthUnits = getFishMaxHealthUnits(fish, species);
  const criticalComfort = !inStorage && !dead && comfort.value <= 0;
  const currentSlot = options.currentSlot || getCurrentMealSlot(now);
  const currentFed = Boolean(options.currentFed);
  const hungry = !mealFreeFish && !currentFed && fish.acquiredAt <= currentSlot.start;
  const settling = fish.acquiredAt > currentSlot.start;
  const fishAsset = getFishDisplayAssetPath(fish, species, now) || species.fallbackAsset || species.asset;
  const corpseState = getFishCorpseDisplayState(fish, now);
  const beingConsumed = corpseState === "devoured";
  const awaitingZombieRise = dead && hasPendingZombieRevival(fish);
  const corpsePressure = !inStorage && hasExposedDeadTankFish(now);
  const showDisposeButton = dead && !beingConsumed;
  const status = inStorage
    ? (dead
      ? awaitingZombieRise
        ? "Stored corpse will rise as a zombie soon."
        : corpseState === "skeleton"
          ? "Stored skeleton awaiting disposal."
          : corpseState === "zombie"
            ? "Stored zombie remains awaiting disposal."
            : (goreEnabled ? "Stored remains awaiting disposal." : "Stored dead fish awaiting disposal.")
      : "Stored safely outside the tank.")
    : dead
      ? beingConsumed
        ? (goreEnabled ? "Piranhas are stripping it to the bone." : "Piranhas are disposing of the remains.")
        : !goreEnabled
          ? "Dead and awaiting disposal."
          : awaitingZombieRise
            ? "A zombie bite is raising it back up."
            : corpseState === "skeleton"
              ? "Reduced to a skeleton."
              : corpseState === "zombie"
                ? "Rotting into a zombie."
                : "Freshly dead and floating at the surface."
      : criticalComfort
        ? corpsePressure
          ? "Panicking while a dead fish fouls the water."
          : "Tank conditions are dangerously filthy."
        : zombieBittenFish
          ? "Bleeding out from a zombie bite."
          : zombieHunterFish
            ? "Stalking living fish for a bite."
            : undeadFish
              ? "Ignores hunger and dirty water, but unnerves the living."
              : piranhaFish
                ? (goreEnabled ? (getActivePiranhaPrey(now) ? "Blood frenzy in progress." : "Hunting any non-undead fish or corpse.") : "Tracks chum without attacking tankmates.")
                : juvenile
                  ? "Growing into full size."
                  : detritusFish
                    ? (species.behavior === "shrimp" ? "Picking through the lower water." : "Suctioned to the back glass.")
                    : currentFed
                      ? "Fed for this meal"
                      : settling
                        ? "Starts care next meal"
                        : hungry
                          ? "Hungry right now"
                          : "Waiting";
  const healthNote = dead
    ? beingConsumed
      ? (goreEnabled
        ? "Piranhas will carry this fish through the zombie and skeleton stages automatically, then finish it off. No disposal needed."
        : "Piranhas will finish disposing of this fish automatically. No manual disposal needed.")
      : !goreEnabled
        ? "This fish died. Gore is off, so it will not decay or rise again."
        : awaitingZombieRise
          ? "Dispose of this corpse before it rises again as a zombie variant."
          : corpseState === "skeleton"
            ? "This fish has reached the skeleton stage. The Skeleton Fish shop unlock triggers here."
            : corpseState === "zombie"
              ? "This fish has reached the zombie stage. Leave it another 12 hours to reach the skeleton unlock."
              : "Leave it for 12 hours to reach the zombie stage, then another 12 hours to become a skeleton."
    : criticalComfort
      ? corpsePressure
        ? "Comfort is 0% while a dead fish stays in the tank. Remove it fast."
        : "Comfort is 0% at maximum dirtiness. Clean the tank before health keeps dropping."
      : zombieBittenFish
        ? "A zombie bite makes this fish panic, spill blood every second, and die in about 30 seconds."
        : zombieHunterFish
          ? "Zombie hunters bite living non-undead fish, then their victims bleed out and may rise again in 1-2 minutes if left alone."
          : undeadFish
            ? "Undead fish ignore hunger, discomfort, and dirty water, but reduce nearby living fish comfort by about 10% and may lash out."
            : piranhaFish
              ? (goreEnabled ? "Piranhas ignore pellets, devour any non-undead fish in the tank, and cloud the water red while feeding." : "Piranhas still go after chum, but they will leave the rest of the tank alone.")
              : juvenile
                ? "Baby fish start at 25% size and grow to full size over a few days."
                : detritusFish
                  ? (species.behavior === "shrimp"
                    ? "Scavenges trace grime and waste instead of pellets."
                    : "Feeds on grime and poop instead of pellets.")
                  : fish.healthUnits < maxHealthUnits
                    ? `Recovery streak: ${Math.min(fish.fedStreak, RECOVERY_FEED_STREAK)}/${RECOVERY_FEED_STREAK}`
                    : "Full hearts and thriving.";
  const rewardLabel = dead
    ? "No meal coins"
    : detritusFish
      ? (species.behavior === "shrimp" ? "Tiny cleanup" : "Cleans tank")
      : mealFreeFish
        ? "No meal coins"
        : `+${species.mealCoins} / meal`;
  const dirtinessLoadPercent = Math.round(getFishDirtinessBonus(fish, species) * 100);

  return `
    <article class="fish-card">
      <img class="fish-thumb" src="${fishAsset}" alt="${fish.name}" />
      <div class="fish-card-main">
        <div class="fish-card-heading">
          <div class="fish-card-title">
            <strong>${fish.name}</strong>
            <div class="fish-species">${displaySpeciesName}</div>
          </div>
          ${showDisposeButton ? `<button class="small-button warn" data-dispose-fish="${fish.id}" title="Dispose of ${fish.name}" aria-label="Dispose of ${fish.name}">&#128701;</button>` : ""}
        </div>
        <div class="hearts">${renderHearts(fish.healthUnits, maxHealthUnits)}</div>
        <div class="fish-status-line">${status}</div>
        <div class="fish-trait-row">
          <span class="fish-trait">${inStorage ? (dead ? `Status: ${getFishCorpseStateLabel(fish, now)}` : "Storage") : dead ? `Status: ${getFishCorpseStateLabel(fish, now)}` : `Comfort: ${comfort.label}`}</span>
          ${juvenile ? `<span class="fish-trait">Stage: Baby</span>` : ""}
          ${detritusFish ? `<span class="fish-trait">Diet: ${species.behavior === "shrimp" ? "trace grime + waste" : "grime + waste"}</span>` : ""}
          ${piranhaFish ? `<span class="fish-trait">Diet: live prey</span>` : ""}
          ${undeadFish ? `<span class="fish-trait">Diet: none</span>` : ""}
          ${zombieBittenFish && !dead ? `<span class="fish-trait">Status: Infected</span>` : ""}
          ${goreEnabled && dead && awaitingZombieRise ? `<span class="fish-trait">Decay: Rising zombie</span>` : ""}
          ${goreEnabled && dead && corpseState === "zombie" ? `<span class="fish-trait">Decay: Zombie</span>` : ""}
          ${goreEnabled && dead && corpseState === "skeleton" ? `<span class="fish-trait">Decay: Skeleton</span>` : ""}
          ${dead && corpseState === "devoured" ? `<span class="fish-trait">Decay: Piranha feeding</span>` : ""}
          ${!dead ? `<span class="fish-trait">Grime load: +${dirtinessLoadPercent}%</span>` : ""}
          <span class="fish-trait">Swim: ${zombieHunterFish ? "Undead hunter" : formatSwimStyle(species.swimStyle)}</span>
          <span class="fish-trait">Age: ${age}</span>
        </div>
        <div class="mini-note fish-health-note">${healthNote}</div>
      </div>
      <div class="fish-actions fish-card-actions">
        <div class="size-controls">
          <button class="small-button icon alt" data-size-fish="${fish.id}" data-size-direction="-1" aria-label="Make ${fish.name} smaller">-</button>
          <span class="size-badge">${formatFishScale(fish.scale)}</span>
          <button class="small-button icon alt" data-size-fish="${fish.id}" data-size-direction="1" aria-label="Make ${fish.name} larger">+</button>
        </div>
        <div class="fish-card-button-row">
          <span class="price-tag">${rewardLabel}</span>
          <button class="small-button" data-copy-fish-size="${fish.id}" title="Use ${formatFishScale(fish.scale)} as the default size for future ${displaySpeciesName.toLowerCase()}s">
            ${usesDefaultScale ? "Default Set" : "Set Default"}
          </button>
          <button class="small-button alt" data-open-fish="${fish.id}">Details</button>
          ${dead ? "" : `
            <button class="small-button alt" data-sell-fish="${fish.id}">
              Sell
            </button>
            <button class="small-button ${inStorage ? "" : "warn"}" data-${inStorage ? "restore-fish" : "store-fish"}="${fish.id}">
              ${inStorage ? "Return to Tank" : "Put Away"}
            </button>
          `}
        </div>
      </div>
    </article>
  `;
}

function renderFishInspector(now) {
  const managed = getManagedFishById(runtime.selectedFishId);
  if (!managed) {
    runtime.selectedFishId = null;
    runtime.fishInspectorSettingsOpen = false;
    dom.fishInspector.hidden = true;
    if (dom.inspectorSellFish) {
      dom.inspectorSellFish.hidden = true;
      delete dom.inspectorSellFish.dataset.sellFish;
    }
    if (dom.inspectorStoreFish) {
      dom.inspectorStoreFish.hidden = true;
      delete dom.inspectorStoreFish.dataset.storeFish;
    }
    if (dom.inspectorDisposeFish) {
      dom.inspectorDisposeFish.hidden = true;
      delete dom.inspectorDisposeFish.dataset.disposeFish;
    }
    if (dom.inspectorBuyAnotherFish) {
      dom.inspectorBuyAnotherFish.hidden = true;
      delete dom.inspectorBuyAnotherFish.dataset.buyAnotherFish;
    }
    return;
  }

  const { fish, inStorage } = managed;
  const baseSpecies = getBaseSpeciesForFish(fish);
  const species = getSpeciesForFish(fish);
  const dead = isFishDead(fish);
  const beingConsumed = dead && isFishBeingConsumedByPiranhas(fish, now);
  const corpseLabel = dead ? getFishCorpseStateLabel(fish, now) : null;
  const canBuyAnother = Boolean(baseSpecies && !dead && !inStorage && isFishSpeciesUnlocked(baseSpecies));
  const purchaseCost = canBuyAnother ? getFishPurchaseCost(fish.speciesId) : 0;
  const resaleValue = getResaleValue(baseSpecies?.cost || 0);
  const canSell = Boolean(baseSpecies) && !dead && !beingConsumed && !isFishJuvenile(fish);
  const canStore = !inStorage && !dead && !hasZombieBiteInfection(fish);
  const comfort = inStorage ? { label: "Stored", value: 1 } : getFishComfort(fish, now);
  dom.fishInspector.hidden = false;
  setTextIfChanged(dom.inspectorSpecies, getFishDisplaySpeciesName(fish, baseSpecies));
  const inspectorHeartsMarkup = renderHearts(fish.healthUnits, getFishMaxHealthUnits(fish, baseSpecies));
  if (dom.inspectorHealth.innerHTML !== inspectorHeartsMarkup) {
    dom.inspectorHealth.innerHTML = inspectorHeartsMarkup;
  }
  setTextIfChanged(
    dom.inspectorComfort,
    inStorage
      ? (dead ? `${corpseLabel} in storage` : "Stored safely")
      : dead
        ? corpseLabel
        : `${Math.round(comfort.value * 100)}% (${comfort.label})`
  );
  setTextIfChanged(dom.inspectorAge, formatFishAge(fish.acquiredAt, now));

  const currentSlot = getCurrentMealSlot(now);
  let mealLabel = isMealFreeFish(fish)
    ? "N/A"
    : hasFishEatenInSlot(fish, currentSlot)
      ? "✅"
      : isFishSettlingForSlot(fish, currentSlot)
        ? "Next meal"
        : "❌";

  if (dom.inspectorMeal) {
    if (mealLabel !== "N/A" && mealLabel !== "Next meal") {
      mealLabel = hasFishEatenInSlot(fish, currentSlot) ? "Yes" : "No";
    }
    setTextIfChanged(dom.inspectorMeal, mealLabel);
  }

  if (dom.inspectorDisposeFish) {
    dom.inspectorDisposeFish.hidden = !dead || beingConsumed;
    dom.inspectorDisposeFish.disabled = !dead || beingConsumed;
    if (dead && !beingConsumed) {
      dom.inspectorDisposeFish.dataset.disposeFish = fish.id;
      dom.inspectorDisposeFish.title = `Dispose of ${fish.name}`;
      dom.inspectorDisposeFish.setAttribute("aria-label", `Dispose of ${fish.name}`);
    } else {
      delete dom.inspectorDisposeFish.dataset.disposeFish;
      dom.inspectorDisposeFish.removeAttribute("title");
      dom.inspectorDisposeFish.setAttribute("aria-label", "Dispose of fish");
    }
  }

  if (dom.inspectorSellFish) {
    const showSell = Boolean(species) && !dead;
    dom.inspectorSellFish.hidden = !showSell;
    dom.inspectorSellFish.disabled = !canSell;
    if (showSell) {
      dom.inspectorSellFish.dataset.sellFish = fish.id;
      dom.inspectorSellFish.textContent = canSell ? "Sell" : "Grow";
      dom.inspectorSellFish.title = canSell
        ? `Sell ${fish.name} for \u{1FA99}${resaleValue}`
        : `${fish.name} needs to grow before being sold`;
      dom.inspectorSellFish.setAttribute(
        "aria-label",
        canSell
          ? `Sell ${fish.name} for ${resaleValue} coins`
          : `${fish.name} needs to grow before being sold`
      );
    } else {
      delete dom.inspectorSellFish.dataset.sellFish;
      dom.inspectorSellFish.textContent = "Sell";
      dom.inspectorSellFish.title = "Sell Fish";
      dom.inspectorSellFish.setAttribute("aria-label", "Sell Fish");
    }
  }

  if (dom.inspectorStoreFish) {
    const showStore = !inStorage && !dead;
    dom.inspectorStoreFish.hidden = !showStore;
    dom.inspectorStoreFish.disabled = !canStore;
    if (showStore) {
      dom.inspectorStoreFish.dataset.storeFish = fish.id;
      dom.inspectorStoreFish.title = canStore
        ? `Move ${fish.name} to storage`
        : `${fish.name} can't be moved to storage right now`;
      dom.inspectorStoreFish.setAttribute(
        "aria-label",
        canStore
          ? `Move ${fish.name} to storage`
          : `${fish.name} can't be moved to storage right now`
      );
    } else {
      delete dom.inspectorStoreFish.dataset.storeFish;
      dom.inspectorStoreFish.title = "Move to Storage";
      dom.inspectorStoreFish.setAttribute("aria-label", "Move to Storage");
    }
  }

  if (dom.inspectorBuyAnotherFish) {
    dom.inspectorBuyAnotherFish.hidden = !canBuyAnother;
    dom.inspectorBuyAnotherFish.disabled = canBuyAnother && state.coins < purchaseCost;
    if (canBuyAnother) {
      dom.inspectorBuyAnotherFish.dataset.buyAnotherFish = fish.id;
      dom.inspectorBuyAnotherFish.textContent = "Buy 1";
      dom.inspectorBuyAnotherFish.title = `Buy another ${baseSpecies.name} for \u{1FA99}${purchaseCost}`;
      dom.inspectorBuyAnotherFish.setAttribute("aria-label", `Buy another ${baseSpecies.name} for ${purchaseCost} coins`);
    } else {
      delete dom.inspectorBuyAnotherFish.dataset.buyAnotherFish;
      dom.inspectorBuyAnotherFish.textContent = "Buy 1";
      dom.inspectorBuyAnotherFish.title = "Buy One";
      dom.inspectorBuyAnotherFish.setAttribute("aria-label", "Buy One");
    }
  }

  if (document.activeElement !== dom.fishNameInput || dom.fishNameInput.dataset.fishId !== fish.id) {
    dom.fishNameInput.value = fish.name;
    dom.fishNameInput.dataset.fishId = fish.id;
  }
  if (dom.fishInspectorSettings) {
    dom.fishInspectorSettings.hidden = !runtime.fishInspectorSettingsOpen || dead;
  }
  if (dom.inspectorFishSettingsButton) {
    dom.inspectorFishSettingsButton.hidden = dead;
    dom.inspectorFishSettingsButton.classList.toggle("is-active", Boolean(runtime.fishInspectorSettingsOpen && !dead));
  }
  renderFishInspectorBehaviorOptions(fish, baseSpecies);
  updateInspectorFishReadouts(fish);
}

function renderDecorShop() {
  if (!runtime.decorCatalog.length) {
    setMarkupIfChanged("decor-shop", dom.decorShop, `<div class="empty-state">No decor PNGs were found in the decor folder yet.</div>`);
    return;
  }

  const searchQuery = getStoreSearchQuery("decor");
  const allCatalog = sortCatalogEntries(
    runtime.decorCatalog.filter((decor) => canUseDecorWithCurrentContentSettings(decor)),
    runtime.storeSorts.decor
  );
  if (!allCatalog.length) {
    setMarkupIfChanged(
      "decor-shop",
      dom.decorShop,
      `${renderShopToolbar("decor", 0, 0)}<div class="empty-state">No decor is available in the shop right now.</div>`
    );
    return;
  }
  const catalog = allCatalog.filter((decor) => matchesShopSearchQuery(getDecorShopSearchHaystack(decor), searchQuery));
  if (!catalog.length) {
    setMarkupIfChanged(
      "decor-shop",
      dom.decorShop,
      `${renderShopToolbar("decor", 0, allCatalog.length)}<div class="empty-state">No decor matches "${escapeHtml(searchQuery.trim())}".</div>`
    );
    return;
  }
  const cardsMarkup = catalog
    .map((decor) => {
      const affordable = state.coins >= decor.cost;
      const owned = state.decorInventory[decor.key] || 0;
      const isCustomUploadProduct = isCustomDecorUploadShopKey(decor.key);
      const isCustomHideUpload = isCustomHideShopKey(decor.key);
      return `
        <article class="shop-card">
          <img class="shop-thumb" src="${decor.path}" alt="${decor.name}" />
          <div class="shop-meta">
            <div>
              <strong>${decor.name}</strong>
              ${renderShopThemePill(decor.theme)}
              <div class="fish-meta">${isCustomHideUpload ? "Upload front and background images for a hide." : isCustomUploadProduct ? "Upload a local image for this decor." : `${owned} in storage`}</div>
            </div>
            <div class="fish-meta"></div>
          </div>
          <div class="shop-meta">
            <span class="price-tag">${decor.cost} ${pluralize("coin", decor.cost)}</span>
            <button class="buy-button" data-buy-decor="${decor.key}" ${affordable ? "" : "disabled"}>
              ${isCustomHideUpload ? "Choose Images" : isCustomUploadProduct ? "Choose Image" : "Buy Decor"}
            </button>
          </div>
        </article>
      `;
    })
    .join("");

  setMarkupIfChanged(
    "decor-shop",
    dom.decorShop,
    `${renderShopToolbar("decor", catalog.length, allCatalog.length)}${cardsMarkup}`
  );
}

function renderEquipmentShop() {
  if (!dom.equipmentShop) {
    return;
  }

  const dispenserInstalled = hasAutoDispenserInstalled();
  const dispenserLoadedCount = getAutoDispenserLoadedCount(state.autoDispenser);
  const dispenserPortion = clamp(Number(state.autoDispenser?.mealPortion) || 0, 0, AUTO_DISPENSER_PORTION_MAX);
  const dispenserAffordable = state.coins >= AUTO_DISPENSER_COST;
  const shopFilters = runtime.filterCatalog.filter((filter) => filter.purchasable && filter.key !== BASIC_FILTER_KEY);
  const filterMarkup = shopFilters.map((filter) => {
    const ownedCount = Math.max(0, Number(state.ownedFilterInventory?.[filter.key]) || 0);
    const equippedCount = getFilterAssignmentCount(filter.key);
    const unusedCount = getUnusedFilterCount(filter.key);
    const equippedHere = state.selectedFilterAsset === filter.key;
    const affordable = state.coins >= filter.cost;
    const resaleValue = getResaleValue(filter.cost);
    const buyLabel = ownedCount > 0 ? "Buy Another" : "Buy & Equip";
    const statusBits = [
      `${ownedCount} owned`,
      equippedCount > 0 ? `${equippedCount} in use` : "none in use",
      unusedCount > 0 ? `${unusedCount} spare` : "no spare copies"
    ];
    return `
      <article class="shop-card">
        <img class="shop-thumb" src="${filter.path}" alt="${filter.name}" />
        <div class="shop-meta shop-card-main">
          <div>
            <strong>${filter.name}</strong>
            <div class="fish-meta">${statusBits.join(" | ")}</div>
          </div>
          <div class="fish-meta">${filter.blurb}</div>
          <div class="fish-meta">Empty tank max grime: ${formatDuration(filter.cleanDays * DAY_MS)}. Mood boost: +${Math.round(filter.comfortBoost * 100)}%.</div>
          ${equippedHere ? `<div class="mini-note">Currently installed in this tank.</div>` : ""}
        </div>
        <div class="shop-meta shop-card-actions">
          <span class="price-tag">${filter.cost} ${pluralize("coin", filter.cost)}</span>
          <div class="shop-button-row">
            <button class="buy-button" data-buy-filter="${filter.key}" ${affordable ? "" : "disabled"}>${buyLabel}</button>
            <button class="small-button alt" data-sell-filter="${filter.key}" ${unusedCount > 0 ? "" : "disabled"}>Sell Spare (${resaleValue})</button>
          </div>
        </div>
      </article>
    `;
  }).join("");

  const dispenserMarkup = `
      <article class="shop-card">
        <img class="shop-thumb" src="${AUTO_DISPENSER_IMAGE_PATH}" alt="Automatic pellet dispenser" />
        <div class="shop-meta shop-card-main">
          <div>
            <strong>Pellet Dispenser</strong>
            <div class="fish-meta">${dispenserInstalled ? "Installed in this tank" : "Not installed in this tank"}</div>
          </div>
          <div class="fish-meta">Mounts at the center waterline, stores up to ${AUTO_DISPENSER_MAX_PELLETS} pellets, and auto-dispenses set amount every 12 hours.</div>
          <div class="mini-note">${dispenserLoadedCount}/${AUTO_DISPENSER_MAX_PELLETS} loaded | Meal amount ${String(dispenserPortion).padStart(2, "0")}</div>
        </div>
        <div class="shop-meta shop-card-actions">
          <span class="price-tag">${AUTO_DISPENSER_COST} ${pluralize("coin", AUTO_DISPENSER_COST)}</span>
          <div class="shop-button-row">
            <button class="buy-button" data-buy-auto-dispenser="true" ${dispenserInstalled || !dispenserAffordable ? "disabled" : ""}>${dispenserInstalled ? "Installed" : "Buy & Install"}</button>
          </div>
        </div>
      </article>
  `;

  const uvLightOwned = isUvLightOwned();
  const uvLightInstalled = isUvLightInstalled();
  const uvLightActive = isUvLightActive();
  const uvLightAffordable = state.coins >= UV_LIGHT_COST;
  const uvLightMarkup = `
      <article class="shop-card">
        <img class="shop-thumb uv-light-shop-thumb" src="${UV_LIGHT_IMAGE_PATH}" alt="UV light" />
        <div class="shop-meta shop-card-main">
          <div>
            <strong>UV Light</strong>
            <div class="fish-meta">${uvLightOwned ? (uvLightInstalled ? `Added to this tank | ${uvLightActive ? "On" : "Off"}` : "Owned | Not added to this tank") : "Not owned"}</div>
          </div>
          <div class="fish-meta">Adds a blacklight glow pass for fish and decor colors that naturally react under UV.</div>
          <div class="mini-note">Once owned, add or remove it from the Edit Tank panel.</div>
        </div>
        <div class="shop-meta shop-card-actions">
          <span class="price-tag">${uvLightOwned ? "Unlocked" : `${UV_LIGHT_COST} ${pluralize("coin", UV_LIGHT_COST)}`}</span>
          <div class="shop-button-row">
            <button class="buy-button" data-buy-uv-light="true" ${uvLightOwned || !uvLightAffordable ? "disabled" : ""}>${uvLightOwned ? "Owned" : "Buy & Add"}</button>
          </div>
        </div>
      </article>
  `;

  const backgroundMarkup = runtime.backgroundCatalog
    .filter((background) => !background.defaultUnlocked)
    .map((background) => {
      const owned = isBackgroundOwned(background.key);
      const selected = state.selectedBackground === background.key;
      const affordable = state.coins >= background.cost;
      const statusLabel = background.defaultUnlocked
        ? "Unlocked by default"
        : owned
          ? "Owned"
          : "Locked";
      const priceLabel = background.defaultUnlocked || owned
        ? "Unlocked"
        : `${background.cost} ${pluralize("coin", background.cost)}`;

      return `
      <article class="shop-card">
        ${renderBackgroundPreview(background, "shop-thumb background-shop-thumb")}
        <div class="shop-meta shop-card-main">
          <div>
            <strong>${background.name}</strong>
            <div class="fish-meta">${statusLabel}</div>
          </div>
        </div>
        <div class="shop-meta shop-card-actions">
          <span class="price-tag">${priceLabel}</span>
          <div class="shop-button-row">
            ${owned
          ? `<button class="small-button alt" data-use-background-shop="${background.key}">${selected ? "Using This Background" : "Use Now"}</button>`
          : `<button class="buy-button" data-buy-background="${background.key}" ${affordable ? "" : "disabled"}>Unlock & Use</button>`}
          </div>
        </div>
      </article>
      `;
    })
    .join("");

  const tankType = getTankTypeMeta("rectangular");
  const ownedCount = getAllTanks().length;
  const affordable = state.coins >= tankType.cost;
  const tankMarkup = `
    <article class="shop-card">
      ${renderTankProductImage(tankType.id, "Aquarium")}
      <div class="shop-meta shop-card-main">
        <div>
          <strong>Additional Aquarium</strong>
          <div class="fish-meta">${ownedCount} owned</div>
        </div>
        <div class="fish-meta">${tankType.description}</div>
        <div class="mini-note">Each aquarium keeps its own fish, decor, filter, and care history.</div>
      </div>
      <div class="shop-meta shop-card-actions">
        <span class="price-tag">${tankType.cost} ${pluralize("coin", tankType.cost)}</span>
        <div class="shop-button-row">
          <button class="buy-button" data-buy-tank="${tankType.id}" ${affordable ? "" : "disabled"}>Buy Aquarium</button>
        </div>
      </div>
    </article>
  `;

  const markup = `
    <section class="shop-section">
      <div class="shop-section-heading">
        <h3>Filters</h3>
        <p>Buy multiple filters, equip them per tank, and sell unused ones for 75% back.</p>
      </div>
      <div class="shop-section-cards">
        ${filterMarkup || `<div class="empty-state">No filter upgrades are available yet.</div>`}
      </div>
    </section>
    <section class="shop-section">
      <div class="shop-section-heading">
        <h3>Dispensers</h3>
        <p>Install one automatic feeder per tank and set its portion directly on the device.</p>
      </div>
      <div class="shop-section-cards">
        ${dispenserMarkup}
      </div>
    </section>
    <section class="shop-section">
      <div class="shop-section-heading">
        <h3>Lighting</h3>
        <p>Unlock a blacklight effect and switch it per tank from the toolbar.</p>
      </div>
      <div class="shop-section-cards">
        ${uvLightMarkup}
      </div>
    </section>
    <section class="shop-section">
      <div class="shop-section-heading">
        <h3>Backgrounds</h3>
        <p>Purchase more backdrops to further customize your fish tanks.</p>
      </div>
      <div class="shop-section-cards">
        ${backgroundMarkup || `<div class="empty-state">No backgrounds are available yet.</div>`}
      </div>
    </section>
    <section class="shop-section">
      <div class="shop-section-heading">
        <h3>Aquariums</h3>
        <p>Own multiple aquariums and switch between them using the arrow buttons/keys.</p>
      </div>
      <div class="shop-section-cards">
        ${tankMarkup}
      </div>
    </section>
  `;

  setMarkupIfChanged("equipment-shop", dom.equipmentShop, markup);
}

function renderDecorInventory() {
  const inventoryDataKey = [
    isViolenceAndGoreEnabled() ? "1" : "0",
    runtime.placementMode?.decorKey || "",
    ...Object.entries(state.decorInventory)
      .filter(([, count]) => count > 0)
      .sort(([leftKey], [rightKey]) => leftKey.localeCompare(rightKey))
      .map(([key, count]) => `${key}:${count}:${formatDecorScale(getDecorScaleDefault(key))}`)
  ].join("|");
  if (!shouldRebuildRenderSection("decor-inventory-data", inventoryDataKey)) {
    return;
  }

  const ownedItems = Object.entries(state.decorInventory)
    .filter(([, count]) => count > 0)
    .sort(([leftKey], [rightKey]) => {
      const left = runtime.decorMap.get(leftKey)?.name || leftKey;
      const right = runtime.decorMap.get(rightKey)?.name || rightKey;
      return left.localeCompare(right);
    });

  if (!ownedItems.length) {
    setMarkupIfChanged("decor-inventory", dom.decorInventory, `
      <div class="empty-state">
        Storage is empty. Open the decor cart to buy cute plants, shells, and props.
      </div>
    `);
    return;
  }

  const markup = ownedItems
    .map(([key, count]) => {
      const decor = runtime.decorMap.get(key) || {
        name: titleFromFile(key),
        path: resolveAppUrl(`assets/decor/${encodeURIComponent(key)}`)
      };
      const disabledByContent = !canUseDecorWithCurrentContentSettings(key);
      const placing = !disabledByContent && runtime.placementMode?.decorKey === key;
      const defaultScale = getDecorScaleDefault(key);

      return `
        <article class="mini-card">
          <img class="decor-thumb" src="${decor.path}" alt="${decor.name}" />
          <div>
            <strong>${decor.name}</strong>
            <div class="fish-meta">${count} in storage.</div>
            <div class="mini-note">Default size: ${formatDecorScale(defaultScale)}</div>
            ${disabledByContent ? `<div class="mini-note">Disabled while Violence & Gore is off.</div>` : ""}
          </div>
          <div class="mini-card-actions">
            <div class="size-controls">
              <button class="small-button icon alt" data-size-decor="${key}" data-size-direction="-1" aria-label="Make ${decor.name} smaller">-</button>
              <span class="size-badge">${formatDecorScale(defaultScale)}</span>
              <button class="small-button icon alt" data-size-decor="${key}" data-size-direction="1" aria-label="Make ${decor.name} larger">+</button>
            </div>
            <button class="small-button alt" data-sell-decor-inventory="${key}">Sell</button>
            <button class="small-button ${placing ? "alt" : ""}" data-place-decor="${key}" ${disabledByContent ? "disabled" : ""}>
              ${placing ? "Cancel Preview" : "Preview & Place"}
            </button>
          </div>
        </article>
      `;
    })
    .join("");
  setMarkupIfChanged("decor-inventory", dom.decorInventory, markup);
}

function renderPlacedDecor() {
  const placedDecorDataKey = state.placedDecor
    .map((item) => [
      item.id,
      item.decorKey,
      getDecorTankLayer(item),
      Number(item.xNorm).toFixed(4),
      Number(item.yNorm).toFixed(4),
      Number(item.scale).toFixed(2),
      isDecorHorizontallyFlipped(item) ? 1 : 0,
      item.groupId || ""
    ].join(","))
    .concat([
      (Array.isArray(runtime.selectedDecorIds) ? runtime.selectedDecorIds : []).join(",")
    ])
    .join("|");
  if (!shouldRebuildRenderSection("placed-decor-data", placedDecorDataKey)) {
    return;
  }

  if (!state.placedDecor.length) {
    setMarkupIfChanged("placed-decor", dom.placedDecorList, `
      <div class="empty-state">
        Nothing is placed yet.
      </div>
    `);
    return;
  }

  const sorted = [...state.placedDecor].sort((left, right) => {
    if (getDecorTankLayer(left) !== getDecorTankLayer(right)) {
      return getDecorTankLayer(right) - getDecorTankLayer(left);
    }
    return left.yNorm - right.yNorm;
  });
  const selectedItems = getSelectedPlacedDecorItems();
  const selectedGroupIds = getDecorGroupIdsForItems(selectedItems);
  const selectionMarkup = selectedItems.length > 1
    ? `
      <article class="mini-card decor-selection-card">
        <div>
          <strong>${selectedItems.length} Selected</strong>
          <div class="fish-meta">${selectedGroupIds.length ? "Grouped selection ready." : "Press G to group them."}</div>
          <div class="mini-note">Shift-click decor tray items to adjust the selection.</div>
        </div>
        <div class="mini-card-actions">
          <button class="small-button" data-group-selected-decor>Group / Add To Group</button>
          <button class="small-button alt" data-ungroup-selected-decor ${selectedGroupIds.length ? "" : "disabled"}>Ungroup</button>
        </div>
      </article>
    `
    : "";
  const markup = selectionMarkup + sorted
    .map((item) => {
      const decor = runtime.decorMap.get(item.decorKey) || {
        name: titleFromFile(item.decorKey),
        path: resolveAppUrl(`assets/decor/${encodeURIComponent(item.decorKey)}`)
      };
      const grouped = isPlacedDecorGrouped(item);
      const selected = getSelectedDecorIdSet().has(item.id);

      return `
        <article class="mini-card ${selected ? "is-selected" : ""}">
          <img class="decor-thumb" src="${decor.path}" alt="${decor.name}"${isDecorHorizontallyFlipped(item) ? ` style="transform: scaleX(-1);"` : ""} />
          <div>
            <strong>${decor.name}</strong>
            <div class="fish-meta">${grouped ? "Grouped decor." : "Placed in the tank."}</div>
            <div class="mini-note">Layer ${getDecorTankLayer(item)}. Current size: ${formatDecorScale(item.scale)}</div>
          </div>
          <div class="mini-card-actions">
            <div class="size-controls">
              <button class="small-button icon alt" data-resize-placed="${item.id}" data-size-direction="-1" aria-label="Make ${decor.name} smaller">-</button>
              <span class="size-badge">${formatDecorScale(item.scale)}</span>
              <button class="small-button icon alt" data-resize-placed="${item.id}" data-size-direction="1" aria-label="Make ${decor.name} larger">+</button>
            </div>
            <button class="small-button" data-copy-size="${item.id}">Set Default</button>
            <button class="small-button alt" data-edit-decor-settings="${item.id}">Settings</button>
            <button class="small-button alt" data-ungroup-decor="${item.id}" ${grouped ? "" : "disabled"}>Ungroup</button>
            <button class="small-button alt" data-sell-decor-placed="${item.id}" ${grouped ? "disabled" : ""}>Sell</button>
            <button class="small-button alt" data-store-decor="${item.id}" ${grouped ? "disabled" : ""}>Put Away</button>
          </div>
        </article>
      `;
    })
    .join("");
  setMarkupIfChanged("placed-decor", dom.placedDecorList, markup);
}

function renderBackgrounds() {
  const containers = [
    ["background-list", dom.backgroundList],
    ["equipment-background-list", dom.equipmentBackgroundList]
  ].filter(([, container]) => container);
  if (!containers.length) {
    return;
  }

  if (!runtime.backgroundCatalog.length) {
    for (const [cacheKey, container] of containers) {
      setMarkupIfChanged(cacheKey, container, `<div class="empty-state">No background PNGs were found.</div>`);
    }
    return;
  }

  const markup = getOwnedBackgroundCatalog()
    .filter((background) => !isCustomBackgroundKey(background.key))
    .map((background) => {
      const selected = state.selectedBackground === background.key;
      return `
        <article class="background-card ${selected ? "is-selected" : ""}">
          ${renderBackgroundPreview(background, "background-thumb")}
          <div>
            <strong>${background.name}</strong>
          </div>
          <button data-select-background="${background.key}">
            ${selected
              ? "Using This Background"
              : isLocalImageBackgroundKey(background.key) && !hasLocalBackgroundImage()
                ? "Choose Image"
                : "Use Background"}
          </button>
        </article>
      `;
    })
    .join("");

  const resolvedMarkup = markup || `<div class="empty-state">No image backgrounds are unlocked yet.</div>`;
  for (const [cacheKey, container] of containers) {
    setMarkupIfChanged(cacheKey, container, resolvedMarkup);
  }
}

function renderSolidBackgroundControls() {
  const container = dom.equipmentBackgroundColorPanel;
  if (!container) {
    return;
  }

  const solidEnabled = isSolidBackgroundEnabled();
  const gradientEnabled = isGradientBackgroundEnabled();
  const localImageSelected = isLocalImageBackgroundKey(state.selectedBackground);
  const localImageReady = hasLocalBackgroundImage();
  const activeColor = getActiveSolidBackgroundColor();
  const activeChoice = getSolidBackgroundColorChoices().find((choice) => choice.color === activeColor)
    || { label: activeColor, color: activeColor };
  const gradientColors = getActiveGradientBackgroundColors();
  const gradientStartChoice = getSolidBackgroundColorChoices().find((choice) => choice.color === gradientColors.start)
    || { label: gradientColors.start, color: gradientColors.start };
  const gradientEndChoice = getSolidBackgroundColorChoices().find((choice) => choice.color === gradientColors.end)
    || { label: gradientColors.end, color: gradientColors.end };
  const swatches = solidEnabled
    ? getSolidBackgroundColorChoices()
      .map((choice) => {
        const selected = choice.color === activeColor;
        return `
        <button
          class="custom-gravel-color-swatch ${selected ? "is-selected" : ""}"
          type="button"
          data-solid-background-color="${choice.color}"
          aria-pressed="${selected}"
          aria-label="Set solid background color to ${choice.label}"
          title="${choice.label}"
          style="--swatch:${choice.color};">
        </button>
      `;
      })
      .join("")
    : "";
  const renderGradientSwatches = (role, activeColorValue) => getSolidBackgroundColorChoices()
    .map((choice) => {
      const selected = choice.color === activeColorValue;
      return `
        <button
          class="custom-gravel-color-swatch ${selected ? "is-selected" : ""}"
          type="button"
          data-gradient-background-role="${role}"
          data-gradient-background-color="${choice.color}"
          aria-pressed="${selected}"
          aria-label="Set gradient ${role === "end" ? "bottom right" : "top left"} color to ${choice.label}"
          title="${choice.label}"
          style="--swatch:${choice.color};">
        </button>
      `;
    })
    .join("");

  const markup = `
    <div class="background-color-panel-shell">
      <label class="settings-toggle-row background-solid-toggle-row" for="solidBackgroundToggle">
        <div class="settings-toggle-copy">
          <span class="settings-toggle-label">Solid Color</span>
          <span class="settings-toggle-note">Use a flat backdrop instead of an image background.</span>
        </div>
        <div class="background-solid-toggle-controls">
          ${solidEnabled ? `<span class="background-fill-preview background-solid-toggle-preview" style="${getCustomBackgroundPreviewStyle()}"></span>` : ""}
          <input
            id="solidBackgroundToggle"
            class="settings-checkbox"
            type="checkbox"
            data-toggle-solid-background
            ${solidEnabled ? "checked" : ""}
            aria-label="Use Solid Color background" />
        </div>
      </label>
      <label class="settings-toggle-row background-solid-toggle-row" for="gradientBackgroundToggle">
        <div class="settings-toggle-copy">
          <span class="settings-toggle-label">Gradient Background</span>
          <span class="settings-toggle-note">Blend two colors diagonally from the top left to the bottom right.</span>
        </div>
        <div class="background-solid-toggle-controls">
          ${gradientEnabled ? `<span class="background-fill-preview background-solid-toggle-preview" style="${getCustomBackgroundPreviewStyle()}"></span>` : ""}
          <input
            id="gradientBackgroundToggle"
            class="settings-checkbox"
            type="checkbox"
            data-toggle-gradient-background
            ${gradientEnabled ? "checked" : ""}
            aria-label="Use Gradient background" />
        </div>
      </label>
      ${solidEnabled ? `
      <article class="custom-gravel-layer-card background-solid-color-card">
        <div class="custom-gravel-layer-header">
          <div>
            <div class="fish-meta">Choose a background color.</div>
          </div>
          <span class="background-fill-preview background-mode-preview" style="${getCustomBackgroundPreviewStyle()}"></span>
        </div>
        <div class="custom-gravel-choice-summary">
          <span>Selected Color</span>
          <strong>${activeChoice.label}</strong>
        </div>
        <div class="custom-gravel-swatches" role="group" aria-label="Solid background color choices">
          ${swatches}
        </div>
      </article>
      ` : ""}
      ${gradientEnabled ? `
      <article class="custom-gravel-layer-card background-solid-color-card">
        <div class="custom-gravel-layer-header">
          <div>
            <div class="fish-meta">Choose two colors for a diagonal gradient backdrop.</div>
          </div>
          <span class="background-fill-preview background-mode-preview" style="${getCustomBackgroundPreviewStyle()}"></span>
        </div>
        <div class="background-gradient-grid">
          <div class="background-gradient-color-group">
            <div class="custom-gravel-choice-summary">
              <span>Top Left</span>
              <strong>${gradientStartChoice.label}</strong>
            </div>
            <div class="custom-gravel-swatches" role="group" aria-label="Top left gradient color choices">
              ${renderGradientSwatches("start", gradientColors.start)}
            </div>
          </div>
          <div class="background-gradient-color-group">
            <div class="custom-gravel-choice-summary">
              <span>Bottom Right</span>
              <strong>${gradientEndChoice.label}</strong>
            </div>
            <div class="custom-gravel-swatches" role="group" aria-label="Bottom right gradient color choices">
              ${renderGradientSwatches("end", gradientColors.end)}
            </div>
          </div>
        </div>
      </article>
      ` : ""}
      <article class="custom-gravel-layer-card background-solid-color-card local-background-panel">
        <div class="custom-gravel-layer-header">
          <div>
            <div class="settings-toggle-label">Local Image Background</div>
            <div class="fish-meta">Use your own image file for this aquarium.</div>
          </div>
          ${localImageReady ? renderBackgroundPreview(runtime.backgroundMap.get(CUSTOM_IMAGE_BACKGROUND_ASSET_KEY), "background-fill-preview background-mode-preview local-background-preview") : `<span class="background-fill-preview background-mode-preview local-background-preview local-background-preview-empty">Image</span>`}
        </div>
        <div class="custom-gravel-choice-summary">
          <span>Status</span>
          <strong>${localImageReady ? (localImageSelected ? "In Use" : "Ready") : "No Image Selected"}</strong>
        </div>
        <div class="shop-button-row local-background-actions">
          <button class="small-button" type="button" data-open-local-background-picker>${localImageReady ? "Replace Image" : "Choose Image"}</button>
          <button class="small-button alt" type="button" data-select-background="${CUSTOM_IMAGE_BACKGROUND_ASSET_KEY}" ${localImageReady ? "" : "disabled"}>${localImageSelected ? "Using This Image" : "Use Image"}</button>
          <button class="small-button alt" type="button" data-clear-local-background ${localImageReady ? "" : "disabled"}>Clear</button>
        </div>
      </article>
    </div>
  `;

  setMarkupIfChanged("equipment-background-color-panel", container, markup);
}

function renderTankAssets() {
  renderSceneAssetCards(dom.tankAssetList, runtime.tankCatalog, state.selectedTankAsset, "data-select-tank", "Use Tank", "Using This Tank");
}

function renderFilterAssets() {
  renderSceneAssetCards(dom.filterAssetList, getOwnedFilterCatalog(), state.selectedFilterAsset, "data-select-filter", "Equip Filter", "Equipped");
  renderSceneAssetCards(dom.equipmentFilterList, getOwnedFilterCatalog(), state.selectedFilterAsset, "data-select-filter", "Equip Filter", "Equipped", "equipment-filter-assets");
}

function renderUvLightControls() {
  const containers = [
    ["uv-light-controls", dom.uvLightList],
    ["equipment-uv-light-controls", dom.equipmentUvLightList]
  ].filter(([, container]) => container);
  if (!containers.length) {
    return;
  }

  const owned = isUvLightOwned();
  const installed = isUvLightInstalled();
  const active = isUvLightActive();
  const markup = owned
    ? `
      <article class="background-card uv-light-card ${installed ? "is-selected" : ""}">
        <img class="scene-thumb" src="${UV_LIGHT_IMAGE_PATH}" alt="UV light" />
        <div>
          <strong>UV Light</strong>
          <div class="fish-meta">${installed ? `Added to this tank. Toolbar switch is ${active ? "on" : "off"}.` : "Owned and ready to add."}</div>
        </div>
        <div class="shop-button-row">
          <button type="button" data-toggle-uv-light-install>${installed ? "Remove from Tank" : "Add to Tank"}</button>
        </div>
      </article>
    `
    : `<div class="empty-state">Buy a UV light from the Tank Shop to add blacklight glow to this aquarium.</div>`;

  for (const [cacheKey, container] of containers) {
    setMarkupIfChanged(cacheKey, container, markup);
  }
}

function renderGravelAssets() {
  const containers = [
    ["scene-assets-gravel", dom.gravelAssetList],
    ["equipment-scene-assets-gravel", dom.equipmentGravelAssetList]
  ].filter(([, container]) => container);
  if (!containers.length) {
    return;
  }

  if (!runtime.gravelCatalog.length) {
    for (const [cacheKey, container] of containers) {
      setMarkupIfChanged(cacheKey, container, `<div class="empty-state">No PNG assets were found in this folder yet.</div>`);
    }
    return;
  }

  const customEnabled = Boolean(state.customGravelEnabled);
  const statusMarkup = customEnabled
    ? `<div class="custom-gravel-status">Sand is currently disabled while Custom Colored Gravel is in use.</div>`
    : "";
  const cardsMarkup = runtime.gravelCatalog
    .map((item) => {
      const selected = state.selectedGravelAsset === item.key;
      const buttonLabel = customEnabled
        ? "Disabled"
        : selected
          ? "Using This Sand"
          : "Use Sand";
      return `
        <article class="background-card ${selected ? "is-selected" : ""}">
          <img class="scene-thumb" src="${item.path}" alt="${item.name}" />
          <div>
            <strong>${item.name}</strong>
            <div class="fish-meta">${item.blurb}</div>
          </div>
          <button data-select-gravel="${item.key}" ${customEnabled ? "disabled" : ""}>
            ${buttonLabel}
          </button>
        </article>
      `;
    })
    .join("");

  for (const [cacheKey, container] of containers) {
    setMarkupIfChanged(cacheKey, container, `${statusMarkup}${cardsMarkup}`);
  }
}

function renderCustomGravelControls() {
  const containers = [
    ["custom-gravel-panel", dom.customGravelPanel],
    ["equipment-custom-gravel-panel", dom.equipmentCustomGravelPanel]
  ].filter(([, container]) => container);
  if (!containers.length) {
    return;
  }

  const layerCatalog = runtime.customGravelLayerCatalog || [];
  const layersReady = hasReadyCustomGravelLayers();
  const enabled = Boolean(state.customGravelEnabled);

  if (!layersReady) {
    for (const [cacheKey, container] of containers) {
      setMarkupIfChanged(
        cacheKey,
        container,
        `<div class="empty-state">Custom gravel layers were not found. Add the three layer PNGs to <code>assets/gravel</code>.</div>`
      );
    }
    return;
  }

  const choices = getCustomGravelColorChoices();
  const activeColors = getActiveCustomGravelLayerColors();
  const activeColorizeSettings = getActiveCustomGravelLayerColorizeSettings();
  const layerMarkup = enabled
    ? layerCatalog
      .map((layer, index) => {
        const activeColor = activeColors[index] || DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR;
        const activeChoice = choices.find((choice) => choice.color === activeColor) || { label: activeColor, color: activeColor };
        const colorizeChecked = activeColorizeSettings[index] === true;
        const swatchMarkup = choices
          .map((choice) => {
            const selected = choice.color === activeColor;
            return `
              <button
                class="custom-gravel-color-swatch ${selected ? "is-selected" : ""}"
                type="button"
                data-custom-gravel-layer="${index}"
                data-custom-gravel-color="${choice.color}"
                aria-pressed="${selected}"
                aria-label="Set ${layer.label} to ${choice.label}"
                title="${choice.label}"
                style="--swatch:${choice.color};">
              </button>
            `;
          })
          .join("");

        return `
          <article class="custom-gravel-layer-card">
            <div class="custom-gravel-layer-header">
              <div>
                <strong>${layer.label}</strong>
                <div class="fish-meta">${layer.drawOrderLabel}</div>
              </div>
              <span class="custom-gravel-layer-swatch" style="--swatch:${activeColor};"></span>
            </div>
            <div class="custom-gravel-choice-summary">
              <span>Selected Color</span>
              <strong>${activeChoice.label}</strong>
            </div>
            <div class="custom-gravel-swatches" role="group" aria-label="${layer.label} color choices">
              ${swatchMarkup}
            </div>
            <label class="cave-colorize-toggle custom-gravel-colorize-toggle">
              <input
                type="checkbox"
                data-custom-gravel-layer="${index}"
                data-custom-gravel-colorize="true"
                ${colorizeChecked ? "checked" : ""} />
              <span>Colorize</span>
            </label>
          </article>
        `;
      })
      .join("")
    : "";

  const markup = `
    <div class="custom-gravel-panel-shell">
      <div class="custom-gravel-toggle-row">
        <div class="compact-heading">
          <strong>Customizable Colored Gravel</strong>
          <p>${enabled
      ? "Sand is disabled while Colored Gravel is enabled."
      : "Enable to replace sand with customizable colored gravel."}</p>
        </div>
        <button
          class="custom-gravel-toggle ${enabled ? "is-active" : ""}"
          type="button"
          data-toggle-custom-gravel="true"
          aria-pressed="${enabled}">
          <span>Enable</span>
          <strong>${enabled ? "On" : "Off"}</strong>
        </button>
      </div>
      ${enabled ? `<div class="custom-gravel-layer-list">${layerMarkup}</div>` : ""}
    </div>
  `;

  for (const [cacheKey, container] of containers) {
    setMarkupIfChanged(cacheKey, container, markup);
  }
}

function renderBubbleAssets() {
  renderSceneAssetCards(dom.bubbleAssetList, runtime.bubbleCatalog, state.selectedBubbleAsset, "data-select-bubble", "Use Bubbles", "Using These Bubbles");
}

function renderSceneAssetCards(container, items, selectedKey, attributeName, useLabel, activeLabel, cacheKeyOverride = "") {
  if (!container) {
    return;
  }

  if (!items.length) {
    setMarkupIfChanged(cacheKeyOverride || `scene-assets-${attributeName}`, container, `<div class="empty-state">No PNG assets were found in this folder yet.</div>`);
    return;
  }

  const markup = items
    .map((item) => {
      const selected = selectedKey === item.key;
      return `
        <article class="background-card ${selected ? "is-selected" : ""}">
          <img class="scene-thumb" src="${item.path}" alt="${item.name}" />
          <div>
            <strong>${item.name}</strong>
            <div class="fish-meta">${item.blurb}</div>
          </div>
          <button ${attributeName}="${item.key}">
            ${selected ? activeLabel : useLabel}
          </button>
        </article>
      `;
    })
    .join("");
  setMarkupIfChanged(cacheKeyOverride || `scene-assets-${attributeName}`, container, markup);
}

function renderControls(now) {
  const currentSlot = getCurrentMealSlot(now);
  const selectedActiveFish = state.fish.find((fish) => fish.id === runtime.selectedFishId);
  const hasCaveDecor = state.placedDecor.some((item) => isCaveDecorKey(item.decorKey));
  const hasCaveFishCandidate = hasCaveDecor && state.fish.some((fish) => {
    const species = getSpeciesForFish(fish);
    return species && species.behavior !== "sucker" && species.caveEnabled !== false && !isFishDead(fish);
  });
  const hasGravelPebbleCandidate = hasFishGravelPebbleCandidate(now);

  dom.feedButton.disabled = false;
  if (dom.medicineButton) {
    dom.medicineButton.disabled = false;
  }

  dom.resetMealsButton.hidden = !DEBUG_MODE;
  dom.debugDispenserButton.hidden = !DEBUG_MODE;
  dom.debugDamageFishButton.hidden = !DEBUG_MODE;
  dom.debugBreedButton.hidden = !DEBUG_MODE;
  dom.resetFishHealthButton.hidden = !DEBUG_MODE;
  dom.addCoinsButton.hidden = !DEBUG_MODE;
  dom.maxDirtButton.hidden = !DEBUG_MODE;
  dom.deleteAllButton.hidden = !DEBUG_MODE;
  dom.debugGravelPebbleButton.hidden = !DEBUG_MODE;
  dom.debugCaveButton.hidden = !DEBUG_MODE;

  dom.resetMealsButton.disabled = !DEBUG_MODE;
  dom.debugDispenserButton.disabled = !DEBUG_MODE || !hasAutoDispenserInstalled();
  dom.resetFishHealthButton.disabled = !DEBUG_MODE;
  dom.addCoinsButton.disabled = !DEBUG_MODE;
  dom.maxDirtButton.disabled = !DEBUG_MODE;
  dom.deleteAllButton.disabled = !DEBUG_MODE;
  dom.debugGravelPebbleButton.disabled = !DEBUG_MODE || !hasGravelPebbleCandidate;
  dom.debugDamageFishButton.disabled = !DEBUG_MODE || !selectedActiveFish || isFishDead(selectedActiveFish);
  dom.debugBreedButton.disabled = !DEBUG_MODE || (!hasDebugBreedingPairCandidate(now) && !runtime.debugBreedingSequence);
  dom.debugBreedButton.classList.toggle("is-active", Boolean(runtime.debugBreedingSequence));
  dom.debugBreedButton.title = runtime.debugBreedingSequence
    ? "Debug: Baby Sequence Running"
    : "Debug: Make a Baby";
  dom.debugBreedButton.setAttribute(
    "aria-label",
    runtime.debugBreedingSequence
      ? "Debug: Baby Sequence Running"
      : "Debug: Make a Baby"
  );
  dom.debugCaveButton.disabled = !DEBUG_MODE || (!hasCaveFishCandidate && !runtime.debugNightCaveMode);
  dom.debugCaveButton.classList.toggle("is-active", runtime.debugNightCaveMode);
  dom.debugCaveButton.title = runtime.debugNightCaveMode
    ? "Debug: Disable Cave Test Loop"
    : "Debug: Force Cave Test Loop";
  dom.debugCaveButton.setAttribute(
    "aria-label",
    runtime.debugNightCaveMode
      ? "Debug: Disable Cave Test Loop"
      : "Debug: Force Cave Test Loop"
  );
  if (dom.debugGravelPebbleButton) {
    dom.debugGravelPebbleButton.title = hasGravelPebbleCandidate
      ? "Debug: Force Gravel Pebble Toss"
      : "Debug: Enable Custom Gravel and keep a living non-sucker fish in the tank";
    dom.debugGravelPebbleButton.setAttribute(
      "aria-label",
      hasGravelPebbleCandidate
        ? "Debug: Force Gravel Pebble Toss"
        : "Debug: Enable Custom Gravel and keep a living non-sucker fish in the tank"
    );
  }

  dom.spongeButton.classList.toggle("is-active", runtime.cleaningMode);
  dom.scoopButton?.classList.toggle("is-active", runtime.scoopMode);
  dom.feedButton.classList.toggle("is-active", runtime.foodTrayOpen || Boolean(runtime.feedingModeFoodKey));
  dom.medicineButton?.classList.toggle("is-active", runtime.medicineTrayOpen || Boolean(runtime.medicineModeKey));
  dom.openEquipmentButton?.classList.toggle("is-active", runtime.equipmentOverlayOpen);
  dom.openSettingsButton?.classList.toggle("is-active", runtime.settingsOverlayOpen);
  dom.openManagementButton?.classList.toggle("is-active", runtime.utilityOverlayOpen && runtime.utilityOverlayMode === "tank-management");
  dom.toggleMouseLockButton?.classList.toggle("is-active", isTankMouseInputLocked());
  if (dom.uvLightToggleButton) {
    const uvInstalled = isUvLightInstalled();
    const uvActive = isUvLightActive();
    dom.uvLightToggleButton.hidden = !uvInstalled;
    dom.uvLightToggleButton.classList.toggle("is-active", uvActive);
    dom.uvLightToggleButton.title = uvActive ? "Turn UV Light Off" : "Turn UV Light On";
    dom.uvLightToggleButton.setAttribute("aria-label", uvActive ? "Turn UV Light Off" : "Turn UV Light On");
    dom.uvLightToggleButton.setAttribute("aria-pressed", String(uvActive));
  }
  if (dom.toolbarTab) {
    const uiSettings = getUiSettings();
    const toolbarCollapsed = uiSettings.toolbarCollapsed;
    const tabLabel = toolbarCollapsed ? "Show Toolbar" : "Hide Toolbar";
    const tabIconMap = {
      "right-center": toolbarCollapsed ? "<" : ">",
      "left-center": toolbarCollapsed ? ">" : "<",
      "bottom-center": toolbarCollapsed ? "^" : "v"
    };
    dom.toolbarTab.textContent = tabIconMap[uiSettings.toolbarPosition] || ">";
    dom.toolbarTab.title = tabLabel;
    dom.toolbarTab.setAttribute("aria-label", tabLabel);
    dom.toolbarTab.setAttribute("aria-pressed", String(toolbarCollapsed));
  }
  if (dom.displayTab) {
    const uiSettings = getUiSettings();
    const displayCollapsed = uiSettings.displayCollapsed;
    const displayAtBottom = uiSettings.displayPosition.startsWith("bottom-");
    const displayLabel = displayCollapsed ? "Show Display" : "Hide Display";
    dom.displayTab.textContent = displayAtBottom
      ? (displayCollapsed ? "^" : "v")
      : (displayCollapsed ? "v" : "^");
    dom.displayTab.title = displayLabel;
    dom.displayTab.setAttribute("aria-label", displayLabel);
    dom.displayTab.setAttribute("aria-pressed", String(displayCollapsed));
  }
  if (dom.openEquipmentButton) {
    dom.openEquipmentButton.title = runtime.equipmentOverlayOpen ? "Edit Tank (Open)" : "Edit Tank";
    dom.openEquipmentButton.setAttribute("aria-label", runtime.equipmentOverlayOpen ? "Edit Tank open" : "Edit Tank");
  }
  if (dom.openSettingsButton) {
    dom.openSettingsButton.title = runtime.settingsOverlayOpen ? "Settings (Open)" : "Settings";
    dom.openSettingsButton.setAttribute("aria-label", runtime.settingsOverlayOpen ? "Settings open" : "Settings");
  }
  if (dom.openManagementButton) {
    const managementOpen = runtime.utilityOverlayOpen && runtime.utilityOverlayMode === "tank-management";
    dom.openManagementButton.title = managementOpen ? "Tank Management (Open)" : "Tank Management";
    dom.openManagementButton.setAttribute("aria-label", managementOpen ? "Tank Management open" : "Tank Management");
  }
  if (dom.toggleMouseLockButton) {
    const locked = isTankMouseInputLocked();
    dom.toggleMouseLockButton.title = locked ? "Unlock Tank Mouse Input" : "Lock Tank Mouse Input";
    dom.toggleMouseLockButton.setAttribute("aria-label", locked ? "Unlock Tank Mouse Input" : "Lock Tank Mouse Input");
    dom.toggleMouseLockButton.setAttribute("aria-pressed", String(locked));
  }
  dom.editModeDockButton?.classList.toggle("is-active", runtime.editTankMode);
  if (dom.editModeDockButton) {
    dom.editModeDockButton.title = runtime.editTankMode ? "Edit Decor (Active)" : "Edit Decor";
    dom.editModeDockButton.setAttribute("aria-label", runtime.editTankMode ? "Edit Decor (Active)" : "Edit Decor");
  }
  const activeDecorShortcutTarget = getActiveDecorShortcutTarget();
  const activeDecorShortcutKey = activeDecorShortcutTarget?.decorKey || "";
  const hasActiveDecorShortcutTarget = Boolean(activeDecorShortcutKey);
  const layerShortcutsDisabled = !hasActiveDecorShortcutTarget;
  const scaleShortcutsDisabled = !hasActiveDecorShortcutTarget;
  const layerShortcutHint = !hasActiveDecorShortcutTarget
    ? "Select or drag decor to change its layer"
    : "";
  if (dom.editLayerUpButton) {
    dom.editLayerUpButton.hidden = !runtime.editTankMode;
    dom.editLayerUpButton.disabled = layerShortcutsDisabled;
    dom.editLayerUpButton.title = layerShortcutsDisabled ? layerShortcutHint : "Next decor layer (Z / Up)";
    dom.editLayerUpButton.setAttribute("aria-label", layerShortcutsDisabled ? layerShortcutHint : "Next decor layer (Z / Up)");
  }
  if (dom.editLayerDownButton) {
    dom.editLayerDownButton.hidden = !runtime.editTankMode;
    dom.editLayerDownButton.disabled = layerShortcutsDisabled;
    dom.editLayerDownButton.title = layerShortcutsDisabled ? layerShortcutHint : "Previous decor layer (X / Down)";
    dom.editLayerDownButton.setAttribute("aria-label", layerShortcutsDisabled ? layerShortcutHint : "Previous decor layer (X / Down)");
  }
  if (dom.editScaleUpButton) {
    dom.editScaleUpButton.hidden = !runtime.editTankMode;
    dom.editScaleUpButton.disabled = scaleShortcutsDisabled;
    dom.editScaleUpButton.title = scaleShortcutsDisabled ? "Select or drag decor to resize it" : "Increase decor size (+)";
    dom.editScaleUpButton.setAttribute("aria-label", scaleShortcutsDisabled ? "Select or drag decor to resize it" : "Increase decor size (+)");
  }
  if (dom.editScaleDownButton) {
    dom.editScaleDownButton.hidden = !runtime.editTankMode;
    dom.editScaleDownButton.disabled = scaleShortcutsDisabled;
    dom.editScaleDownButton.title = scaleShortcutsDisabled ? "Select or drag decor to resize it" : "Decrease decor size (-)";
    dom.editScaleDownButton.setAttribute("aria-label", scaleShortcutsDisabled ? "Select or drag decor to resize it" : "Decrease decor size (-)");
  }
  dom.fishEditModeDockButton?.classList.toggle("is-active", runtime.fishEditMode);
  if (dom.fishEditModeDockButton) {
    dom.fishEditModeDockButton.title = runtime.fishEditMode ? "Manage Fish (Active)" : "Manage Fish";
    dom.fishEditModeDockButton.setAttribute("aria-label", runtime.fishEditMode ? "Manage Fish (Active)" : "Manage Fish");
  }
  dom.toggleEditMode.classList.toggle("is-active", runtime.editTankMode);
  dom.toggleEditMode.textContent = runtime.editTankMode ? "Editing" : "Edit";
  renderScrubProgress();

  renderPlacementHint();

  dom.tankStage.style.cursor = (runtime.cleaningMode || runtime.scoopMode || runtime.feedingModeFoodKey || runtime.medicineModeKey)
    ? "none"
    : (runtime.dragState || runtime.fishDragState)
      ? "grabbing"
      : (runtime.editTankMode || runtime.fishEditMode)
        ? "grab"
        : "default";
  renderToolCursor();
}

function renderToolCursor() {
  const visible = (runtime.cleaningMode || runtime.scoopMode || runtime.feedingModeFoodKey || runtime.medicineModeKey) && runtime.pointerStagePx;
  dom.toolCursor.hidden = !visible;

  if (!visible) {
    dom.toolCursor.textContent = "";
    return;
  }

  if (runtime.feedingModeFoodKey || runtime.medicineModeKey) {
    dom.toolCursor.textContent = runtime.medicineModeKey ? "💊" : "🍗";
    dom.toolCursor.style.left = `${runtime.pointerStagePx.x}px`;
    dom.toolCursor.style.top = `${runtime.pointerStagePx.y}px`;
    return;
  }

  dom.toolCursor.textContent = runtime.scoopMode ? "🥄" : "🧽";
  dom.toolCursor.style.left = `${runtime.pointerStagePx.x}px`;
  dom.toolCursor.style.top = `${runtime.pointerStagePx.y}px`;
}

function renderScrubProgress() {
  const scrubPercent = Math.round(getScrubCoverage() * 100);
  if (dom.scrubProgressLabel) {
    dom.scrubProgressLabel.textContent = `${scrubPercent}%`;
  }
  if (dom.scrubProgressBar) {
    dom.scrubProgressBar.style.width = `${scrubPercent}%`;
  }
}

function animationLoop(frameTime) {
  window.requestAnimationFrame(animationLoop);
  const rafDeltaSeconds = runtime.lastAnimationFrameAt
    ? Math.min(1, (frameTime - runtime.lastAnimationFrameAt) / 1000)
    : 0.016;
  runtime.lastAnimationFrameAt = frameTime;
  if (isWallpaperEnginePauseActive()) {
    runtime.lastAnimationUpdateAt = frameTime;
    runtime.wallpaperEngineFpsCarrySeconds = 0;
    return;
  }
  if (runtime.wallpaperEngineFpsLimit > 0) {
    runtime.wallpaperEngineFpsCarrySeconds += rafDeltaSeconds;
    const fpsThreshold = 1 / runtime.wallpaperEngineFpsLimit;
    if (runtime.wallpaperEngineFpsCarrySeconds < fpsThreshold) {
      return;
    }
    runtime.wallpaperEngineFpsCarrySeconds = Math.max(0, runtime.wallpaperEngineFpsCarrySeconds - fpsThreshold);
  }

  const now = Date.now();
  const deltaSeconds = runtime.lastAnimationUpdateAt
    ? Math.min(0.05, (frameTime - runtime.lastAnimationUpdateAt) / 1000)
    : 0.016;
  runtime.lastAnimationUpdateAt = frameTime;
  updateAmbienceAudioLoop();
  updateCleaningTransition(now);
  updateSplashBursts(now);
  updateFishMotion(now, deltaSeconds);
  renderTank(now);
  updateSelectedDecorActionButtons();
  renderCustomDecorMotionPreview(now);
  renderDecorSettingsMotionPreview(now);
}

function getPiranhaTargetCandidate(now = Date.now()) {
  if (!PIRANHA_BEHAVIOR_ENABLED || !isViolenceEnabled()) {
    return null;
  }

  const activePrey = getActivePiranhaPrey(now);
  if (activePrey) {
    return activePrey;
  }

  const piranhas = getLivingPiranhaFish();
  if (!piranhas.length) {
    return null;
  }

  const draggedFishId = runtime.fishDragState?.fishId || null;
  const centroid = piranhas.reduce((accumulator, fish) => ({
    xNorm: accumulator.xNorm + fish.xNorm,
    yNorm: accumulator.yNorm + fish.yNorm
  }), { xNorm: 0, yNorm: 0 });
  centroid.xNorm /= piranhas.length;
  centroid.yNorm /= piranhas.length;

  return state.fish
    .filter((fish) => (
      fish
      && fish.id !== draggedFishId
      && !isPiranhaSpecies(fish)
      && !isUndeadFish(fish)
      && !isFishBeingConsumedByPiranhas(fish, now)
      && (
        isValidPiranhaConsumptionPrey(fish)
        || (
          !isFishDead(fish)
          && !isFishProtectedFromPredators(fish, now)
          && !hasZombieBiteInfection(fish)
        )
      )
    ))
    .sort((left, right) => {
      const leftDead = isFishDead(left) ? 0 : 1;
      const rightDead = isFishDead(right) ? 0 : 1;
      if (leftDead !== rightDead) {
        return leftDead - rightDead;
      }

      const leftDistance = Math.hypot(left.xNorm - centroid.xNorm, left.yNorm - centroid.yNorm);
      const rightDistance = Math.hypot(right.xNorm - centroid.xNorm, right.yNorm - centroid.yNorm);
      return leftDistance - rightDistance
        || (right.tankAddedAt || right.acquiredAt || 0) - (left.tankAddedAt || left.acquiredAt || 0);
    })[0] || null;
}

function getActivePiranhaPrey(now = Date.now()) {
  return state.fish.find((fish) => isFishBeingConsumedByPiranhas(fish, now)) || null;
}

function clearPiranhaAttackState(fish) {
  if (!fish) {
    return;
  }

  fish.piranhaAttackStartedAt = null;
  fish.piranhaLastDamageAt = null;
  fish.piranhaLastBloodAt = null;
}

function clearFishPanicState(fish) {
  if (!fish) {
    return;
  }

  fish.panicUntil = null;
  fish.panicSpeedBoost = null;
}

function clearZombieAttackState(fish) {
  if (!fish) {
    return;
  }

  fish.zombieBiteStartedAt = null;
  fish.zombieBiteLastBloodAt = null;
  fish.zombieBiteAttackerId = null;
  clearFishPanicState(fish);
  if (!isFishDead(fish)) {
    fish.zombieReviveAt = null;
    fish.zombieReviveSourceId = null;
  }
}

function resetLivingFishPredatorState(fish, now = Date.now(), options = {}) {
  if (!fish || isFishDead(fish)) {
    return;
  }

  clearFishPanicState(fish);
  clearZombieAttackState(fish);
  clearPiranhaAttackState(fish);
  fish.piranhaConsumptionStartedAt = null;
  fish.piranhaConsumptionEndsAt = null;
  fish.piranhaLastBloodAt = null;
  fish.decayStage = null;
  fish.tankAddedAt = now;

  if (options.entryAnimation) {
    fish.entryStartedAt = now;
    fish.entryDurationMs = Math.max(0, Number(options.entryDurationMs) || 1450);
    fish.entryFromYNorm = Number.isFinite(Number(options.entryFromYNorm))
      ? clamp(Number(options.entryFromYNorm), 0.02, 0.18)
      : 0.03;
    fish.entrySplashTriggered = false;
  }
}

function applyContentSettingsEffects(now = Date.now()) {
  if (!state) {
    return false;
  }

  const settings = getContentSettings();
  const violenceAndGoreEnabled = settings.violenceAndGoreEnabled;
  let changed = false;

  if (!violenceAndGoreEnabled && (runtime.bloodClouds.length || runtime.bloodWaterTint > 0)) {
    runtime.bloodClouds = [];
    runtime.bloodWaterTint = 0;
  }

  if (!violenceAndGoreEnabled && runtime.chumBloodCloudAtByPelletId?.size) {
    runtime.chumBloodCloudAtByPelletId.clear();
  }

  if (!violenceAndGoreEnabled && runtime.bettaPassLocks.size) {
    runtime.bettaPassLocks.clear();
  }

  if (!violenceAndGoreEnabled && runtime.medicineModeKey === "antidote") {
    runtime.medicineModeKey = "";
  }

  if (!violenceAndGoreEnabled && isFilteredGoreDecor(runtime.placementMode?.decorKey)) {
    runtime.placementMode = null;
    runtime.placementPreview = null;
  }

  for (const fish of [...state.fish, ...state.storedFish]) {
    if (!fish) {
      continue;
    }

    const hasZombieState = (
      hasDefinedFiniteNumber(fish.zombieBiteStartedAt)
      || hasDefinedFiniteNumber(fish.zombieBiteLastBloodAt)
      || hasDefinedFiniteNumber(fish.zombieReviveAt)
      || (typeof fish.zombieReviveSourceId === "string" && fish.zombieReviveSourceId.trim())
    );
    const hasPiranhaState = (
      hasDefinedFiniteNumber(fish.piranhaAttackStartedAt)
      || hasDefinedFiniteNumber(fish.piranhaLastDamageAt)
      || hasDefinedFiniteNumber(fish.piranhaConsumptionStartedAt)
      || hasDefinedFiniteNumber(fish.piranhaConsumptionEndsAt)
      || hasDefinedFiniteNumber(fish.piranhaLastBloodAt)
    );

    if (!violenceAndGoreEnabled && hasZombieState) {
      clearZombieAttackState(fish);
      fish.zombieReviveAt = null;
      fish.zombieReviveSourceId = null;
      changed = true;
    }

    if (!violenceAndGoreEnabled && hasPiranhaState) {
      clearPiranhaAttackState(fish);
      fish.piranhaConsumptionStartedAt = null;
      fish.piranhaConsumptionEndsAt = null;
      fish.piranhaLastBloodAt = null;
      changed = true;
    }

    if (!violenceAndGoreEnabled && fish.decayStage !== null) {
      fish.decayStage = null;
      changed = true;
    }
  }

  return changed;
}

function setContentSetting(settingKey, value) {
  if (!state || settingKey !== "violenceAndGoreEnabled") {
    return;
  }

  const currentSettings = getContentSettings();
  const nextSettings = sanitizeContentSettings({
    ...currentSettings,
    [settingKey]: Boolean(value)
  });

  if (currentSettings.violenceAndGoreEnabled === nextSettings.violenceAndGoreEnabled) {
    return;
  }

  state.contentSettings = nextSettings;
  const now = Date.now();
  applyContentSettingsEffects(now);
  saveState();
  renderUi(now);
  showToast(
    nextSettings.violenceAndGoreEnabled
      ? "Violence & Gore enabled."
      : "Violence & Gore disabled."
  );
}

function setToolbarPosition(toolbarPosition) {
  if (!state) {
    return;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    toolbarPosition
  });
  if (currentSettings.toolbarPosition === nextSettings.toolbarPosition) {
    return;
  }

  state.uiSettings = nextSettings;
  saveState();
  renderUi(Date.now());
}

function setDisplayPosition(displayPosition) {
  if (!state) {
    return;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    displayPosition
  });
  if (currentSettings.displayPosition === nextSettings.displayPosition) {
    return;
  }

  state.uiSettings = nextSettings;
  saveState();
  renderUi(Date.now(), { full: false });
}

function setSoundMuted(value, options = {}) {
  if (!state) {
    return false;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    soundMuted: Boolean(value)
  });
  if (currentSettings.soundMuted === nextSettings.soundMuted) {
    return false;
  }

  const shouldSave = options.save !== false;
  const shouldRender = options.render !== false;
  const shouldShowToast = options.showToast !== false;
  state.uiSettings = nextSettings;
  syncAmbienceAudio();
  if (nextSettings.soundMuted) {
    stopActiveSoundEffects();
  }
  if (shouldSave) {
    saveState();
  }
  if (shouldRender) {
    renderUi(Date.now(), { full: false });
  }
  if (shouldShowToast) {
    showToast(nextSettings.soundMuted ? "Sounds muted." : "Sounds on.");
  }
  return true;
}

function clearTankMouseInteractionState() {
  runtime.suppressNextTankClick = false;
  runtime.pointerDown = false;
  runtime.lastTankPoint = null;
  runtime.lastScrubPoint = null;
  runtime.pointerStagePx = null;
  resetScrubWipeSoundState();
  clearPrimaryToolModes();
  runtime.selectedFishId = null;
}

function setTankMouseInputLocked(value) {
  if (!state) {
    return;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    tankMouseInputLocked: Boolean(value)
  });
  if (currentSettings.tankMouseInputLocked === nextSettings.tankMouseInputLocked) {
    return;
  }

  if (nextSettings.tankMouseInputLocked) {
    clearTankMouseInteractionState();
  }

  state.uiSettings = nextSettings;
  saveState();
  renderUi(Date.now(), { full: false });
  showToast(
    nextSettings.tankMouseInputLocked
      ? "Tank mouse input locked."
      : "Tank mouse input unlocked."
  );
}

function toggleTankMouseInputLocked(force = null) {
  const currentSettings = getUiSettings();
  setTankMouseInputLocked(
    typeof force === "boolean"
      ? force
      : !currentSettings.tankMouseInputLocked
  );
}

function toggleToolbarCollapsed(force = null) {
  if (!state) {
    return;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    toolbarCollapsed: typeof force === "boolean"
      ? force
      : !currentSettings.toolbarCollapsed
  });
  if (currentSettings.toolbarCollapsed === nextSettings.toolbarCollapsed) {
    return;
  }

  state.uiSettings = nextSettings;
  saveState();
  renderUi(Date.now(), { full: false });
}

function toggleDisplayCollapsed(force = null) {
  if (!state) {
    return;
  }

  const currentSettings = getUiSettings();
  const nextSettings = sanitizeUiSettings({
    ...currentSettings,
    displayCollapsed: typeof force === "boolean"
      ? force
      : !currentSettings.displayCollapsed
  });
  if (currentSettings.displayCollapsed === nextSettings.displayCollapsed) {
    return;
  }

  state.uiSettings = nextSettings;
  saveState();
  renderUi(Date.now(), { full: false });
}

function getFishPredatorProtectionStartedAt(fish) {
  if (!fish) {
    return null;
  }

  const candidates = [
    fish.tankAddedAt,
    fish.entryStartedAt,
    fish.acquiredAt
  ]
    .map((value) => Number(value))
    .filter(Number.isFinite);

  if (!candidates.length) {
    return null;
  }

  return Math.max(...candidates);
}

function isFishProtectedFromPredators(fish, now = Date.now()) {
  const protectedStartedAt = getFishPredatorProtectionStartedAt(fish);
  if (!Number.isFinite(protectedStartedAt)) {
    return false;
  }

  return (now - protectedStartedAt) < FISH_SPAWN_PROTECTION_MS;
}

function scrubProtectedFishPredatorState(fish, now = Date.now()) {
  if (!fish || isFishDead(fish) || !isFishProtectedFromPredators(fish, now)) {
    return false;
  }

  let changed = false;

  if (
    hasDefinedFiniteNumber(fish.zombieBiteStartedAt)
    || hasDefinedFiniteNumber(fish.zombieBiteLastBloodAt)
    || hasDefinedFiniteNumber(fish.zombieReviveAt)
  ) {
    clearZombieAttackState(fish);
    changed = true;
  }

  if (
    hasDefinedFiniteNumber(fish.piranhaAttackStartedAt)
    || hasDefinedFiniteNumber(fish.piranhaLastDamageAt)
    || hasDefinedFiniteNumber(fish.piranhaConsumptionStartedAt)
    || hasDefinedFiniteNumber(fish.piranhaConsumptionEndsAt)
    || hasDefinedFiniteNumber(fish.piranhaLastBloodAt)
    || fish.decayStage !== null
  ) {
    clearPiranhaAttackState(fish);
    clearFishPanicState(fish);
    fish.piranhaConsumptionStartedAt = null;
    fish.piranhaConsumptionEndsAt = null;
    fish.piranhaLastBloodAt = null;
    fish.decayStage = null;
    changed = true;
  }

  return changed;
}

function scrubProtectedTankFishPredatorState(now = Date.now()) {
  if (!state?.fish?.length) {
    return false;
  }

  let changed = false;
  for (const fish of state.fish) {
    changed = scrubProtectedFishPredatorState(fish, now) || changed;
  }

  return changed;
}

function scrubImpossiblePredatorState(now = Date.now()) {
  if (!state) {
    return false;
  }

  let changed = false;
  const zombieHunterIds = getLivingZombieHunterIds();
  const piranhaContext = hasPiranhaContext();

  for (const fish of [...state.fish, ...state.storedFish]) {
    if (!fish) {
      continue;
    }

    if (
      (
        hasDefinedFiniteNumber(fish.zombieBiteStartedAt)
        || hasDefinedFiniteNumber(fish.zombieBiteLastBloodAt)
      )
      && !hasValidZombieBiteSource(fish, zombieHunterIds)
    ) {
      clearZombieAttackState(fish);
      changed = true;
    }

    if (
      isFishDead(fish)
      && hasDefinedFiniteNumber(fish.zombieReviveAt)
      && typeof fish.zombieReviveSourceId === "string"
      && fish.zombieReviveSourceId.trim()
      && !zombieHunterIds.has(fish.zombieReviveSourceId.trim())
    ) {
      fish.zombieReviveAt = null;
      fish.zombieReviveSourceId = null;
      changed = true;
    }

    if (
      !piranhaContext
      && (
        hasDefinedFiniteNumber(fish.piranhaAttackStartedAt)
        || hasDefinedFiniteNumber(fish.piranhaLastDamageAt)
        || hasDefinedFiniteNumber(fish.piranhaConsumptionStartedAt)
        || hasDefinedFiniteNumber(fish.piranhaConsumptionEndsAt)
        || hasDefinedFiniteNumber(fish.piranhaLastBloodAt)
      )
    ) {
      clearPiranhaAttackState(fish);
      clearFishPanicState(fish);
      fish.piranhaConsumptionStartedAt = null;
      fish.piranhaConsumptionEndsAt = null;
      fish.piranhaLastBloodAt = null;
      fish.decayStage = isFishDead(fish) ? getFishDecayStage(fish, now) : null;
      changed = true;
    }

    if (
      !hasZombieBiteInfection(fish)
      && !isFishCriticallyLowHealth(fish)
      && (
        hasDefinedFiniteNumber(fish.panicUntil)
        || hasDefinedFiniteNumber(fish.panicSpeedBoost)
      )
    ) {
      clearFishPanicState(fish);
      changed = true;
    }
  }

  return changed;
}

function isValidZombieBiteTarget(fish, now = Date.now()) {
  if (!fish) {
    return false;
  }

  if (isFishDead(fish)) {
    return false;
  }

  if (isPiranhaSpecies(fish)) {
    return false;
  }

  if (isUndeadFish(fish)) {
    return false;
  }

  if (isFishProtectedFromPredators(fish, now)) {
    return false;
  }

  if (hasZombieBiteInfection(fish)) {
    return false;
  }

  if (hasDefinedFiniteNumber(fish.piranhaAttackStartedAt)) {
    return false;
  }

  if (isFishBeingConsumedByPiranhas(fish, now)) {
    return false;
  }

  return true;
}

function isValidPiranhaPrey(fish, now = Date.now()) {
  if (!fish) {
    return false;
  }

  if (isFishDead(fish)) {
    return false;
  }

  if (isPiranhaSpecies(fish)) {
    return false;
  }

  if (isUndeadFish(fish)) {
    return false;
  }

  if (isFishProtectedFromPredators(fish, now)) {
    return false;
  }

  if (hasZombieBiteInfection(fish)) {
    return false;
  }

  if (isFishBeingConsumedByPiranhas(fish, now)) {
    return false;
  }

  return true;
}

function isValidPiranhaConsumptionPrey(fish) {
  if (!fish) {
    return false;
  }

  if (!isFishDead(fish)) {
    return false;
  }

  if (isPiranhaSpecies(fish) || isUndeadFish(fish)) {
    return false;
  }

  return state.fish.some((entry) => entry.id === fish.id);
}

function startPiranhaAttack(prey, now = Date.now()) {
  if (!PIRANHA_BEHAVIOR_ENABLED || !isViolenceEnabled()) {
    return false;
  }

  if (!isValidPiranhaPrey(prey, now) || isFishDead(prey)) {
    return false;
  }

  if (!hasDefinedFiniteNumber(prey.piranhaAttackStartedAt)) {
    prey.piranhaAttackStartedAt = now;
    prey.piranhaLastDamageAt = now;
    prey.piranhaLastBloodAt = now - PIRANHA_BLOOD_CLOUD_INTERVAL_MS;
    pushEvent(`Piranhas started attacking ${prey.name}.`, now);
    saveState();
  }

  return true;
}

function updatePiranhaSwarmTargets(now = Date.now()) {
  if (!PIRANHA_BEHAVIOR_ENABLED || !isViolenceEnabled()) {
    return;
  }

  const piranhas = getLivingPiranhaFish();
  const prey = getPiranhaTargetCandidate(now);
  if (!piranhas.length || !prey) {
    return;
  }

  const preyLayer = isFishDead(prey)
    ? clampTankLayer(Math.min(getFishTankLayer(prey), 2))
    : clampTankLayer(Math.max(1, Math.min(TANK_DEPTH_LAYERS - 1, getFishTankLayer(prey))));
  const orbitRadius = isFishBeingConsumedByPiranhas(prey, now) ? 0.022 : 0.05;

  piranhas.forEach((piranha, index) => {
    if (runtime.fishDragState?.fishId === piranha.id) {
      return;
    }

    const species = getSpeciesForFish(piranha);
    if (!species) {
      return;
    }

    const angle = ((now / 420) + index / Math.max(1, piranhas.length)) * Math.PI * 2 + (piranha.phase || 0) * Math.PI * 2;
    piranha.targetXNorm = clamp(prey.xNorm + Math.cos(angle) * orbitRadius, 0.08, 0.92);
    piranha.targetYNorm = clamp(prey.yNorm + Math.sin(angle) * orbitRadius * 0.65, 0.14, 0.8);
    piranha.targetAt = now + PIRANHA_TARGET_REFRESH_MS;
    piranha.hangoutDecorId = null;
    setFishDesiredTankLayer(piranha, preyLayer);
    piranha.swimSpeed = normalizeFishSpeed(
      species,
      randomBetween(Math.max(species.speedMin, species.speedMax * 0.82), species.speedMax)
    );
  });
}

function beginPiranhaConsumption(prey, now = Date.now()) {
  if (!PIRANHA_BEHAVIOR_ENABLED || !isViolenceEnabled()) {
    return false;
  }
  if (!isValidPiranhaConsumptionPrey(prey)) {
    return false;
  }

  if (isFishBeingConsumedByPiranhas(prey, now)) {
    return false;
  }

  clearPiranhaAttackState(prey);
  pushEvent(`Piranhas started feeding on ${prey.name}.`, now);

  prey.decayStage = "fresh";
  prey.piranhaConsumptionStartedAt = now;
  prey.piranhaConsumptionEndsAt = now + PIRANHA_CONSUMPTION_DURATION_MS;
  prey.piranhaLastBloodAt = now - PIRANHA_BLOOD_CLOUD_INTERVAL_MS;

  spawnBloodCloud(prey.xNorm, prey.yNorm, 2.2);
  runtime.bloodWaterTint = clamp(runtime.bloodWaterTint + 0.12, 0, 1);
  saveState();
  return true;
}

function handlePiranhaSwarm(now, deltaSeconds) {
  if (!PIRANHA_BEHAVIOR_ENABLED || !isViolenceEnabled()) {
    return;
  }

  if (finalizePiranhaConsumedFish(getCompletedPiranhaConsumedFish(now), now, { immediate: true })) {
    return;
  }

  const piranhas = getLivingPiranhaFish();
  if (!piranhas.length) {
    return;
  }

  const activePrey = getActivePiranhaPrey(now);
  if (activePrey) {
    runtime.bloodWaterTint = clamp(runtime.bloodWaterTint + deltaSeconds * 0.07, 0, 1);

    if (
      !hasDefinedFiniteNumber(activePrey.piranhaLastBloodAt)
      || now - Number(activePrey.piranhaLastBloodAt) >= PIRANHA_BLOOD_CLOUD_INTERVAL_MS
    ) {
      const intensity = 2.2 + piranhas.length * 0.45;
      spawnBloodCloud(
        clamp(activePrey.xNorm + randomBetween(-0.008, 0.008), 0.08, 0.92),
        clamp(activePrey.yNorm + randomBetween(-0.008, 0.008), 0.14, 0.8),
        intensity
      );
      activePrey.piranhaLastBloodAt = now;
    }

    return;
  }

  const prey = getPiranhaTargetCandidate(now);
  if (!prey) {
    return;
  }

  const preyIsDead = isFishDead(prey);
  if (preyIsDead ? !isValidPiranhaConsumptionPrey(prey) : !isValidPiranhaPrey(prey, now)) {
    return;
  }

  const nearestDistance = Math.min(
    ...piranhas.map((piranha) => Math.hypot(piranha.xNorm - prey.xNorm, piranha.yNorm - prey.yNorm))
  );

  const inAttackRange = nearestDistance <= PIRANHA_ATTACK_TRIGGER_RANGE_NORM;
  const lostTarget = nearestDistance > PIRANHA_ATTACK_RELEASE_RANGE_NORM;

  if (!preyIsDead && lostTarget) {
    clearPiranhaAttackState(prey);
    return;
  }

  if (!inAttackRange) {
    return;
  }

  if (preyIsDead) {
    if (beginPiranhaConsumption(prey, now)) {
      renderUi(now);
    }
    return;
  }

  if (!startPiranhaAttack(prey, now)) {
    return;
  }

  runtime.bloodWaterTint = clamp(runtime.bloodWaterTint + deltaSeconds * 0.025, 0, 1);

  if (
    !hasDefinedFiniteNumber(prey.piranhaLastBloodAt)
    || now - Number(prey.piranhaLastBloodAt) >= PIRANHA_BLOOD_CLOUD_INTERVAL_MS
  ) {
    spawnBloodCloud(
      clamp(prey.xNorm + randomBetween(-0.006, 0.006), 0.08, 0.92),
      clamp(prey.yNorm + randomBetween(-0.006, 0.006), 0.14, 0.8),
      1.5 + piranhas.length * 0.22
    );
    prey.piranhaLastBloodAt = now;
  }

  if (
    !hasDefinedFiniteNumber(prey.piranhaLastDamageAt)
    || now - Number(prey.piranhaLastDamageAt) >= PIRANHA_BITE_DAMAGE_INTERVAL_MS
  ) {
    prey.piranhaLastDamageAt = now;
    prey.healthUnits = Math.max(0, (Number(prey.healthUnits) || 0) - PIRANHA_BITE_DAMAGE_UNITS);
    prey.fedStreak = 0;

    if (prey.healthUnits <= 0) {
      if (markFishAsDead(prey, now, `${prey.name} was swarmed by piranhas.`)) {
        beginPiranhaConsumption(prey, now);
        showToast(`Piranhas killed ${prey.name}.`);
        renderUi(now);
      }
      return;
    }
  }

  const attackStartedAt = Number(prey.piranhaAttackStartedAt) || now;
  if (now - attackStartedAt >= PIRANHA_ATTACK_BUILDUP_MS) {
    if (markFishAsDead(prey, now, `${prey.name} was swarmed by piranhas.`)) {
      beginPiranhaConsumption(prey, now);
      showToast(`Piranhas killed ${prey.name}.`);
      renderUi(now);
    }
  }
}

function getZombieAttackTarget(attacker, now = Date.now()) {
  if (!attacker || isFishDead(attacker) || !usesZombieHunterBehavior(attacker)) {
    return null;
  }

  const draggedFishId = runtime.fishDragState?.fishId || null;
  return state.fish
    .filter((fish) => (
      fish
      && fish.id !== draggedFishId
      && fish.id !== attacker.id
      && isValidZombieBiteTarget(fish, now)
    ))
    .sort((left, right) => {
      const leftDistance = Math.hypot(left.xNorm - attacker.xNorm, left.yNorm - attacker.yNorm);
      const rightDistance = Math.hypot(right.xNorm - attacker.xNorm, right.yNorm - attacker.yNorm);
      return leftDistance - rightDistance
        || (left.tankAddedAt || left.acquiredAt || 0) - (right.tankAddedAt || right.acquiredAt || 0);
    })[0] || null;
}

function infectFishWithZombieBite(target, attacker, now = Date.now()) {
  if (
    !target
    || !attacker
    || isFishDead(target)
    || isFishDead(attacker)
    || isUndeadFish(target)
    || hasZombieBiteInfection(target)
    || isFishProtectedFromPredators(target, now)
    || hasDefinedFiniteNumber(target.piranhaAttackStartedAt)
    || isFishBeingConsumedByPiranhas(target, now)
  ) {
    return false;
  }

  target.zombieBiteStartedAt = now;
  target.zombieBiteLastBloodAt = now;
  target.zombieBiteAttackerId = attacker.id;
  target.zombieReviveAt = null;
  target.zombieReviveSourceId = null;
  makeFishScurryFromAttack(target, attacker, now);
  pushEvent(`${attacker.name} bit ${target.name} with a zombie bite.`, now);
  return true;
}

function reviveFishAsZombieVariant(fish, now = Date.now()) {
  const species = getSpeciesForFish(fish);
  if (
    !fish
    || !species
    || !isFishDead(fish)
    || isUndeadFish(fish)
    || isFishBeingConsumedByPiranhas(fish, now)
  ) {
    return false;
  }

  fish.deadAt = null;
  fish.zombieVariant = true;
  fish.zombieBiteStartedAt = null;
  fish.zombieBiteLastBloodAt = null;
  fish.zombieBiteAttackerId = null;
  fish.zombieReviveAt = null;
  fish.zombieReviveSourceId = null;
  fish.decayStage = null;
  fish.piranhaConsumptionStartedAt = null;
  fish.piranhaConsumptionEndsAt = null;
  fish.piranhaLastBloodAt = null;
  clearPiranhaAttackState(fish);
  fish.healthUnits = getFishMaxHealthUnits(fish, species);
  fish.fedStreak = 0;
  fish.missedMealsInRow = 0;
  fish.comfortDamageProgressMs = 0;
  fish.activity = "roam";
  fish.feedingPelletId = null;
  fish.hangoutDecorId = null;
  fish.blockedDecorId = null;
  fish.blockedDecorUntil = null;
  fish.wallAvoidUntil = now + 600;
  fish.panicUntil = null;
  fish.panicSpeedBoost = null;
  fish.targetXNorm = clamp(fish.xNorm + randomBetween(-0.16, 0.16), 0.08, 0.92);
  fish.targetYNorm = clamp(randomBetween(0.26, 0.64), 0.14, 0.8);
  fish.targetAt = now + ZOMBIE_ATTACK_TARGET_REFRESH_MS;
  fish.swimSpeed = normalizeFishSpeed(
    species,
    randomBetween(Math.max(species.speedMin, species.speedMax * 0.82), species.speedMax)
  );
  clearFishSchoolFollowState(fish);
  clearFishCaveBehavior(fish);
  setFishTankLayers(
    fish,
    getEffectiveFishBehavior(fish, species) === "sucker"
      ? TANK_DEPTH_LAYERS
      : clampTankLayer(Math.max(1, Math.min(TANK_DEPTH_LAYERS - 1, Number(fish.tankLayer) || DEFAULT_TANK_LAYER))),
    getEffectiveFishBehavior(fish, species) === "sucker"
      ? TANK_DEPTH_LAYERS
      : clampTankLayer(Math.max(1, Math.min(TANK_DEPTH_LAYERS - 1, Number(fish.tankLayer) || DEFAULT_TANK_LAYER)))
  );
  unlockFishSpecies("zombie-fish", now, "Zombie Fish unlocked after a fish rose again as a zombie.");
  spawnBloodCloud(fish.xNorm, fish.yNorm, 1.4);
  pushEvent(`${fish.name} rose again as a zombie ${species.name.toLowerCase()}.`, now);
  return true;
}

function processZombieInfections(now) {
  let changed = false;

  if (!isViolenceEnabled() || !isZombieModeEnabled()) {
    for (const fish of state.fish) {
      if (
        hasDefinedFiniteNumber(fish.zombieBiteStartedAt)
        || hasDefinedFiniteNumber(fish.zombieBiteLastBloodAt)
        || hasDefinedFiniteNumber(fish.zombieReviveAt)
        || (typeof fish.zombieReviveSourceId === "string" && fish.zombieReviveSourceId.trim())
      ) {
        clearZombieAttackState(fish);
        fish.zombieReviveAt = null;
        fish.zombieReviveSourceId = null;
        changed = true;
      }
    }

    return changed;
  }

  for (const fish of state.fish) {
    if (hasZombieBiteInfection(fish)) {
      if (!hasValidZombieBiteSource(fish)) {
        clearZombieAttackState(fish);
        changed = true;
        continue;
      }

      if (
        !hasDefinedFiniteNumber(fish.zombieBiteLastBloodAt)
        || now - Number(fish.zombieBiteLastBloodAt) >= ZOMBIE_BITE_BLOOD_INTERVAL_MS
      ) {
        spawnBloodCloud(
          clamp(fish.xNorm + randomBetween(-0.004, 0.004), 0.08, 0.92),
          clamp(fish.yNorm + randomBetween(-0.004, 0.004), 0.14, 0.8),
          1.1
        );
        fish.zombieBiteLastBloodAt = now;
        changed = true;
      }

      if (now - Number(fish.zombieBiteStartedAt) >= ZOMBIE_BITE_FATAL_MS) {
        const reviveSourceId = typeof fish.zombieBiteAttackerId === "string" && fish.zombieBiteAttackerId.trim()
          ? fish.zombieBiteAttackerId.trim()
          : null;
        if (markFishAsDead(fish, now, `${fish.name} bled out after a zombie bite.`)) {
          changed = true;
        }
        fish.zombieReviveAt = now + randomBetween(ZOMBIE_BITE_REVIVE_MIN_MS, ZOMBIE_BITE_REVIVE_MAX_MS);
        fish.zombieReviveSourceId = reviveSourceId;
        changed = true;
      }
      continue;
    }

    if (hasPendingZombieRevival(fish) && now >= Number(fish.zombieReviveAt) && reviveFishAsZombieVariant(fish, now)) {
      changed = true;
    }
  }

  return changed;
}

function canFishUsePassAttack(species) {
  return Boolean(species && (species.id === "betta" || (isZombieModeEnabled() && species.undeadType === "skeleton")));
}

function canFishPassAttackTarget(attackerSpecies, target) {
  if (!attackerSpecies || !target || isFishDead(target)) {
    return false;
  }

  if (attackerSpecies.undeadType === "skeleton") {
    return !isUndeadFish(target);
  }

  return true;
}

function handleZombieBiteAttacks(now) {
  if (!state?.fish?.length || !isViolenceEnabled() || !isZombieModeEnabled()) {
    return;
  }

  const draggedFishId = runtime.fishDragState?.fishId || null;
  const breedingFishIds = runtime.debugBreedingSequence
    ? new Set([runtime.debugBreedingSequence.leftFishId, runtime.debugBreedingSequence.rightFishId].filter(Boolean))
    : null;
  const landedMessages = [];

  for (const attacker of state.fish) {
    if (
      isFishDead(attacker)
      || attacker.id === draggedFishId
      || breedingFishIds?.has(attacker.id)
      || !usesZombieHunterBehavior(attacker)
      || attacker.activity !== "roam"
      || Number(attacker.motionLevel) < 0.14
    ) {
      continue;
    }

    const target = getZombieAttackTarget(attacker, now);
    if (!target || breedingFishIds?.has(target.id)) {
      continue;
    }

    if (Math.hypot(attacker.xNorm - target.xNorm, attacker.yNorm - target.yNorm) > BETTA_ATTACK_TRIGGER_RANGE_NORM) {
      continue;
    }

    if (!infectFishWithZombieBite(target, attacker, now)) {
      continue;
    }

    landedMessages.push(`${attacker.name} bit ${target.name}.`);
  }

  if (!landedMessages.length) {
    return;
  }

  saveState();
  renderUi(now);
  showToast(landedMessages.length === 1 ? landedMessages[0] : `${landedMessages.length} zombie bites landed.`);
}

function handleBettaPassAttacks(now) {
  if (!state?.fish?.length || !isViolenceEnabled()) {
    runtime.bettaPassLocks.clear();
    return;
  }

  const draggedFishId = runtime.fishDragState?.fishId || null;
  const breedingFishIds = runtime.debugBreedingSequence
    ? new Set([runtime.debugBreedingSequence.leftFishId, runtime.debugBreedingSequence.rightFishId].filter(Boolean))
    : null;
  const livingFish = state.fish.filter((fish) => !isFishDead(fish));
  if (livingFish.length < 2) {
    runtime.bettaPassLocks.clear();
    return;
  }

  const nextLocks = new Set();
  const landedMessages = [];

  for (const attacker of livingFish) {
    if (
      attacker.id === draggedFishId
      || breedingFishIds?.has(attacker.id)
      || !canFishUsePassAttack(getSpeciesForFish(attacker))
      || attacker.activity !== "roam"
      || Number(attacker.motionLevel) < 0.18
    ) {
      continue;
    }

    const travelDistance = Math.hypot(attacker.targetXNorm - attacker.xNorm, attacker.targetYNorm - attacker.yNorm);
    if (travelDistance < 0.01) {
      continue;
    }

    for (const target of livingFish) {
      const attackerSpecies = getSpeciesForFish(attacker);
      if (
        target.id === attacker.id
        || target.id === draggedFishId
        || breedingFishIds?.has(target.id)
        || !canFishPassAttackTarget(attackerSpecies, target)
      ) {
        continue;
      }

      const pairKey = `${attacker.id}:${target.id}`;
      const isLocked = runtime.bettaPassLocks.has(pairKey);
      const distanceNorm = Math.hypot(attacker.xNorm - target.xNorm, attacker.yNorm - target.yNorm);
      const proximityLimit = isLocked ? BETTA_ATTACK_RELEASE_RANGE_NORM : BETTA_ATTACK_TRIGGER_RANGE_NORM;
      if (distanceNorm > proximityLimit) {
        continue;
      }

      nextLocks.add(pairKey);
      if (isLocked || Math.random() >= BETTA_ATTACK_PASS_CHANCE) {
        continue;
      }

      const outcome = applyFishDamage(
        target,
        1,
        now,
        `${attacker.name} attacked ${target.name} for half a heart.`,
        `${target.name} died after an attack from ${attacker.name}.`
      );
      if (!outcome.changed) {
        continue;
      }

      if (!outcome.dead) {
        makeFishScurryFromAttack(target, attacker, now);
      } else {
        spawnBloodCloud(target.xNorm, target.yNorm, 1.5);
      }

      landedMessages.push(outcome.dead ? `${attacker.name} killed ${target.name}.` : `${attacker.name} nipped ${target.name}.`);
    }
  }

  runtime.bettaPassLocks = nextLocks;
  if (!landedMessages.length) {
    return;
  }

  saveState();
  renderUi(now);
  showToast(landedMessages.length === 1 ? landedMessages[0] : `${landedMessages.length} attacks landed.`);
}

function spawnBloodCloud(xNorm, yNorm, intensity = 1) {
  if (!isGoreEnabled()) {
    return;
  }

  const count = Math.round(42 + intensity * 36);

  for (let i = 0; i < count; i += 1) {
    const angle = Math.random() * Math.PI * 2;
    const speed = randomBetween(0.00006, 0.00034) * intensity;
    const drift = randomBetween(0.00002, 0.0001);

    runtime.bloodClouds.push({
      xNorm: xNorm + randomBetween(-0.003, 0.003),
      yNorm: yNorm + randomBetween(-0.003, 0.003),
      vx: Math.cos(angle) * speed + randomBetween(-drift, drift),
      vy: Math.sin(angle) * speed + randomBetween(-drift, drift) - randomBetween(0.000005, 0.00003),
      radiusNorm: randomBetween(0.0018, 0.0046) * randomBetween(0.9, 1.4),
      alpha: randomBetween(0.22, 0.5),
      lifeMs: randomBetween(2200, 4600),
      ageMs: 0
    });
  }
}

function updateChumBloodClouds(now = Date.now()) {
  if (!runtime.chumBloodCloudAtByPelletId) {
    runtime.chumBloodCloudAtByPelletId = new Map();
  }

  if (!isGoreEnabled()) {
    runtime.chumBloodCloudAtByPelletId.clear();
    return;
  }

  const chumPellets = state.floatingPellets.filter((pellet) => pellet?.foodKey === "chum");
  const activeIds = new Set(chumPellets.map((pellet) => pellet.id));
  for (const pelletId of runtime.chumBloodCloudAtByPelletId.keys()) {
    if (!activeIds.has(pelletId)) {
      runtime.chumBloodCloudAtByPelletId.delete(pelletId);
    }
  }

  for (const pellet of chumPellets) {
    const nextCloudAt = Number(runtime.chumBloodCloudAtByPelletId.get(pellet.id));
    if (Number.isFinite(nextCloudAt) && now < nextCloudAt) {
      continue;
    }

    const pose = getPelletPose(pellet, now);
    spawnBloodCloud(pose.xNorm, pose.yNorm, randomBetween(0.38, 0.58));
    runtime.bloodWaterTint = clamp(runtime.bloodWaterTint + 0.012, 0, 1);
    runtime.chumBloodCloudAtByPelletId.set(
      pellet.id,
      now + randomBetween(CHUM_BLOOD_CLOUD_INTERVAL_MS * 0.72, CHUM_BLOOD_CLOUD_INTERVAL_MS * 1.22)
    );
  }
}

function updateBloodClouds(deltaSeconds) {
  if (!isGoreEnabled()) {
    runtime.bloodClouds = [];
    runtime.bloodWaterTint = 0;
    return;
  }

  runtime.bloodWaterTint = clamp(runtime.bloodWaterTint - deltaSeconds * BLOOD_WATER_TINT_DECAY_PER_SECOND, 0, 1);

  for (let i = runtime.bloodClouds.length - 1; i >= 0; i -= 1) {
    const cloud = runtime.bloodClouds[i];
    cloud.ageMs += deltaSeconds * 1000;

    if (cloud.ageMs >= cloud.lifeMs) {
      runtime.bloodClouds.splice(i, 1);
      continue;
    }

    const t = cloud.ageMs / cloud.lifeMs;

    cloud.xNorm += cloud.vx * deltaSeconds * 60;
    cloud.yNorm += cloud.vy * deltaSeconds * 60;

    cloud.vx *= 0.992;
    cloud.vy *= 0.992;

    cloud.radiusNorm *= 1.006;

    if (t < 0.25) {
      cloud.alpha *= 0.997;
    } else if (t < 0.65) {
      cloud.alpha *= 0.991;
    } else {
      cloud.alpha *= 0.972;
    }
  }
}

function drawWaterBloodTint() {
  const tintStrength = clamp(runtime.bloodWaterTint, 0, 1);
  if (tintStrength <= 0.001) {
    return;
  }

  const width = TANK_WIDTH - GLASS_MARGIN_X * 2;
  const height = TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM;

  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y, width, height);
  tankContext.clip();

  const wash = tankContext.createLinearGradient(0, WATER_SURFACE_Y, 0, TANK_HEIGHT);
  wash.addColorStop(0, `rgba(126, 10, 10, ${clamp(tintStrength * 0.08, 0, 0.12)})`);
  wash.addColorStop(0.46, `rgba(120, 8, 8, ${clamp(tintStrength * 0.16, 0, 0.22)})`);
  wash.addColorStop(1, `rgba(82, 4, 4, ${clamp(tintStrength * 0.24, 0, 0.32)})`);
  tankContext.fillStyle = wash;
  tankContext.fillRect(GLASS_MARGIN_X, WATER_SURFACE_Y, width, height);

  const haze = tankContext.createRadialGradient(
    TANK_WIDTH * 0.5,
    WATER_SURFACE_Y + height * 0.6,
    0,
    TANK_WIDTH * 0.5,
    WATER_SURFACE_Y + height * 0.6,
    height * 0.74
  );
  haze.addColorStop(0, `rgba(156, 18, 18, ${clamp(tintStrength * 0.1, 0, 0.18)})`);
  haze.addColorStop(0.62, `rgba(110, 10, 10, ${clamp(tintStrength * 0.06, 0, 0.12)})`);
  haze.addColorStop(1, "rgba(45, 0, 0, 0)");
  tankContext.fillStyle = haze;
  tankContext.fillRect(GLASS_MARGIN_X, WATER_SURFACE_Y, width, height);
  tankContext.restore();
}

function drawBloodClouds() {
  if (!runtime.bloodClouds.length) {
    return;
  }

  tankContext.save();
  tankContext.globalCompositeOperation = "source-over";

  for (const cloud of runtime.bloodClouds) {
    const x = cloud.xNorm * TANK_WIDTH;
    const y = cloud.yNorm * TANK_HEIGHT;
    const radius = cloud.radiusNorm * Math.min(TANK_WIDTH, TANK_HEIGHT);

    const gradient = tankContext.createRadialGradient(x, y, 0, x, y, radius);

    gradient.addColorStop(0, `rgba(110, 0, 0, ${clamp(cloud.alpha * 1.15, 0, 1)})`);
    gradient.addColorStop(0.22, `rgba(92, 0, 0, ${clamp(cloud.alpha * 0.9, 0, 1)})`);
    gradient.addColorStop(0.55, `rgba(58, 0, 0, ${clamp(cloud.alpha * 0.42, 0, 1)})`);
    gradient.addColorStop(1, "rgba(20, 0, 0, 0)");

    tankContext.fillStyle = gradient;
    tankContext.beginPath();
    tankContext.arc(x, y, radius, 0, Math.PI * 2);
    tankContext.fill();
  }

  tankContext.restore();
}

function drawMedicineWaterTint(now) {
  const tint = state.medicineWaterTint;
  if (!tint || !tint.color) {
    return;
  }

  const rgb = hexToRgb(tint.color);
  if (!rgb) {
    return;
  }

  const duration = Math.max(1, (tint.endsAt || 0) - (tint.startedAt || 0));
  const remaining = clamp(((tint.endsAt || 0) - now) / duration, 0, 1);
  if (remaining <= 0.001) {
    return;
  }

  const width = TANK_WIDTH - GLASS_MARGIN_X * 2;
  const height = TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM;
  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y, width, height);
  tankContext.clip();
  tankContext.fillStyle = `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${0.18 * remaining})`;
  tankContext.fillRect(GLASS_MARGIN_X, WATER_SURFACE_Y, width, height);
  tankContext.restore();
}

function drawMedicineClouds(now) {
  if (!state.medicineClouds.length) {
    return;
  }

  tankContext.save();
  for (const cloud of state.medicineClouds) {
    const rgb = hexToRgb(cloud.color);
    if (!rgb) {
      continue;
    }

    const duration = Math.max(1, (cloud.endsAt || 0) - (cloud.startedAt || 0));
    const progress = clamp((now - (cloud.startedAt || 0)) / duration, 0, 1);
    const alpha = (1 - progress) * 0.32;
    if (alpha <= 0.001) {
      continue;
    }

    const x = (cloud.xNorm || 0.5) * TANK_WIDTH;
    const y = (cloud.yNorm || 0.5) * TANK_HEIGHT;
    const radius = Math.max(36, Math.min(TANK_WIDTH, TANK_HEIGHT) * (0.06 + progress * 0.12));
    const gradient = tankContext.createRadialGradient(x, y, 0, x, y, radius);
    gradient.addColorStop(0, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha})`);
    gradient.addColorStop(0.45, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha * 0.46})`);
    gradient.addColorStop(1, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`);
    tankContext.fillStyle = gradient;
    tankContext.beginPath();
    tankContext.arc(x, y, radius, 0, Math.PI * 2);
    tankContext.fill();
  }
  tankContext.restore();
}

function makeFishScurryFromAttack(victim, attacker, now) {
  if (!victim || !attacker || isFishDead(victim)) {
    return;
  }

  const species = runtime.fishMap.get(victim.speciesId);
  if (!species) {
    return;
  }

  const dx = victim.xNorm - attacker.xNorm;
  const dy = victim.yNorm - attacker.yNorm;
  const distance = Math.max(0.0001, Math.hypot(dx, dy));
  const nx = dx / distance;
  const ny = dy / distance;

  victim.activity = "roam";
  victim.feedingPelletId = null;
  clearFishSchoolFollowState(victim);
  clearFishCaveBehavior(victim);
  victim.hangoutDecorId = null;
  victim.blockedDecorId = null;
  victim.blockedDecorUntil = null;
  victim.wallAvoidUntil = now + 450;

  victim.panicUntil = now + randomBetween(1100, 1900);
  victim.panicSpeedBoost = randomBetween(1.9, 2.5);
  victim.targetXNorm = clamp(victim.xNorm + nx * randomBetween(0.16, 0.26), 0.08, 0.92);
  victim.targetYNorm = clamp(victim.yNorm + ny * randomBetween(0.08, 0.16), 0.14, 0.8);
  victim.targetAt = victim.panicUntil;

  if (Math.abs(victim.targetXNorm - victim.xNorm) > 0.001) {
    setFishDirection(victim, victim.targetXNorm >= victim.xNorm ? 1 : -1, species, now);
  }

  spawnBloodCloud(
    clamp(victim.xNorm + randomBetween(-0.004, 0.004), 0.08, 0.92),
    clamp(victim.yNorm + randomBetween(-0.004, 0.004), 0.14, 0.8),
    0.9
  );
}

function retargetFishAfterBlockedMove(fish, species, resolvedMove, attemptedXNorm, attemptedYNorm, now) {
  if (!fish || !species || fish.activity !== "roam") {
    return;
  }

  const blockedX = Math.abs(resolvedMove.xNorm - attemptedXNorm) > 0.0005;
  const blockedY = Math.abs(resolvedMove.yNorm - attemptedYNorm) > 0.0005;

  if (!blockedX && !blockedY) {
    return;
  }

  clearFishSchoolFollowState(fish);

  if (fish.caveState) {
    fish.targetAt = Math.max(Number(fish.targetAt) || 0, now + 1200);
    fish.wallAvoidUntil = now + 220;
    return;
  }

  if (resolvedMove?.blockingCave) {
    const blocking = resolvedMove.blockingCave;
    const safeFrontLayer = Math.max(1, clampTankLayer((blocking.span?.front || 3) - 1));
    setFishTankLayers(fish, safeFrontLayer, safeFrontLayer);
    setFishDesiredTankLayer(fish, safeFrontLayer);
    fish.hangoutDecorId = null;
    fish.blockedDecorId = blocking.item?.id || null;
    fish.blockedDecorUntil = now + 2400;
    fish.wallAvoidUntil = now + 420;
    fish.targetXNorm = clamp(attemptedXNorm, 0.08, 0.92);
    fish.targetYNorm = clamp(attemptedYNorm, 0.14, 0.8);
    fish.targetAt = now + 1400 + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 12000;
    if (Math.abs(fish.targetXNorm - fish.xNorm) > 0.002) {
      setFishDirection(fish, fish.targetXNorm >= fish.xNorm ? 1 : -1, species, now);
    }
    return;
  }

  if (Number.isFinite(fish.wallAvoidUntil) && now < fish.wallAvoidUntil) {
    return;
  }

  const awayX = blockedX
    ? (attemptedXNorm >= fish.xNorm ? -1 : 1)
    : (Math.random() < 0.5 ? -1 : 1);

  const awayY = blockedY
    ? (attemptedYNorm >= fish.yNorm ? -1 : 1)
    : (Math.random() < 0.5 ? -1 : 1);

  const horizontalDistance = blockedX
    ? randomBetween(0.1, 0.2)
    : randomBetween(0.04, 0.1);

  const verticalDistance = blockedY
    ? randomBetween(0.08, 0.16)
    : randomBetween(0.03, 0.08);

  const blockedDecorId = fish.hangoutDecorId || fish.blockedDecorId || null;

  fish.targetXNorm = clamp(fish.xNorm + awayX * horizontalDistance, 0.08, 0.92);
  fish.targetYNorm = clamp(fish.yNorm + awayY * verticalDistance, 0.14, 0.8);
  fish.targetAt = now + 900 + Math.random() * 900;
  fish.wallAvoidUntil = now + 650;
  fish.hangoutDecorId = null;
  fish.blockedDecorId = blockedDecorId;
  fish.blockedDecorUntil = now + 3200;

  if (species.speedMode === "dynamic") {
    fish.swimSpeed = normalizeFishSpeed(
      species,
      randomBetween(
        Math.max(species.speedMin, species.speedMax * 0.58),
        species.speedMax
      )
    );
  }

  if (Math.abs(fish.targetXNorm - fish.xNorm) > 0.002) {
    setFishDirection(fish, fish.targetXNorm >= fish.xNorm ? 1 : -1, species, now);
  }
}

function updateFishMotion(now, deltaSeconds) {
  if (!state?.fish.length) {
    runtime.fishGravelPebbleActions.clear();
    runtime.fishPebbleTosses = [];
    runtime.bettaPassLocks.clear();
    return;
  }
  pruneFishGravelPebbleRuntimeState(now);
  const activelyDraggedFishId = runtime.fishDragState?.fishId || null;
  const activeDebugBreedingSequence = updateDebugBreedingSequence(now);
  const activePiranhaPrey = getActivePiranhaPrey(now);
  let retargetsThisFrame = 0;
  updatePiranhaSwarmTargets(now);

  for (const fish of state.fish) {
    const species = getSpeciesForFish(fish);
    if (!species) {
      continue;
    }
    const effectiveBehavior = getEffectiveFishBehavior(fish, species);
    const debugCaveTestFish = isDebugCaveTestFish(fish);
    const breedingRole = activeDebugBreedingSequence
      ? (fish.id === activeDebugBreedingSequence.leftFish.id
        ? "left"
        : (fish.id === activeDebugBreedingSequence.rightFish.id ? "right" : null))
      : null;
    const piranhaLockedOnPrey = isPiranhaSpecies(fish) && Boolean(activePiranhaPrey);
    const zombieAttackTarget = !piranhaLockedOnPrey && !breedingRole && usesZombieHunterBehavior(fish)
      ? getZombieAttackTarget(fish, now)
      : null;
    const zombieLockedOnTarget = Boolean(zombieAttackTarget);
    const zombieBittenVictim = hasZombieBiteInfection(fish);
    let pellet = null;

    if (fish.id === activelyDraggedFishId) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      fish.activity = "roam";
      fish.feedingPelletId = null;
      fish.targetXNorm = fish.xNorm;
      fish.targetYNorm = fish.yNorm;
      fish.targetAt = now + 1200;
      fish.hangoutDecorId = null;
      fish.motionLevel = clamp(fish.motionLevel + (0.18 - fish.motionLevel) * Math.min(1, deltaSeconds * 6), 0.04, 0.4);
      fish.wiggleClock += deltaSeconds * 0.42;
      setFishTankLayers(
        fish,
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish),
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish)
      );
      continue;
    }

    if (isFishDead(fish)) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      fish.activity = "dead";
      fish.feedingPelletId = null;
      setFishTankLayers(
        fish,
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish),
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish)
      );
      fish.hangoutDecorId = null;
      fish.panicUntil = null;
      fish.panicSpeedBoost = null;
      fish.entryStartedAt = null;
      fish.entryDurationMs = 0;
      fish.entryFromYNorm = null;
      fish.entrySplashTriggered = false;
      fish.turnStartedAt = null;
      fish.turnDurationMs = 0;
      fish.displayDirection = Number(fish.direction) < 0 ? -1 : 1;
      fish.displayAngle = fish.displayDirection < 0 ? Math.PI : 0;
      fish.turnFromDirection = fish.displayDirection;
      fish.turnToDirection = fish.displayDirection;
      fish.turnFromAngle = fish.displayAngle;
      fish.turnToAngle = fish.displayAngle;
      fish.turnSpinDirection = fish.displayDirection < 0 ? 1 : -1;
      if (isFishBeingConsumedByPiranhas(fish, now)) {
        const livingPiranhas = getLivingPiranhaFish();
        const swarmCenter = livingPiranhas.length
          ? livingPiranhas.reduce((accumulator, piranha) => ({
            xNorm: accumulator.xNorm + piranha.xNorm,
            yNorm: accumulator.yNorm + piranha.yNorm
          }), { xNorm: 0, yNorm: 0 })
          : { xNorm: fish.xNorm, yNorm: fish.yNorm };
        if (livingPiranhas.length) {
          swarmCenter.xNorm /= livingPiranhas.length;
          swarmCenter.yNorm /= livingPiranhas.length;
        }

        fish.xNorm = clamp(
          fish.xNorm + (swarmCenter.xNorm - fish.xNorm) * Math.min(1, deltaSeconds * 1.6) + Math.sin(now / 360 + fish.phase * Math.PI) * deltaSeconds * 0.005,
          0.08,
          0.92
        );
        fish.yNorm = clamp(
          fish.yNorm + (swarmCenter.yNorm - fish.yNorm) * Math.min(1, deltaSeconds * 1.6) + Math.cos(now / 290 + fish.phase * Math.PI * 1.6) * deltaSeconds * 0.004,
          0.16,
          0.78
        );
        fish.motionLevel = clamp(fish.motionLevel + (0.42 - fish.motionLevel) * Math.min(1, deltaSeconds * 6), 0.12, 0.7);
        fish.wiggleClock += deltaSeconds * 1.8;
        continue;
      }

      const surfaceYNorm = clamp((WATER_SURFACE_Y + 18) / TANK_HEIGHT, 0.12, 0.2);
      fish.yNorm = clamp(fish.yNorm + (surfaceYNorm - fish.yNorm) * Math.min(1, deltaSeconds * 1.05), 0.12, 0.8);
      fish.xNorm = clamp(
        fish.xNorm + Math.sin(now / 2600 + fish.phase * Math.PI * 2) * deltaSeconds * 0.0036,
        0.08,
        0.92
      );
      fish.motionLevel = clamp(fish.motionLevel + (0.05 - fish.motionLevel) * Math.min(1, deltaSeconds * 3), 0.02, 0.18);
      fish.wiggleClock += deltaSeconds * 0.18;
      continue;
    }

    updateFishTurnState(fish, species, now);

    if (!piranhaLockedOnPrey && !breedingRole && isFishCriticallyLowHealth(fish) && fish.activity === "roam" && Math.random() < deltaSeconds * 0.35) {
      fish.panicUntil = now + randomBetween(1600, 3200);
      fish.panicSpeedBoost = randomBetween(1.45, 2.15);
      fish.targetAt = now;
      if (species.speedMode === "dynamic") {
        fish.swimSpeed = normalizeFishSpeed(species, randomBetween(Math.max(species.speedMin, species.speedMax * 0.72), species.speedMax));
      }
    }

    if (effectiveBehavior === "sucker") {
      setFishTankLayers(fish, TANK_DEPTH_LAYERS, TANK_DEPTH_LAYERS);
      fish.hangoutDecorId = null;
      if (fish.activity === "feeding") {
        fish.activity = "roam";
        fish.feedingPelletId = null;
      }
    }

    if (debugCaveTestFish && fish.activity === "feeding") {
      fish.activity = "roam";
      fish.feedingPelletId = null;
      releasePelletsTargetingFishIds(fish.id);
      fish.targetAt = now;
    }

    if (breedingRole) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      if (fish.caveState) {
        abortFishCaveBehavior(fish, now, false);
      }
      setFishBreedingTarget(fish, species, activeDebugBreedingSequence.sequence, breedingRole, now);
    }

    if (pushFishOutOfBlockingCave(fish, species, now)) {
      fish.motionLevel = clamp(fish.motionLevel + (0.42 - fish.motionLevel) * Math.min(1, deltaSeconds * 5), 0.08, 0.7);
    }

    if (fish.entryStartedAt && fish.entryDurationMs > 0) {
      const progress = clamp((now - fish.entryStartedAt) / fish.entryDurationMs, 0, 1);
      fish.motionLevel = clamp(fish.motionLevel + (0.2 - fish.motionLevel) * Math.min(1, deltaSeconds * 6), 0.04, 0.4);
      fish.wiggleClock += deltaSeconds * 1.15;
      setFishTankLayers(
        fish,
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish),
        effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish)
      );
      fish.hangoutDecorId = null;

      if (!fish.entrySplashTriggered && progress >= 0.22) {
        fish.entrySplashTriggered = true;
        spawnFishReturnSplash(fish.xNorm);
      }

      if (progress < 1) {
        continue;
      }

      fish.entryStartedAt = null;
      fish.entryDurationMs = 0;
      fish.entryFromYNorm = null;
      fish.entrySplashTriggered = false;
      fish.targetAt = now + 900 + Math.random() * 1400;
    }

    if (zombieLockedOnTarget) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      if (fish.caveState) {
        abortFishCaveBehavior(fish, now, false);
      }
      fish.activity = "roam";
      fish.feedingPelletId = null;
      fish.hangoutDecorId = null;
      fish.blockedDecorId = null;
      fish.blockedDecorUntil = null;
      fish.panicUntil = null;
      fish.panicSpeedBoost = null;
      clearFishSchoolFollowState(fish);
      fish.targetXNorm = clamp(
        zombieAttackTarget.xNorm + (zombieAttackTarget.xNorm >= fish.xNorm ? -1 : 1) * randomBetween(0.005, 0.02),
        0.08,
        0.92
      );
      fish.targetYNorm = clamp(zombieAttackTarget.yNorm + randomBetween(-0.018, 0.018), 0.14, 0.8);
      fish.targetAt = now + ZOMBIE_ATTACK_TARGET_REFRESH_MS;
      setFishDesiredTankLayer(
        fish,
        effectiveBehavior === "sucker"
          ? TANK_DEPTH_LAYERS
          : clampTankLayer(Math.max(1, Math.min(TANK_DEPTH_LAYERS - 1, getFishTankLayer(zombieAttackTarget))))
      );
      fish.swimSpeed = normalizeFishSpeed(
        species,
        randomBetween(Math.max(species.speedMin, species.speedMax * 0.84), species.speedMax)
      );
    } else if (zombieBittenVictim) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      if (fish.caveState) {
        abortFishCaveBehavior(fish, now, false);
      }
      fish.activity = "roam";
      fish.feedingPelletId = null;
      fish.hangoutDecorId = null;
      fish.blockedDecorId = null;
      fish.blockedDecorUntil = null;
      clearFishSchoolFollowState(fish);
      fish.panicUntil = now + 900;
      fish.panicSpeedBoost = Math.max(Number(fish.panicSpeedBoost) || 0, randomBetween(2.15, 2.85));
      if (now >= fish.targetAt) {
        fish.targetXNorm = clamp(fish.xNorm + randomBetween(-0.24, 0.24), 0.08, 0.92);
        fish.targetYNorm = clamp(fish.yNorm + randomBetween(-0.18, 0.18), 0.14, 0.8);
        fish.targetAt = now + randomBetween(260, 720);
      }
      setFishDesiredTankLayer(
        fish,
        effectiveBehavior === "sucker"
          ? TANK_DEPTH_LAYERS
          : clampTankLayer(Math.max(1, Math.min(TANK_DEPTH_LAYERS - 1, getFishTankLayer(fish))))
      );
    } else if (piranhaLockedOnPrey) {
      clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      if (fish.caveState) {
        abortFishCaveBehavior(fish, now, false);
      }
      fish.activity = "roam";
      fish.feedingPelletId = null;
      fish.hangoutDecorId = null;
      fish.blockedDecorId = null;
      fish.blockedDecorUntil = null;
      fish.panicUntil = null;
      fish.panicSpeedBoost = null;
      clearFishSchoolFollowState(fish);
    } else {
      pellet = fish.feedingPelletId ? state.floatingPellets.find((entry) => entry.id === fish.feedingPelletId) : null;
      if (fish.activity === "feeding" && pellet && !canFishTargetFoodPellet(fish, pellet, now)) {
        if (pellet.targetFishId === fish.id) {
          pellet.targetFishId = "";
        }
        fish.activity = "roam";
        fish.feedingPelletId = null;
        fish.targetAt = now;
        fish.hangoutDecorId = null;
        fish.hangoutZoneType = null;
        pellet = null;
      }
      if (fish.activity === "feeding" && pellet) {
        if (fish.caveState) {
          abortFishCaveBehavior(fish, now, false);
        }
        const pelletPose = getPelletPose(pellet, now);
        fish.targetXNorm = pelletPose.xNorm;
        fish.targetYNorm = clamp(pelletPose.yNorm + (pellet.settled ? -0.012 : 0.014), 0.14, pellet.settled ? 0.9 : 0.82);
        fish.targetAt = now + 1000;
        setFishDesiredTankLayer(
          fish,
          effectiveBehavior === "sucker"
            ? TANK_DEPTH_LAYERS
            : (pellet.settled ? TANK_DEPTH_LAYERS : clampTankLayer(Math.min(getFishTankLayer(fish), 2)))
        );
        fish.hangoutDecorId = null;
      } else if (fish.activity === "feeding" && !pellet) {
        fish.activity = "roam";
        fish.feedingPelletId = null;
        fish.targetAt = now + 800 + Math.random() * 1200;
        fish.swimSpeed = normalizeFishSpeed(species);
        setFishDesiredTankLayer(fish, effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish));
        fish.hangoutDecorId = null;
      }

      if (fish.activity !== FISH_GRAVEL_PEBBLE_ACTIVITY && getFishGravelPebbleAction(fish)) {
        clearFishGravelPebbleAction(fish, species, now, { resetTarget: false });
      }

      if (fish.activity === "roam" && !breedingRole && !fish.caveState && !debugCaveTestFish) {
        maybeStartFishGravelPebbleAction(fish, species, now, deltaSeconds);
      }

      const gravelPebbleOwnsMovement = !breedingRole && updateFishGravelPebbleAction(fish, species, now);
      const caveBehaviorOwnsMovement = !breedingRole && !gravelPebbleOwnsMovement && fish.activity === "roam" && updateFishCaveBehavior(fish, species, now);
      if (fish.activity === "roam" && !breedingRole && !caveBehaviorOwnsMovement && now >= fish.targetAt) {
        if (retargetsThisFrame >= MAX_FISH_RETARGETS_PER_FRAME) {
          fish.targetAt = now + 30 + Math.random() * 60;
        } else {
          assignSwimTarget(fish, species, now);
          retargetsThisFrame += 1;
        }
      }

      if (fish.activity === "roam" && !fish.caveState && !breedingRole) {
        updateFishSchoolFollowTarget(fish, species, now);
      }
    }

    enforceFishLayerBoundary(fish, species);

    const moveDx = fish.targetXNorm - fish.xNorm;
    const moveDy = fish.targetYNorm - fish.yNorm;
    const moveDistance = Math.hypot(moveDx, moveDy);
    const isDirectedSwim = fish.activity === "feeding" || fish.activity === FISH_GRAVEL_PEBBLE_ACTIVITY;
    let motionTarget = fish.activity === "feeding"
      ? 1
      : fish.activity === FISH_GRAVEL_PEBBLE_ACTIVITY
        ? 0.76
        : (isFishCriticallyLowHealth(fish) ? 0.22 : 0.08);
    if (zombieLockedOnTarget) {
      motionTarget = Math.max(motionTarget, 0.78);
    } else if (zombieBittenVictim) {
      motionTarget = Math.max(motionTarget, 0.92);
    }
    let handledDirectionThisFrame = false;

    if (moveDistance > 0.0001) {
      let speedMultiplier = fish.activity === "feeding"
        ? FEED_CHASE_MULTIPLIER
        : fish.activity === FISH_GRAVEL_PEBBLE_ACTIVITY
          ? 1.14
          : 1;

      if (Number.isFinite(fish.panicUntil)) {
        if (now < fish.panicUntil) {
          speedMultiplier *= Number(fish.panicSpeedBoost) || 2;
        } else {
          fish.panicUntil = null;
          fish.panicSpeedBoost = null;
        }
      }

      if (isFishCriticallyLowHealth(fish) && fish.activity !== "feeding" && fish.activity !== FISH_GRAVEL_PEBBLE_ACTIVITY) {
        speedMultiplier *= 1.22;
      }

      if (zombieLockedOnTarget) {
        speedMultiplier *= 1.18;
      } else if (zombieBittenVictim) {
        speedMultiplier *= 1.24;
      }

      if (isPiranhaSpecies(fish)) {
        speedMultiplier *= getPiranhaTargetCandidate(now) ? 1.2 : 1.04;
      }

      const speed = fish.swimSpeed * FISH_MOTION_SCALE * speedMultiplier;
      const step = Math.min(moveDistance, speed * deltaSeconds);

      const nextXNorm = clamp(fish.xNorm + (moveDx / moveDistance) * step, 0.08, 0.92);
      const movementMaxYNorm = fish.activity === "feeding" && pellet?.settled ? 0.9 : 0.8;
      const nextYNorm = clampFishYNormToLayer(
        fish.yNorm + (moveDy / moveDistance) * step,
        fish,
        species,
        getFishTankLayer(fish),
        { minYNorm: 0.14, maxYNorm: movementMaxYNorm }
      );

      if (effectiveBehavior === "sucker") {
        fish.xNorm = nextXNorm;
        fish.yNorm = nextYNorm;
      } else {
        const activeCavePlan = fish.caveState ? getActiveFishCavePlan(fish) : null;
        const skipDebugCaveCollision = Boolean(
          activeCavePlan?.debugForced &&
          isDebugCaveTestFish(fish) &&
          ["enter", "inside", "exit", "depart"].includes(fish.caveState) &&
          fish.caveDecorId &&
          activeCavePlan.decorId === fish.caveDecorId
        );

        if (skipDebugCaveCollision) {
          fish.xNorm = nextXNorm;
          fish.yNorm = nextYNorm;
        } else {
          const resolvedMove = resolveFishCaveCollision(fish, nextXNorm, nextYNorm, now);
          fish.xNorm = resolvedMove.xNorm;
          fish.yNorm = resolvedMove.yNorm;

          if (resolvedMove.blocked && fish.activity === "roam") {
            if (fish.hangoutDecorId) {
              fish.blockedDecorId = fish.hangoutDecorId;
            }
            retargetFishAfterBlockedMove(fish, species, resolvedMove, nextXNorm, nextYNorm, now);
            handledDirectionThisFrame = true;
          } else if (resolvedMove.blocked && fish.activity === FISH_GRAVEL_PEBBLE_ACTIVITY) {
            clearFishGravelPebbleAction(fish, species, now);
            handledDirectionThisFrame = true;
          }
        }

        if (fish.caveState && !skipDebugCaveCollision) {
          enforceActiveCaveMaskRule(fish, species, now);
        }
      }

      const travelRatio = clamp(step / Math.max(0.00001, speed * deltaSeconds), 0, 1);
      motionTarget = fish.activity === "feeding"
        ? 1
        : fish.activity === FISH_GRAVEL_PEBBLE_ACTIVITY
          ? clamp(0.54 + travelRatio * 0.38 + Math.min(0.12, moveDistance * 3), 0.34, 0.86)
          : clamp(0.44 + travelRatio * 0.5 + Math.min(0.16, moveDistance * 4.5), 0.16, 0.92);

      if (effectiveBehavior === "sucker") {
        setSuckerFishAngle(fish, Math.atan2(moveDy, moveDx), now);
      } else if (!handledDirectionThisFrame) {
        const facingDx = fish.targetXNorm - fish.xNorm;
        if (Math.abs(facingDx) > FISH_DIRECTION_TARGET_DEADZONE_NORM) {
          setFishDirection(fish, facingDx >= 0 ? 1 : -1, species, now);
          handledDirectionThisFrame = true;
        }
      }
    }

    if (
      fish.activity === "roam" &&
      !fish.caveState &&
      !handledDirectionThisFrame &&
      !(Number.isFinite(fish.wallAvoidUntil) && now < fish.wallAvoidUntil)
    ) {
      const nearbyCorpse = getNearestDeadFish(fish);
      if (nearbyCorpse && nearbyCorpse.distanceNorm <= 0.16) {
        if (effectiveBehavior === "sucker") {
          setSuckerFishAngle(
            fish,
            Math.atan2(nearbyCorpse.fish.yNorm - fish.yNorm, nearbyCorpse.fish.xNorm - fish.xNorm),
            now
          );
        } else {
          setFishDirection(fish, nearbyCorpse.fish.xNorm >= fish.xNorm ? 1 : -1, species, now);
        }
      }
    }

    fish.motionLevel = clamp(
      fish.motionLevel + (motionTarget - fish.motionLevel) * Math.min(1, deltaSeconds * (isDirectedSwim ? 6.2 : 4.2)),
      0.04,
      1
    );
    fish.wiggleClock += deltaSeconds * (0.35 + fish.motionLevel * (1.85 + fish.swimSpeed * 18)) * (isFishCriticallyLowHealth(fish) ? 1.22 : 1);

    if (fish.activity === "feeding" && pellet) {
      const pelletPose = getPelletPose(pellet, now);
      if (Math.hypot(fish.xNorm - pelletPose.xNorm, fish.yNorm - pelletPose.yNorm) < 0.024) {
        handleFishEatFoodPellet(fish, pellet, now);
        state.floatingPellets = state.floatingPellets.filter((entry) => entry.id !== pellet.id);
        fish.activity = "roam";
        fish.feedingPelletId = null;
        setFishDesiredTankLayer(fish, effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : getFishTankLayer(fish));
        fish.hangoutDecorId = null;
        fish.targetXNorm = clamp(fish.xNorm + (Math.random() - 0.5) * 0.18, 0.08, 0.92);
        fish.targetYNorm = randomSwimY(getDesiredFishTankLayer(fish), fish, species);
        fish.targetAt = now + 1500 + Math.random() * 2400;
        fish.swimSpeed = normalizeFishSpeed(species);
      }
    }

    syncFishDrawLayer(fish, species, now);
  }

  scrubImpossiblePredatorState(now);
  scrubProtectedTankFishPredatorState(now);
  handlePiranhaSwarm(now, deltaSeconds);
  handleZombieBiteAttacks(now);
  handleBettaPassAttacks(now);
  updateFishPebbleTosses(now);
  updateChumBloodClouds(now);
  updateBloodClouds(deltaSeconds);
}

function assignSwimTarget(fish, species, now) {
  clearFishSchoolFollowState(fish);
  const effectiveBehavior = getEffectiveFishBehavior(fish, species);

  if (runtime.debugNightCaveMode && isDebugCaveTestFish(fish)) {
    if (startDebugCaveLoopCycle(now, { silentFailure: true, suppressEvent: true })) {
      return;
    }
  } else if (runtime.debugNightCaveMode && !runtime.debugForcedCaveFishId) {
    if (
      startDebugCaveLoopCycle(now, { silentFailure: true, suppressEvent: true })
      && runtime.debugForcedCaveFishId === fish.id
    ) {
      return;
    }
  }

  const vigilTarget = pickDeadFishVigilTarget(fish, species, now);
  if (vigilTarget) {
    clearFishPanicState(fish);
    fish.targetXNorm = vigilTarget.xNorm;
    fish.targetYNorm = vigilTarget.yNorm;
    fish.targetAt = now + vigilTarget.lingerMs;
    setFishDesiredTankLayer(fish, effectiveBehavior === "sucker" ? TANK_DEPTH_LAYERS : vigilTarget.targetLayer);
    fish.hangoutDecorId = null;
    if (species.speedMode === "dynamic") {
      fish.swimSpeed = normalizeFishSpeed(species, randomBetween(species.speedMin, Math.max(species.speedMin, species.speedMax * 0.86)));
    }
    return;
  }

  if (Number.isFinite(fish.blockedDecorUntil) && now >= fish.blockedDecorUntil) {
    fish.blockedDecorUntil = null;
    fish.blockedDecorId = null;
  }

  if (isFishSickOrDying(fish) && species.behavior !== "sucker") {
    const hideout = pickDecorHangoutTarget(species, fish, now, {
      allowedZoneTypes: ["hide", "plant", "hardscape", "spooky"],
      chanceMultiplier: 2.3,
      lingerMultiplier: 2.7,
      occupancyLimit: DECOR_HANGOUT_SICK_OCCUPANCY_LIMIT,
      preferBackLayer: true
    });
    if (hideout) {
      fish.targetXNorm = hideout.xNorm;
      fish.targetYNorm = hideout.yNorm;
      fish.targetAt = now + hideout.lingerMs;
      setFishDesiredTankLayer(fish, hideout.targetLayer);
      fish.hangoutDecorId = hideout.decorId;
      fish.hangoutZoneType = hideout.zoneType;
      fish.swimSpeed = normalizeFishSpeed(species, randomBetween(Math.max(species.speedMin, species.speedMax * 0.76), species.speedMax));
      return;
    }
  }

  if (effectiveBehavior === "sucker") {
    const currentFacing = Math.cos(getFishFacingAngle(fish)) < 0 ? -1 : 1;
    const nearLeftWall = fish.xNorm <= 0.12;
    const nearRightWall = fish.xNorm >= 0.88;
    const nearTopWall = fish.yNorm <= 0.24;
    const nearBottomWall = fish.yNorm >= 0.7;
    const shouldReverse = nearLeftWall || nearRightWall || Math.random() < 0.12;
    const crawlDirection = nearLeftWall
      ? 1
      : nearRightWall
        ? -1
        : (shouldReverse ? -currentFacing : currentFacing);
    const crawlDistance = randomBetween(
      shouldReverse ? 0.14 : 0.22,
      shouldReverse ? 0.24 : 0.4
    );
    const nextXNorm = clamp(fish.xNorm + crawlDirection * crawlDistance + randomBetween(-0.01, 0.01), 0.1, 0.9);
    const verticalShift = nearTopWall
      ? randomBetween(0.05, 0.16)
      : nearBottomWall
        ? -randomBetween(0.05, 0.16)
        : randomBetween(-0.14, 0.14);
    const nextYNorm = clamp(fish.yNorm + verticalShift + randomBetween(-0.015, 0.015), 0.22, 0.72);
    const crawlSpeed = normalizeFishSpeed(species, randomBetween(species.speedMin, species.speedMax));
    const travelDistance = Math.hypot(nextXNorm - fish.xNorm, nextYNorm - fish.yNorm);
    const travelSeconds = travelDistance / Math.max(0.00001, crawlSpeed * FISH_MOTION_SCALE);
    const lingerMultiplier = shouldReverse ? randomBetween(1.12, 1.34) : randomBetween(1.35, 1.7);
    fish.targetXNorm = nextXNorm;
    fish.targetYNorm = nextYNorm;
    fish.targetAt = now + Math.max(
      species.targetMinMs,
      travelSeconds * 1000 * lingerMultiplier,
      species.targetMinMs + Math.random() * Math.max(2400, species.targetMaxMs - species.targetMinMs)
    );
    setFishTankLayers(fish, TANK_DEPTH_LAYERS, TANK_DEPTH_LAYERS);
    fish.hangoutDecorId = null;
    fish.swimSpeed = crawlSpeed;
    return;
  }

  if (effectiveBehavior === "shrimp") {
    const plantHangout = pickDecorHangoutTarget(species, fish, now, {
      allowedZoneTypes: ["plant"],
      chanceMultiplier: 1.75,
      lingerMultiplier: 0.7,
      occupancyLimit: DECOR_HANGOUT_SHRIMP_OCCUPANCY_LIMIT,
      occupancyGroup: "shrimp",
      preferBackLayer: true
    });
    if (plantHangout) {
      fish.targetXNorm = plantHangout.xNorm;
      fish.targetYNorm = clamp(Math.max(0.36, plantHangout.yNorm), 0.34, 0.82);
      fish.targetAt = now + Math.max(species.targetMinMs, plantHangout.lingerMs);
      setFishDesiredTankLayer(fish, clampTankLayer(Math.max(TANK_DEPTH_LAYERS - 1, plantHangout.targetLayer)));
      fish.hangoutDecorId = plantHangout.decorId;
      fish.hangoutZoneType = plantHangout.zoneType;
      fish.swimSpeed = normalizeFishSpeed(species, randomBetween(species.speedMin, species.speedMax));
      return;
    }

    const currentFacing = getFishFacingDirection(fish);
    const nearLeftWall = fish.xNorm <= 0.12;
    const nearRightWall = fish.xNorm >= 0.88;
    const nearFloor = fish.yNorm >= 0.74;
    const tooHigh = fish.yNorm <= 0.42;
    const dartDirection = nearLeftWall
      ? 1
      : nearRightWall
        ? -1
        : (Math.random() < 0.32 ? -currentFacing : currentFacing);
    const dartDistance = randomBetween(0.05, 0.14);
    const nextXNorm = clamp(fish.xNorm + dartDirection * dartDistance + randomBetween(-0.015, 0.015), 0.1, 0.9);
    const verticalShift = nearFloor
      ? -randomBetween(0.02, 0.08)
      : tooHigh
        ? randomBetween(0.03, 0.08)
        : randomBetween(-0.05, 0.05);
    const nextYNorm = clamp(fish.yNorm + verticalShift + randomBetween(-0.012, 0.012), 0.36, 0.82);
    fish.targetXNorm = nextXNorm;
    fish.targetYNorm = nextYNorm;
    fish.targetAt = now + randomBetween(species.targetMinMs, species.targetMaxMs);
    setFishDesiredTankLayer(
      fish,
      clampTankLayer(Math.random() < 0.72 ? TANK_DEPTH_LAYERS - 1 : TANK_DEPTH_LAYERS - 2)
    );
    fish.hangoutDecorId = null;
    fish.swimSpeed = normalizeFishSpeed(species, randomBetween(species.speedMin, species.speedMax));
    return;
  }

  const hangout = pickDecorHangoutTarget(species, fish, now);
  if (hangout) {
    fish.targetXNorm = hangout.xNorm;
    fish.targetYNorm = hangout.yNorm;
    fish.targetAt = now + hangout.lingerMs;
    setFishDesiredTankLayer(fish, hangout.targetLayer);
    fish.hangoutDecorId = hangout.decorId;
    fish.hangoutZoneType = hangout.zoneType;
    if (species.speedMode === "dynamic") {
      fish.swimSpeed = normalizeFishSpeed(species);
    }
    return;
  }

  const socialFollow = pickSameSpeciesFollowTarget(fish, species, now);
  if (socialFollow) {
    fish.targetXNorm = socialFollow.xNorm;
    fish.targetYNorm = socialFollow.yNorm;
    fish.targetAt = now + socialFollow.lingerMs;
    setFishDesiredTankLayer(fish, socialFollow.targetLayer);
    fish.hangoutDecorId = null;
    if (species.speedMode === "dynamic") {
      fish.swimSpeed = normalizeFishSpeed(species);
    }
    return;
  }

  const cavePlan = pickCaveEntryBehavior(species, fish, now);
  if (cavePlan) {
    beginFishCaveBehavior(fish, cavePlan, now);
    if (species.speedMode === "dynamic") {
      fish.swimSpeed = normalizeFishSpeed(species);
    }
    return;
  }

  const nextRoamLayer = effectiveBehavior === "sucker"
    ? TANK_DEPTH_LAYERS
    : clampTankLayer(1 + Math.floor(Math.random() * TANK_DEPTH_LAYERS));
  fish.targetXNorm = randomSwimX();
  fish.targetYNorm = randomSwimY(nextRoamLayer, fish, species);
  fish.targetAt = isFishCriticallyLowHealth(fish)
    ? now + randomBetween(900, Math.max(1400, species.targetMaxMs * 0.45))
    : now + species.targetMinMs + Math.random() * Math.max(200, species.targetMaxMs - species.targetMinMs);
  setFishDesiredTankLayer(fish, nextRoamLayer);
  fish.hangoutDecorId = null;
  fish.hangoutZoneType = null;
  if (species.speedMode === "dynamic" || isFishCriticallyLowHealth(fish)) {
    fish.swimSpeed = normalizeFishSpeed(
      species,
      isFishCriticallyLowHealth(fish)
        ? randomBetween(Math.max(species.speedMin, species.speedMax * 0.72), species.speedMax)
        : undefined
    );
  }
}

function getDecorFishBehaviorMeta(itemOrKey) {
  const decorKey = typeof itemOrKey === "string" ? itemOrKey : itemOrKey?.decorKey;
  if (!decorKey) {
    return null;
  }

  return runtime.decorMap.get(decorKey)?.fishBehavior
    || runtime.decorMeta[decorKey]?.fishBehavior
    || null;
}

function getDecorHangoutOccupancyGroup(fish, species = getSpeciesForFish(fish)) {
  return getEffectiveFishBehavior(fish, species) === "shrimp" ? "shrimp" : "fish";
}

function getDecorHangoutOccupancy(zone, requestingFish = null, group = "fish") {
  if (!zone?.decorId || !state?.fish?.length) {
    return 0;
  }

  return state.fish.filter((otherFish) => {
    if (
      !otherFish
      || otherFish.id === requestingFish?.id
      || isFishDead(otherFish)
      || otherFish.activity !== "roam"
      || otherFish.caveState
      || otherFish.hangoutDecorId !== zone.decorId
    ) {
      return false;
    }

    const otherGroup = getDecorHangoutOccupancyGroup(otherFish);
    if (group === "shrimp") {
      return otherGroup === "shrimp";
    }

    if (otherGroup === "shrimp") {
      return false;
    }

    const otherZoneType = typeof otherFish.hangoutZoneType === "string" ? otherFish.hangoutZoneType : "";
    return !otherZoneType || otherZoneType === zone.type;
  }).length;
}

function getDecorHangoutLimit(zone, group, options = {}) {
  if (Number.isFinite(Number(options.occupancyLimit))) {
    return Math.max(1, Math.floor(Number(options.occupancyLimit)));
  }

  if (Number.isFinite(Number(zone?.occupancyLimit))) {
    return Math.max(1, Math.floor(Number(zone.occupancyLimit)));
  }

  return group === "shrimp"
    ? DECOR_HANGOUT_SHRIMP_OCCUPANCY_LIMIT
    : DECOR_HANGOUT_DEFAULT_OCCUPANCY_LIMIT;
}

function pickDecorHangoutTarget(species, fish = null, now = Date.now(), options = {}) {
  const chanceByStyle = {
    peaceful: 0.62,
    steady: 0.46,
    sporadic: 0.34
  };
  const chanceMultiplier = Number.isFinite(Number(options.chanceMultiplier)) ? Number(options.chanceMultiplier) : 1;

  if (
    !state.placedDecor.length
    || (!options.force && Math.random() > clamp((chanceByStyle[species.swimStyle] || 0.4) * chanceMultiplier, 0, 1))
  ) {
    return null;
  }

  const allowedZoneTypes = normalizeStringList(options.allowedZoneTypes)
    .map((type) => type.toLowerCase().replace(/[-_\s]+/g, "-"));
  const occupancyGroup = typeof options.occupancyGroup === "string"
    ? options.occupancyGroup
    : getDecorHangoutOccupancyGroup(fish, species);
  const zones = getCachedDecorHangoutZones().filter((zone) => {
    if (allowedZoneTypes.length && !allowedZoneTypes.includes(zone.type)) {
      return false;
    }

    if (!fish) {
      return true;
    }

    if (
      fish.blockedDecorId &&
      zone.decorId === fish.blockedDecorId &&
      Number.isFinite(fish.blockedDecorUntil) &&
      now < fish.blockedDecorUntil
    ) {
      return false;
    }

    if (!options.ignoreOccupancy) {
      const limit = getDecorHangoutLimit(zone, occupancyGroup, options);
      if (getDecorHangoutOccupancy(zone, fish, occupancyGroup) >= limit) {
        return false;
      }
    }

    return true;
  });

  if (!zones.length) {
    return null;
  }

  const zone = zones[Math.floor(Math.random() * zones.length)];
  const targetLayer = options.preferBackLayer
    ? clampTankLayer(zone.targetLayerMax)
    : clampTankLayer(zone.targetLayerMin + Math.floor(Math.random() * (zone.targetLayerMax - zone.targetLayerMin + 1)));
  const lingerMultiplier = Number.isFinite(Number(options.lingerMultiplier)) ? Number(options.lingerMultiplier) : 1;
  const targetYNorm = clampFishYNormToLayer(randomBetween(zone.yMin, zone.yMax), fish, species, targetLayer, {
    minYNorm: 0.16,
    maxYNorm: 0.8
  });
  return {
    xNorm: clamp(randomBetween(zone.xMin, zone.xMax), 0.08, 0.92),
    yNorm: targetYNorm,
    targetLayer,
    decorId: zone.decorId,
    zoneType: zone.type,
    lingerMs: (zone.lingerMinMs + Math.random() * (zone.lingerMaxMs - zone.lingerMinMs)) * lingerMultiplier
  };
}

function getDecorHangoutZonesCacheKey() {
  if (!state?.placedDecor?.length) {
    return "none";
  }

  return state.placedDecor
    .map((item) => [
      item.id,
      item.decorKey,
      Number(item.xNorm).toFixed(4),
      Number(item.yNorm).toFixed(4),
      Number(item.scale).toFixed(4),
      getDecorTankLayer(item)
    ].join("|"))
    .join("::");
}

function getCachedDecorHangoutZones() {
  const cacheKey = getDecorHangoutZonesCacheKey();
  if (runtime.decorHangoutZonesKey === cacheKey && Array.isArray(runtime.decorHangoutZones)) {
    return runtime.decorHangoutZones;
  }

  const zones = buildDecorHangoutZones();
  runtime.decorHangoutZonesKey = cacheKey;
  runtime.decorHangoutZones = zones;
  return zones;
}

function buildDecorHangoutZones() {
  const zones = [];

  for (const item of state.placedDecor) {
    const bounds = getPlacedDecorBounds(item);
    if (!bounds) {
      continue;
    }

    const key = item.decorKey.toLowerCase();
    const fishBehavior = getDecorFishBehaviorMeta(item);
    const explicitHangoutTypes = (Array.isArray(fishBehavior?.hangoutTypes)
      ? fishBehavior.hangoutTypes
      : []).filter((type) => type !== "bubbler");
    if (isCaveDecorKey(key) && !explicitHangoutTypes.length) {
      continue;
    }
    const decorLayer = getDecorTankLayer(item);
    const behindLayer = clampTankLayer(Math.min(TANK_DEPTH_LAYERS, decorLayer + 1));
    const widthNorm = (bounds.right - bounds.left) / TANK_WIDTH;
    const heightNorm = (bounds.bottom - bounds.top) / TANK_HEIGHT;
    const addZone = (type, config) => {
      zones.push({
        decorId: item.id,
        type,
        occupancyLimit: Number.isFinite(Number(fishBehavior?.occupancyLimit))
          ? Math.max(1, Math.floor(Number(fishBehavior.occupancyLimit)))
          : null,
        ...config
      });
    };
    const addTypedZone = (type) => {
      if (type === "hide") {
        addZone("hide", {
          targetLayerMin: behindLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.14,
          xMax: item.xNorm + widthNorm * 0.14,
          yMin: item.yNorm - heightNorm * 0.32,
          yMax: item.yNorm - heightNorm * 0.12,
          lingerMinMs: 6000,
          lingerMaxMs: 11000
        });
        return;
      }

      if (type === "plant") {
        addZone("plant", {
          targetLayerMin: behindLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.2,
          xMax: item.xNorm + widthNorm * 0.2,
          yMin: item.yNorm - heightNorm * 0.5,
          yMax: item.yNorm - heightNorm * 0.16,
          lingerMinMs: 5000,
          lingerMaxMs: 9000
        });
        return;
      }

      if (type === "hardscape") {
        addZone("hardscape", {
          targetLayerMin: decorLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.24,
          xMax: item.xNorm + widthNorm * 0.24,
          yMin: item.yNorm - heightNorm * 0.46,
          yMax: item.yNorm - heightNorm * 0.12,
          lingerMinMs: 4600,
          lingerMaxMs: 8200
        });
        return;
      }

      if (type === "lure") {
        addZone("lure", {
          targetLayerMin: decorLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.28,
          xMax: item.xNorm + widthNorm * 0.28,
          yMin: item.yNorm - heightNorm * 0.28,
          yMax: item.yNorm + heightNorm * 0.12,
          lingerMinMs: 3200,
          lingerMaxMs: 6800
        });
        return;
      }

      if (type === "bubbler") {
        addZone("bubbler", {
          targetLayerMin: decorLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.22,
          xMax: item.xNorm + widthNorm * 0.22,
          yMin: item.yNorm - heightNorm * 0.95,
          yMax: item.yNorm - heightNorm * 0.28,
          lingerMinMs: 3500,
          lingerMaxMs: 7000
        });
        return;
      }

      if (type === "spooky") {
        addZone("spooky", {
          targetLayerMin: decorLayer,
          targetLayerMax: behindLayer,
          xMin: item.xNorm - widthNorm * 0.2,
          xMax: item.xNorm + widthNorm * 0.2,
          yMin: item.yNorm - heightNorm * 0.45,
          yMax: item.yNorm - heightNorm * 0.1,
          lingerMinMs: 5000,
          lingerMaxMs: 9500
        });
      }
    };

    if (explicitHangoutTypes.length || fishBehavior?.explicitHangout) {
      for (const type of explicitHangoutTypes) {
        addTypedZone(type);
      }
      continue;
    }

    if (/(castle|terracotta|bridge|arch|hide|pagoda)/.test(key)) {
      addTypedZone("hide");
    }

    if (/(coral|seaweed|grass|anubias|moss|bloom|bunch)/.test(key)) {
      addTypedZone("plant");
    }

    if (/(driftwood|root|shell|chest|rock)/.test(key)) {
      addTypedZone("hardscape");
    }
  }

  return zones;
}

function renderTank(now) {
  const dirtiness = getTankDirtiness(now);
  drawTankBackdrop();
  tankContext.save();
  clipToTankShellBounds(tankContext);
  drawBackground(now);
  drawUvLightAtmosphere(now, "back");
  drawFishPebbleTosses(now);
  drawFish(now, TANK_DEPTH_LAYERS, { onlyBehavior: "sucker" });
  drawAmbientBubbles(now, 1);
  drawWaterFilter(now);
  drawTankFloor(now);
  //drawLooseGravelCap();
  drawGroundShadows(now);
  drawPellets(now);
  //drawLooseGravel(now, { surfaceKind: "floor" });
  for (let layer = TANK_DEPTH_LAYERS; layer >= 1; layer -= 1) {
    if (layer === 3) {
      drawAmbientBubbles(now, 2);
    }
    drawDecor(layer, now);
    drawPoops(now, layer);
    //drawLooseGravel(now, { surfaceKind: "decor", decorLayer: layer });
    drawFish(now, layer, { excludeBehavior: "sucker" });
  }
  drawDecorBubbleStreams(now);
  drawAmbientBubbles(now, 3);
  //drawLooseGravel(now, { transientOnly: true });
  drawMedicineWaterTint(now);
  drawMedicineClouds(now);
  drawWaterBloodTint();
  drawBloodClouds();
  drawDecorPreview();
  drawDecorSwimGuide(now);
  drawActiveDecorLayerCue();
  drawWaterSurface(now);
  drawUvLightAtmosphere(now, "front");
  drawSplashBursts(now);
// Front glass glare is disabled for this display-focused view.
  tankContext.restore();
  drawAutoDispenser(now);
  drawGrime(dirtiness);
  drawCleaningSparkles(now);
  glassContext.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  const visibleDirtiness = getVisibleGrimeDirtiness(dirtiness);
  const lightGrime = getLightGrimeVisualIntensity(dirtiness);
  const severeGrime = getSevereGrimeVisualIntensity(dirtiness);
  const tankCanvasFilter = severeGrime > 0
    ? `blur(${(severeGrime * 1.8).toFixed(2)}px) saturate(${(1 - severeGrime * 0.18).toFixed(3)}) brightness(${(1 - severeGrime * 0.12).toFixed(3)})`
    : "none";
  if (runtime.lastTankCanvasFilter !== tankCanvasFilter) {
    dom.tankCanvas.style.filter = tankCanvasFilter;
    runtime.lastTankCanvasFilter = tankCanvasFilter;
  }
  const grimeCanvasFilter = visibleDirtiness > 0
    ? `blur(${(0.12 + lightGrime * 0.48 + severeGrime * 1.6).toFixed(2)}px)`
    : "none";
  if (runtime.lastGrimeCanvasFilter !== grimeCanvasFilter) {
    dom.grimeCanvas.style.filter = grimeCanvasFilter;
    runtime.lastGrimeCanvasFilter = grimeCanvasFilter;
  }
}

function getScaledTankShellPoints(pointSet) {
  return pointSet.map(([xNorm, yNorm]) => ({
    x: xNorm * TANK_WIDTH,
    y: yNorm * TANK_HEIGHT
  }));
}

function getTankShellPointSet(variant = "inner", target = getCurrentTank()) {
  if (!isBowlTank(target)) {
    return null;
  }
  return getScaledTankShellPoints(variant === "outer" ? BOWL_TANK_OUTER_POINTS : BOWL_TANK_INNER_POINTS);
}

function getPolygonBounds(points = []) {
  if (!points.length) {
    return {
      left: 0,
      top: 0,
      right: TANK_WIDTH,
      bottom: TANK_HEIGHT,
      width: TANK_WIDTH,
      height: TANK_HEIGHT
    };
  }

  const xs = points.map((point) => point.x);
  const ys = points.map((point) => point.y);
  const left = Math.min(...xs);
  const right = Math.max(...xs);
  const top = Math.min(...ys);
  const bottom = Math.max(...ys);
  return {
    left,
    top,
    right,
    bottom,
    width: right - left,
    height: bottom - top
  };
}

function tracePolygonPath(context, points = []) {
  if (!points.length) {
    return;
  }

  context.beginPath();
  context.moveTo(points[0].x, points[0].y);
  for (let index = 1; index < points.length; index += 1) {
    context.lineTo(points[index].x, points[index].y);
  }
  context.closePath();
}

function traceTankShellPath(context, options = {}) {
  const target = options.tank || getCurrentTank();
  const variant = options.variant === "outer" ? "outer" : "inner";
  const shellPoints = getTankShellPointSet(variant, target);
  if (!shellPoints) {
    const { outerLeft, outerTop, outerWidth, outerHeight, innerLeft, innerTop, innerWidth, innerHeight } = getTankShellBounds(target);
    context.beginPath();
    context.rect(
      variant === "outer" ? outerLeft : innerLeft,
      variant === "outer" ? outerTop : innerTop,
      variant === "outer" ? outerWidth : innerWidth,
      variant === "outer" ? outerHeight : innerHeight
    );
    return;
  }

  tracePolygonPath(context, shellPoints);
}

function pointInPolygon(point, polygon = []) {
  if (!polygon.length) {
    return true;
  }

  let inside = false;
  for (let leftIndex = 0, rightIndex = polygon.length - 1; leftIndex < polygon.length; rightIndex = leftIndex, leftIndex += 1) {
    const leftPoint = polygon[leftIndex];
    const rightPoint = polygon[rightIndex];
    const intersects = ((leftPoint.y > point.y) !== (rightPoint.y > point.y))
      && (point.x < ((rightPoint.x - leftPoint.x) * (point.y - leftPoint.y)) / ((rightPoint.y - leftPoint.y) || 0.00001) + leftPoint.x);
    if (intersects) {
      inside = !inside;
    }
  }
  return inside;
}

function projectPointIntoPolygon(point, polygon = []) {
  if (!polygon.length || pointInPolygon(point, polygon)) {
    return {
      x: point.x,
      y: point.y,
      inside: true
    };
  }

  const bounds = getPolygonBounds(polygon);
  let insidePoint = {
    x: bounds.left + bounds.width * 0.5,
    y: bounds.top + bounds.height * 0.5
  };
  let outsidePoint = {
    x: point.x,
    y: point.y
  };

  for (let index = 0; index < 18; index += 1) {
    const midpoint = {
      x: (insidePoint.x + outsidePoint.x) * 0.5,
      y: (insidePoint.y + outsidePoint.y) * 0.5
    };
    if (pointInPolygon(midpoint, polygon)) {
      insidePoint = midpoint;
    } else {
      outsidePoint = midpoint;
    }
  }

  return {
    x: insidePoint.x,
    y: insidePoint.y,
    inside: false
  };
}

function constrainPointToTankShell(x, y, options = {}) {
  const target = options.tank || getCurrentTank();
  const variant = options.variant === "outer" ? "outer" : "inner";
  const shellPoints = getTankShellPointSet(variant, target);
  const clampedPoint = {
    x: clamp(Number(x) || 0, 0, TANK_WIDTH),
    y: clamp(Number(y) || 0, 0, TANK_HEIGHT)
  };
  if (!shellPoints) {
    return {
      ...clampedPoint,
      inside: true
    };
  }
  return projectPointIntoPolygon(clampedPoint, shellPoints);
}

function constrainNormalizedPointToTankShell(xNorm, yNorm, options = {}) {
  const constrained = constrainPointToTankShell(
    Number(xNorm) * TANK_WIDTH,
    Number(yNorm) * TANK_HEIGHT,
    options
  );
  return {
    xNorm: constrained.x / TANK_WIDTH,
    yNorm: constrained.y / TANK_HEIGHT,
    inside: constrained.inside
  };
}

function getTankShellBounds(target = getCurrentTank()) {
  const outerPoints = getTankShellPointSet("outer", target);
  const innerPoints = getTankShellPointSet("inner", target);
  if (!outerPoints || !innerPoints) {
    return {
      outerLeft: 0,
      outerTop: 0,
      outerWidth: TANK_WIDTH,
      outerHeight: TANK_HEIGHT,
      innerLeft: 0,
      innerTop: 0,
      innerWidth: TANK_WIDTH,
      innerHeight: TANK_HEIGHT,
      shape: "rectangular"
    };
  }

  const outerBounds = getPolygonBounds(outerPoints);
  const innerBounds = getPolygonBounds(innerPoints);
  return {
    outerLeft: outerBounds.left,
    outerTop: outerBounds.top,
    outerWidth: outerBounds.width,
    outerHeight: outerBounds.height,
    innerLeft: innerBounds.left,
    innerTop: innerBounds.top,
    innerWidth: innerBounds.width,
    innerHeight: innerBounds.height,
    shape: "bowl",
    outerPoints,
    innerPoints
  };
}

function clipToTankShellBounds(context = tankContext, target = getCurrentTank(), variant = "inner") {
  traceTankShellPath(context, { tank: target, variant });
  context.clip();
}

function drawTankBackdrop() {
  tankContext.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  if (isBowlTank()) {
    tankContext.fillStyle = "#000";
    tankContext.fillRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
    return;
  }
  const background = tankContext.createLinearGradient(0, 0, 0, TANK_HEIGHT);
  background.addColorStop(0, "#09121d");
  background.addColorStop(1, "#03080f");
  tankContext.fillStyle = background;
  tankContext.fillRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
}

function drawBackground(now = Date.now()) {
  const background = runtime.backgroundMap.get(state.selectedBackground);
  const localImage = isLocalImageBackgroundKey(background?.key) ? runtime.images.get(getLocalBackgroundImageDataUrl()) : null;
  const image = background && !isCustomBackgroundKey(background.key) && !isLocalImageBackgroundKey(background.key)
    ? runtime.images.get(background.path)
    : localImage;
  const backgroundLeft = GLASS_MARGIN_X;
  const backgroundTop = 0;
  const backgroundWidth = TANK_WIDTH - GLASS_MARGIN_X * 2;
  const backgroundHeight = TANK_HEIGHT - GLASS_MARGIN_BOTTOM;
  const waterTop = WATER_SURFACE_Y;
  const waterHeight = TANK_HEIGHT - waterTop - GLASS_MARGIN_BOTTOM;

  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(backgroundLeft, backgroundTop, backgroundWidth, backgroundHeight);
  tankContext.clip();

  if (image) {
    drawImageCover(tankContext, image, backgroundLeft, backgroundTop, backgroundWidth, backgroundHeight);
  } else if (isCustomBackgroundKey(background?.key)) {
    tankContext.fillStyle = createCustomBackgroundFill(tankContext, backgroundLeft, backgroundTop, backgroundWidth, backgroundHeight);
    tankContext.fillRect(backgroundLeft, backgroundTop, backgroundWidth, backgroundHeight);
  } else {
    const gradient = tankContext.createLinearGradient(0, backgroundTop, 0, TANK_HEIGHT);
    gradient.addColorStop(0, "#10171c");
    gradient.addColorStop(1, "#05090d");
    tankContext.fillStyle = gradient;
    tankContext.fillRect(backgroundLeft, backgroundTop, backgroundWidth, backgroundHeight);
  }
  tankContext.restore();

  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, waterTop, backgroundWidth, waterHeight);
  tankContext.clip();

  const clearWaterShade = tankContext.createLinearGradient(0, waterTop, 0, TANK_HEIGHT);
  clearWaterShade.addColorStop(0, "rgba(255, 255, 255, 0.024)");
  clearWaterShade.addColorStop(0.42, "rgba(255, 255, 255, 0.006)");
  clearWaterShade.addColorStop(1, "rgba(0, 0, 0, 0.028)");
  tankContext.fillStyle = clearWaterShade;
  tankContext.fillRect(GLASS_MARGIN_X, waterTop, backgroundWidth, waterHeight);

  tankContext.globalAlpha = 0.16;
  tankContext.strokeStyle = "rgba(255, 255, 255, 0.03)";
  tankContext.lineWidth = Math.max(0.4, 0.65 * getViewportStableAssetScale());
  tankContext.lineCap = "round";
  for (let index = 0; index < 5; index += 1) {
    const y = waterTop + waterHeight * (0.18 + index * 0.14);
    const drift = Math.sin(now / 2600 + index * 1.7) * 8;
    tankContext.beginPath();
    tankContext.moveTo(GLASS_MARGIN_X + 60, y + drift * 0.1);
    tankContext.bezierCurveTo(
      TANK_WIDTH * 0.32,
      y + Math.sin(now / 3100 + index) * 5,
      TANK_WIDTH * 0.68,
      y - Math.cos(now / 2900 + index * 0.8) * 4,
      TANK_WIDTH - GLASS_MARGIN_X - 60,
      y + drift * 0.1
    );
    tankContext.stroke();
  }
  tankContext.restore();
}

function drawAmbientBubbles(now, layer = 3) {
  const layerProfile = getAmbientBubbleLayerProfile(layer);
  if (!layerProfile) {
    return;
  }

  const stableScale = getViewportStableAssetScale();
  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y + 2, TANK_WIDTH - GLASS_MARGIN_X * 2, TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM - 2);
  tankContext.clip();

  for (const bubble of runtime.scene.bubbles) {
    if (getAmbientBubbleRenderPass(bubble.layer || 3) !== layer) {
      continue;
    }

    const bubbleImage = getBubbleSpriteByIndex(bubble.spriteIndex);
    const progress = ((now / 1000) * bubble.speed + bubble.offset) % 1;
    const travelPhase = progress * bubble.wave + bubble.offset * 8;
    const x = bubble.x * TANK_WIDTH
      + Math.sin(travelPhase) * bubble.wobble * layerProfile.wobbleScale * stableScale
      + Math.cos(now / layerProfile.parallaxMs + bubble.offset * 11) * layerProfile.parallaxPx * stableScale;
    const y = TANK_HEIGHT - GLASS_MARGIN_BOTTOM - 8 - progress * (TANK_HEIGHT - WATER_SURFACE_Y - 20);
    if (y <= WATER_SURFACE_Y + 2) {
      continue;
    }

    if (bubbleImage && bubble.style === "sprite") {
      const size = bubble.size * bubble.spriteScale * layerProfile.sizeScale * stableScale;
      tankContext.save();
      tankContext.translate(x, y);
      tankContext.rotate(Math.sin(now / 1600 + bubble.offset * 12) * 0.14);
      tankContext.globalAlpha = bubble.alpha * layerProfile.alphaScale;
      tankContext.drawImage(bubbleImage, -size / 2, -size / 2, size, size);
      tankContext.restore();
      continue;
    }

    if (bubble.style === "cluster") {
      drawBubbleOrb(x, y, bubble.size * 0.78 * layerProfile.sizeScale, bubble.alpha * layerProfile.alphaScale, bubble.stretch);
      drawBubbleOrb(
        x + bubble.size * 0.74 * layerProfile.sizeScale * stableScale,
        y - bubble.size * 0.48 * layerProfile.sizeScale * stableScale,
        bubble.size * 0.5 * layerProfile.sizeScale,
        bubble.alpha * 0.84 * layerProfile.alphaScale,
        1.04
      );
      drawBubbleOrb(
        x - bubble.size * 0.6 * layerProfile.sizeScale * stableScale,
        y + bubble.size * 0.46 * layerProfile.sizeScale * stableScale,
        bubble.size * 0.42 * layerProfile.sizeScale,
        bubble.alpha * 0.74 * layerProfile.alphaScale,
        0.92
      );
      continue;
    }

    if (bubble.style === "fizz") {
      for (let index = 0; index < bubble.count; index += 1) {
        const offsetY = index * (bubble.size * 0.95 * layerProfile.sizeScale * stableScale);
        const offsetX = Math.sin(now / 460 + bubble.offset * 14 + index) * 1.8 * layerProfile.wobbleScale * stableScale;
        drawBubbleOrb(
          x + offsetX,
          y + offsetY,
          bubble.size * (0.26 + index * 0.08) * layerProfile.sizeScale,
          bubble.alpha * (0.85 - index * 0.1) * layerProfile.alphaScale,
          1
        );
      }
      continue;
    }

    drawBubbleOrb(x, y, bubble.size * layerProfile.sizeScale, bubble.alpha * layerProfile.alphaScale, bubble.stretch);
  }

  tankContext.restore();
}

function getAmbientBubbleRenderPass(sourceLayer = 3) {
  const normalizedLayer = clamp(Math.round(Number(sourceLayer) || 3), 1, 5);
  if (normalizedLayer <= 2) {
    return 1;
  }
  if (normalizedLayer === 3) {
    return 2;
  }
  return 3;
}

function getAmbientBubbleLayerProfile(layer = 3) {
  const profiles = {
    1: { alphaScale: 0.42, sizeScale: 0.84, wobbleScale: 0.76, parallaxPx: 3.5, parallaxMs: 7600 },
    2: { alphaScale: 0.68, sizeScale: 1, wobbleScale: 0.94, parallaxPx: 6.2, parallaxMs: 6100 },
    3: { alphaScale: 0.94, sizeScale: 1.15, wobbleScale: 1.12, parallaxPx: 8.4, parallaxMs: 4700 }
  };
  return profiles[layer] || profiles[3];
}

function drawWaterFilter(now) {
  tankContext.save();
  const filterAsset = runtime.filterMap.get(state.selectedFilterAsset);
  const filterImage = filterAsset ? runtime.images.get(filterAsset.path) : null;
  if (!filterImage) {
    tankContext.restore();
    return;
  }
  const filterProfile = getFilterProfile();
  const stableScale = getViewportStableAssetScale();
  const filterScale = stableScale * FILTER_VIEWPORT_SIZE_MULTIPLIER;

  const filterDrawWidth = 148 * filterScale;
  const filterDrawHeight = 220 * filterScale;
  const streamDistance = getViewportPxAsTankVirtual(FILTER_BUBBLE_STREAM_DISTANCE_PX + filterProfile.flow * 18);
  const spoutLipOffset = 8 * filterScale;
  const visibleBounds = getVisibleTankVirtualBounds();
  const groupWidth = streamDistance + filterDrawWidth - spoutLipOffset;
  const desiredGroupRightX = visibleBounds.right - getViewportPxAsTankVirtual(FILTER_GROUP_RIGHT_MARGIN_PX);
  const minGroupRightX = visibleBounds.left + groupWidth + getViewportPxAsTankVirtual(8);
  const maxGroupRightX = visibleBounds.right - getViewportPxAsTankVirtual(8);
  const groupRightX = clamp(desiredGroupRightX, Math.min(minGroupRightX, maxGroupRightX), maxGroupRightX);
  const groupLeftX = groupRightX - groupWidth;
  const spoutX = groupLeftX + streamDistance;
  const outletX = spoutX + getViewportPxAsTankVirtual(FILTER_BUBBLE_OUTLET_X_OFFSET_PX);
  const filterDrawX = spoutX - spoutLipOffset;
  const filterDrawY = visibleBounds.top;
  // Anchor the flow to the rendered outlet nozzle rather than the full image bounds.
  const outletY = filterDrawY + filterDrawHeight * (88 / 260) + getViewportPxAsTankVirtual(14);
  const flowIntensity = 0.86 + filterProfile.flow * 0.22;
  const flowActive = isFilterBubbleFlowActive(now);

  if (flowActive) {
    tankContext.save();
    tankContext.beginPath();
    tankContext.rect(
      GLASS_MARGIN_X,
      WATER_SURFACE_Y - 10,
      TANK_WIDTH - GLASS_MARGIN_X * 2,
      TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM + 10
    );
    tankContext.clip();

    const bubbleCount = 18 + Math.round(filterProfile.flow * 6);
    const streamRise = getViewportPxAsTankVirtual(FILTER_BUBBLE_STREAM_RISE_PX);
    for (let index = 0; index < bubbleCount; index += 1) {
      const lane = index % 4;
      const phase = ((now / (150 + lane * 20)) + index * 0.14) % 1;
      const drift = phase * streamDistance;
      const riseProgress = clamp((phase - 0.68) / 0.32, 0, 1);
      const riseEase = 1 - (1 - riseProgress) * (1 - riseProgress);
      const fadeOut = 1 - riseEase;
      const x = outletX - drift + Math.sin(now / 170 + index * 1.7) * getViewportPxAsTankVirtual(1.6 + lane * 0.35);
      const y = outletY
        + (lane - 1.5) * getViewportPxAsTankVirtual(2.3)
        + Math.sin(now / 210 + index * 1.35) * getViewportPxAsTankVirtual(0.95)
        - streamRise * riseEase;
      const radius = 2.2 + (index % 3) * 0.7 + filterProfile.flow * 0.22;
      const alpha = (0.16 + (1 - phase) * 0.38 * flowIntensity) * fadeOut;
      drawBubbleOrb(x, y, radius, alpha, 1 + lane * 0.03);
    }

    for (let index = 0; index < 7; index += 1) {
      const pulse = ((now / 120) + index * 0.21) % 1;
      const riseProgress = clamp((pulse - 0.68) / 0.32, 0, 1);
      const riseEase = 1 - (1 - riseProgress) * (1 - riseProgress);
      const x = outletX - pulse * streamDistance;
      const y = outletY + Math.sin(now / 150 + index * 1.2) * getViewportPxAsTankVirtual(1.1) - streamRise * riseEase;
      tankContext.fillStyle = `rgba(214, 247, 255, ${((0.07 + (1 - pulse) * 0.12) * (1 - riseEase)).toFixed(3)})`;
      tankContext.beginPath();
      tankContext.ellipse(
        x,
        y,
        getViewportPxAsTankVirtual(1.8 + pulse * 1.6),
        getViewportPxAsTankVirtual(0.9 + pulse * 0.62),
        0,
        0,
        Math.PI * 2
      );
      tankContext.fill();
    }
    tankContext.restore();
  }

  if (filterImage) {
    tankContext.globalAlpha = 1;
    tankContext.drawImage(filterImage, filterDrawX, filterDrawY, filterDrawWidth, filterDrawHeight);
    tankContext.globalAlpha = 1;
  }
  tankContext.restore();
}

function isFilterBubbleFlowActive(now = Date.now()) {
  return getBaseTankDirtiness(now) < CRITICAL_TANK_DIRTINESS;
}

function drawAutoDispenserButton(bounds, label, options = {}) {
  tankContext.save();
  const gradient = tankContext.createLinearGradient(bounds.left, bounds.top, bounds.left, bounds.bottom);
  const green = options.variant === "play";
  const red = options.variant === "reset";
  if (green) {
    gradient.addColorStop(0, "rgba(109, 230, 93, 0.98)");
    gradient.addColorStop(0.52, "rgba(50, 170, 67, 0.98)");
    gradient.addColorStop(1, "rgba(18, 96, 43, 0.98)");
  } else if (red) {
    gradient.addColorStop(0, "rgba(245, 82, 82, 0.98)");
    gradient.addColorStop(0.52, "rgba(210, 36, 36, 0.98)");
    gradient.addColorStop(1, "rgba(142, 12, 16, 0.98)");
  } else {
    gradient.addColorStop(0, "rgba(242, 177, 74, 0.96)");
    gradient.addColorStop(1, "rgba(150, 92, 18, 0.96)");
  }
  tankContext.fillStyle = gradient;
  tankContext.beginPath();
  tankContext.roundRect(bounds.left, bounds.top, bounds.right - bounds.left, bounds.bottom - bounds.top, 6);
  tankContext.fill();
  tankContext.strokeStyle = green
    ? "rgba(209, 255, 190, 0.68)"
    : red
      ? "rgba(255, 196, 196, 0.72)"
      : "rgba(255, 239, 188, 0.55)";
  tankContext.lineWidth = 1.5 * getViewportStableAssetScale();
  tankContext.stroke();
  tankContext.fillStyle = green ? "#06210D" : red ? "#050505" : "#1E1204";
  tankContext.strokeStyle = tankContext.fillStyle;
  const width = bounds.right - bounds.left;
  const height = bounds.bottom - bounds.top;
  const centerX = (bounds.left + bounds.right) / 2;
  const centerY = (bounds.top + bounds.bottom) / 2;
  if (options.icon === "play") {
    const iconSize = Math.min(width, height) * 0.48;
    tankContext.beginPath();
    tankContext.moveTo(centerX - iconSize * 0.34, centerY - iconSize * 0.48);
    tankContext.lineTo(centerX - iconSize * 0.34, centerY + iconSize * 0.48);
    tankContext.lineTo(centerX + iconSize * 0.46, centerY);
    tankContext.closePath();
    tankContext.fill();
    tankContext.restore();
    return;
  }

  if (options.icon === "reset") {
    tankContext.font = `900 ${Math.max(10, Math.round(height * 0.82))}px "Segoe UI Symbol", "Arial Unicode MS", "Trebuchet MS", sans-serif`;
    tankContext.textAlign = "center";
    tankContext.textBaseline = "middle";
    tankContext.fillText("↺", centerX, centerY + height * 0.03, width * 0.86);
    tankContext.restore();
    return;
  }

  const textScale = options.textScale || (String(label).length > 2 ? 0.5 : 0.9);
  tankContext.font = `bold ${Math.max(10, Math.round(height * textScale))}px "Trebuchet MS", sans-serif`;
  tankContext.textAlign = "center";
  tankContext.textBaseline = "middle";
  tankContext.fillText(label, centerX, centerY + 0.5);
  tankContext.restore();
}

function getAutoDispenserHopperCache() {
  if (!runtime.autoDispenserHopperCache) {
    runtime.autoDispenserHopperCache = {
      key: "",
      canvas: document.createElement("canvas")
    };
  }
  return runtime.autoDispenserHopperCache;
}

function getAutoDispenserHopperCacheKey(storedPellets, width, height) {
  const pelletKey = storedPellets
    .slice(0, AUTO_DISPENSER_HOPPER_MAX_DRAWN_PELLETS)
    .map((pellet) => `${pellet.id || ""}:${pellet.foodKey || ""}:${pellet.spritePath || ""}`)
    .join("|");
  return [
    Math.round(width),
    Math.round(height),
    isViolenceAndGoreEnabled() ? "gore" : "safe",
    pelletKey
  ].join(";");
}

function drawFoodPelletPieceToContext(context, x, y, pellet, appearance) {
  const sprite = getTintedFoodPelletSprite(appearance);
  const stableScale = getViewportStableAssetScale();
  const scale = clamp(Number(pellet?.scale) || 1, 0.75, 1.35) * stableScale;

  context.save();
  context.translate(x, y);
  context.rotate((Number(pellet?.rotation) || 0) * 0.35);
  context.globalAlpha = 0.94;
  if (sprite) {
    const size = 9.8 * scale;
    const drawWidth = size;
    const drawHeight = size * (sprite.height / Math.max(1, sprite.width));
    context.drawImage(sprite, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);
  } else {
    const width = 8.8 * scale;
    const height = 6.2 * scale;
    context.fillStyle = appearance.baseColor;
    context.beginPath();
    context.ellipse(0, 0, width / 2, height / 2, 0, 0, Math.PI * 2);
    context.fill();

    context.fillStyle = appearance.accentColor;
    context.beginPath();
    context.ellipse(width * 0.06, height * 0.02, width * 0.3, height * 0.22, 0.05, 0, Math.PI * 2);
    context.fill();

    context.fillStyle = appearance.highlightColor;
    context.beginPath();
    context.ellipse(-width * 0.15, -height * 0.16, width * 0.16, height * 0.22, 0.1, 0, Math.PI * 2);
    context.fill();
  }
  context.restore();
}

function drawFoodSpritePieceToContext(context, x, y, pellet, spritePath) {
  const image = spritePath ? runtime.images.get(spritePath) : null;
  if (!image) {
    return false;
  }

  const stableScale = getViewportStableAssetScale();
  const scale = clamp(Number(pellet?.scale) || 1, 0.8, 1.4) * stableScale;
  const fitScale = Math.min((24 * scale) / Math.max(1, image.width), (24 * scale) / Math.max(1, image.height));
  const drawWidth = Math.max(10 * stableScale, image.width * fitScale);
  const drawHeight = Math.max(10 * stableScale, image.height * fitScale);

  context.save();
  context.translate(x, y);
  context.rotate(Number(pellet?.rotation) || 0);
  context.globalAlpha = 0.96;
  context.drawImage(image, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);
  context.restore();
  return true;
}

function buildAutoDispenserHopperPile(storedPellets, width, height) {
  const visiblePelletCount = Math.min(
    storedPellets.length,
    AUTO_DISPENSER_MAX_PELLETS,
    AUTO_DISPENSER_HOPPER_MAX_DRAWN_PELLETS
  );
  const fullness = clamp(visiblePelletCount / AUTO_DISPENSER_MAX_PELLETS, 0, 1);
  const fillHeightRatio = clamp(0.2 + fullness * 0.8, 0, 1);
  const fillTop = height * (1 - fillHeightRatio);
  const stableScale = getViewportStableAssetScale();
  const margin = Math.max(5 * stableScale, 3);
  const pieces = [];

  for (let index = 0; index < visiblePelletCount; index += 1) {
    const storedPellet = storedPellets[index];
    const rand = mulberry32(hashStringToUint32(`${storedPellet.id || ""}|${storedPellet.foodKey || ""}|hopper|${index}`) ^ 0x6a09e667);
    const food = getFoodMeta(storedPellet.foodKey);
    const dropStyle = getFoodDropStyle(food);
    const yUnit = Math.pow(randomBetweenWith(rand, 0, 1), 0.72);
    const xJitter = (randomBetweenWith(rand, -1, 1) + randomBetweenWith(rand, -1, 1)) * 0.5;
    const x = clamp(
      width * (0.5 + xJitter * 0.48),
      margin,
      Math.max(margin, width - margin)
    );
    const y = clamp(
      fillTop + yUnit * Math.max(1, height - fillTop),
      fillTop + margin * 0.45,
      Math.max(fillTop + margin * 0.45, height - margin * 0.28)
    );
    pieces.push({
      x,
      y,
      storedPellet,
      pellet: {
        scale: dropStyle === "sprite"
          ? randomBetweenWith(rand, 0.92, 1.18)
          : randomBetweenWith(rand, 0.94, 1.08),
        rotation: dropStyle === "sprite"
          ? randomBetweenWith(rand, -0.95, 0.95)
          : randomBetweenWith(rand, -0.22, 0.22),
        spritePath: storedPellet.spritePath
      }
    });
  }

  return pieces.sort((left, right) => left.y - right.y);
}

function renderAutoDispenserHopperCache(dispenser, layout) {
  const storedPellets = Array.isArray(dispenser.storedPellets) ? dispenser.storedPellets : [];
  const width = Math.max(1, Math.ceil(layout.hopperBounds.right - layout.hopperBounds.left));
  const height = Math.max(1, Math.ceil(layout.hopperBounds.bottom - layout.hopperBounds.top));
  const cache = getAutoDispenserHopperCache();
  const key = getAutoDispenserHopperCacheKey(storedPellets, width, height);
  if (cache.key === key && cache.canvas.width === width && cache.canvas.height === height) {
    return cache.canvas;
  }

  cache.key = key;
  cache.canvas.width = width;
  cache.canvas.height = height;
  const context = cache.canvas.getContext("2d");
  context.clearRect(0, 0, width, height);
  const appearanceCache = new Map();
  for (const piece of buildAutoDispenserHopperPile(storedPellets, width, height)) {
    const { storedPellet, pellet } = piece;
    const cacheKey = `${storedPellet.foodKey || ""}|${storedPellet.spritePath || ""}`;
    let appearance = appearanceCache.get(cacheKey);
    if (!appearance) {
      appearance = getFoodDropAppearance(storedPellet.foodKey, storedPellet);
      appearanceCache.set(cacheKey, appearance);
    }

    if (appearance.dropStyle === "sprite") {
      if (!drawFoodSpritePieceToContext(context, piece.x, piece.y, pellet, appearance.spritePath)) {
        drawFoodPelletPieceToContext(context, piece.x, piece.y, pellet, appearance);
      }
    } else {
      drawFoodPelletPieceToContext(context, piece.x, piece.y, pellet, appearance);
    }
  }
  return cache.canvas;
}

function drawAutoDispenser(now = Date.now()) {
  if (!hasAutoDispenserInstalled()) {
    return;
  }

  const dispenser = state.autoDispenser;
  const layout = getAutoDispenserLayout();
  const backgroundImage = runtime.images.get(AUTO_DISPENSER_BG_PATH);
  const foregroundImage = runtime.images.get(AUTO_DISPENSER_IMAGE_PATH);

  tankContext.save();
  if (backgroundImage) {
    tankContext.drawImage(backgroundImage, layout.x, layout.y, layout.width, layout.height);
  }

  tankContext.save();
  tankContext.beginPath();
  tankContext.roundRect(
    layout.hopperBounds.left,
    layout.hopperBounds.top,
    layout.hopperBounds.right - layout.hopperBounds.left,
    layout.hopperBounds.bottom - layout.hopperBounds.top,
    10
  );
  tankContext.clip();

  const hopperCanvas = renderAutoDispenserHopperCache(dispenser, layout);
  tankContext.drawImage(
    hopperCanvas,
    layout.hopperBounds.left,
    layout.hopperBounds.top,
    layout.hopperBounds.right - layout.hopperBounds.left,
    layout.hopperBounds.bottom - layout.hopperBounds.top
  );
  tankContext.restore();

  if (foregroundImage) {
    tankContext.drawImage(foregroundImage, layout.x, layout.y, layout.width, layout.height);
  }

  const lowFood = isAutoDispenserFoodLow(dispenser) || dispenser.refillAlert;
  const blinking = lowFood && Math.floor(now / AUTO_DISPENSER_LOW_FOOD_BLINK_MS) % 2 === 0;
  const screenBounds = layout.screenBounds;
  const screenGradient = tankContext.createLinearGradient(screenBounds.left, screenBounds.top, screenBounds.left, screenBounds.bottom);
  screenGradient.addColorStop(0, "rgba(82, 86, 86, 0.98)");
  screenGradient.addColorStop(0.48, "rgba(55, 58, 58, 0.98)");
  screenGradient.addColorStop(1, "rgba(31, 33, 34, 0.98)");
  tankContext.fillStyle = screenGradient;
  tankContext.beginPath();
  tankContext.roundRect(
    screenBounds.left,
    screenBounds.top,
    screenBounds.right - screenBounds.left,
    screenBounds.bottom - screenBounds.top,
    6
  );
  tankContext.fill();
  tankContext.strokeStyle = "rgba(12, 13, 13, 0.72)";
  tankContext.lineWidth = getViewportStableAssetScale();
  tankContext.stroke();

  const displayValue = String(clamp(dispenser.mealPortion || 0, AUTO_DISPENSER_PORTION_MIN, AUTO_DISPENSER_PORTION_MAX)).padStart(2, "0");
  const screenWidth = screenBounds.right - screenBounds.left;
  const screenHeight = screenBounds.bottom - screenBounds.top;
  tankContext.save();
  tankContext.textAlign = "center";
  tankContext.textBaseline = "middle";
  tankContext.font = `700 ${Math.max(9, Math.round(screenHeight * 0.82))}px "E1234Display", "Consolas", "Courier New", monospace`;
  tankContext.fillStyle = blinking ? "#E92525" : "#050505";
  tankContext.shadowColor = blinking ? "rgba(255, 28, 28, 0.55)" : "transparent";
  tankContext.shadowBlur = blinking ? Math.max(2, screenHeight * 0.18) : 0;
  tankContext.fillText(displayValue, screenBounds.left + screenWidth / 2, screenBounds.top + screenHeight * 0.57, screenWidth * 0.82);
  tankContext.restore();

  drawAutoDispenserButton(layout.minusBounds, "-");
  drawAutoDispenserButton(layout.plusBounds, "+");
  drawAutoDispenserButton(layout.resetBounds, "", { icon: "reset", variant: "reset" });
  drawAutoDispenserButton(layout.playBounds, "", { icon: "play", variant: "play" });
  tankContext.restore();
}

function getTintedFoodPelletSprite(appearance) {
  const image = runtime.images.get(FOOD_PELLET_IMAGE_PATH);
  if (!image?.width || !image?.height) {
    return null;
  }

  const baseRgb = hexToRgb(appearance?.baseColor) || hexToRgb("#825930");
  const accentRgb = hexToRgb(appearance?.accentColor) || baseRgb;
  const highlightRgb = hexToRgb(appearance?.highlightColor) || accentRgb;
  const cacheKey = `${appearance?.baseColor || ""}|${appearance?.accentColor || ""}|${appearance?.highlightColor || ""}`;
  const cached = runtime.foodPelletTintCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const canvas = document.createElement("canvas");
  canvas.width = image.width;
  canvas.height = image.height;
  const context = canvas.getContext("2d", { willReadFrequently: true });
  if (!context) {
    return null;
  }

  context.clearRect(0, 0, canvas.width, canvas.height);
  context.drawImage(image, 0, 0, canvas.width, canvas.height);
  const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
  const pixels = imageData.data;
  const mixRgb = (left, right, amount) => {
    const weight = clamp(amount, 0, 1);
    return {
      r: left.r + (right.r - left.r) * weight,
      g: left.g + (right.g - left.g) * weight,
      b: left.b + (right.b - left.b) * weight
    };
  };

  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3];
    if (alpha <= 4) {
      continue;
    }

    const luminance = (pixels[index] * 0.299 + pixels[index + 1] * 0.587 + pixels[index + 2] * 0.114) / 255;
    const shade = clamp(Math.pow(luminance, 0.82), 0, 1);
    const target = shade < 0.62
      ? mixRgb(baseRgb, accentRgb, shade / 0.62)
      : mixRgb(accentRgb, highlightRgb, (shade - 0.62) / 0.38);

    pixels[index] = Math.round(target.r);
    pixels[index + 1] = Math.round(target.g);
    pixels[index + 2] = Math.round(target.b);
  }

  context.putImageData(imageData, 0, 0);
  runtime.foodPelletTintCache.set(cacheKey, canvas);
  return canvas;
}

function drawProceduralFoodPelletPiece(x, y, pellet, appearance) {
  const scale = clamp(Number(pellet?.scale) || 1, 0.75, 1.35) * getViewportStableAssetScale();
  const width = 11.6 * scale;
  const height = 6.6 * scale;
  const accentWidth = width * 0.65;
  const accentHeight = height * 0.66;

  tankContext.save();
  tankContext.translate(x, y);
  tankContext.rotate((Number(pellet?.rotation) || 0) * 0.35);
  tankContext.globalAlpha = 0.92;

  tankContext.fillStyle = appearance.baseColor;
  tankContext.beginPath();
  tankContext.roundRect(-width / 2, -height / 2, width, height, height / 2);
  tankContext.fill();

  tankContext.fillStyle = appearance.accentColor;
  tankContext.beginPath();
  tankContext.roundRect(-accentWidth / 2 + width * 0.02, -accentHeight / 2, accentWidth, accentHeight, accentHeight / 2);
  tankContext.fill();

  tankContext.fillStyle = appearance.highlightColor;
  tankContext.beginPath();
  tankContext.ellipse(-width * 0.15, -height * 0.16, width * 0.16, height * 0.22, 0.1, 0, Math.PI * 2);
  tankContext.fill();

  tankContext.restore();
}

function drawFoodPelletPiece(x, y, pellet, appearance) {
  const sprite = getTintedFoodPelletSprite(appearance);
  if (!sprite) {
    drawProceduralFoodPelletPiece(x, y, pellet, appearance);
    return;
  }

  const scale = clamp(Number(pellet?.scale) || 1, 0.75, 1.35) * getViewportStableAssetScale();
  const size = 9.8 * scale;
  const drawWidth = size;
  const drawHeight = size * (sprite.height / Math.max(1, sprite.width));

  tankContext.save();
  tankContext.translate(x, y);
  tankContext.rotate((Number(pellet?.rotation) || 0) * 0.35);
  tankContext.globalAlpha = 0.94;
  tankContext.drawImage(sprite, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);
  tankContext.restore();
}

function drawFallbackChumPiece(x, y, pellet) {
  const scale = clamp(Number(pellet?.scale) || 1, 0.8, 1.35) * getViewportStableAssetScale();

  tankContext.save();
  tankContext.translate(x, y);
  tankContext.rotate(Number(pellet?.rotation) || 0);
  tankContext.globalAlpha = 0.94;

  tankContext.fillStyle = "#791421";
  tankContext.beginPath();
  tankContext.ellipse(0, 0, 8.6 * scale, 5.4 * scale, 0.28, 0, Math.PI * 2);
  tankContext.fill();

  tankContext.fillStyle = "#B34555";
  tankContext.beginPath();
  tankContext.ellipse(-1.6 * scale, -0.4 * scale, 4.2 * scale, 2.5 * scale, -0.25, 0, Math.PI * 2);
  tankContext.fill();

  tankContext.fillStyle = "rgba(255, 207, 214, 0.38)";
  tankContext.beginPath();
  tankContext.ellipse(1.8 * scale, -1.1 * scale, 2.1 * scale, 1.15 * scale, 0.18, 0, Math.PI * 2);
  tankContext.fill();

  tankContext.restore();
}

function drawFoodSpritePiece(x, y, pellet, spritePath) {
  const image = spritePath ? runtime.images.get(spritePath) : null;
  if (!image) {
    return false;
  }

  const stableScale = getViewportStableAssetScale();
  const scale = clamp(Number(pellet?.scale) || 1, 0.8, 1.4) * stableScale;
  const fitScale = Math.min((24 * scale) / Math.max(1, image.width), (24 * scale) / Math.max(1, image.height));
  const drawWidth = Math.max(10 * stableScale, image.width * fitScale);
  const drawHeight = Math.max(10 * stableScale, image.height * fitScale);

  tankContext.save();
  tankContext.translate(x, y);
  tankContext.rotate(Number(pellet?.rotation) || 0);
  tankContext.globalAlpha = 0.96;
  tankContext.drawImage(image, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);
  tankContext.restore();
  return true;
}

function drawPellets(now) {
  if (!state.floatingPellets.length) {
    return;
  }

  tankContext.save();
  for (const pellet of state.floatingPellets) {
    const pose = getPelletPose(pellet, now);
    const x = pose.xNorm * TANK_WIDTH;
    const settledOffset = pellet.settled ? FOOD_PELLET_SETTLED_Y_OFFSET_PX * getViewportStableAssetScale() : 0;
    const y = pose.yNorm * TANK_HEIGHT - settledOffset;

    const appearance = getFoodDropAppearance(pellet.foodKey, pellet);
    if (appearance.dropStyle === "sprite") {
      if (!drawFoodSpritePiece(x, y, pellet, appearance.spritePath)) {
        drawFallbackChumPiece(x, y, pellet);
      }
    } else {
      drawFoodPelletPiece(x, y, pellet, appearance);
    }
  }
  tankContext.restore();
}

function getTankFloorDrawBounds() {
  const left = GLASS_MARGIN_X;
  const right = TANK_WIDTH - GLASS_MARGIN_X;
  const bottom = getVisibleTankFloorBottomY();
  const baseTop = getTankFloorSurfaceYAtX(TANK_WIDTH * 0.5) - 26;
  const floorHeight = Math.max(40, bottom - baseTop);

  return {
    left,
    right,
    bottom,
    baseTop,
    floorHeight,
    drawTop: baseTop - 10,
    drawHeight: floorHeight + 20,
    drawWidth: right - left
  };
}

function getTankFloorMaskSurfaceYAtX(x, bounds = getTankFloorDrawBounds()) {
  const { left, right, baseTop } = bounds;
  const t = clamp((x - left) / Math.max(1, right - left), 0, 1);
  const wave1 = Math.sin(t * Math.PI * 2 * 1.2) * 8;
  const wave2 = Math.sin(t * Math.PI * 2 * 3.4 + 0.8) * 3;
  const crestBias = Math.sin(t * Math.PI) * 4;
  return baseTop + wave1 + wave2 - crestBias;
}

function traceTankFloorMaskPath(context, bounds = getTankFloorDrawBounds()) {
  const { left, right, bottom } = bounds;

  context.beginPath();
  context.moveTo(left, bottom);

  for (let x = left; x <= right; x += 8) {
    context.lineTo(x, getTankFloorMaskSurfaceYAtX(x, bounds));
  }

  context.lineTo(right, bottom);
  context.closePath();
}

function drawSelectedGravelFloorImage(bounds) {
  const gravel = runtime.gravelMap.get(state.selectedGravelAsset) || runtime.gravelCatalog[0] || null;
  const gravelImage = gravel ? runtime.images.get(gravel.path) : null;
  if (!gravelImage) {
    return false;
  }

  drawImageCover(tankContext, gravelImage, bounds.left, bounds.drawTop, bounds.drawWidth, bounds.drawHeight);
  return true;
}

function getCustomGravelAssetImage(asset) {
  if (!asset) {
    return { image: null, path: "" };
  }

  const resolvedPath = typeof asset.path === "string" ? asset.path : "";
  return {
    image: resolvedPath ? runtime.images.get(resolvedPath) || null : null,
    path: resolvedPath
  };
}

function getCustomGravelLayerImage(layer) {
  return getCustomGravelAssetImage(layer);
}

function getTintedCustomGravelAsset(asset, color, options = {}) {
  const normalizedColor = normalizeHexColor(color) || DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR;
  const colorize = normalizeDecorColorizeSetting(options.colorize);
  const { image, path } = getCustomGravelAssetImage(asset);
  if (!image?.width || !image?.height || !path) {
    return null;
  }

  const maxDimension = Number.isFinite(options.maxDimension) && options.maxDimension > 0
    ? Math.max(1, Math.round(options.maxDimension))
    : 0;
  const scale = maxDimension
    ? Math.min(1, maxDimension / Math.max(image.width, image.height))
    : 1;
  const width = Math.max(1, Math.round(image.width * scale));
  const height = Math.max(1, Math.round(image.height * scale));
  const cacheScope = typeof options.cacheScope === "string" && options.cacheScope ? options.cacheScope : "base";
  const cacheKey = `${cacheScope}|${path}|${normalizedColor}|${colorize ? "colorize" : "hue"}|${width}x${height}`;
  const cached = runtime.customGravelTintCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  context.clearRect(0, 0, canvas.width, canvas.height);
  context.drawImage(image, 0, 0, canvas.width, canvas.height);
  const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
  const pixels = imageData.data;
  const targetRgb = hexToRgb(normalizedColor) || hexToRgb(DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR);
  if (!targetRgb) {
    return null;
  }
  const targetHsl = rgbToHsl(targetRgb);
  const sourceStats = getCaveLayerSourceStats(path, canvas.width, canvas.height, pixels);
  const hueDelta = getHueDeltaUnit(sourceStats.avgHue, targetHsl.h);

  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3];
    if (alpha <= 0) {
      continue;
    }

    if (colorize) {
      const luminance = (pixels[index] * 0.299 + pixels[index + 1] * 0.587 + pixels[index + 2] * 0.114) / 255;
      const shade = Math.pow(luminance, 0.92);
      pixels[index] = Math.round(targetRgb.r * shade);
      pixels[index + 1] = Math.round(targetRgb.g * shade);
      pixels[index + 2] = Math.round(targetRgb.b * shade);
      continue;
    }

    const hsl = rgbToHsl({
      r: pixels[index],
      g: pixels[index + 1],
      b: pixels[index + 2]
    });
    const hasSourceHue = hsl.s > 0.035;
    const nextHue = hasSourceHue ? normalizeHueUnit(hsl.h + hueDelta) : targetHsl.h;
    const nextSat = targetHsl.s <= 0.02
      ? clamp(hsl.s * 0.18, 0, 0.18)
      : hasSourceHue
        ? clamp(hsl.s * 0.34 + targetHsl.s * 0.68, 0.08, 1)
        : clamp(targetHsl.s * 0.58, 0.08, 0.95);
    const nextLight = clamp(
      hsl.l * (0.5 + targetHsl.l * 0.64) + targetHsl.l * 0.08,
      0,
      1
    );
    const rgb = hslToRgb({ h: nextHue, s: nextSat, l: nextLight });
    pixels[index] = rgb.r;
    pixels[index + 1] = rgb.g;
    pixels[index + 2] = rgb.b;
  }

  context.putImageData(imageData, 0, 0);
  runtime.customGravelTintCache.set(cacheKey, canvas);
  return canvas;
}

function getTintedCustomGravelLayer(layer, color, options = {}) {
  return getTintedCustomGravelAsset(layer, color, {
    cacheScope: "layer",
    colorize: options.colorize,
    now: options.now
  });
}

function getTintedCustomGravelPebble(asset, color, options = {}) {
  return getTintedCustomGravelAsset(asset, color, {
    cacheScope: "pebble",
    colorize: options.colorize,
    now: options.now,
    maxDimension: CUSTOM_GRAVEL_TOP_PEBBLE_SPRITE_CACHE_SIZE
  });
}

function hasReadyCustomGravelLayers() {
  return runtime.customGravelLayerCatalog.length === CUSTOM_GRAVEL_LAYER_COUNT
    && runtime.customGravelLayerCatalog.every((layer) => Boolean(getCustomGravelLayerImage(layer).image));
}

function getCustomGravelLoosePebbleAssets() {
  return (runtime.customGravelPebbleCatalog || [])
    .filter((asset) => Boolean(getCustomGravelAssetImage(asset).image));
}

function canUseFishGravelPebblePlay() {
  return Boolean(state?.customGravelEnabled) && getCustomGravelLoosePebbleAssets().length > 0;
}

function getCustomGravelPebbleSpriteByPath(path, color, options = {}) {
  if (typeof path !== "string" || !path) {
    return null;
  }

  return getTintedCustomGravelAsset(
    { path },
    color,
    {
      cacheScope: "pebble",
      colorize: options.colorize,
      now: options.now,
      maxDimension: CUSTOM_GRAVEL_TOP_PEBBLE_SPRITE_CACHE_SIZE
    }
  );
}

function getCustomGravelTopLayerCacheKey(bounds, now = Date.now()) {
  const colors = getResolvedCustomGravelLayerColors(now).join("|");
  const colorize = getActiveCustomGravelLayerColorizeSettings().map((enabled) => (enabled ? "1" : "0")).join("|");
  const assets = getCustomGravelLoosePebbleAssets().map((asset) => asset.key).join("|");
  return [
    state.gravelSeed || 1,
    colors,
    colorize,
    assets,
    bounds.left,
    bounds.right,
    bounds.bottom,
    bounds.baseTop
  ].join("|");
}

function getCustomGravelTopLayerCanvas(bounds, now = Date.now()) {
  const pebbleAssets = getCustomGravelLoosePebbleAssets();
  if (!pebbleAssets.length) {
    return null;
  }

  const cacheKey = getCustomGravelTopLayerCacheKey(bounds, now);
  if (runtime.customGravelTopLayerCanvas && runtime.customGravelTopLayerCacheKey === cacheKey) {
    return runtime.customGravelTopLayerCanvas;
  }

  const colors = getResolvedCustomGravelLayerColors(now);
  const colorizeSettings = getActiveCustomGravelLayerColorizeSettings();
  const canvas = document.createElement("canvas");
  canvas.width = TANK_WIDTH;
  canvas.height = TANK_HEIGHT;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  const rand = mulberry32((Math.abs(Math.floor(state.gravelSeed || 1)) || 1) ^ 0x51f2e34d);
  const stamps = [];

  for (let index = 0; index < CUSTOM_GRAVEL_TOP_PEBBLE_COUNT; index += 1) {
    const asset = pebbleAssets[Math.floor(rand() * pebbleAssets.length)] || pebbleAssets[0];
    const colorIndex = Math.floor(rand() * colors.length);
    const color = colors[colorIndex] || DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR;
    const sprite = getTintedCustomGravelPebble(asset, color, {
      colorize: colorizeSettings[colorIndex],
      now
    });
    if (!sprite?.width || !sprite?.height) {
      continue;
    }

    const size = randomBetweenWith(rand, CUSTOM_GRAVEL_TOP_PEBBLE_SIZE_MIN_PX, CUSTOM_GRAVEL_TOP_PEBBLE_SIZE_MAX_PX);
    const aspect = sprite.width / Math.max(1, sprite.height);
    const drawWidth = aspect >= 1 ? size : size * aspect;
    const drawHeight = aspect >= 1 ? size / aspect : size;
    const x = randomBetweenWith(rand, bounds.left + drawWidth * 0.5, bounds.right - drawWidth * 0.5);
    const surfaceY = getTankFloorMaskSurfaceYAtX(x, bounds);
    const depthOffset = Math.pow(rand(), 1.8) * CUSTOM_GRAVEL_TOP_PEBBLE_DEPTH_PX;

    stamps.push({
      sprite,
      x,
      y: surfaceY + depthOffset,
      width: drawWidth,
      height: drawHeight,
      rotation: randomBetweenWith(rand, -Math.PI, Math.PI)
    });
  }

  stamps.sort((left, right) => left.y - right.y);
  for (const stamp of stamps) {
    context.save();
    context.translate(stamp.x, stamp.y);
    context.rotate(stamp.rotation);
    context.globalAlpha = 1;
    context.drawImage(
      stamp.sprite,
      -stamp.width * 0.5,
      -stamp.height * 0.5,
      stamp.width,
      stamp.height
    );
    context.restore();
  }

  runtime.customGravelTopLayerCanvas = canvas;
  runtime.customGravelTopLayerCacheKey = cacheKey;
  return canvas;
}

function drawCustomGravelLoosePebbles(bounds, now = Date.now()) {
  const canvas = getCustomGravelTopLayerCanvas(bounds, now);
  if (!canvas) {
    return false;
  }

  tankContext.drawImage(canvas, 0, 0);
  return true;
}

function isCustomGravelUvReactiveColor(color) {
  const normalizedColor = normalizeHexColor(color);
  if (!normalizedColor) {
    return false;
  }

  const matchedChoice = CUSTOM_GRAVEL_COLOR_OPTIONS.find((choice) => normalizeHexColor(choice.color) === normalizedColor);
  if (matchedChoice) {
    return CUSTOM_GRAVEL_UV_REACTIVE_COLOR_KEYS.has(matchedChoice.key);
  }

  const rgb = hexToRgb(normalizedColor);
  if (!rgb) {
    return false;
  }

  const hsl = rgbToHsl(rgb);
  const hue = normalizeHueUnit(hsl.h);
  const value = Math.max(rgb.r, rgb.g, rgb.b) / 255;
  if (value < 0.42) {
    return false;
  }

  if (hsl.s < 0.18) {
    return value > 0.9;
  }

  if (hue >= 0.07 && hue <= 0.14 && hsl.s < 0.62 && value < 0.92) {
    return false;
  }

  return hsl.s >= 0.34 && value >= 0.58;
}

function drawCustomGravelFloor(bounds, now = Date.now()) {
  const layerColors = getResolvedCustomGravelLayerColors(now);
  const layerColorize = getActiveCustomGravelLayerColorizeSettings();
  let drewLayer = false;

  for (let index = 0; index < runtime.customGravelLayerCatalog.length; index += 1) {
    const layer = runtime.customGravelLayerCatalog[index];
    const tintedLayer = getTintedCustomGravelLayer(
      layer,
      layerColors[index] || DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR,
      {
        colorize: layerColorize[index],
        now
      }
    );
    if (!tintedLayer) {
      continue;
    }

    drawImageCover(tankContext, tintedLayer, bounds.left, bounds.drawTop, bounds.drawWidth, bounds.drawHeight);
    if (isCustomGravelUvReactiveColor(layerColors[index])) {
      drawUvGlowImageCoverToContext(
        tankContext,
        tintedLayer,
        bounds.left,
        bounds.drawTop,
        bounds.drawWidth,
        bounds.drawHeight,
        0.52,
        0.32 + index * 0.05
      );
    }
    drewLayer = true;
  }

  return drewLayer;
}

function drawTankFloor(now = Date.now()) {
  const bounds = getTankFloorDrawBounds();

  tankContext.save();
  traceTankFloorMaskPath(tankContext, bounds);
  tankContext.clip();

  const usedCustomGravel = state.customGravelEnabled && drawCustomGravelFloor(bounds, now);
  if (!usedCustomGravel) {
    drawSelectedGravelFloorImage(bounds);
  }

  tankContext.restore();

  if (usedCustomGravel) {
    drawCustomGravelLoosePebbles(bounds, now);
  }
}

function invalidateGravelBedCache(clearTintCache = true) {
  runtime.gravelBedCacheKey = "";
  runtime.gravelBedCanvas = null;
  runtime.gravelCapCanvas = null;
  if (clearTintCache) {
    runtime.gravelTintCache.clear();
  }
}

function ensureGravelLayouts() {
  if (!runtime.scene) {
    return;
  }

  const assetKey = runtime.gravelCatalog.map((item) => item.key).join("|");
  const layoutKey = `${state.gravelSeed}|${assetKey}|${getGravelFloorLayoutKey()}`;
  const contourKey = `${state.gravelSeed}|surface`;
  if (runtime.scene.gravelSurfaceContourKey !== contourKey) {
    runtime.scene.gravelSurfaceContourKey = contourKey;
    runtime.scene.gravelSurfaceContour = buildGravelSurfaceContour(state.gravelSeed || 1);
  }
  if (runtime.scene.gravelLayoutKey === layoutKey) {
    return;
  }

  const rand = mulberry32((state.gravelSeed || 1) ^ 0x6d2b79f5);
  const spriteCount = Math.max(1, runtime.gravelCatalog.length || 1);
  const stamps = [];
  const capStamps = [];
  const floorLeft = GLASS_MARGIN_X - 28;
  const floorRight = TANK_WIDTH - GLASS_MARGIN_X + 28;

  const pushStamp = (stamp, capMultiplier = 0.92) => {
    const nextStamp = {
      ...stamp,
      sortKey: stamp.y + stamp.size * 0.24
    };
    stamps.push(nextStamp);
    const surfaceY = getTankFloorSurfaceYAtX(nextStamp.x);
    if (nextStamp.y - nextStamp.size * 0.18 <= surfaceY + GRAVEL_SURFACE_CAP_DEPTH_PX + nextStamp.size * 0.18) {
      capStamps.push({
        ...nextStamp,
        alpha: clamp(nextStamp.alpha * capMultiplier, 0.6, 1)
      });
    }
  };

  const layRowPass = ({
    rowStepPx,
    depthPx,
    startOffsetPx,
    sizeMin,
    sizeMax,
    advanceMin,
    advanceMax,
    alphaMin,
    alphaMax,
    jitterX,
    jitterY,
    stretchMin,
    stretchMax,
    capMultiplier = 0.92
  }) => {
    const rowCount = Math.max(4, Math.ceil((depthPx + 16) / rowStepPx));
    for (let rowIndex = 0; rowIndex < rowCount; rowIndex += 1) {
      const depthRatio = rowIndex / Math.max(1, rowCount - 1);
      let cursorX = floorLeft + randomBetweenWith(rand, -10, 10);
      while (cursorX < floorRight) {
        const sizeBias = 0.92 + depthRatio * 0.22;
        const size = randomBetweenWith(rand, sizeMin * sizeBias, sizeMax * sizeBias);
        const x = cursorX + size * 0.5 + randomBetweenWith(rand, -jitterX, jitterX);
        const surfaceY = getTankFloorSurfaceYAtX(x);
        const y = surfaceY + startOffsetPx + depthRatio * depthPx + randomBetweenWith(rand, -jitterY, jitterY);
        pushStamp({
          x,
          y,
          size,
          rotation: randomBetweenWith(rand, -Math.PI, Math.PI),
          alpha: randomBetweenWith(rand, alphaMin, alphaMax),
          spriteIndex: Math.floor(rand() * spriteCount),
          colorIndex: Math.floor(rand() * 3),
          variantIndex: Math.floor(rand() * GRAVEL_VARIANT_BUCKETS),
          stretchY: randomBetweenWith(rand, stretchMin, stretchMax)
        }, capMultiplier);
        cursorX += Math.max(2.8, size * randomBetweenWith(rand, advanceMin, advanceMax));
      }
    }
  };

  layRowPass({
    rowStepPx: 7,
    depthPx: GRAVEL_BED_DEPTH_PX + 18,
    startOffsetPx: 2,
    sizeMin: GRAVEL_PEBBLE_SIZE_MIN * 0.92,
    sizeMax: GRAVEL_PEBBLE_SIZE_MAX * 1.1,
    advanceMin: 0.8,
    advanceMax: 1.12,
    alphaMin: 0.88,
    alphaMax: 1,
    jitterX: 4.6,
    jitterY: 2.2,
    stretchMin: 0.84,
    stretchMax: 1.2,
    capMultiplier: 0.95
  });

  layRowPass({
    rowStepPx: 6.2,
    depthPx: GRAVEL_BED_DEPTH_PX * 0.7,
    startOffsetPx: 0.5,
    sizeMin: GRAVEL_PEBBLE_SIZE_MIN * 0.62,
    sizeMax: GRAVEL_PEBBLE_SIZE_MAX * 0.84,
    advanceMin: 0.85,
    advanceMax: 1.18,
    alphaMin: 0.78,
    alphaMax: 0.95,
    jitterX: 4.2,
    jitterY: 1.9,
    stretchMin: 0.82,
    stretchMax: 1.24,
    capMultiplier: 0.92
  });

  layRowPass({
    rowStepPx: 4.8,
    depthPx: GRAVEL_SURFACE_CAP_DEPTH_PX + 10,
    startOffsetPx: -1.2,
    sizeMin: GRAVEL_PEBBLE_SIZE_MIN * 0.42,
    sizeMax: GRAVEL_PEBBLE_SIZE_MAX * 0.68,
    advanceMin: 0.92,
    advanceMax: 1.28,
    alphaMin: 0.72,
    alphaMax: 0.9,
    jitterX: 3.1,
    jitterY: 1.35,
    stretchMin: 0.8,
    stretchMax: 1.26,
    capMultiplier: 0.88
  });

  const fillerCount = Math.max(900, Math.ceil(GRAVEL_BED_STAMP_COUNT * 0.18));
  for (let index = 0; index < fillerCount; index += 1) {
    const x = GLASS_MARGIN_X + rand() * (TANK_WIDTH - GLASS_MARGIN_X * 2);
    const surfaceY = getTankFloorSurfaceYAtX(x);
    const depthRatio = Math.pow(rand(), 1.18);
    const nearSurface = rand() < 0.55;
    const size = nearSurface
      ? randomBetweenWith(rand, GRAVEL_PEBBLE_SIZE_MIN * 0.4, GRAVEL_PEBBLE_SIZE_MAX * 0.62)
      : randomBetweenWith(rand, GRAVEL_PEBBLE_SIZE_MIN * 0.56, GRAVEL_PEBBLE_SIZE_MAX * 0.88);
    const y = surfaceY
      + (nearSurface ? randomBetweenWith(rand, -1.2, GRAVEL_SURFACE_CAP_DEPTH_PX + 6) : 5 + depthRatio * (GRAVEL_BED_DEPTH_PX + 14))
      + randomBetweenWith(rand, -1.6, 2.2);
    pushStamp({
      x: x + randomBetweenWith(rand, -7, 7),
      y,
      size,
      rotation: randomBetweenWith(rand, -Math.PI, Math.PI),
      alpha: randomBetweenWith(rand, nearSurface ? 0.72 : 0.8, nearSurface ? 0.9 : 0.96),
      spriteIndex: Math.floor(rand() * spriteCount),
      colorIndex: Math.floor(rand() * 3),
      variantIndex: Math.floor(rand() * GRAVEL_VARIANT_BUCKETS),
      stretchY: randomBetweenWith(rand, 0.82, 1.24)
    }, nearSurface ? 0.86 : 0.9);
  }

  runtime.scene.gravelLayoutKey = layoutKey;
  runtime.scene.gravelBedStamps = stamps.sort((left, right) => left.sortKey - right.sortKey);
  runtime.scene.gravelCapStamps = capStamps.sort((left, right) => left.sortKey - right.sortKey);
}

function getGravelBedCacheKey() {
  const palette = getActiveGravelPalette().join("|");
  const assets = runtime.gravelCatalog.map((item) => item.key).join("|");
  const resolution = getGravelCacheDimensions();
  return `${state.gravelSeed}|${palette}|${assets}|${resolution.width}x${resolution.height}|${getGravelFloorLayoutKey()}`;
}

function getGravelBedCanvas() {
  ensureGravelLayouts();
  const cacheKey = getGravelBedCacheKey();
  if (runtime.gravelBedCanvas && runtime.gravelCapCanvas && runtime.gravelBedCacheKey === cacheKey) {
    return runtime.gravelBedCanvas;
  }

  const resolution = getGravelCacheDimensions();
  const scaleX = resolution.width / TANK_WIDTH;
  const scaleY = resolution.height / TANK_HEIGHT;
  const canvas = document.createElement("canvas");
  canvas.width = resolution.width;
  canvas.height = resolution.height;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  context.setTransform(scaleX, 0, 0, scaleY, 0, 0);
  configureCanvasContext(context);
  renderGravelBedToCanvas(context);

  const capCanvas = document.createElement("canvas");
  capCanvas.width = resolution.width;
  capCanvas.height = resolution.height;
  const capContext = capCanvas.getContext("2d");
  if (!capContext) {
    return null;
  }

  capContext.setTransform(scaleX, 0, 0, scaleY, 0, 0);
  configureCanvasContext(capContext);
  renderGravelCapToCanvas(capContext);
  runtime.gravelBedCanvas = canvas;
  runtime.gravelCapCanvas = capCanvas;
  runtime.gravelBedCacheKey = cacheKey;
  return canvas;
}

function getGravelCapCanvas() {
  if (!getGravelBedCanvas()) {
    return null;
  }
  return runtime.gravelCapCanvas;
}

function getGravelCacheDimensions() {
  const baseWidth = Math.max(TANK_WIDTH, dom.tankCanvas?.width || 0);
  const baseHeight = Math.max(TANK_HEIGHT, dom.tankCanvas?.height || 0);
  return {
    width: Math.max(TANK_WIDTH, Math.round(baseWidth * GRAVEL_CACHE_OVERSAMPLE)),
    height: Math.max(TANK_HEIGHT, Math.round(baseHeight * GRAVEL_CACHE_OVERSAMPLE))
  };
}

function renderGravelBedToCanvas(context) {
  context.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  if (!runtime.scene?.gravelBedStamps?.length) {
    return;
  }

  context.save();
  traceTankFloorPath(context);
  context.clip();

  const palette = getActiveGravelPalette();
  for (const stamp of runtime.scene.gravelBedStamps) {
    const color = palette[stamp.colorIndex] || palette[0];
    drawGravelPebbleSprite(
      context,
      stamp.x,
      stamp.y,
      stamp.size,
      stamp.rotation,
      stamp.spriteIndex,
      color,
      stamp.alpha,
      stamp.stretchY,
      stamp.variantIndex
    );
  }

  context.restore();
}

function renderGravelCapToCanvas(context) {
  context.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  if (!runtime.scene?.gravelCapStamps?.length) {
    return;
  }

  context.save();
  traceTankFloorSurfaceBandPath(context);
  context.clip();

  const palette = getActiveGravelPalette();
  for (const stamp of runtime.scene.gravelCapStamps) {
    const color = palette[stamp.colorIndex] || palette[0];
    drawGravelPebbleSprite(
      context,
      stamp.x,
      stamp.y,
      stamp.size,
      stamp.rotation,
      stamp.spriteIndex,
      color,
      stamp.alpha,
      stamp.stretchY,
      stamp.variantIndex
    );
  }

  context.restore();
}

function drawLooseGravel(now, options = {}) {
  const { surfaceKind = null, decorLayer = null, transientOnly = false } = options;
  const loosePebbles = [];
  const draggedExistingId = runtime.pebbleDragState?.existingId || null;

  if (!transientOnly) {
    for (const pebble of state.gravelLivePebbles) {
      if (pebble.id === draggedExistingId) {
        continue;
      }
      if (surfaceKind && pebble.surfaceKind !== surfaceKind) {
        continue;
      }
      if (surfaceKind === "decor" && decorLayer !== null) {
        const decorItem = state.placedDecor.find((item) => item.id === pebble.decorId);
        if (!decorItem || getDecorTankLayer(decorItem) !== decorLayer) {
          continue;
        }
      }
      const pose = resolveLiveGravelPebblePose(pebble);
      if (!pose) {
        continue;
      }
      loosePebbles.push({ pebble, pose, alpha: 1, grounded: true });
    }
  }

  if (transientOnly) {
    for (const falling of runtime.fallingGravelPebbles) {
      loosePebbles.push({ pebble: falling.pebble, pose: getFallingGravelPebblePose(falling, now), alpha: 0.96, grounded: false });
    }

    if (runtime.pebbleDragState) {
      loosePebbles.push({
        pebble: runtime.pebbleDragState.pebble,
        pose: {
          x: runtime.pebbleDragState.pebble.xNorm * TANK_WIDTH,
          y: runtime.pebbleDragState.pebble.yNorm * TANK_HEIGHT
        },
        alpha: 0.98,
        grounded: false
      });
    }
  }

  loosePebbles
    .sort((left, right) => left.pose.y - right.pose.y)
    .forEach(({ pebble, pose, alpha, grounded }) => {
      if (grounded) {
        drawLoosePebbleGrounding(pose, pebble, alpha);
      }
      drawGravelPebbleSprite(
        tankContext,
        pose.x,
        pose.y,
        pebble.size,
        pebble.rotation,
        pebble.spriteIndex,
        getActiveGravelPalette()[pebble.colorIndex] || getActiveGravelPalette()[0],
        alpha * (pebble.alpha || 1),
        pebble.stretchY,
        pebble.variantIndex
      );
    });
}

function drawLoosePebbleGrounding(pose, pebble, alpha) {
  if (!pose || !pebble) {
    return;
  }

  const contactOpacity = pebble.surfaceKind === "decor"
    ? 0.06
    : 0.09 + (1 - clamp(pebble.liftPx / Math.max(1, GRAVEL_LIVE_LAYER_DEPTH_PX), 0, 1)) * 0.1;
  const rx = pebble.size * 0.34;
  const ry = Math.max(1.2, pebble.size * 0.14);
  const offsetY = pebble.surfaceKind === "decor" ? pebble.size * 0.12 : pebble.size * 0.16;

  tankContext.save();
  tankContext.globalAlpha = alpha * contactOpacity;
  tankContext.fillStyle = "rgba(10, 14, 18, 0.88)";
  tankContext.beginPath();
  tankContext.ellipse(pose.x, pose.y + offsetY, rx, ry, 0, 0, Math.PI * 2);
  tankContext.fill();
  tankContext.restore();
}

function drawLooseGravelCap() {
  const capCanvas = getGravelCapCanvas();
  if (!capCanvas) {
    return;
  }

  tankContext.save();
  traceTankFloorSurfaceBandPath(tankContext);
  tankContext.clip();
  tankContext.drawImage(capCanvas, 0, 0, TANK_WIDTH, TANK_HEIGHT);
  tankContext.restore();
}

function drawGravelPebbleSprite(context, x, y, size, rotation, spriteIndex, color, alpha = 1, stretchY = 1, variantIndex = 0) {
  const asset = getGravelPebbleAsset(spriteIndex);
  const tintedSprite = asset ? getTintedGravelPebbleSprite(asset.path, color, variantIndex) : null;
  if (!tintedSprite) {
    return;
  }

  const width = size;
  const height = Math.max(4, width * (tintedSprite.height / tintedSprite.width) * clamp(stretchY, 0.72, 1.32));
  context.save();
  context.translate(x, y);
  context.rotate(rotation);
  context.globalAlpha = alpha;
  context.drawImage(tintedSprite, -width / 2, -height / 2, width, height);
  context.restore();
}

function getGravelPebbleAsset(index = 0) {
  const assets = runtime.gravelCatalog;
  if (!assets.length) {
    return null;
  }

  const normalizedIndex = Number.isFinite(Number(index)) ? Math.floor(Number(index)) : 0;
  const wrappedIndex = ((normalizedIndex % assets.length) + assets.length) % assets.length;
  return assets[wrappedIndex] || assets[0];
}

function getPebbleShapeDescriptor(pebble, poseOverride = null) {
  const asset = getGravelPebbleAsset(pebble?.spriteIndex);
  if (!asset) {
    return null;
  }

  const mask = getImageAlphaMask(asset.path);
  if (!mask) {
    return null;
  }

  const pose = poseOverride || resolveLiveGravelPebblePose(pebble);
  if (!pose) {
    return null;
  }

  const width = pebble.size;
  const height = Math.max(4, width * (mask.height / mask.width) * clamp(pebble.stretchY, 0.72, 1.32));
  const rotation = pebble.rotation || 0;
  const cos = Math.cos(-rotation);
  const sin = Math.sin(-rotation);
  const worldCos = Math.cos(rotation);
  const worldSin = Math.sin(rotation);
  const localToWorld = (localX, localY) => ({
    x: pose.x + localX * worldCos - localY * worldSin,
    y: pose.y + localX * worldSin + localY * worldCos
  });
  const corners = [
    localToWorld(-width / 2, -height / 2),
    localToWorld(width / 2, -height / 2),
    localToWorld(width / 2, height / 2),
    localToWorld(-width / 2, height / 2)
  ];

  return {
    mask,
    pose,
    bounds: {
      left: Math.min(...corners.map((corner) => corner.x)),
      right: Math.max(...corners.map((corner) => corner.x)),
      top: Math.min(...corners.map((corner) => corner.y)),
      bottom: Math.max(...corners.map((corner) => corner.y))
    },
    worldToUv(worldX, worldY) {
      let localX = worldX - pose.x;
      let localY = worldY - pose.y;
      const rotatedX = localX * cos - localY * sin;
      const rotatedY = localX * sin + localY * cos;
      localX = rotatedX;
      localY = rotatedY;
      return {
        u: (localX + width / 2) / width,
        v: (localY + height / 2) / height
      };
    }
  };
}

function getTintedGravelPebbleSprite(spritePath, color, variantIndex = 0) {
  if (!spritePath) {
    return null;
  }

  const normalizedColor = normalizeHexColor(color) || DEFAULT_GRAVEL_PALETTE[0];
  const normalizedVariantIndex = clamp(Math.floor(Number(variantIndex) || 0), 0, GRAVEL_VARIANT_BUCKETS - 1);
  const cacheKey = `${spritePath}|${normalizedColor}|${normalizedVariantIndex}`;
  const cached = runtime.gravelTintCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const image = runtime.images.get(spritePath);
  if (!image?.width || !image?.height) {
    return null;
  }

  const scale = Math.min(GRAVEL_SPRITE_CACHE_SIZE / image.width, GRAVEL_SPRITE_CACHE_SIZE / image.height, 1);
  const width = Math.max(18, Math.round(image.width * scale));
  const height = Math.max(18, Math.round(image.height * scale));
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  context.clearRect(0, 0, width, height);
  context.drawImage(image, 0, 0, width, height);
  const imageData = context.getImageData(0, 0, width, height);
  const sourceStats = getPebbleSourceStats(spritePath, width, height, imageData.data);
  const targetHsl = rgbToHsl(hexToRgb(normalizedColor) || hexToRgb(DEFAULT_GRAVEL_PALETTE[0]));
  const variantCenter = (GRAVEL_VARIANT_BUCKETS - 1) / 2;
  const variantOffset = (normalizedVariantIndex - variantCenter) / Math.max(1, variantCenter);
  const targetHue = normalizeHueUnit(targetHsl.h + variantOffset * 0.022);
  const hueDelta = getHueDeltaUnit(sourceStats.avgHue, targetHue);
  const satNudge = variantOffset * 0.055;
  const lightNudge = variantOffset * 0.016;
  const pixels = imageData.data;

  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3];
    if (alpha <= 6) {
      continue;
    }

    const hsl = rgbToHsl({
      r: pixels[index],
      g: pixels[index + 1],
      b: pixels[index + 2]
    });

    let nextHue = targetHue;
    let nextSat = hsl.s;
    let nextLight = hsl.l;

    if (hsl.s > 0.035) {
      nextHue = normalizeHueUnit(hsl.h + hueDelta);
      nextSat = clamp(hsl.s * (0.96 + targetHsl.s * 0.16 + satNudge) + targetHsl.s * 0.05, 0.05, 1);
      nextLight = clamp(hsl.l * (1 + lightNudge), 0, 1);
    } else if (targetHsl.s > 0.08) {
      nextSat = clamp(hsl.s + targetHsl.s * 0.08, 0, 0.16);
    }

    const rgb = hslToRgb({ h: nextHue, s: nextSat, l: nextLight });
    pixels[index] = rgb.r;
    pixels[index + 1] = rgb.g;
    pixels[index + 2] = rgb.b;
  }

  context.putImageData(imageData, 0, 0);

  runtime.gravelTintCache.set(cacheKey, canvas);
  return canvas;
}

function getPebbleSourceStats(spritePath, width, height, sourcePixels = null) {
  const cacheKey = `${spritePath}|${width}x${height}`;
  const cached = runtime.gravelSourceStats.get(cacheKey);
  if (cached) {
    return cached;
  }

  let pixels = sourcePixels;
  if (!pixels) {
    const image = runtime.images.get(spritePath);
    if (!image?.width || !image?.height) {
      return { avgHue: 0 };
    }
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) {
      return { avgHue: 0 };
    }
    context.drawImage(image, 0, 0, width, height);
    pixels = context.getImageData(0, 0, width, height).data;
  }

  let sumX = 0;
  let sumY = 0;
  let weightTotal = 0;
  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3] / 255;
    if (alpha <= 0.03) {
      continue;
    }

    const hsl = rgbToHsl({
      r: pixels[index],
      g: pixels[index + 1],
      b: pixels[index + 2]
    });
    if (hsl.s <= 0.035) {
      continue;
    }

    const weight = alpha * (0.3 + hsl.s * 0.7) * (0.55 + Math.abs(hsl.l - 0.5));
    sumX += Math.cos(hsl.h * Math.PI * 2) * weight;
    sumY += Math.sin(hsl.h * Math.PI * 2) * weight;
    weightTotal += weight;
  }

  const stats = {
    avgHue: weightTotal > 0 ? normalizeHueUnit(Math.atan2(sumY, sumX) / (Math.PI * 2)) : 0
  };
  runtime.gravelSourceStats.set(cacheKey, stats);
  return stats;
}

function getCaveLayerSourceStats(imagePath, width, height, sourcePixels = null) {
  const cacheKey = `${imagePath}|${width}x${height}`;
  const cached = runtime.caveSourceStats.get(cacheKey);
  if (cached) {
    return cached;
  }

  let pixels = sourcePixels;
  if (!pixels) {
    const image = runtime.images.get(imagePath);
    if (!image?.width || !image?.height) {
      return { avgHue: 0 };
    }
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) {
      return { avgHue: 0 };
    }
    context.drawImage(image, 0, 0, width, height);
    pixels = context.getImageData(0, 0, width, height).data;
  }

  let sumX = 0;
  let sumY = 0;
  let weightTotal = 0;
  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3] / 255;
    if (alpha <= 0.03) {
      continue;
    }

    const hsl = rgbToHsl({
      r: pixels[index],
      g: pixels[index + 1],
      b: pixels[index + 2]
    });
    if (hsl.s <= 0.035) {
      continue;
    }

    const weight = alpha * (0.32 + hsl.s * 0.68) * (0.5 + Math.abs(hsl.l - 0.5));
    sumX += Math.cos(hsl.h * Math.PI * 2) * weight;
    sumY += Math.sin(hsl.h * Math.PI * 2) * weight;
    weightTotal += weight;
  }

  const stats = {
    avgHue: weightTotal > 0 ? normalizeHueUnit(Math.atan2(sumY, sumX) / (Math.PI * 2)) : 0
  };
  runtime.caveSourceStats.set(cacheKey, stats);
  return stats;
}

function getTintedCaveLayerImage(imagePath, color, options = {}) {
  const normalizedColor = normalizeHexColor(color);
  if (!imagePath || !normalizedColor) {
    return runtime.images.get(imagePath) || null;
  }

  const colorize = options.colorize === true;
  const cacheKey = `${imagePath}|${normalizedColor}|${colorize ? "colorize" : "hue"}`;
  const cached = runtime.caveTintCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const image = runtime.images.get(imagePath);
  if (!image?.width || !image?.height) {
    return null;
  }

  const width = Math.max(1, Math.round(Number(image.naturalWidth || image.width) || 1));
  const height = Math.max(1, Math.round(Number(image.naturalHeight || image.height) || 1));
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  context.clearRect(0, 0, width, height);
  context.drawImage(image, 0, 0, width, height);
  const imageData = context.getImageData(0, 0, width, height);
  const pixels = imageData.data;
  const targetRgb = hexToRgb(normalizedColor) || hexToRgb(DEFAULT_CUSTOM_GRAVEL_LAYER_COLOR);
  const targetHsl = rgbToHsl(targetRgb);
  const sourceStats = getCaveLayerSourceStats(imagePath, width, height, pixels);
  const hueDelta = getHueDeltaUnit(sourceStats.avgHue, targetHsl.h);

  for (let index = 0; index < pixels.length; index += 4) {
    const alpha = pixels[index + 3];
    if (alpha <= 6) {
      continue;
    }

    const hsl = rgbToHsl({
      r: pixels[index],
      g: pixels[index + 1],
      b: pixels[index + 2]
    });
    if (colorize) {
      const luminance = (pixels[index] * 0.299 + pixels[index + 1] * 0.587 + pixels[index + 2] * 0.114) / 255;
      const shade = Math.pow(luminance, 0.92);
      pixels[index] = Math.round(targetRgb.r * shade);
      pixels[index + 1] = Math.round(targetRgb.g * shade);
      pixels[index + 2] = Math.round(targetRgb.b * shade);
      continue;
    }

    const hasSourceHue = hsl.s > 0.035;
    const nextHue = hasSourceHue ? normalizeHueUnit(hsl.h + hueDelta) : targetHsl.h;
    const nextSat = targetHsl.s <= 0.02
      ? clamp(hsl.s * 0.18, 0, 0.18)
      : hasSourceHue
        ? clamp(hsl.s * 0.34 + targetHsl.s * 0.72, 0.08, 1)
        : clamp(targetHsl.s * 0.58, 0.08, 0.95);
    const nextLight = clamp(
      hsl.l * (0.48 + targetHsl.l * 0.72) + targetHsl.l * 0.08,
      0,
      1
    );
    const rgb = hslToRgb({ h: nextHue, s: nextSat, l: nextLight });
    pixels[index] = rgb.r;
    pixels[index + 1] = rgb.g;
    pixels[index + 2] = rgb.b;
  }

  context.putImageData(imageData, 0, 0);
  runtime.caveTintCache.set(cacheKey, canvas);
  return canvas;
}

function drawDecorColorLayerImageToContext(context, sourceImage, imagePath, colorSetting, colorizeSetting, drawX, drawY, width, height, item, now, motion, alpha = 1) {
  if (!sourceImage) {
    return false;
  }

  const normalizedSetting = normalizeDecorColorSetting(colorSetting);
  const colorize = normalizeDecorColorizeSetting(colorizeSetting);
  if (isDecorRgbColorSetting(normalizedSetting)) {
    if ("filter" in context) {
      context.save();
      context.filter = colorize ? getDecorRgbColorizeFilter(now) : getDecorRgbCycleFilter(now);
      drawDecorImageLayerToContext(context, sourceImage, drawX, drawY, width, height, item, now, motion, alpha);
      context.restore();
      return true;
    }

    const fallbackImage = getTintedCaveLayerImage(imagePath, getDecorRgbCycleColor(now), { colorize }) || sourceImage;
    drawDecorImageLayerToContext(context, fallbackImage, drawX, drawY, width, height, item, now, motion, alpha);
    return true;
  }

  const image = getTintedCaveLayerImage(imagePath, normalizedSetting, { colorize }) || sourceImage;
  drawDecorImageLayerToContext(context, image, drawX, drawY, width, height, item, now, motion, alpha);
  return true;
}

function decorKeyHasTag(item, tag) {
  return String(item?.decorKey || "").toLowerCase().includes(String(tag || "").toLowerCase());
}

function getDecorWarpSliceCount(height) {
  return clamp(
    Math.round(Math.max(1, Number(height) || 1) / DECOR_WARP_SLICE_TARGET_PX),
    DECOR_WARP_MIN_SLICES,
    DECOR_WARP_MAX_SLICES
  );
}

function normalizeDecorWarpOffset(offset) {
  return {
    x: Number.isFinite(Number(offset?.x)) ? Number(offset.x) : 0,
    y: Number.isFinite(Number(offset?.y)) ? Number(offset.y) : 0
  };
}

function drawWarpedImageBandsToContext(context, image, drawX, drawY, width, height, sliceCount, getOffsetAt) {
  const sourceWidth = Math.max(1, Number(image.naturalWidth || image.width) || 1);
  const sourceHeight = Math.max(1, Number(image.naturalHeight || image.height) || 1);
  const sliceHeight = height / sliceCount;
  const sourceSliceHeight = sourceHeight / sliceCount;
  const overlap = Math.min(Math.max(0.35, DECOR_WARP_SLICE_OVERLAP_PX), Math.max(0.35, sliceHeight * 0.9));
  const sourceOverlap = overlap * (sourceHeight / Math.max(1, height));

  for (let i = 0; i < sliceCount; i += 1) {
    const t0 = i / sliceCount;
    const t1 = (i + 1) / sliceCount;
    const srcY = t0 * sourceHeight;
    const srcH = Math.min(sourceHeight - srcY, sourceSliceHeight + sourceOverlap);
    const topOffset = normalizeDecorWarpOffset(getOffsetAt(t0));
    const bottomOffset = normalizeDecorWarpOffset(getOffsetAt(t1));
    const slopeX = (bottomOffset.x - topOffset.x) / Math.max(1, sliceHeight);
    const destY = i * sliceHeight;

    context.save();
    context.transform(1, 0, slopeX, 1, drawX + topOffset.x, drawY + destY + topOffset.y);
    context.drawImage(
      image,
      0,
      srcY,
      sourceWidth,
      srcH,
      0,
      0,
      width,
      sliceHeight + overlap
    );
    context.restore();
  }
}

function drawDecorWarpedToContext(context, image, drawX, drawY, width, height, item, now, motion = null) {
  const resolvedMotion = motion || getDecorMotion(item, now);
  const sliceCount = getDecorWarpSliceCount(height);
  drawWarpedImageBandsToContext(
    context,
    image,
    drawX,
    drawY,
    width,
    height,
    sliceCount,
    (t) => getDecorSliceOffset(item, now, t, resolvedMotion)
  );
}

function drawDecorWarped(image, drawX, drawY, width, height, item, now, motion = null) {
  drawDecorWarpedToContext(tankContext, image, drawX, drawY, width, height, item, now, motion);
}

function drawDecorMotionImageToContext(context, image, drawX, drawY, width, height, item, now, resolvedMotion) {
  if (resolvedMotion.customMotionType) {
    drawCustomDecorMotionImageLayerToContext(context, image, drawX, drawY, width, height, now, resolvedMotion);
  } else if (resolvedMotion.isFloating || resolvedMotion.isSeaweed || resolvedMotion.isLure) {
    drawDecorWarpedToContext(context, image, drawX, drawY, width, height, item, now, resolvedMotion);
  } else {
    context.drawImage(image, drawX, drawY, width, height);
  }
}

function drawDecorImageLayerToContext(context, image, drawX, drawY, width, height, item, now, motion = null, alpha = 1) {
  if (!image) {
    return;
  }

  const resolvedMotion = motion || getDecorMotion(item, now);
  context.save();
  context.globalAlpha = clamp(alpha, 0, 1);
  if (isDecorHorizontallyFlipped(item)) {
    context.translate(drawX + width, 0);
    context.scale(-1, 1);
    drawX = 0;
  }
  drawDecorMotionImageToContext(context, image, drawX, drawY, width, height, item, now, resolvedMotion);
  drawUvGlowDecorImageToContext(context, image, drawX, drawY, width, height, item, now, resolvedMotion, getDecorUvGlowIntensity(item), alpha);
  context.restore();
}

function getCustomDecorMotionOffsetAt(t, now, resolvedMotion, motionConfig, width) {
  const hasBob = Boolean(motionConfig.hasBob);
  const bobX = hasBob ? resolvedMotion.bobX : 0;
  const bobY = hasBob ? resolvedMotion.bobY : 0;
  const splitY = sanitizeCustomDecorMotionSplit(resolvedMotion.customMotionSplitY);
  const swaySide = normalizeDecorSwaySide(resolvedMotion.customMotionSwaySide);
  const swayIntensity = sanitizeCustomDecorMotionIntensity(resolvedMotion.customMotionIntensity);
  const swayProgress = getDecorSwaySliceProgress(t, splitY, swaySide);
  const seaweedLike = motionConfig.id === "standard-seaweed" || motionConfig.id === "floating-seaweed";
  const swayAmplitude = (seaweedLike
    ? clamp(width * 0.045, 2.4, 15)
    : clamp(width * 0.028, 1.8, 9)) * swayIntensity;

  if (swayProgress <= 0) {
    return hasBob ? { x: bobX, y: bobY } : { x: 0, y: 0 };
  }

  const speed = sanitizeDecorMotionSpeed(resolvedMotion.swaySpeed);
  const strength = Math.pow(swayProgress, seaweedLike ? 1.15 : 1.35);
  const phase = resolvedMotion.phase;
  const primaryWave = Math.sin((now / (seaweedLike ? 1040 : 1180)) * speed + phase + swayProgress * 2.6);
  const secondaryWave = Math.sin((now / 1680) * speed + phase * 1.33 + swayProgress * 4.1) * 0.35;
  const offsetY = motionConfig.id === "suspended-static"
    ? Math.sin((now / 1260) * speed + phase + swayProgress * 1.8) * 0.45 * swayIntensity * strength
    : 0;

  return {
    x: bobX + (primaryWave + secondaryWave) * swayAmplitude * strength,
    y: bobY + offsetY
  };
}

function drawCustomDecorMotionImageLayerToContext(context, image, drawX, drawY, width, height, now, resolvedMotion) {
  const motionConfig = getCustomDecorMotionTypeConfig(resolvedMotion.customMotionType);
  const hasBob = Boolean(motionConfig.hasBob);
  const hasSway = Boolean(motionConfig.hasSway);
  const bobX = hasBob ? resolvedMotion.bobX : 0;
  const bobY = hasBob ? resolvedMotion.bobY : 0;

  if (!hasSway) {
    context.drawImage(image, drawX + bobX, drawY + bobY, width, height);
    return;
  }

  drawWarpedImageBandsToContext(
    context,
    image,
    drawX,
    drawY,
    width,
    height,
    getDecorWarpSliceCount(height),
    (t) => getCustomDecorMotionOffsetAt(t, now, resolvedMotion, motionConfig, width)
  );
}

function drawCustomDecorMotionImageLayer(image, drawX, drawY, width, height, item, now, motion = null) {
  const resolvedMotion = motion || getDecorMotion(item, now);
  drawCustomDecorMotionImageLayerToContext(tankContext, image, drawX, drawY, width, height, now, resolvedMotion);
}

function getDecorSliceOffset(item, now, t, motion = null) {
  const resolvedMotion = motion || getDecorMotion(item, now);
  const motionPhase = resolvedMotion.phase;
  let offsetX = 0;
  let offsetY = 0;

  const phase = resolvedMotion.phase;
  const swayProgress = getDecorSwaySliceProgress(t, resolvedMotion.swaySplitY, resolvedMotion.swaySide);

  if (resolvedMotion.isSeaweed && !resolvedMotion.isFloating && swayProgress > 0) {
    const strength = swayProgress * swayProgress;
    offsetX += Math.sin(now / (860 / resolvedMotion.swaySpeed) + phase) * 5.5 * resolvedMotion.swayIntensity * strength;
  }

  if ((resolvedMotion.isFloating || resolvedMotion.isLure) && swayProgress > 0) {
    const strength = swayProgress * swayProgress;
    const baseAmplitude = resolvedMotion.isLure ? 1.5 : 2.4;
    offsetX += Math.sin(now / (1080 / resolvedMotion.swaySpeed) + phase * 1.15) * baseAmplitude * resolvedMotion.swayIntensity * strength;
  }

  offsetX += (resolvedMotion.isFloating || resolvedMotion.isLure) ? resolvedMotion.bobX : 0;
  offsetY += (resolvedMotion.isFloating || resolvedMotion.isLure) ? resolvedMotion.bobY : 0;
  return { x: offsetX, y: offsetY };
}

function getDecorMotion(item, now) {
  const key = String(item?.decorKey || "").toLowerCase();
  const phase = item.xNorm * 11.73 + item.yNorm * 7.19;
  const decor = runtime.decorMap.get(item?.decorKey);
  const capabilities = getDecorMotionCapabilities(item);
  const motionSettings = getPlacedDecorMotionSettings(item);
  const customMotionType = isCustomDecorAssetKey(item?.decorKey)
    ? normalizeCustomDecorMotionType(decor?.motionType)
    : "";
  const customMotionConfig = customMotionType ? getCustomDecorMotionTypeConfig(customMotionType) : null;
  const isFloating = Boolean(capabilities.hasBob);
  const isSeaweed = Boolean(capabilities.hasSway);
  const customMotionIntensity = motionSettings.swayIntensity;
  const isLure = capabilities.isLure || key.includes("lure");
  const lureBobX = isLure
    ? (Math.sin(now / (980 / motionSettings.bobSpeed) + phase * 0.85) * 2.1 + Math.sin(now / (1630 / motionSettings.bobSpeed) + phase * 1.4) * 0.7) * motionSettings.bobIntensity
    : 0;
  const lureBobY = isLure
    ? (Math.sin(now / (790 / motionSettings.bobSpeed) + phase) * 2.2 + Math.cos(now / (1280 / motionSettings.bobSpeed) + phase * 0.7) * 0.85) * motionSettings.bobIntensity
    : 0;

  return {
    isFloating,
    isSeaweed,
    isLure,
    customMotionType,
    customMotionSplitY: customMotionConfig ? motionSettings.swaySplitY : DEFAULT_CUSTOM_DECOR_MOTION_SPLIT_Y,
    customMotionSwaySide: motionSettings.swaySide,
    customMotionIntensity,
    swaySplitY: motionSettings.swaySplitY,
    swaySide: motionSettings.swaySide,
    swayIntensity: motionSettings.swayIntensity,
    bobIntensity: motionSettings.bobIntensity,
    swaySpeed: motionSettings.swaySpeed,
    bobSpeed: motionSettings.bobSpeed,
    phase,
    bobX: isLure ? lureBobX : isFloating ? Math.sin(now / (980 / motionSettings.bobSpeed) + phase * 0.85) * 0.8 * motionSettings.bobIntensity : 0,
    bobY: isLure ? lureBobY : isFloating ? Math.sin(now / (760 / motionSettings.bobSpeed) + phase) * 1.4 * motionSettings.bobIntensity : 0
  };
}

function getFishShadowLayerPlaneY(fish) {
  const layer = getFishTankLayer(fish);
  const floorY = getTankFloorSurfaceYAtX((fish?.xNorm || 0.5) * TANK_WIDTH) + 7;
  return clamp(
    getTankLayerBottomBoundaryY(layer),
    WATER_SURFACE_Y + getViewportPxAsTankVirtual(24),
    floorY
  );
}

function getSmoothedFishShadowPlaneY(fish, targetPlaneY, now = Date.now()) {
  if (!fish?.id || !Number.isFinite(targetPlaneY)) {
    return targetPlaneY;
  }

  const previous = runtime.fishShadowPlaneCache.get(fish.id);
  if (!previous || !Number.isFinite(previous.y) || !Number.isFinite(previous.updatedAt)) {
    runtime.fishShadowPlaneCache.set(fish.id, { y: targetPlaneY, updatedAt: now });
    return targetPlaneY;
  }

  const elapsedMs = clamp(now - previous.updatedAt, 0, 1000);
  const ease = 1 - Math.exp(-elapsedMs / FISH_SHADOW_LAYER_EASE_MS);
  const y = previous.y + (targetPlaneY - previous.y) * ease;
  runtime.fishShadowPlaneCache.set(fish.id, { y, updatedAt: now });
  return y;
}

function pruneFishShadowPlaneCache() {
  if (!runtime.fishShadowPlaneCache.size) {
    return;
  }

  const activeFishIds = new Set((state?.fish || []).map((fish) => fish?.id).filter(Boolean));
  for (const fishId of runtime.fishShadowPlaneCache.keys()) {
    if (!activeFishIds.has(fishId)) {
      runtime.fishShadowPlaneCache.delete(fishId);
    }
  }
}

function drawGroundShadows(now) {
  shadowContext.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  shadowContext.save();
  traceTankFloorPath(shadowContext);
  shadowContext.clip();

  const decorShadowItems = [...state.placedDecor].sort((left, right) => left.yNorm - right.yNorm);
  for (const item of decorShadowItems) {
    const decor = runtime.decorMap.get(item.decorKey);
    const image = decor ? runtime.images.get(decor.path) : null;
    if (!decor || !image) {
      continue;
    }

    const width = getDecorDisplayWidth(decor, item);
    const height = width * (image.height / image.width);
    const motion = getDecorMotion(item, now);
    const x = item.xNorm * TANK_WIDTH + ((motion.isFloating || motion.isLure) ? motion.bobX : 0);
    const y = item.yNorm * TANK_HEIGHT + ((motion.isFloating || motion.isLure) ? motion.bobY : 0);
    drawProjectedShadow(shadowContext, x, y, width, height, 0.18, 0.24);
  }
  shadowContext.restore();

  shadowContext.save();
  shadowContext.beginPath();
  shadowContext.rect(
    GLASS_MARGIN_X,
    WATER_SURFACE_Y,
    TANK_WIDTH - GLASS_MARGIN_X * 2,
    getVisibleTankFloorBottomY() - WATER_SURFACE_Y + getViewportPxAsTankVirtual(12)
  );
  shadowContext.clip();
  pruneFishShadowPlaneCache();
  const fishShadowItems = [...state.fish].sort((left, right) => left.yNorm - right.yNorm);
  for (const fish of fishShadowItems) {
    const species = getSpeciesForFish(fish);
    const image = species ? runtime.images.get(getFishDisplayAssetPath(fish, species, now) || species.asset) : null;
    if (!species || !image || getEffectiveFishBehavior(fish, species) === "sucker") {
      continue;
    }

    const pose = getFishPose(fish, species, now);
    const width = getFishDisplayWidth(fish, species, now);
    const height = width * (image.height / image.width);
    const shadowPlaneY = getSmoothedFishShadowPlaneY(fish, getFishShadowLayerPlaneY(fish), now);
    drawFishProjectedShadow(
      shadowContext,
      pose.x,
      pose.y + height * 0.14,
      width,
      height,
      0.15,
      species.shadowScale || 0.28,
      shadowPlaneY
    );
  }
  shadowContext.restore();

  tankContext.save();
  tankContext.globalCompositeOperation = "multiply";
  tankContext.drawImage(runtime.shadowCanvas, 0, 0);
  tankContext.restore();
}

function drawProjectedShadow(context, x, objectBottomY, width, height, opacity, widthScale) {
  const floorY = getTankFloorSurfaceYAtX(x) + 8;
  const heightAboveFloor = Math.max(0, floorY - objectBottomY);
  const shadowWidth = Math.max(16, width * (widthScale + Math.min(0.12, heightAboveFloor / 640)));
  const shadowHeight = Math.max(8, shadowWidth * 0.18);
  const offsetX = 12 + Math.min(30, heightAboveFloor * 0.08);
  const alpha = clamp(opacity - heightAboveFloor / 1500, 0.05, opacity);
  // context.fillStyle = `rgba(6, 15, 24, ${alpha.toFixed(3)})`;
  // context.beginPath();
  // context.ellipse(x + offsetX, floorY, shadowWidth, shadowHeight, -0.08, 0, Math.PI * 2);
  // context.fill();
}

function drawFishProjectedShadow(context, x, objectBottomY, width, height, opacity, widthScale, planeY = null) {
  const floorY = Number.isFinite(planeY) ? planeY : getTankFloorSurfaceYAtX(x) + 7;
  const heightAboveFloor = Math.max(0, floorY - objectBottomY);
  const baseWidth = width * clamp(widthScale, 0.14, 0.3) * 0.82;
  const altitudeStretch = Math.min(width * 0.04, heightAboveFloor * 0.022);
  const shadowWidth = clamp(baseWidth + altitudeStretch, 12, Math.max(26, width * 0.3));
  const shadowHeight = Math.max(5, shadowWidth * 0.14);
  const offsetX = 8 + Math.min(18, heightAboveFloor * 0.045);
  const alpha = clamp(opacity - heightAboveFloor / 1800, 0.04, opacity * 0.92);
  context.fillStyle = `rgba(6, 15, 24, ${alpha.toFixed(3)})`;
  context.beginPath();
  context.ellipse(x + offsetX, floorY, shadowWidth, shadowHeight, -0.08, 0, Math.PI * 2);
  context.fill();
}

function drawDecorImageLayer(image, drawX, drawY, width, height, item, now, motion = null, alpha = 1) {
  drawDecorImageLayerToContext(tankContext, image, drawX, drawY, width, height, item, now, motion, alpha);
}

function drawCaveBackgroundLayerToContext(context, item, decor, now, options = {}) {
  const bgImage = decor?.bgPath ? runtime.images.get(decor.bgPath) : null;
  if (!bgImage) {
    return false;
  }

  const width = Number.isFinite(Number(options.width)) ? Number(options.width) : getDecorDisplayWidth(decor, item);
  const baseImage = runtime.images.get(decor.path);
  const baseHeight = Number.isFinite(Number(options.baseHeight))
    ? Number(options.baseHeight)
    : width * ((baseImage?.height || 1) / Math.max(1, baseImage?.width || 1));
  const bgHeight = width * (bgImage.height / Math.max(1, bgImage.width));
  const drawX = Number.isFinite(Number(options.drawX)) ? Number(options.drawX) : (item.xNorm * TANK_WIDTH - width / 2);
  const drawY = Number.isFinite(Number(options.bgDrawY))
    ? Number(options.bgDrawY)
    : Number.isFinite(Number(options.drawY))
      ? Number(options.drawY) + (baseHeight - bgHeight)
      : (item.yNorm * TANK_HEIGHT - bgHeight);
  const motion = options.motion || getDecorMotion(item, now);
  const alpha = Number.isFinite(Number(options.alpha)) ? options.alpha : 1;
  const settings = hasDecorCaveColorLayers(decor) ? getPlacedCaveColorSettings(item, decor) : {};
  const colorizeSettings = hasDecorCaveColorLayers(decor) ? getPlacedCaveColorizeSettings(item, decor) : {};
  drawDecorColorLayerImageToContext(context, bgImage, decor.bgPath, settings.color1, colorizeSettings.color1, drawX, drawY, width, bgHeight, item, now, motion, alpha);
  return true;
}

function drawCaveColorLayersToContext(context, item, decor, now, options = {}) {
  const layers = getVisibleDecorColorLayers(decor);
  if (!layers.length) {
    return false;
  }

  const width = Number.isFinite(Number(options.width)) ? Number(options.width) : getDecorDisplayWidth(decor, item);
  const baseImage = runtime.images.get(decor.path);
  const height = Number.isFinite(Number(options.height))
    ? Number(options.height)
    : width * ((baseImage?.height || 1) / Math.max(1, baseImage?.width || 1));
  const drawX = Number.isFinite(Number(options.drawX)) ? Number(options.drawX) : (item.xNorm * TANK_WIDTH - width / 2);
  const drawY = Number.isFinite(Number(options.drawY)) ? Number(options.drawY) : (item.yNorm * TANK_HEIGHT - height);
  const motion = options.motion || getDecorMotion(item, now);
  const alpha = Number.isFinite(Number(options.alpha)) ? options.alpha : 1;
  const settings = getPlacedCaveColorSettings(item, decor);
  const colorizeSettings = getPlacedCaveColorizeSettings(item, decor);
  let drewLayer = false;

  for (const layer of layers) {
    const layerPath = resolveDecorColorLayerPath(layer);
    const layerImage = runtime.images.get(layerPath);
    if (!layerImage) {
      continue;
    }

    drawDecorColorLayerImageToContext(context, layerImage, layerPath, settings[layer.id], colorizeSettings[layer.id], drawX, drawY, width, height, item, now, motion, alpha);
    drewLayer = true;
  }

  return drewLayer;
}

function getDecorSameLayerRenderPriority(item) {
  return canConfigureDecorBubbler(item) ? 1 : 0;
}

function comparePlacedDecorDrawOrder(left, right) {
  const priorityDelta = getDecorSameLayerRenderPriority(left) - getDecorSameLayerRenderPriority(right);
  if (priorityDelta) {
    return priorityDelta;
  }

  return left.yNorm - right.yNorm;
}

function comparePlacedDecorHitOrder(left, right) {
  const layerDelta = getDecorTankLayer(left) - getDecorTankLayer(right);
  if (layerDelta) {
    return layerDelta;
  }

  const priorityDelta = getDecorSameLayerRenderPriority(right) - getDecorSameLayerRenderPriority(left);
  if (priorityDelta) {
    return priorityDelta;
  }

  return right.yNorm - left.yNorm;
}

function drawDecor(layer = null, now = Date.now()) {
  const sorted = [...state.placedDecor]
    .filter((item) => {
      if (layer === null) {
        return true;
      }

      const span = getDecorLayerSpan(item.decorKey, getDecorTankLayer(item));
      return layer >= span.min && layer <= span.max;
    })
    .sort(comparePlacedDecorDrawOrder);

  for (const item of sorted) {
    const decor = runtime.decorMap.get(item.decorKey);
    if (!decor) {
      continue;
    }

    const span = getDecorLayerSpan(item.decorKey, getDecorTankLayer(item));

    let imagePath = decor.path;

    if (isCaveDecorKey(item.decorKey)) {
      if (layer === span.back && decor.bgPath) {
        imagePath = decor.bgPath;
      } else if (layer === span.front) {
        imagePath = decor.path;
      } else {
        continue;
      }
    } else if (layer !== null && layer !== span.front) {
      continue;
    }

    const image = runtime.images.get(imagePath);
    if (!image) {
      continue;
    }

    const width = getDecorDisplayWidth(decor, item);
    const height = width * (image.height / image.width);
    const x = item.xNorm * TANK_WIDTH;
    const y = item.yNorm * TANK_HEIGHT;
    const drawX = x - width / 2;
    const drawY = y - height;
    const motion = getDecorMotion(item, now);
    if (layer === span.front && decor.bubbler) {
      const bgImage = decor.bgPath ? runtime.images.get(decor.bgPath) : null;
      if (bgImage) {
        const bgHeight = width * (bgImage.height / bgImage.width);
        drawDecorImageLayer(bgImage, drawX, y - bgHeight, width, bgHeight, item, now, motion);
      }
      drawDecorBubblerEffect(item, decor, image, now);
      if (!isCustomBubblerDecorKey(item.decorKey) || runtime.editTankMode) {
        if (!drawCaveColorLayersToContext(tankContext, item, decor, now, {
          drawX,
          drawY,
          width,
          height,
          motion
        })) {
          drawDecorImageLayer(image, drawX, drawY, width, height, item, now, motion);
        }
      }
      continue;
    }

    if (layer === span.back && hasDecorCaveColorLayers(decor)) {
      const bgHeight = width * (image.height / Math.max(1, image.width));
      if (drawCaveBackgroundLayerToContext(tankContext, item, decor, now, {
        drawX,
        bgDrawY: y - bgHeight,
        width,
        baseHeight: height,
        motion
      })) {
        continue;
      }
    }

    if (layer === span.front && hasDecorCaveColorLayers(decor)) {
      if (drawCaveColorLayersToContext(tankContext, item, decor, now, {
        drawX,
        drawY,
        width,
        height,
        motion
      })) {
        continue;
      }
    }

    drawDecorImageLayer(image, drawX, drawY, width, height, item, now, motion);
  }
}

function drawDecorPreview() {
  if (!runtime.placementMode || runtime.dragState || !runtime.placementPreview) {
    return;
  }

  const decor = runtime.decorMap.get(runtime.placementMode.decorKey);
  if (!decor) {
    return;
  }

  const image = runtime.images.get(decor.path);
  if (!image) {
    return;
  }

  const width = getDecorDisplayWidth(decor, Number(runtime.placementMode.scale) || getDecorScaleDefault(decor.key));
  const height = width * (image.height / image.width);
  const x = runtime.placementPreview.xNorm * TANK_WIDTH;
  const y = runtime.placementPreview.yNorm * TANK_HEIGHT;
  const previewLayer = runtime.placementMode.tankLayer || runtime.decorPlacementLayer;

  tankContext.save();
  tankContext.globalAlpha = 0.72;
  tankContext.fillStyle = "rgba(120, 215, 235, 0.18)";
  tankContext.beginPath();
  tankContext.ellipse(x, y + 3, width * 0.34, Math.max(10, width * 0.08), 0, 0, Math.PI * 2);
  tankContext.fill();
  const previewItem = {
    id: "placement-preview",
    decorKey: decor.key,
    xNorm: runtime.placementPreview.xNorm,
    yNorm: runtime.placementPreview.yNorm,
    scale: Number(runtime.placementMode.scale) || getDecorScaleDefault(decor.key),
    tankLayer: previewLayer,
    flipped: Boolean(runtime.placementMode.flipped)
  };
  const previewMotion = getDecorMotion(previewItem, Date.now());
  if ((decor.bubbler || isCaveDecorKey(decor.key) || hasDecorCaveColorLayers(decor)) && decor.bgPath) {
    if (hasDecorCaveColorLayers(decor)) {
      drawCaveBackgroundLayerToContext(tankContext, previewItem, decor, Date.now(), {
        drawX: x - width / 2,
        drawY: y - height,
        width,
        baseHeight: height,
        motion: previewMotion,
        alpha: 0.72
      });
    } else {
      const bgImage = runtime.images.get(decor.bgPath);
      if (bgImage) {
      const bgHeight = width * (bgImage.height / bgImage.width);
      drawDecorImageLayer(bgImage, x - width / 2, y - bgHeight, width, bgHeight, previewItem, Date.now(), previewMotion, 0.72);
      }
    }
  }
  if (decor.bubbler) {
    drawDecorBubblerEffect(
      previewItem,
      decor,
      image,
      Date.now(),
      { alphaScale: 0.72 }
    );
  }
  if (hasDecorCaveColorLayers(decor)) {
    drawCaveColorLayersToContext(tankContext, previewItem, decor, Date.now(), {
      drawX: x - width / 2,
      drawY: y - height,
      width,
      height,
      motion: previewMotion,
      alpha: 0.72
    });
    tankContext.restore();
    return;
  }
  drawDecorImageLayer(image, x - width / 2, y - height, width, height, previewItem, Date.now(), previewMotion, 0.72);
  tankContext.restore();
}

function shouldShowDecorSwimGuide() {
  return Boolean(runtime.editTankMode && (runtime.placementMode || runtime.dragState));
}

function getFishMaxSwimGuideY(now = Date.now()) {
  const activeDecorTarget = getActiveDecorShortcutTarget();
  if (activeDecorTarget?.mode === "placement" && runtime.placementMode) {
    return getTankLayerBottomBoundaryY(runtime.placementMode.tankLayer || runtime.decorPlacementLayer);
  }
  if (activeDecorTarget?.item) {
    return getTankLayerBottomBoundaryY(getDecorTankLayer(activeDecorTarget.item));
  }

  if (!state?.fish?.length) {
    return null;
  }

  let guideY = null;
  for (const fish of state.fish) {
    if (!fish || isFishDead(fish)) {
      continue;
    }

    const species = getSpeciesForFish(fish);
    if (!species || species.behavior === "sucker") {
      continue;
    }

    const maxCenterYNorm = species.behavior === "shrimp" ? 0.82 : 0.8;
    const footprint = getFishFootprintBoundsAtPose(
      fish,
      species,
      now,
      {
        x: TANK_WIDTH * 0.5,
        y: maxCenterYNorm * TANK_HEIGHT,
        swayX: 0
      }
    );
    if (!footprint) {
      continue;
    }

    guideY = guideY === null ? footprint.bottom : Math.max(guideY, footprint.bottom);
  }

  return guideY;
}

function drawDecorSwimGuide(now = Date.now()) {
  if (!shouldShowDecorSwimGuide()) {
    return;
  }

  const guideY = getFishMaxSwimGuideY(now);
  if (!Number.isFinite(guideY)) {
    return;
  }

  const shellBounds = getTankShellBounds();
  const startX = shellBounds.innerLeft + 18;
  const endX = shellBounds.innerLeft + shellBounds.innerWidth - 18;
  const clampedGuideY = clamp(guideY, shellBounds.innerTop + 18, shellBounds.innerTop + shellBounds.innerHeight - 6);

  tankContext.save();
  tankContext.lineWidth = 3;
  tankContext.setLineDash([14, 10]);
  tankContext.strokeStyle = "rgba(255, 72, 72, 0.72)";
  tankContext.shadowColor = "rgba(255, 72, 72, 0.24)";
  tankContext.shadowBlur = 8;
  tankContext.beginPath();
  tankContext.moveTo(startX, clampedGuideY);
  tankContext.lineTo(endX, clampedGuideY);
  tankContext.stroke();
  tankContext.setLineDash([]);
  tankContext.restore();
}

function drawActiveDecorLayerCue() {
  const selectedDecor = runtime.editTankMode ? getSelectedPlacedDecor() : null;
  if (runtime.editTankMode) {
    const selectedItems = getSelectedPlacedDecorItems();
    for (const item of selectedItems) {
      drawSelectedDecorHighlight(item);
    }
  }

  if (runtime.placementMode && runtime.placementPreview && !runtime.dragState) {
    const decor = runtime.decorMap.get(runtime.placementMode.decorKey);
    const image = decor ? runtime.images.get(decor.path) : null;
    if (decor && image) {
      const width = getDecorDisplayWidth(decor, Number(runtime.placementMode.scale) || getDecorScaleDefault(decor.key));
      const height = width * (image.height / image.width);
      drawDecorLayerBadge(
        runtime.placementPreview.xNorm * TANK_WIDTH,
        runtime.placementPreview.yNorm * TANK_HEIGHT - height - 16,
        runtime.placementMode.tankLayer || runtime.decorPlacementLayer,
        runtime.placementMode.decorKey
      );
    }
  }

  if (runtime.dragState) {
    const item = state.placedDecor.find((entry) => entry.id === runtime.dragState.placedId);
    const decor = item ? runtime.decorMap.get(item.decorKey) : null;
    const image = decor ? runtime.images.get(decor.path) : null;
    if (item && decor && image) {
      const width = getDecorDisplayWidth(decor, item);
      const height = width * (image.height / image.width);
      drawDecorLayerBadge(
        item.xNorm * TANK_WIDTH,
        item.yNorm * TANK_HEIGHT - height - 16,
        runtime.dragState.tankLayer ?? item.tankLayer ?? DEFAULT_TANK_LAYER,
        item.decorKey
      );
    }
    return;
  }

  if (selectedDecor) {
    const decor = runtime.decorMap.get(selectedDecor.decorKey);
    const image = decor ? runtime.images.get(decor.path) : null;
    if (decor && image) {
      const width = getDecorDisplayWidth(decor, selectedDecor);
      const height = width * (image.height / image.width);
      drawDecorLayerBadge(
        selectedDecor.xNorm * TANK_WIDTH,
        selectedDecor.yNorm * TANK_HEIGHT - height - 16,
        getDecorTankLayer(selectedDecor),
        selectedDecor.decorKey
      );
      if (!dom.selectedDecorSettingsButton && canOpenDecorSettings(selectedDecor)) {
        drawDecorSettingsBadge(selectedDecor);
      }
    }
  }
}

function drawDecorSettingsBadge(item) {
  const bounds = getPlacedDecorOpaqueBounds(item);
  if (!bounds) {
    return;
  }

  const text = "[S] Settings";
  const x = (bounds.left + bounds.right) / 2;
  const y = Math.min(TANK_HEIGHT - 18, Math.max(WATER_SURFACE_Y + 18, bounds.bottom + 18));

  tankContext.save();
  tankContext.font = "800 11px Trebuchet MS";
  tankContext.textAlign = "center";
  tankContext.textBaseline = "middle";
  const width = Math.ceil(tankContext.measureText(text).width) + 18;
  const height = 22;
  tankContext.fillStyle = "rgba(6, 16, 24, 0.82)";
  tankContext.strokeStyle = "rgba(156, 241, 255, 0.74)";
  tankContext.lineWidth = 1.2;
  tankContext.shadowColor = "rgba(104, 232, 255, 0.32)";
  tankContext.shadowBlur = 12;
  tankContext.beginPath();
  tankContext.roundRect(x - width / 2, y - height / 2, width, height, 8);
  tankContext.fill();
  tankContext.stroke();
  tankContext.shadowBlur = 0;
  tankContext.fillStyle = "rgba(234, 248, 255, 0.96)";
  tankContext.fillText(text, x, y + 0.5);
  tankContext.restore();
}

function drawSelectedDecorHighlight(item) {
  const bounds = getPlacedDecorOpaqueBounds(item);
  if (!bounds) {
    return;
  }

  const padding = 10;
  const left = bounds.left - padding;
  const top = bounds.top - padding;
  const width = bounds.right - bounds.left + padding * 2;
  const height = bounds.bottom - bounds.top + padding * 2;
  const radius = Math.max(12, Math.min(width, height) * 0.16);

  tankContext.save();
  tankContext.fillStyle = "rgba(104, 232, 255, 0.08)";
  tankContext.strokeStyle = "rgba(156, 241, 255, 0.95)";
  tankContext.lineWidth = 2.5;
  tankContext.shadowColor = "rgba(104, 232, 255, 0.4)";
  tankContext.shadowBlur = 18;
  tankContext.beginPath();
  tankContext.roundRect(left, top, width, height, radius);
  tankContext.fill();
  tankContext.stroke();
  tankContext.restore();
}

function drawDecorLayerBadge(x, y, layer, decorKey = "") {
  tankContext.save();
  tankContext.font = "700 12px Trebuchet MS";
  tankContext.textAlign = "center";
  tankContext.textBaseline = "middle";

  const span = getDecorLayerSpan(decorKey, layer);
  const text = span.label;
  const now = Date.now();
  const pulseActive = runtime.layerLimitPulseUntil > now && runtime.layerLimitPulseLayer === clampTankLayer(layer);
  const pulseElapsed = Math.max(0, now - (runtime.layerLimitPulseStartedAt || now));
  const pulseStrength = pulseActive
    ? 0.45 + Math.abs(Math.sin((pulseElapsed / LAYER_LIMIT_PULSE_MS) * Math.PI * 3)) * 0.55
    : 0;

  const width = Math.ceil(tankContext.measureText(text).width) + 16;
  const height = 20;
  tankContext.fillStyle = pulseActive
    ? `rgba(88, 8, 12, ${0.72 + pulseStrength * 0.18})`
    : "rgba(6, 16, 24, 0.78)";
  tankContext.beginPath();
  tankContext.roundRect(x - width / 2, y - height / 2, width, height, 9);
  tankContext.fill();
  tankContext.strokeStyle = pulseActive
    ? `rgba(255, 74, 74, ${0.62 + pulseStrength * 0.38})`
    : "rgba(198, 236, 247, 0.32)";
  tankContext.lineWidth = pulseActive ? 1.8 : 1;
  tankContext.shadowColor = pulseActive ? "rgba(255, 52, 52, 0.65)" : "transparent";
  tankContext.shadowBlur = pulseActive ? 10 + pulseStrength * 10 : 0;
  tankContext.stroke();
  tankContext.fillStyle = pulseActive
    ? "rgba(255, 236, 236, 0.98)"
    : "rgba(234, 248, 255, 0.96)";
  tankContext.fillText(text, x, y + 0.5);
  tankContext.restore();
}

function drawPoops(now, layer = null) {
  const targetLayer = Number.isFinite(Number(layer)) ? clampTankLayer(layer) : null;
  for (const poop of state.poops) {
    if (targetLayer !== null && getPoopTankLayer(poop) !== targetLayer) {
      continue;
    }

    const pose = getPoopPose(poop, now);
    if (!pose?.sprite) {
      continue;
    }

    tankContext.save();
    tankContext.translate(pose.x, pose.y + 4);
    tankContext.rotate(pose.wobble);
    drawPoopUvGlowToContext(tankContext, pose, now);
    tankContext.globalAlpha = 0.9;
    tankContext.drawImage(pose.sprite, -pose.width / 2, -pose.height * 0.88, pose.width, pose.height);
    tankContext.restore();
  }
}

function drawPoopUvGlowToContext(context, pose, now = Date.now()) {
  if (!isUvLightActive() || !pose?.sprite) {
    return;
  }

  const pulse = 0.5 + Math.sin(now / 1700 + pose.x * 0.018) * 0.5;
  drawUvGlowImageToContext(
    context,
    pose.sprite,
    -pose.width / 2,
    -pose.height * 0.88,
    pose.width,
    pose.height,
    1.35,
    0.82 + pulse * 0.12,
    "biological-waste"
  );
}

function drawFishHeldGravelPebble(fish, species, now, pose, width, height) {
  const action = getFishGravelPebbleAction(fish);
  if (!action || action.stage !== "carry") {
    return;
  }

  const sprite = getCustomGravelPebbleSpriteByPath(action.assetPath, action.color, { colorize: action.colorize });
  if (!sprite?.width || !sprite?.height) {
    return;
  }

  const aspect = sprite.width / Math.max(1, sprite.height);
  const size = (Number.isFinite(action.holdSizePx) ? action.holdSizePx : FISH_GRAVEL_PEBBLE_HOLD_SIZE_MIN_PX) * getViewportStableAssetScale();
  const drawWidth = aspect >= 1 ? size : size * aspect;
  const drawHeight = aspect >= 1 ? size / aspect : size;
  const mouth = getFishGravelPebbleMouthLocalPoint(fish, species, width, height, pose, now);

  tankContext.save();
  tankContext.globalAlpha = 1;
  tankContext.drawImage(
    sprite,
    mouth.x - drawWidth * FISH_GRAVEL_PEBBLE_MOUTH_OVERLAP_RATIO,
    mouth.y - drawHeight * 0.5,
    drawWidth,
    drawHeight
  );
  tankContext.restore();
}

function getFishSameLayerRenderPriority(fish) {
  if (!fish?.caveDecorId || !["enter", "inside", "exit", "depart"].includes(fish.caveState)) {
    return 0;
  }

  return 1;
}

function drawFishPebbleTosses(now) {
  if (!runtime.fishPebbleTosses.length) {
    return;
  }

  for (const toss of runtime.fishPebbleTosses) {
    const sprite = getCustomGravelPebbleSpriteByPath(toss.assetPath, toss.color, { colorize: toss.colorize });
    if (!sprite?.width || !sprite?.height) {
      continue;
    }

    const pose = getFishPebbleTossPose(toss, now);
    const aspect = sprite.width / Math.max(1, sprite.height);
    const size = (Number.isFinite(toss.sizePx) ? toss.sizePx : FISH_GRAVEL_PEBBLE_HOLD_SIZE_MIN_PX) * getViewportStableAssetScale();
    const drawWidth = aspect >= 1 ? size : size * aspect;
    const drawHeight = aspect >= 1 ? size / aspect : size;

    tankContext.save();
    tankContext.translate(pose.x, pose.y);
    tankContext.rotate(pose.rotation);
    tankContext.globalAlpha = 1;
    tankContext.drawImage(
      sprite,
      -drawWidth * 0.5,
      -drawHeight * 0.5,
      drawWidth,
      drawHeight
    );
    tankContext.restore();
  }
}

function drawFish(now, layer = null, options = {}) {
  if (!state.fish.length) {
    return;
  }

  const sortedFish = [...state.fish]
    .filter((fish) => {
      if (layer !== null && getFishTankLayer(fish) !== layer) {
        return false;
      }

      const species = getSpeciesForFish(fish);
      if (!species) {
        return false;
      }

      const effectiveBehavior = getEffectiveFishBehavior(fish);
      if (options.onlyBehavior && effectiveBehavior !== options.onlyBehavior) {
        return false;
      }

      if (options.excludeBehavior && effectiveBehavior === options.excludeBehavior) {
        return false;
      }

      return true;
    })
    .sort((left, right) => {
      const priorityDelta = getFishSameLayerRenderPriority(left) - getFishSameLayerRenderPriority(right);
      if (priorityDelta) {
        return priorityDelta;
      }

      return left.yNorm - right.yNorm;
    });

  for (const fish of sortedFish) {
    const species = getSpeciesForFish(fish);
    const imagePath = getFishDisplayAssetPath(fish, species, now) || species.asset;
    const image = runtime.images.get(imagePath);
    if (!image) {
      continue;
    }
    const renderImage = getFishTintedImage(imagePath, image, fish);

    const pose = getFishPose(fish, species, now);
    const width = getFishDisplayWidth(fish, species, now);
    const height = width * (image.height / image.width);
    const stableScale = getViewportStableAssetScale();
    const shellBounds = getTankShellBounds();
    const topFrameBottomY = shellBounds.outerTop + 28;

    tankContext.save();
    tankContext.translate(pose.x + pose.swayX, pose.y);
    tankContext.scale(pose.facingScaleX ?? (pose.direction < 0 ? -1 : 1), 1);
    tankContext.rotate(pose.tilt);
    tankContext.scale(pose.bodyScaleX, pose.bodyScaleY);

    const healthRatio = getFishHealthRatio(fish, species);
    const fishDrawX = -width / 2 + pose.wiggle * width * 0.018;
    tankContext.filter = getFishCanvasFilter(fish, healthRatio, now);
    tankContext.drawImage(renderImage, fishDrawX, -height / 2, width, height);
    tankContext.filter = "none";
    drawUvGlowImageToContext(tankContext, renderImage, fishDrawX, -height / 2, width, height, getFishUvGlowIntensity(fish, species));
    drawFishHeldGravelPebble(fish, species, now, pose, width, height);
    tankContext.restore();

    if ((!pose.isBeingConsumed && pose.isDead) || fish.healthUnits === 1) {
      const statusY = Math.max(topFrameBottomY + 12 * stableScale, pose.y - height * 0.72);
      tankContext.save();
      tankContext.font = `${22 * stableScale}px sans-serif`;
      tankContext.textAlign = "center";
      tankContext.textBaseline = "middle";
      tankContext.fillText(
        pose.isDead ? "☠️" : "💔",
        pose.x + pose.swayX,
        statusY
      );
      tankContext.restore();
    }

    if (runtime.selectedFishId === fish.id) {
      tankContext.save();
      tankContext.font = `600 ${13 * stableScale}px Trebuchet MS`;
      tankContext.textAlign = "center";
      tankContext.textBaseline = "middle";
      const labelWidth = Math.ceil(tankContext.measureText(fish.name).width) + 18 * stableScale;
      const labelHeight = 22 * stableScale;
      const labelY = pose.isDead
        ? Math.max(topFrameBottomY + labelHeight / 2 + 18 * stableScale, pose.y - height * 0.62)
        : pose.y - height * 0.62;
      tankContext.fillStyle = "rgba(5, 14, 22, 0.5)";
      tankContext.beginPath();
      tankContext.roundRect(pose.x - labelWidth / 2, labelY - labelHeight / 2, labelWidth, labelHeight, 11 * stableScale);
      tankContext.fill();
      tankContext.strokeStyle = "rgba(232, 247, 255, 0.16)";
      tankContext.lineWidth = stableScale;
      tankContext.stroke();
      tankContext.fillStyle = "rgba(240, 251, 255, 0.92)";
      tankContext.fillText(fish.name, pose.x, labelY + 0.5);
      tankContext.restore();
    }
  }
}

function drawForegroundLight() {
  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y, TANK_WIDTH - GLASS_MARGIN_X * 2, Math.max(40, FLOOR_Y - WATER_SURFACE_Y - 54));
  tankContext.clip();
  const gradient = tankContext.createLinearGradient(0, 0, TANK_WIDTH, TANK_HEIGHT);
  gradient.addColorStop(0, "rgba(255,255,255,0.08)");
  gradient.addColorStop(0.25, "rgba(255,255,255,0.012)");
  gradient.addColorStop(1, "rgba(255,255,255,0)");
  tankContext.fillStyle = gradient;
  tankContext.beginPath();
  tankContext.moveTo(120, 0);
  tankContext.lineTo(360, 0);
  tankContext.lineTo(720, TANK_HEIGHT);
  tankContext.lineTo(420, TANK_HEIGHT);
  tankContext.closePath();
  tankContext.fill();
  tankContext.restore();
}

function drawWaterSurface(now) {
  tankContext.save();
  const surfaceStartX = GLASS_MARGIN_X - 8;
  const surfaceEndX = TANK_WIDTH - GLASS_MARGIN_X + 8;
  const traceRipple = (yOffset, amplitude, phase, step = 16) => {
    tankContext.beginPath();
    for (let x = surfaceStartX; x <= surfaceEndX; x += step) {
      const y = WATER_SURFACE_Y
        + yOffset
        + Math.sin(now / 620 + x / 112 + phase) * amplitude
        + Math.sin(now / 980 + x / 43 + phase * 0.6) * amplitude * 0.32;
      if (x === surfaceStartX) {
        tankContext.moveTo(x, y);
      } else {
        tankContext.lineTo(x, y);
      }
    }
  };

  tankContext.lineCap = "round";
  tankContext.lineJoin = "round";

  tankContext.strokeStyle = "rgba(8, 13, 16, 0.16)";
  tankContext.lineWidth = 1.05;
  traceRipple(1.45, 1.05, 0.7);
  tankContext.stroke();

  tankContext.strokeStyle = "rgba(236, 250, 252, 0.2)";
  tankContext.lineWidth = 0.85;
  traceRipple(0, 1.24, 0);
  tankContext.stroke();

  tankContext.setLineDash([28, 96]);
  tankContext.lineDashOffset = -now / 120;
  tankContext.strokeStyle = "rgba(194, 238, 244, 0)";
  tankContext.lineWidth = 0.45;
  traceRipple(-0.4, 0.9, 1.4, 14);
  tankContext.stroke();
  tankContext.restore();
}

function drawSplashBursts(now) {
  if (!runtime.splashBursts.length) {
    return;
  }

  tankContext.save();
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y - 72, TANK_WIDTH - GLASS_MARGIN_X * 2, TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM + 72);
  tankContext.clip();

  for (const burst of runtime.splashBursts) {
    const progress = clamp((now - burst.startedAt) / Math.max(1, burst.endsAt - burst.startedAt), 0, 1);
    if (progress >= 1) {
      continue;
    }

    const rippleAlpha = (1 - progress) * 0.52;
    tankContext.save();
    tankContext.strokeStyle = `rgba(224, 247, 255, ${rippleAlpha.toFixed(3)})`;
    tankContext.lineWidth = 2.4 - progress * 1.2;
    tankContext.beginPath();
    tankContext.ellipse(
      burst.x,
      burst.y + 1,
      14 + progress * 48,
      3 + progress * 10,
      0,
      0,
      Math.PI * 2
    );
    tankContext.stroke();
    tankContext.restore();

    for (const droplet of burst.droplets) {
      const dropletProgress = clamp((progress - droplet.delay) / 0.34, 0, 1);
      if (dropletProgress <= 0 || dropletProgress >= 1) {
        continue;
      }

      const x = burst.x + droplet.drift * dropletProgress;
      const y = burst.y - droplet.lift * Math.sin(dropletProgress * Math.PI) + droplet.fall * dropletProgress * dropletProgress;
      tankContext.fillStyle = `rgba(229, 249, 255, ${(0.9 - dropletProgress * 0.5).toFixed(3)})`;
      tankContext.beginPath();
      tankContext.ellipse(x, y, droplet.size * 0.82, droplet.size * 1.18, 0, 0, Math.PI * 2);
      tankContext.fill();
    }

    for (const bubble of burst.bubbles) {
      const bubbleProgress = clamp((progress - bubble.delay) / 0.62, 0, 1);
      if (bubbleProgress <= 0 || bubbleProgress >= 1) {
        continue;
      }

      const bubbleY = burst.y + 18 + bubble.rise * (1 - bubbleProgress);
      drawBubbleOrb(
        burst.x + bubble.drift * bubbleProgress + Math.sin(progress * 18 + bubble.drift) * bubble.wobble,
        bubbleY,
        bubble.radius * (0.84 + bubbleProgress * 0.28),
        0.16 + (1 - bubbleProgress) * 0.22,
        1
      );
    }
  }

  tankContext.restore();
}

function drawGlassFrame() {
  glassContext.save();
  const currentTank = getCurrentTank();
  const {
    outerLeft,
    outerTop,
    outerWidth,
    outerHeight,
    innerLeft,
    innerTop,
    innerWidth,
    innerHeight
  } = getTankShellBounds(currentTank);

  const tankAsset = runtime.tankMap.get(state.selectedTankAsset);
  const tankImage = tankAsset ? runtime.images.get(tankAsset.path) : null;
  if (tankImage) {
    glassContext.globalAlpha = 1;
    glassContext.drawImage(tankImage, 0, 0, TANK_WIDTH, TANK_HEIGHT);
    glassContext.restore();
    return;
  }

  if (isBowlTank(currentTank)) {
    const outerPoints = getTankShellPointSet("outer", currentTank) || [];
    const innerPoints = getTankShellPointSet("inner", currentTank) || [];
    const topLeft = outerPoints[0];
    const topRight = outerPoints[1];
    const rightShoulder = outerPoints[2];
    const leftShoulder = outerPoints[outerPoints.length - 1];

    glassContext.shadowColor = "rgba(0, 0, 0, 0.38)";
    glassContext.shadowBlur = 28;
    if (topLeft && topRight && leftShoulder && rightShoulder) {
      const topCap = glassContext.createLinearGradient(0, topLeft.y, 0, rightShoulder.y + 10);
      topCap.addColorStop(0, "rgba(11, 18, 25, 0.98)");
      topCap.addColorStop(1, "rgba(20, 32, 44, 0.94)");
      glassContext.fillStyle = topCap;
      glassContext.beginPath();
      glassContext.moveTo(leftShoulder.x, leftShoulder.y + 6);
      glassContext.lineTo(topLeft.x, topLeft.y);
      glassContext.lineTo(topRight.x, topRight.y);
      glassContext.lineTo(rightShoulder.x, rightShoulder.y + 6);
      glassContext.closePath();
      glassContext.fill();
    }

    glassContext.shadowBlur = 0;
    glassContext.strokeStyle = "rgba(255, 255, 255, 0.1)";
    glassContext.lineWidth = 16;
    traceTankShellPath(glassContext, { tank: currentTank, variant: "outer" });
    glassContext.stroke();

    glassContext.strokeStyle = "rgba(225, 241, 250, 0.22)";
    glassContext.lineWidth = 4;
    traceTankShellPath(glassContext, { tank: currentTank, variant: "outer" });
    glassContext.stroke();

    glassContext.strokeStyle = "rgba(214, 245, 255, 0.18)";
    glassContext.lineWidth = 2;
    traceTankShellPath(glassContext, { tank: currentTank, variant: "inner" });
    glassContext.stroke();

    glassContext.save();
    clipToTankShellBounds(glassContext, currentTank, "inner");
    const glare = glassContext.createLinearGradient(innerLeft, innerTop, innerLeft + innerWidth * 0.34, innerTop + innerHeight * 0.2);
    glare.addColorStop(0, "rgba(255,255,255,0.22)");
    glare.addColorStop(0.42, "rgba(255,255,255,0.08)");
    glare.addColorStop(1, "rgba(255,255,255,0)");
    glassContext.fillStyle = glare;
    glassContext.fillRect(innerLeft + 10, innerTop + 12, innerWidth * 0.28, innerHeight * 0.86);
    glassContext.restore();

    glassContext.restore();
    return;
  }

  const topFrame = glassContext.createLinearGradient(0, outerTop, 0, outerTop + 32);
  topFrame.addColorStop(0, "rgba(24, 34, 43, 0.98)");
  topFrame.addColorStop(1, "rgba(8, 13, 18, 0.98)");
  const sideFrame = glassContext.createLinearGradient(0, outerTop, outerLeft, outerTop);
  sideFrame.addColorStop(0, "rgba(38, 52, 64, 0.94)");
  sideFrame.addColorStop(1, "rgba(8, 13, 18, 0.98)");
  const bottomFrame = glassContext.createLinearGradient(0, outerHeight + outerTop - 30, 0, outerHeight + outerTop);
  bottomFrame.addColorStop(0, "rgba(26, 36, 47, 0.98)");
  bottomFrame.addColorStop(1, "rgba(6, 10, 14, 0.98)");

  glassContext.shadowColor = "rgba(0, 0, 0, 0.34)";
  glassContext.shadowBlur = 24;
  glassContext.fillStyle = topFrame;
  glassContext.fillRect(outerLeft, outerTop, outerWidth, 28);
  glassContext.fillStyle = bottomFrame;
  glassContext.fillRect(outerLeft, TANK_HEIGHT - GLASS_MARGIN_BOTTOM - 2, outerWidth, 28);
  glassContext.fillStyle = sideFrame;
  glassContext.fillRect(outerLeft, outerTop + 24, 16, outerHeight - 52);
  glassContext.fillRect(TANK_WIDTH - outerLeft - 16, outerTop + 24, 16, outerHeight - 52);
  glassContext.shadowBlur = 0;

  glassContext.strokeStyle = "rgba(220, 236, 244, 0.2)";
  glassContext.lineWidth = 2;
  glassContext.strokeRect(innerLeft, innerTop, innerWidth, innerHeight);
  glassContext.strokeStyle = "rgba(255,255,255,0.1)";
  glassContext.lineWidth = 1.5;
  glassContext.beginPath();
  glassContext.moveTo(innerLeft + 12, innerTop + 12);
  glassContext.lineTo(innerLeft + 12, innerTop + innerHeight - 20);
  glassContext.moveTo(TANK_WIDTH - innerLeft - 12, innerTop + 12);
  glassContext.lineTo(TANK_WIDTH - innerLeft - 12, innerTop + innerHeight - 20);
  glassContext.stroke();

  const glare = glassContext.createLinearGradient(innerLeft, 0, innerLeft + 120, 0);
  glare.addColorStop(0, "rgba(255,255,255,0.18)");
  glare.addColorStop(1, "rgba(255,255,255,0)");
  glassContext.fillStyle = glare;
  glassContext.fillRect(innerLeft + 10, innerTop + 12, 22, innerHeight - 22);
  glassContext.restore();
}

function drawGrime(dirtiness) {
  grimeContext.clearRect(0, 0, TANK_WIDTH, TANK_HEIGHT);
  if (getVisibleGrimeDirtiness(dirtiness) <= 0 && runtime.scrubStamps.length === 0) {
    return;
  }

  const grimeBaseCacheKey = getGrimeBaseCacheKey(dirtiness);
  if (runtime.grimeBaseCacheKey !== grimeBaseCacheKey) {
    renderGrimeBaseCanvas(dirtiness);
    runtime.grimeBaseCacheKey = grimeBaseCacheKey;
  }

  grimeContext.save();
  clipToTankShellBounds(grimeContext, getCurrentTank(), "outer");
  grimeContext.drawImage(runtime.grimeBaseCanvas, 0, 0, TANK_WIDTH, TANK_HEIGHT);

  if (runtime.scrubStamps.length) {
    grimeContext.globalCompositeOperation = "destination-out";
    grimeContext.drawImage(runtime.scrubMaskCanvas, 0, 0, TANK_WIDTH, TANK_HEIGHT);
  }
  grimeContext.restore();
}

function drawCleaningSparkles(now) {
  if (!runtime.cleaningTransition) {
    return;
  }

  const { startedAt, fadeEndsAt, sparkleEndsAt, sparkles } = runtime.cleaningTransition;
  const fadeProgress = clamp((now - startedAt) / Math.max(1, fadeEndsAt - startedAt), 0, 1);
  const sparkleFade = now <= fadeEndsAt
    ? fadeProgress
    : clamp(1 - (now - fadeEndsAt) / Math.max(1, sparkleEndsAt - fadeEndsAt), 0, 1);

  if (sparkleFade <= 0) {
    return;
  }

  tankContext.save();
  clipToTankShellBounds(tankContext, getCurrentTank(), "inner");
  tankContext.beginPath();
  tankContext.rect(GLASS_MARGIN_X, WATER_SURFACE_Y + 2, TANK_WIDTH - GLASS_MARGIN_X * 2, TANK_HEIGHT - WATER_SURFACE_Y - GLASS_MARGIN_BOTTOM - 2);
  tankContext.clip();
  tankContext.globalCompositeOperation = "screen";

  for (const sparkle of sparkles) {
    const life = clamp((now - startedAt) / CLEAN_SPARKLE_MS - sparkle.delay, 0, 1);
    if (life <= 0 || life >= 1) {
      continue;
    }

    const pulse = Math.sin((life * Math.PI + sparkle.delay) * sparkle.twinkle * Math.PI);
    const burst = Math.sin(life * Math.PI);
    const alpha = Math.max(0, pulse) * sparkleFade * (0.7 + sparkle.glow * 0.38);
    if (alpha <= 0.02) {
      continue;
    }

    const size = sparkle.size * (0.86 + pulse * 0.22 + burst * 0.16);
    const glowRadius = size * (1.8 + sparkle.glow * 0.65);
    const coreColor = `hsla(${sparkle.hue.toFixed(1)}, 92%, 78%, ${Math.min(0.98, alpha).toFixed(3)})`;
    const glowGradient = tankContext.createRadialGradient(
      sparkle.x,
      sparkle.y,
      0,
      sparkle.x,
      sparkle.y,
      glowRadius
    );
    glowGradient.addColorStop(0, `hsla(${sparkle.hue.toFixed(1)}, 100%, 86%, ${(alpha * 0.34).toFixed(3)})`);
    glowGradient.addColorStop(0.45, `hsla(${sparkle.hue.toFixed(1)}, 96%, 70%, ${(alpha * 0.2).toFixed(3)})`);
    glowGradient.addColorStop(1, `hsla(${sparkle.hue.toFixed(1)}, 96%, 60%, 0)`);
    tankContext.fillStyle = glowGradient;
    tankContext.beginPath();
    tankContext.arc(sparkle.x, sparkle.y, glowRadius, 0, Math.PI * 2);
    tankContext.fill();

    tankContext.save();
    tankContext.translate(sparkle.x, sparkle.y);
    tankContext.rotate(sparkle.rotation + pulse * 0.12);
    tankContext.strokeStyle = coreColor;
    tankContext.lineWidth = 1.5 + sparkle.glow * 0.85;
    tankContext.beginPath();
    tankContext.moveTo(-size, 0);
    tankContext.lineTo(size, 0);
    tankContext.moveTo(0, -size);
    tankContext.lineTo(0, size);
    tankContext.stroke();
    if (sparkle.diagonal) {
      const diag = size * 0.72;
      tankContext.beginPath();
      tankContext.moveTo(-diag, -diag);
      tankContext.lineTo(diag, diag);
      tankContext.moveTo(diag, -diag);
      tankContext.lineTo(-diag, diag);
      tankContext.stroke();
    }
    tankContext.restore();

    tankContext.fillStyle = `hsla(${sparkle.hue.toFixed(1)}, 100%, 92%, ${(alpha * 0.92).toFixed(3)})`;
    tankContext.beginPath();
    tankContext.arc(sparkle.x, sparkle.y, Math.max(1.6, size * 0.18), 0, Math.PI * 2);
    tankContext.fill();

    tankContext.fillStyle = `rgba(255,255,255, ${(alpha * 0.74).toFixed(3)})`;
    tankContext.beginPath();
    tankContext.arc(
      sparkle.x - size * 0.14,
      sparkle.y - size * 0.18,
      Math.max(1.1, size * 0.08),
      0,
      Math.PI * 2
    );
    tankContext.fill();
  }

  tankContext.restore();
}

function getFishPose(fish, species, now) {
  if (isFishBeingConsumedByPiranhas(fish, now)) {
    const churnClock = now / 1000;
    const facing = getFishFacingDirection(fish);
    return {
      x: fish.xNorm * TANK_WIDTH + Math.sin(churnClock * 2.2 + fish.phase * Math.PI * 2) * 8,
      y: fish.yNorm * TANK_HEIGHT + Math.cos(churnClock * 2.8 + fish.phase * Math.PI * 1.6) * 5,
      direction: facing,
      facingScaleX: facing,
      tilt: Math.PI * 0.5 + Math.sin(churnClock * 3.2 + fish.phase * Math.PI) * 0.42,
      wiggle: Math.sin(churnClock * 4.4 + fish.phase * Math.PI) * 0.28,
      bodyScaleX: 0.92,
      bodyScaleY: 1.06,
      swayX: Math.sin(churnClock * 3.6 + fish.phase * Math.PI * 2) * 4,
      isDead: true,
      isBeingConsumed: true
    };
  }

  if (isFishDead(fish)) {
    const floatClock = now / 1000;
    const facing = getFishFacingDirection(fish);
    return {
      x: fish.xNorm * TANK_WIDTH + Math.sin(floatClock * 0.34 + fish.phase * Math.PI * 2) * 3.2,
      y: fish.yNorm * TANK_HEIGHT + Math.sin(floatClock * 0.82 + fish.phase * Math.PI * 1.6) * 1.8,
      direction: facing,
      facingScaleX: facing,
      tilt: Math.PI + Math.sin(floatClock * 0.48 + fish.phase * Math.PI) * 0.06,
      wiggle: Math.sin(floatClock * 0.18 + fish.phase * Math.PI) * 0.05,
      bodyScaleX: 1,
      bodyScaleY: 1,
      swayX: 0,
      isDead: true
    };
  }

  const motionLevel = clamp(Number(fish.motionLevel) || 0.12, 0.04, 1);
  const sickMotionBoost = isFishCriticallyLowHealth(fish) ? 1.22 : 1;
  const wiggleClock = Number.isFinite(fish.wiggleClock) ? fish.wiggleClock : (now / 1000) * (0.45 + fish.swimSpeed * 14);
  if (getEffectiveFishBehavior(fish, species) === "sucker") {
    const facing = getFishFacingDirection(fish);
    const turnProgress = fish.turnStartedAt && fish.turnDurationMs > 0
      ? clamp((now - fish.turnStartedAt) / fish.turnDurationMs, 0, 1)
      : null;
    const currentAngle = getFishFacingAngle(fish);
    const turnFromAngle = Number.isFinite(Number(fish.turnFromAngle))
      ? normalizeAngle(Number(fish.turnFromAngle))
      : currentAngle;
    const turnToAngle = Number.isFinite(Number(fish.turnToAngle))
      ? normalizeAngle(Number(fish.turnToAngle))
      : currentAngle;
    const turnSpinDirection = Number(fish.turnSpinDirection) < 0 ? -1 : 1;
    const clingMotion = clamp(motionLevel * 0.18, 0.01, 0.12);
    const clingWiggle = Math.sin(wiggleClock * 0.18 + fish.phase * Math.PI) * clingMotion;
    const turnDelta = turnProgress === null ? 0 : getDirectedAngleDelta(turnFromAngle, turnToAngle, turnSpinDirection);
    const turnAngle = turnProgress === null
      ? currentAngle
      : normalizeAngle(turnFromAngle + turnDelta * turnProgress);
    const turnLift = turnProgress === null ? 0 : Math.sin(turnProgress * Math.PI) * 2.6;
    const crawlTilt = clamp((fish.targetYNorm - fish.yNorm) * 0.18, -0.18, 0.18);
    return {
      x: fish.xNorm * TANK_WIDTH,
      y: fish.yNorm * TANK_HEIGHT - turnLift,
      direction: facing,
      facingScaleX: 1,
      tilt: normalizeAngle(turnAngle + (turnProgress === null ? crawlTilt : crawlTilt * 0.35)),
      wiggle: clingWiggle,
      bodyScaleX: 1 - Math.abs(clingWiggle) * 0.008,
      bodyScaleY: 1 + Math.abs(clingWiggle) * 0.006,
      swayX: clingWiggle * 0.18,
      isDead: false
    };
  }
  const wiggle = Math.sin(wiggleClock + fish.phase * Math.PI * 2) * sickMotionBoost;
  const glide = Math.sin(wiggleClock * 0.48 + fish.phase * Math.PI * 1.4) * sickMotionBoost;
  const entryProgress = fish.entryStartedAt && fish.entryDurationMs > 0
    ? clamp((now - fish.entryStartedAt) / fish.entryDurationMs, 0, 1)
    : null;
  const easedEntry = entryProgress === null ? null : 1 - Math.pow(1 - entryProgress, 3);
  const renderYNorm = easedEntry === null || fish.entryFromYNorm === null
    ? fish.yNorm
    : fish.entryFromYNorm + (fish.yNorm - fish.entryFromYNorm) * easedEntry;
  const x = fish.xNorm * TANK_WIDTH;
  const y = renderYNorm * TANK_HEIGHT
    + Math.sin(wiggleClock * (0.2 + species.bobSpeed * 0.16) + fish.phase * Math.PI * 2) * (0.9 + motionLevel * 4.4) * sickMotionBoost
    + glide * (0.45 + motionLevel * 1.35)
    + (entryProgress === null ? 0 : Math.sin(entryProgress * Math.PI * 2.4 + fish.phase * Math.PI) * (1 - entryProgress) * 9);
  const wiggleStretch = 0.008 + motionLevel * 0.018;
  const turnProgress = fish.turnStartedAt && fish.turnDurationMs > 0
    ? clamp((now - fish.turnStartedAt) / fish.turnDurationMs, 0, 1)
    : null;
  const turnAmount = turnProgress === null ? 0 : Math.sin(turnProgress * Math.PI);
  const turnFromDirection = Number(fish.turnFromDirection) < 0 ? -1 : 1;
  const turnToDirection = Number(fish.turnToDirection) < 0 ? -1 : 1;
  const renderDirection = turnProgress === null
    ? getFishFacingDirection(fish)
    : (turnProgress < 0.5 ? turnFromDirection : turnToDirection);
  const turnLean = turnProgress === null
    ? 0
    : (Number(fish.turnSpinDirection) < 0 ? -1 : 1) * turnAmount * 0.14;
  const tilt = clamp(
    (fish.targetYNorm - fish.yNorm) * (0.9 + motionLevel * 0.35)
    + wiggle * (0.008 + motionLevel * 0.04)
    + turnLean,
    -0.26,
    0.26
  );
  const bodyScaleX = (1 - Math.abs(wiggle) * wiggleStretch) * (1 - turnAmount * (1 - FISH_TURN_MIN_SCALE_X));
  const bodyScaleY = (1 + Math.abs(wiggle) * (wiggleStretch * 0.78)) * (1 + turnAmount * (FISH_TURN_MAX_SCALE_Y - 1));
  const turnSway = turnProgress === null
    ? 0
    : (Number(fish.turnSpinDirection) < 0 ? -1 : 1) * turnAmount * (0.35 + motionLevel * 0.95);
  return {
    x,
    y,
    direction: fish.direction || 1,
    facingScaleX: renderDirection,
    tilt,
    wiggle,
    bodyScaleX,
    bodyScaleY,
    swayX: wiggle * (0.7 + motionLevel * 1.55) + turnSway,
    isDead: false
  };
}

function getTankDirtiness(now) {
  const cleanDirtiness = getBaseTankDirtiness(now);
  if (!runtime.cleaningTransition) {
    return cleanDirtiness;
  }

  const progress = clamp((now - runtime.cleaningTransition.startedAt) / CLEAN_FADE_MS, 0, 1);
  const eased = 1 - (1 - progress) * (1 - progress);
  return clamp(
    runtime.cleaningTransition.fromDirtiness + (cleanDirtiness - runtime.cleaningTransition.fromDirtiness) * eased,
    0,
    1
  );
}

function getBaseTankDirtiness(now) {
  return clamp((now - state.lastCleanedAt) / getFilterMaxDirtyDurationMs(), 0, 1);
}

function getFilterProfile(filterKey = state?.selectedFilterAsset) {
  const currentTank = getCurrentTank();
  if (!tankSupportsFilters(currentTank)) {
    return {
      cleanDays: Math.max(1.2, Number(getTankTypeMeta(currentTank?.tankTypeId).baseCleanDays) || FILTERLESS_BASE_TANK_DIRTY_DAYS),
      comfortBoost: 0,
      cost: 0,
      flow: 0.9,
      purchasable: false,
      tier: -1
    };
  }

  const fallbackFilterKey = getDefaultFilterKey();
  const filter = runtime.filterMap.get(filterKey || fallbackFilterKey) || runtime.filterMap.get(fallbackFilterKey) || {};
  return {
    cleanDays: Math.max(BASE_TANK_DIRTY_DAYS, Number(filter.cleanDays) || BASE_TANK_DIRTY_DAYS),
    comfortBoost: clamp(Number(filter.comfortBoost) || 0, 0, 0.25),
    cost: Math.max(0, Math.floor(Number(filter.cost) || 0)),
    flow: clamp(Number(filter.flow) || 1, 0.8, 1.3),
    purchasable: Boolean(filter.purchasable),
    tier: Math.max(0, Math.floor(Number(filter.tier) || 0))
  };
}

function getFilterAssistPercent(filterKey = state?.selectedFilterAsset) {
  const profile = getFilterProfile(filterKey);
  return Math.round((1 - BASE_TANK_DIRTY_DAYS / Math.max(BASE_TANK_DIRTY_DAYS, profile.cleanDays)) * 100);
}

function normalizeFishSpeed(species, explicitValue) {
  if (Number.isFinite(explicitValue)) {
    return clamp(explicitValue, species.speedMin, species.speedMax);
  }

  if (species.speedMode === "dynamic") {
    return clamp(species.speedMin + Math.random() * (species.speedMax - species.speedMin), species.speedMin, species.speedMax);
  }

  return species.speedMin;
}

function getFishTurnDurationMs(fish, species) {
  if (!fish || !species) {
    return FISH_TURN_MIN_MS + Math.random() * (FISH_TURN_MAX_MS - FISH_TURN_MIN_MS);
  }

  const speedMin = Math.max(0.00001, Number(species.speedMin) || 0.00001);
  const speedMax = Math.max(speedMin, Number(species.speedMax) || speedMin);
  const currentSpeed = normalizeFishSpeed(species, Number(fish.swimSpeed));
  const speedBlend = speedMax <= speedMin
    ? 0.5
    : clamp((currentSpeed - speedMin) / Math.max(0.00001, speedMax - speedMin), 0, 1);
  const slowBias = 1 - speedBlend;
  const minMs = FISH_TURN_MIN_MS + slowBias * 55;
  const maxMs = FISH_TURN_MAX_MS + slowBias * 130;
  return minMs + Math.random() * Math.max(1, maxMs - minMs);
}

function formatSwimStyle(swimStyle) {
  switch (swimStyle) {
    case "peaceful":
      return "peaceful and slow";
    case "sporadic":
      return "sporadic and quick";
    default:
      return "steady";
  }
}

function describeGrime(dirtiness) {
  if (dirtiness < 0.14) {
    return "Tank is crystal clear.";
  }
  if (dirtiness < 0.34) {
    return "A little haze is starting to creep in.";
  }
  if (dirtiness < 0.62) {
    return "The glass is getting fuzzy and green.";
  }
  return "The tank is murky and really needs a sponge run.";
}

function getCurrentMealSlot(timestamp) {
  const date = new Date(timestamp);
  const morning = date.getHours() < 12;
  const start = new Date(date);
  start.setHours(morning ? 0 : 12, 0, 0, 0);
  return buildMealSlot(start);
}

function getTodaysMealSlots(timestamp) {
  const date = new Date(timestamp);
  const morning = new Date(date);
  morning.setHours(0, 0, 0, 0);
  const evening = new Date(date);
  evening.setHours(12, 0, 0, 0);
  return [buildMealSlot(morning), buildMealSlot(evening)];
}

function buildMealSlot(startDate) {
  const start = new Date(startDate);
  const end = new Date(start);
  end.setHours(end.getHours() + 12, 0, 0, 0);
  const part = start.getHours() < 12 ? "Morning" : "Evening";
  return {
    key: `${start.getFullYear()}-${String(start.getMonth() + 1).padStart(2, "0")}-${String(start.getDate()).padStart(2, "0")}-${part.toLowerCase()}`,
    label: part,
    start: start.getTime(),
    end: end.getTime()
  };
}

function getCompletedMealSlots(startTs, endTs) {
  const slots = [];
  let boundary = getNextMealBoundary(startTs);
  while (boundary.getTime() <= endTs) {
    const slotStart = new Date(boundary);
    slotStart.setHours(slotStart.getHours() - 12, 0, 0, 0);
    slots.push(buildMealSlot(slotStart));
    boundary = new Date(boundary);
    boundary.setHours(boundary.getHours() + 12, 0, 0, 0);
  }
  return slots;
}

function getMealSlotsStartingBetween(startTs, endTs) {
  const slots = [];
  let boundary = getNextMealBoundary(startTs);
  while (boundary.getTime() <= endTs) {
    slots.push(buildMealSlot(boundary));
    boundary = new Date(boundary);
    boundary.setHours(boundary.getHours() + 12, 0, 0, 0);
  }
  return slots;
}

function getNextMealBoundary(timestamp) {
  const date = new Date(timestamp);
  const boundary = new Date(date);

  if (date.getHours() < 12 || (date.getHours() === 12 && (date.getMinutes() > 0 || date.getSeconds() > 0 || date.getMilliseconds() > 0))) {
    boundary.setHours(12, 0, 0, 0);
    if (boundary.getTime() <= timestamp) {
      boundary.setDate(boundary.getDate() + 1);
      boundary.setHours(0, 0, 0, 0);
    }
  } else {
    boundary.setDate(boundary.getDate() + 1);
    boundary.setHours(0, 0, 0, 0);
  }

  return boundary;
}

function getTankPoint(event, options = {}) {
  const rect = dom.tankStage.getBoundingClientRect();
  if (!rect.width || !rect.height) {
    return null;
  }

  runtime.pointerStagePx = {
    x: event.clientX - rect.left,
    y: event.clientY - rect.top
  };

  const dpr = Math.max(1, window.devicePixelRatio || 1);
  const scale = Math.max(0.0001, Number(runtime.stageRenderScale) || 1);
  const offsetX = Number(runtime.stageRenderOffsetX) || 0;
  const offsetY = Number(runtime.stageRenderOffsetY) || 0;
  const canvasX = (event.clientX - rect.left) * dpr;
  const canvasY = (event.clientY - rect.top) * dpr;
  const rawPoint = {
    x: (canvasX - offsetX) / scale,
    y: (canvasY - offsetY) / scale
  };
  if (options.variant === "glass") {
    const glassBounds = {
      left: GLASS_MARGIN_X,
      right: TANK_WIDTH - GLASS_MARGIN_X,
      top: WATER_SURFACE_Y,
      bottom: TANK_HEIGHT - GLASS_MARGIN_BOTTOM
    };
    if (
      rawPoint.x < glassBounds.left
      || rawPoint.x > glassBounds.right
      || rawPoint.y < glassBounds.top
      || rawPoint.y > glassBounds.bottom
    ) {
      return null;
    }

    return {
      x: clamp(rawPoint.x, glassBounds.left, glassBounds.right),
      y: clamp(rawPoint.y, glassBounds.top, glassBounds.bottom)
    };
  }

  const constrainedPoint = constrainPointToTankShell(rawPoint.x, rawPoint.y, { variant: "inner" });
  const dragging = Boolean(runtime.dragState || runtime.fishDragState || runtime.pebbleDragState);
  if (!constrainedPoint.inside && !dragging) {
    return null;
  }
  return {
    x: constrainedPoint.x,
    y: constrainedPoint.y
  };
}

function getPelletPose(pellet, now) {
  updatePelletSettledState(pellet, now);
  const hasCustomDropStart = Number.isFinite(Number(pellet?.dropStartXNorm))
    && Number.isFinite(Number(pellet?.dropStartYNorm));
  const dropDurationMs = hasCustomDropStart
    ? clamp(Number(pellet.dropDurationMs) || AUTO_DISPENSER_DROP_DURATION_MS, 120, 3000)
    : 900;
  const dropProgress = clamp((now - pellet.createdAt) / dropDurationMs, 0, 1);
  const easedDrop = 1 - (1 - dropProgress) * (1 - dropProgress);
  const stableScale = getViewportStableAssetScale();
  const floorYNorm = clamp(
    Number.isFinite(Number(pellet.floorYNorm))
      ? Number(pellet.floorYNorm)
      : getPelletFloorYNormAtX(pellet.xNorm),
    0.18,
    0.96
  );
  if (pellet.settled) {
    return {
      xNorm: clamp(Number(pellet.xNorm) || 0.5, 0.08, 0.92),
      yNorm: getPelletFloorYNormAtX(pellet.xNorm)
    };
  }
  const floatingXNorm = clamp(
    pellet.xNorm + (Math.sin(now / 780 + pellet.sway * Math.PI * 2) * 5.5 * stableScale) / TANK_WIDTH,
    0.08,
    0.92
  );
  const startYNorm = clamp(
    Number.isFinite(Number(pellet.startYNorm)) ? Number(pellet.startYNorm) : Number(pellet.yNorm) || WATER_SURFACE_Y / TANK_HEIGHT + 0.08,
    0.09,
    floorYNorm
  );
  const sinkDuration = Math.max(1000, Number(pellet.sinkDurationMs) || FOOD_PELLET_SINK_DURATION_MS);
  const sinkProgress = clamp((now - pellet.createdAt) / sinkDuration, 0, 1);
  const easedSink = sinkProgress;
  const bobY = Math.sin(now / 980 + pellet.sway * 12) * 1.2 * stableScale / TANK_HEIGHT;
  const floatingY = clamp(startYNorm + (floorYNorm - startYNorm) * easedSink + bobY, 0.09, floorYNorm);
  if (hasCustomDropStart) {
    const startXNorm = clamp(Number(pellet.dropStartXNorm), 0.08, 0.92);
    const dropStartYNorm = clamp(Number(pellet.dropStartYNorm), 0.02, AUTO_DISPENSER_PELLET_MAX_Y_NORM);
    return {
      xNorm: clamp(startXNorm + (floatingXNorm - startXNorm) * easedDrop, 0.08, 0.92),
      yNorm: clamp(
        dropStartYNorm + (floatingY - dropStartYNorm) * easedDrop,
        0.02,
        floorYNorm
      )
    };
  }
  return {
    xNorm: floatingXNorm,
    yNorm: floatingY
  };
}

function getPelletHitBounds(pellet, now = Date.now()) {
  if (!pellet) {
    return null;
  }

  const pose = getPelletPose(pellet, now);
  const x = pose.xNorm * TANK_WIDTH;
  const y = pose.yNorm * TANK_HEIGHT;
  const stableScale = getViewportStableAssetScale();
  const scale = clamp(Number(pellet.scale) || 1, 0.75, 1.4) * stableScale;
  const appearance = getFoodDropAppearance(pellet.foodKey, pellet);
  if (appearance.dropStyle === "sprite") {
    const image = appearance.spritePath ? runtime.images.get(appearance.spritePath) : null;
    const fitScale = image
      ? Math.min((24 * scale) / Math.max(1, image.width), (24 * scale) / Math.max(1, image.height))
      : 1;
    const width = image ? Math.max(10 * stableScale, image.width * fitScale) : 18 * scale;
    const height = image ? Math.max(10 * stableScale, image.height * fitScale) : 14 * scale;
    return {
      pellet,
      x,
      y,
      left: x - width / 2,
      right: x + width / 2,
      top: y - height / 2,
      bottom: y + height / 2
    };
  }

  const width = 11.6 * scale;
  const height = 6.6 * scale;
  return {
    pellet,
    x,
    y,
    left: x - width / 2,
    right: x + width / 2,
    top: y - height / 2,
    bottom: y + height / 2
  };
}

function rgbaString({ r, g, b }, alpha = 1) {
  return `rgba(${clamp(Math.round(r), 0, 255)}, ${clamp(Math.round(g), 0, 255)}, ${clamp(Math.round(b), 0, 255)}, ${clamp(alpha, 0, 1).toFixed(3)})`;
}

function getBubbleOrbPalette(color = DEFAULT_BUBBLER_BUBBLE_COLOR, options = {}) {
  const normalizedColor = normalizeHexColor(color) || DEFAULT_BUBBLER_BUBBLE_COLOR;
  const baseRgb = hexToRgb(normalizedColor) || hexToRgb(DEFAULT_BUBBLER_BUBBLE_COLOR);
  const colorize = normalizeDecorColorizeSetting(options.colorize);
  const fillOpacity = clamp(
    Number.isFinite(Number(options.fillOpacity)) ? Number(options.fillOpacity) : DEFAULT_BUBBLER_FILL_OPACITY,
    0,
    1
  );
  const fillColor = colorize ? mixColors(normalizedColor, "#FFFFFF", 0.04) : mixColors(normalizedColor, "#FFFFFF", 0.18);
  const fillRgb = hexToRgb(fillColor) || baseRgb;
  const strokeRgb = hexToRgb(mixColors(normalizedColor, "#FFFFFF", colorize ? 0.12 : 0.34)) || baseRgb;
  const highlightRgb = hexToRgb(mixColors(normalizedColor, "#FFF8EE", colorize ? 0.34 : 0.58)) || strokeRgb;
  const glowRgb = hexToRgb(mixColors(normalizedColor, "#000000", colorize ? 0.02 : 0.08)) || baseRgb;
  return {
    tint: rgbaString(baseRgb, 0.98),
    glow: rgbaString(glowRgb, colorize ? 0.2 : 0.16),
    fill: rgbaString(fillRgb, colorize ? clamp(fillOpacity + 0.08, 0, 1) : fillOpacity),
    stroke: rgbaString(strokeRgb, colorize ? 0.92 : 0.86),
    highlight: rgbaString(highlightRgb, colorize ? 0.28 : 0.34)
  };
}

function getOptionalBubbleOrbSprite() {
  return runtime.images.get(resolveAppUrl(OPTIONAL_BUBBLE_ORB_ASSET_PATH)) || null;
}

function getTintedBubbleOrbSprite(palette) {
  const sprite = getOptionalBubbleOrbSprite();
  if (!sprite?.width || !sprite?.height) {
    return null;
  }

  const cacheKey = [
    palette?.tint || "",
    palette?.stroke || "",
    palette?.highlight || ""
  ].join("|");
  const cached = runtime.bubbleOrbTintCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const canvas = document.createElement("canvas");
  canvas.width = sprite.width;
  canvas.height = sprite.height;
  const context = canvas.getContext("2d");
  if (!context) {
    return null;
  }

  context.clearRect(0, 0, canvas.width, canvas.height);
  context.drawImage(sprite, 0, 0, canvas.width, canvas.height);

  const tintColor = palette?.tint || palette?.stroke || palette?.fill || null;
  if (tintColor) {
    context.save();
    context.globalCompositeOperation = "source-in";
    context.fillStyle = tintColor;
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.restore();
  }

  if (palette?.stroke) {
    context.save();
    context.globalCompositeOperation = "screen";
    context.globalAlpha = 0.18;
    context.fillStyle = palette.stroke;
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.restore();
  }

  // Bring back a small amount of the source sprite so the result still reads as glass.
  context.save();
  context.globalCompositeOperation = "screen";
  context.globalAlpha = 0.1;
  context.drawImage(sprite, 0, 0, canvas.width, canvas.height);
  context.restore();

  if (palette?.highlight) {
    context.save();
    context.globalCompositeOperation = "screen";
    context.globalAlpha = 0.12;
    context.fillStyle = palette.highlight;
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.restore();
  }

  // Re-apply the source sprite alpha so tint passes cannot leak into the transparent bounds.
  context.save();
  context.globalCompositeOperation = "destination-in";
  context.drawImage(sprite, 0, 0, canvas.width, canvas.height);
  context.restore();

  runtime.bubbleOrbTintCache.set(cacheKey, canvas);
  return canvas;
}

function drawBubbleOrbInteriorFillToContext(context, x, y, radius, stretch, fillStyle, insetScale = 1) {
  if (!fillStyle) {
    return;
  }

  const innerRadius = Math.max(0, radius * insetScale);
  if (innerRadius <= 0) {
    return;
  }

  context.beginPath();
  context.ellipse(x, y, innerRadius * stretch, innerRadius, 0, 0, Math.PI * 2);
  context.fillStyle = fillStyle;
  context.fill();
}

function drawBubbleOrbInteriorFill(x, y, radius, stretch, fillStyle, insetScale = 1) {
  drawBubbleOrbInteriorFillToContext(tankContext, x, y, radius, stretch, fillStyle, insetScale);
}

function drawBubbleOrbToContext(context, x, y, radius, alpha, stretch = 1, palette = null, stableScale = getViewportStableAssetScale()) {
  const drawRadius = radius * stableScale;
  const resolvedPalette = palette || {
    tint: "rgba(255, 255, 255, 0.98)",
    glow: "rgba(220, 240, 255, 0.080)",
    fill: "rgba(255, 255, 255, 0.16)",
    stroke: "rgba(240, 250, 255, 0.700)",
    highlight: "rgba(250, 253, 255, 0.400)"
  };
  const bubbleSprite = getTintedBubbleOrbSprite(resolvedPalette);
  context.save();
  context.globalAlpha = alpha;
  if (!bubbleSprite && resolvedPalette.glow) {
    context.beginPath();
    context.ellipse(x, y, drawRadius * stretch * 1.45, drawRadius * 1.45, 0, 0, Math.PI * 2);
    context.fillStyle = resolvedPalette.glow;
    context.fill();
  }
  if (bubbleSprite) {
    const drawWidth = Math.max(2 * stableScale, drawRadius * stretch * 2.3);
    const drawHeight = Math.max(2 * stableScale, drawRadius * 2.3);
    drawBubbleOrbInteriorFillToContext(context, x, y, drawRadius, stretch, resolvedPalette.fill, 0.82);
    context.drawImage(bubbleSprite, x - drawWidth / 2, y - drawHeight / 2, drawWidth, drawHeight);
    context.restore();
    return;
  }
  context.beginPath();
  context.ellipse(x, y, drawRadius * stretch, drawRadius, 0, 0, Math.PI * 2);
  drawBubbleOrbInteriorFillToContext(context, x, y, drawRadius, stretch, resolvedPalette.fill);
  context.lineWidth = Math.max(stableScale, drawRadius * 0.18);
  context.strokeStyle = resolvedPalette.stroke;
  context.stroke();
  context.fillStyle = resolvedPalette.highlight;
  context.beginPath();
  context.ellipse(x - drawRadius * 0.3, y - drawRadius * 0.32, drawRadius * 0.2, drawRadius * 0.16, -0.2, 0, Math.PI * 2);
  context.fill();
  context.restore();
}

function drawBubbleOrb(x, y, radius, alpha, stretch = 1, palette = null) {
  drawBubbleOrbToContext(tankContext, x, y, radius, alpha, stretch, palette);
}

function getBubblerSpoutSourceOffsetRatio(imagePath, spout) {
  const cacheKey = `${imagePath}|${spout.horizontalLocation ?? ""}|${spout.horizontalOffsetPx ?? ""}`;
  const cached = runtime.bubblerSpoutOriginCache.get(cacheKey);
  if (Number.isFinite(cached)) {
    return cached;
  }

  const mask = getImageAlphaMask(imagePath);
  if (!mask?.width || !mask?.height) {
    runtime.bubblerSpoutOriginCache.set(cacheKey, 0.18);
    return 0.18;
  }

  const sampleX = Number.isFinite(spout.horizontalOffsetPx)
    ? clamp(Math.round(spout.horizontalOffsetPx), 0, mask.width - 1)
    : clamp(Math.round((spout.horizontalLocation ?? 0.5) * (mask.width - 1)), 0, mask.width - 1);
  let offsetRatio = 0.18;

  for (let y = 0; y < mask.height; y += 1) {
    const alpha = mask.alpha[(y * mask.width + sampleX) * 4 + 3];
    if (alpha >= ALPHA_HIT_THRESHOLD) {
      offsetRatio = clamp((y + 1) / mask.height, 0.02, 0.95);
      break;
    }
  }

  runtime.bubblerSpoutOriginCache.set(cacheKey, offsetRatio);
  return offsetRatio;
}

function getBubblerSpoutHorizontalLocation(spout, image = null) {
  const imageWidth = Math.max(1, Number(image?.width) || 0);
  return Number.isFinite(Number(spout?.horizontalLocation))
    ? clamp(Number(spout.horizontalLocation), 0, 1)
    : Number.isFinite(Number(spout?.horizontalOffsetPx)) && imageWidth > 0
      ? clamp(Number(spout.horizontalOffsetPx) / imageWidth, 0, 1)
      : 0.5;
}

function getBubblerDirectionVector(direction) {
  switch (normalizeBubblerDirection(direction)) {
    case "left":
      return { x: -1, y: -0.08 };
    case "right":
      return { x: 1, y: -0.08 };
    case "down":
      return { x: 0, y: 1 };
    case "up":
    default:
      return { x: 0, y: -1 };
  }
}

function drawDecorBubblerEffectToContext(context, item, decor, image, now = Date.now(), options = {}) {
  const bubbler = getPlacedDecorBubblerMeta(item, decor);
  if (!item || !decor || !image || !bubbler?.spouts?.length) {
    return;
  }

  const alphaScale = clamp(Number.isFinite(Number(options.alphaScale)) ? Number(options.alphaScale) : 1, 0, 1);
  const stableScale = clamp(Number.isFinite(Number(options.stableScale)) ? Number(options.stableScale) : getViewportStableAssetScale(), 0.25, 6);
  const width = Number.isFinite(Number(options.width)) ? Number(options.width) : getDecorDisplayWidth(decor, item);
  const height = Number.isFinite(Number(options.height)) ? Number(options.height) : width * (image.height / image.width);
  const drawX = Number.isFinite(Number(options.drawX)) ? Number(options.drawX) : (item.xNorm * TANK_WIDTH - width / 2);
  const drawY = Number.isFinite(Number(options.drawY)) ? Number(options.drawY) : (item.yNorm * TANK_HEIGHT - height);
  const waterSurfaceY = Number.isFinite(Number(options.waterSurfaceY)) ? Number(options.waterSurfaceY) : WATER_SURFACE_Y;

  bubbler.spouts.forEach((spout, spoutIndex) => {
    const spoutBubbleColors = Array.isArray(spout.bubbleColors) && spout.bubbleColors.length
      ? spout.bubbleColors
      : [spout.bubbleColor || DEFAULT_BUBBLER_BUBBLE_COLOR];
    const intensity = clamp(Number(spout.intensity) || DEFAULT_BUBBLER_INTENSITY, 0.15, MAX_BUBBLER_INTENSITY);
    const bubbleOpacity = clamp(Number(spout.bubbleOpacity) || DEFAULT_BUBBLER_BUBBLE_OPACITY, MIN_CUSTOM_BUBBLER_OPACITY, MAX_CUSTOM_BUBBLER_OPACITY);
    const bubbleSize = clamp(Number(spout.bubbleSize) || DEFAULT_CUSTOM_BUBBLER_BUBBLE_SIZE, MIN_CUSTOM_BUBBLER_BUBBLE_SIZE, MAX_CUSTOM_BUBBLER_BUBBLE_SIZE);
    const bubbleFillOpacity = clamp(Number.isFinite(Number(spout.bubbleFillOpacity)) ? Number(spout.bubbleFillOpacity) : DEFAULT_BUBBLER_FILL_OPACITY, 0, 1);
    const bubbleColorize = normalizeDecorColorizeSetting(spout.bubbleColorize);
    const spoutPalettes = spoutBubbleColors.map((color) => getBubbleOrbPalette(
      resolveDecorColorSettingForRender(color, now, DEFAULT_BUBBLER_BUBBLE_COLOR),
      {
        fillOpacity: bubbleFillOpacity,
        colorize: bubbleColorize
      }
    ));
    const speed = clamp(Number(spout.speed) || DEFAULT_BUBBLER_SPEED, MIN_BUBBLER_SPEED, MAX_BUBBLER_SPEED);
    const direction = normalizeBubblerDirection(spout.direction);
    const sourceLocation = getBubblerSpoutHorizontalLocation(spout, image);
    const renderedSourceLocation = resolveDecorHorizontalUnit(item, sourceLocation);
    const sourceX = drawX + width * renderedSourceLocation;
    const sourceYOffsetRatio = getBubblerSpoutSourceOffsetRatio(
      decor.path,
      {
        horizontalLocation: sourceLocation,
        horizontalOffsetPx: null
      }
    );
    const sourceY = drawY + height * sourceYOffsetRatio + Math.max(2 * stableScale, item.scale * 2 * stableScale);
    const spoutWidthPx = Math.max(0, spout.spread * item.scale * stableScale);
    const fadeDistancePx = Math.max(24 * stableScale, spout.fadeDistance * stableScale);
    const totalBubbleCount = clamp(
      Math.round(8 + intensity * 4.2 + spoutWidthPx / 18),
      8,
      MAX_BUBBLER_VISIBLE_BUBBLES_PER_SPOUT
    );
    const cadenceMs = clamp(
      getBubblerCadenceFromIntensity(intensity) / speed,
      MIN_BUBBLER_STREAM_CADENCE_MS,
      MAX_BUBBLER_STREAM_CADENCE_MS
    );
    const wobblePx = Math.min(2.1, 0.55 + intensity * 0.06) * stableScale;
    const availableTravelPx = Math.max(24, sourceY - (waterSurfaceY + 6));
    const renderedBubbles = [];

    for (let slotIndex = 0; slotIndex < totalBubbleCount; slotIndex += 1) {
      const slotSeed = hashStringToUint32(
        `${item.id}|${item.decorKey}|${spoutIndex}|slot|${slotIndex}`
      );
      const slotRand = mulberry32(slotSeed ^ 0x27d4eb2d);
      const slotCadenceMs = cadenceMs * randomBetweenWith(slotRand, 0.84, 1.16);
      const slotWobbleCadenceMs = Math.max(
        180,
        slotCadenceMs * randomBetweenWith(slotRand, 0.78, 1.28)
      );
      const slotPhaseOffset = randomBetweenWith(slotRand, 0, 1);
      const slotWobblePx = wobblePx * randomBetweenWith(slotRand, 0.45, 1.15);

      const rawPhase = (now / slotCadenceMs) + slotPhaseOffset;
      const emissionCycle = Math.floor(rawPhase);
      const phase = rawPhase - emissionCycle;
      const riseProgress = Math.pow(phase, 0.94);
      const emissionSeed = hashStringToUint32(
        `${item.id}|${item.decorKey}|${spoutIndex}|${slotIndex}|${emissionCycle}`
      );
      const emissionRand = mulberry32(emissionSeed ^ 0x5f3759df);
      const colorRand = mulberry32(emissionSeed ^ 0x85ebca6b);
      const depthRand = mulberry32(emissionSeed ^ 0x9e3779b9);
      const palette = spoutPalettes[
        clamp(Math.floor(randomBetweenWith(colorRand, 0, 1) * spoutPalettes.length), 0, spoutPalettes.length - 1)
      ] || spoutPalettes[0] || getBubbleOrbPalette(DEFAULT_BUBBLER_BUBBLE_COLOR);
      const depth = Math.pow(randomBetweenWith(depthRand, 0, 1), 0.88);
      const depthScale = 0.72 + depth * 0.52;
      const depthAlphaScale = 0.48 + depth * 0.74;
      const depthWobblePx = slotWobblePx * (0.58 + depth * 0.62);
      const spawnSpreadBias = (randomBetweenWith(emissionRand, -1, 1) + randomBetweenWith(emissionRand, -1, 1)) * 0.5;
      const spawnOffsetX = spawnSpreadBias * spoutWidthPx * 0.5;
      const trajectoryDriftPx = randomBetweenWith(emissionRand, -1, 1) * Math.min(4.5, spoutWidthPx * 0.2);
      const sway = Math.sin(
        now / (slotWobbleCadenceMs + (slotIndex % 5) * 24) + slotIndex * 0.93 + spoutIndex * 0.9
      ) * depthWobblePx
        + Math.sin(phase * 10.2 + slotIndex * 0.31) * depthWobblePx * 0.28;
      const travelPx = Math.min(
        fadeDistancePx * randomBetweenWith(emissionRand, 0.88, 1.06),
        availableTravelPx
      );
      const turnRatio = clamp(0.16 + speed * 0.1, 0.2, 0.56);
      const turnProgress = clamp(riseProgress / Math.max(0.0001, turnRatio), 0, 1);
      const upwardProgress = Math.pow(
        clamp((riseProgress - turnRatio) / Math.max(0.0001, 1 - turnRatio), 0, 1),
        0.86
      );
      const turnDistancePx = Math.min(
        travelPx * turnRatio,
        (20 + speed * 26) * stableScale
      );
      const directionVector = getBubblerDirectionVector(direction);
      const directionEase = Math.sin(turnProgress * Math.PI * 0.5);
      const directionalX = directionVector.x * turnDistancePx * directionEase;
      const directionalY = directionVector.y * turnDistancePx * directionEase;
      const upwardTravelPx = upwardProgress * (travelPx + Math.max(0, directionalY));
      const x = sourceX + spawnOffsetX + directionalX + trajectoryDriftPx * riseProgress + sway * (0.64 + upwardProgress * 0.5);
      const y = sourceY + directionalY - upwardTravelPx;

      const spawnFade = phase < 0.08 ? phase / 0.08 : 1;
      const fadeWindowPx = clamp(travelPx * 0.34, 26 * stableScale, 110 * stableScale);
      const fadeStartProgress = clamp(1 - fadeWindowPx / Math.max(1, travelPx), 0.35, 0.92);
      const distanceFade = riseProgress <= fadeStartProgress
        ? 1
        : Math.pow(clamp(1 - (riseProgress - fadeStartProgress) / Math.max(0.0001, 1 - fadeStartProgress), 0, 1), 1.8);
      const alpha = clamp(
        (0.16 + intensity * 0.018) * distanceFade * spawnFade * alphaScale * bubbleOpacity * depthAlphaScale,
        0,
        1
      );
      if (alpha <= 0.008) {
        continue;
      }

      const sizeBias = Math.pow(randomBetweenWith(emissionRand, 0, 1), 1.45);
      const occasionalLargeBubble = randomBetweenWith(emissionRand, 0, 1) > 0.9 ? 1.18 : 1;
      const radiusMin = (0.95 + intensity * 0.03) * bubbleSize;
      const radiusMax = (1.65 + intensity * 0.08 + Math.min(0.8, spoutWidthPx * 0.02)) * bubbleSize;
      const radius = clamp(
        (radiusMin + (radiusMax - radiusMin) * sizeBias) * occasionalLargeBubble,
        0.45,
        12
      );
      const fadeScale = 0.72 + distanceFade * 0.28;
      const fadedRadius = radius * fadeScale * depthScale;
      const stretch = 1
        + riseProgress * 0.2
        + Math.min(0.34, intensity * 0.015)
        + depth * 0.06
        + randomBetweenWith(emissionRand, -0.04, 0.06);
      renderedBubbles.push({
        depth,
        x,
        y,
        radius: fadedRadius,
        alpha,
        stretch,
        palette
      });
    }

    renderedBubbles
      .sort((left, right) => left.depth - right.depth || left.y - right.y)
      .forEach((bubble) => {
        drawBubbleOrbToContext(context, bubble.x, bubble.y, bubble.radius, bubble.alpha, bubble.stretch, bubble.palette, stableScale);
      });
  });
}

function drawDecorBubblerEffect(item, decor, image, now = Date.now(), options = {}) {
  drawDecorBubblerEffectToContext(tankContext, item, decor, image, now, options);
}

function drawDecorBubbleStreams(now) {
  if (!state.placedDecor.length) {
    return;
  }

  const stableScale = getViewportStableAssetScale();
  for (const item of state.placedDecor) {
    if (isBubblerDecorKey(item.decorKey)) {
      continue;
    }

    const decor = runtime.decorMap.get(item.decorKey);
    const image = decor ? runtime.images.get(decor.path) : null;
    if (!decor || !image) {
      continue;
    }

    const intensity = getDecorBubbleIntensity(item.decorKey);
    if (intensity <= 0) {
      continue;
    }

    const width = getDecorDisplayWidth(decor, item);
    const height = width * (image.height / image.width);
    const sourceX = item.xNorm * TANK_WIDTH;
    const sourceY = item.yNorm * TANK_HEIGHT - height * 0.2;
    const streamCount = intensity >= 1.3 ? 2 : 1;

    for (let streamIndex = 0; streamIndex < streamCount; streamIndex += 1) {
      const laneOffset = (streamIndex - (streamCount - 1) / 2) * (12 * stableScale + width * 0.03);
      const bubbleCount = 2 + Math.round(intensity);
      for (let bubbleIndex = 0; bubbleIndex < bubbleCount; bubbleIndex += 1) {
        const cycle = (now / 1000) * (0.055 + bubbleIndex * 0.008 + streamIndex * 0.006) + item.xNorm * 7 + bubbleIndex * 0.19;
        const progress = cycle % 1;
        const x = sourceX + laneOffset + Math.sin(cycle * 8) * (3.2 + bubbleIndex * 0.9) * stableScale;
        const y = sourceY - progress * (70 + bubbleIndex * 28 + intensity * 12) * stableScale;
        if (y <= WATER_SURFACE_Y + 6) {
          continue;
        }

        const radius = 1.8 + bubbleIndex * 0.7;
        drawBubbleOrb(x, y, radius, 0.14 + bubbleIndex * 0.05, 1);
      }
    }
  }
}

function getDecorBubbleIntensity(decorKey) {
  const key = decorKey.toLowerCase();
  if (/(coral|seaweed|grass|moss|anubias|bloom|bunch)/.test(key)) {
    return 1.45;
  }
  if (/(castle|cave|terracotta|pagoda|bridge|arch)/.test(key)) {
    return 1.05;
  }
  if (/(rock|driftwood|chest|shell)/.test(key)) {
    return 0.6;
  }
  return 0.35;
}

function getBubbleSpriteByIndex(index) {
  const overrideSprite = getOptionalBubbleOrbSprite();
  if (overrideSprite) {
    return overrideSprite;
  }

  if (!runtime.bubbleCatalog.length) {
    return null;
  }

  const item = runtime.bubbleCatalog[index % runtime.bubbleCatalog.length];
  return item ? runtime.images.get(item.path) : null;
}

function getPoopPose(poop, now = Date.now()) {
  if (!poop) {
    return null;
  }

  const poopSprite = runtime.images.get(poop.asset || resolveAppUrl(POOP_ASSET_PATH));
  if (!poopSprite) {
    return null;
  }

  const sinkProgress = clamp((now - poop.createdAt) / POOP_FALL_MS, 0, 1);
  const x = poop.xNorm * TANK_WIDTH + Math.sin(now / 520 + poop.xNorm * 11) * (1 - sinkProgress) * 6;
  const width = POOP_DRAW_WIDTH_PX;
  const height = width * (poopSprite.height / Math.max(1, poopSprite.width));
  const targetYNorm = Number.isFinite(Number(poop.tankLayer))
    ? getPoopLayerTargetYNorm(poop, poopSprite, width)
    : (Number.isFinite(Number(poop.yNorm)) ? Number(poop.yNorm) : getPoopFloorYNormAtXNorm(poop.xNorm));
  const startYNorm = Math.min(
    clamp(Number(poop.startYNorm) || 0.54, 0.14, 0.82),
    Math.max(0.14, targetYNorm - 0.012)
  );
  const y = (startYNorm + (targetYNorm - startYNorm) * sinkProgress) * TANK_HEIGHT;
  const wobble = Math.sin(now / 720 + poop.xNorm * 17) * (1 - sinkProgress) * 0.12;

  return {
    x,
    y,
    wobble,
    width,
    height,
    sprite: poopSprite,
    left: x - width / 2,
    right: x + width / 2,
    top: y + 4 - height * 0.88,
    bottom: y + 4 + height * 0.12
  };
}

function findFloatingPelletAtPoint(x, y, now = Date.now()) {
  const pellets = [...state.floatingPellets].reverse();
  for (const pellet of pellets) {
    const bounds = getPelletHitBounds(pellet, now);
    if (!bounds) {
      continue;
    }

    const padding = pellet.foodKey === "chum" ? 7 : 5;
    if (
      x >= bounds.left - padding
      && x <= bounds.right + padding
      && y >= bounds.top - padding
      && y <= bounds.bottom + padding
    ) {
      return pellet;
    }
  }

  return null;
}

function findPoopAtPoint(x, y, now = Date.now()) {
  const poops = [...state.poops].reverse();
  for (const poop of poops) {
    const pose = getPoopPose(poop, now);
    if (!pose) {
      continue;
    }

    const padding = 6;
    if (
      x >= pose.left - padding
      && x <= pose.right + padding
      && y >= pose.top - padding
      && y <= pose.bottom + padding
    ) {
      return poop;
    }
  }

  return null;
}

function getAutoDispenserLayout() {
  const stableScale = getViewportStableAssetScale();
  const dispenserScale = stableScale * AUTO_DISPENSER_VIEWPORT_SIZE_MULTIPLIER;
  const width = AUTO_DISPENSER_DRAW_WIDTH * dispenserScale;
  const height = AUTO_DISPENSER_DRAW_HEIGHT * dispenserScale;
  const visibleBounds = getVisibleTankVirtualBounds();
  const x = TANK_WIDTH * 0.5 - width / 2;
  const y = visibleBounds.top - getViewportPxAsTankVirtual(AUTO_DISPENSER_TOP_MOUNT_OVERHANG_PX);
  const screenWidth = width * 0.12;
  const screenHeight = height * 0.2;
  const screenLeft = x + width * 0.72;
  const screenTop = y + height * 0.23;
  const buttonSize = height * 0.18;
  const buttonTop = screenTop + (screenHeight - buttonSize) / 2;
  const resetWidth = width * 0.085;
  const playWidth = width * 0.095;
  const lowerButtonGap = width * 0.012;
  const lowerButtonsWidth = resetWidth + lowerButtonGap + playWidth;
  const resetHeight = height * 0.13;
  const resetLeft = screenLeft + (screenWidth - lowerButtonsWidth) / 2;
  const resetTop = screenTop + screenHeight + height * 0.022;
  const playLeft = resetLeft + resetWidth + lowerButtonGap;

  return {
    x,
    y,
    scale: dispenserScale,
    width,
    height,
    bodyBounds: {
      left: x,
      right: x + width,
      top: y,
      bottom: y + height
    },
    hopperBounds: {
      left: x + width * 0.085,
      right: x + width * 0.53,
      top: y + height * 0.225,
      bottom: y + height * 0.515
    },
    screenBounds: {
      left: screenLeft,
      right: screenLeft + screenWidth,
      top: screenTop,
      bottom: screenTop + screenHeight
    },
    minusBounds: {
      left: screenLeft - buttonSize - width * 0.018,
      right: screenLeft - width * 0.018,
      top: buttonTop,
      bottom: buttonTop + buttonSize
    },
    plusBounds: {
      left: screenLeft + screenWidth + width * 0.018,
      right: screenLeft + screenWidth + width * 0.018 + buttonSize,
      top: buttonTop,
      bottom: buttonTop + buttonSize
    },
    resetBounds: {
      left: resetLeft,
      right: resetLeft + resetWidth,
      top: resetTop,
      bottom: resetTop + resetHeight
    },
    playBounds: {
      left: playLeft,
      right: playLeft + playWidth,
      top: resetTop,
      bottom: resetTop + resetHeight
    },
    nozzle: {
      x: x + width * 0.5,
      y: y + height * 0.77
    }
  };
}

function pointInSimpleBounds(x, y, bounds) {
  return Boolean(
    bounds
    && x >= bounds.left
    && x <= bounds.right
    && y >= bounds.top
    && y <= bounds.bottom
  );
}

function expandBoundsAroundCenter(bounds, scale = 1) {
  if (!bounds || !Number.isFinite(Number(scale)) || scale <= 1) {
    return bounds || null;
  }

  const centerX = (bounds.left + bounds.right) / 2;
  const centerY = (bounds.top + bounds.bottom) / 2;
  const halfWidth = ((bounds.right - bounds.left) * scale) / 2;
  const halfHeight = ((bounds.bottom - bounds.top) * scale) / 2;
  return {
    left: centerX - halfWidth,
    right: centerX + halfWidth,
    top: centerY - halfHeight,
    bottom: centerY + halfHeight
  };
}

function getAutoDispenserHitTarget(x, y) {
  if (!hasAutoDispenserInstalled()) {
    return "";
  }

  const layout = getAutoDispenserLayout();
  if (!pointInSimpleBounds(x, y, layout.bodyBounds)) {
    return "";
  }
  if (pointInSimpleBounds(x, y, layout.minusBounds)) {
    return "minus";
  }
  if (pointInSimpleBounds(x, y, layout.plusBounds)) {
    return "plus";
  }
  if (pointInSimpleBounds(x, y, layout.resetBounds)) {
    return "reset";
  }
  if (pointInSimpleBounds(x, y, layout.playBounds)) {
    return "play";
  }
  return "body";
}

function handleAutoDispenserInteractionAtPoint(point, now = Date.now()) {
  if (!point || !hasAutoDispenserInstalled()) {
    return false;
  }

  const hitTarget = getAutoDispenserHitTarget(point.x, point.y);
  if (!hitTarget) {
    return false;
  }

  if (hitTarget === "minus") {
    adjustAutoDispenserMealPortion(-1, now);
    return true;
  }

  if (hitTarget === "plus") {
    adjustAutoDispenserMealPortion(1, now);
    return true;
  }

  if (hitTarget === "reset") {
    openAutoDispenserResetConfirmation();
    return true;
  }

  if (hitTarget === "play") {
    dispenseAutoDispenserNow(now);
    return true;
  }

  if (runtime.medicineModeKey) {
    showToast("Only food can be loaded into the pellet dispenser.");
    return true;
  }

  return loadSelectedFoodIntoAutoDispenser(now);
}

function scoopTankItemAtPoint(x, y, now = Date.now()) {
  const pellet = findFloatingPelletAtPoint(x, y, now);
  if (pellet) {
    state.floatingPellets = state.floatingPellets.filter((entry) => entry.id !== pellet.id);
    runtime.chumBloodCloudAtByPelletId?.delete?.(pellet.id);
    for (const fish of state.fish) {
      if (fish.feedingPelletId === pellet.id) {
        fish.feedingPelletId = null;
      }
    }
    assignFloatingPelletsToHungryFish(now);
    return {
      kind: "food",
      label: pellet.foodKey === "chum" ? "Chum scooped out." : "Soggy food scooped out."
    };
  }

  const poop = findPoopAtPoint(x, y, now);
  if (poop) {
    state.poops = state.poops.filter((entry) => entry.id !== poop.id);
    return {
      kind: "poop",
      label: "Waste scooped out."
    };
  }

  const fish = findFishAtPoint(x, y, now);
  if (fish) {
    storeFish(fish.id, { allowDead: true });
    return {
      kind: "fish",
      label: ""
    };
  }

  return null;
}

function handleScoopAtPoint(point, now = Date.now()) {
  if (!point) {
    return false;
  }

  const scoopResult = scoopTankItemAtPoint(point.x, point.y, now);
  if (!scoopResult) {
    return false;
  }

  if (scoopResult.label) {
    saveState();
    renderUi(now);
    showToast(scoopResult.label);
  }

  return true;
}

function findFishAtPoint(x, y, now) {
  const sortedFish = [...state.fish].sort((left, right) => {
    if (getFishTankLayer(left) !== getFishTankLayer(right)) {
      return getFishTankLayer(left) - getFishTankLayer(right);
    }
    return right.yNorm - left.yNorm;
  });
  for (const fish of sortedFish) {
    const species = getSpeciesForFish(fish);
    const descriptor = species ? getFishShapeDescriptor(fish, species, now) : null;
    if (descriptor && pointHitsShapeDescriptor(descriptor, x, y)) {
      return fish;
    }
  }

  return null;
}

function getUndeadComfortPenalty(fish) {
  if (!fish || isUndeadFish(fish) || !isGoreEnabled()) {
    return 0;
  }

  const undeadNeighbors = state.fish.filter((otherFish) => (
    otherFish
    && otherFish.id !== fish.id
    && !isFishDead(otherFish)
    && isUndeadFish(otherFish)
  )).length;
  return clamp(undeadNeighbors * UNDEAD_COMFORT_PENALTY, 0, MAX_UNDEAD_COMFORT_PENALTY);
}

function getFishComfort(fish, now) {
  if (isFishDead(fish)) {
    return { value: 0, label: "Deceased" };
  }

  if (hasActiveTankMedicineEffect("betaBlocker", now)) {
    return { value: 1, label: "Calm" };
  }

  if (isUndeadFish(fish) && isGoreEnabled()) {
    return { value: 1, label: "Undead" };
  }

  const dirtiness = getTankDirtiness(now);
  if (hasExposedDeadTankFish(now) || dirtiness >= CRITICAL_TANK_DIRTINESS) {
    return { value: 0, label: "Critical" };
  }

  const cleanlinessScore = clamp(1 - dirtiness * 1.08, 0, 1);
  const healthScore = getFishHealthRatio(fish);
  const servedToday = getTodaysMealSlots(now).filter((slot) => isMealSlotServed(slot)).length / 2;
  const decorScore = clamp(state.placedDecor.length / Math.max(1, state.fish.length + 1), 0, 1);
  const filterBoost = getFilterProfile().comfortBoost;
  const undeadPenalty = getUndeadComfortPenalty(fish);
  const comfortValue = clamp(
    healthScore * 0.38
    + cleanlinessScore * 0.34
    + servedToday * 0.12
    + decorScore * 0.08
    + filterBoost
    - undeadPenalty,
    0,
    1
  );
  const label = comfortValue >= 0.84
    ? "Cozy"
    : comfortValue >= 0.64
      ? "Content"
      : comfortValue >= 0.4
        ? "Uneasy"
        : comfortValue >= 0.16
          ? "Stressed"
          : "Panicked";
  return { value: comfortValue, label };
}

function formatFishAge(acquiredAt, now = Date.now()) {
  const diff = Math.max(0, now - acquiredAt);
  const days = Math.floor(diff / DAY_MS);
  if (days >= 1) {
    const hours = Math.floor((diff % DAY_MS) / HOUR_MS);
    return hours > 0 ? `${days}d ${hours}h` : `${days}d`;
  }

  const hours = Math.floor(diff / HOUR_MS);
  if (hours >= 1) {
    const minutes = Math.floor((diff % HOUR_MS) / MINUTE_MS);
    return minutes > 0 ? `${hours}h ${minutes}m` : `${hours}h`;
  }

  const minutes = Math.floor(diff / MINUTE_MS);
  if (minutes >= 1) {
    return `${minutes}m`;
  }

  return `${Math.floor(diff / 1000)}s`;
}

function clampDecorPlacement(xNorm, yNorm, options = {}) {
  const shellBounds = getTankShellBounds();
  const minXNorm = shellBounds.innerLeft / TANK_WIDTH;
  const maxXNorm = (shellBounds.innerLeft + shellBounds.innerWidth) / TANK_WIDTH;
  const minYNorm = shellBounds.innerTop / TANK_HEIGHT;
  const maxYNorm = (shellBounds.innerTop + shellBounds.innerHeight) / TANK_HEIGHT;
  const normalizedX = clamp(Number.isFinite(Number(xNorm)) ? Number(xNorm) : 0.5, 0, 1);
  const normalizedY = clamp(Number.isFinite(Number(yNorm)) ? Number(yNorm) : 0.8, 0, 1);
  const decorKey = options.item?.decorKey || options.decorKey || runtime.placementMode?.decorKey || null;
  const resolvedLayer = decorKey
    ? getDecorFrontLayer(
      decorKey,
      options.item?.tankLayer
      ?? options.tankLayer
      ?? runtime.placementMode?.tankLayer
      ?? runtime.decorPlacementLayer
      ?? DEFAULT_TANK_LAYER
    )
    : DEFAULT_TANK_LAYER;
  const layerBoundaryY = getTankLayerBottomBoundaryY(resolvedLayer);
  const layerBoundaryYNorm = layerBoundaryY / TANK_HEIGHT;
  const effectiveMaxYNorm = Math.max(minYNorm, Math.min(maxYNorm, layerBoundaryYNorm));

  if (!decorKey) {
    const constrained = constrainNormalizedPointToTankShell(
      clamp(normalizedX, minXNorm, maxXNorm),
      clamp(normalizedY, minYNorm, effectiveMaxYNorm)
    );
    return {
      xNorm: clamp(constrained.xNorm, minXNorm, maxXNorm),
      yNorm: clamp(constrained.yNorm, minYNorm, effectiveMaxYNorm)
    };
  }

  const resolvedScale = clamp(
    Number.isFinite(Number(options.item?.scale))
      ? Number(options.item.scale)
      : Number.isFinite(Number(options.scale))
        ? Number(options.scale)
        : Number.isFinite(Number(runtime.placementMode?.scale))
          ? Number(runtime.placementMode.scale)
          : getDecorScaleDefault(decorKey),
    DECOR_SCALE_MIN,
    DECOR_SCALE_MAX
  );
  const resolvedFlipped = options.item && Object.prototype.hasOwnProperty.call(options.item, "flipped")
    ? Boolean(options.item.flipped)
    : (Object.prototype.hasOwnProperty.call(options, "flipped")
      ? Boolean(options.flipped)
      : Boolean(runtime.placementMode?.flipped));
  const candidate = {
    ...(options.item || {}),
    decorKey,
    scale: resolvedScale,
    flipped: resolvedFlipped,
    tankLayer: resolvedLayer,
    xNorm: normalizedX,
    yNorm: normalizedY
  };
  const placementBounds = getPlacedDecorPlacementBounds(candidate);
  if (!placementBounds) {
    const constrained = constrainNormalizedPointToTankShell(
      clamp(normalizedX, minXNorm, maxXNorm),
      clamp(normalizedY, minYNorm, effectiveMaxYNorm)
    );
    return {
      xNorm: clamp(constrained.xNorm, minXNorm, maxXNorm),
      yNorm: clamp(constrained.yNorm, minYNorm, effectiveMaxYNorm)
    };
  }

  const anchorX = normalizedX * TANK_WIDTH;
  const anchorY = normalizedY * TANK_HEIGHT;
  const relLeft = placementBounds.left - anchorX;
  const relRight = placementBounds.right - anchorX;
  const relTop = placementBounds.top - anchorY;
  const relBottom = placementBounds.bottom - anchorY;
  const relBounds = { left: relLeft, right: relRight, top: relTop, bottom: relBottom };
  const minAnchorX = shellBounds.innerLeft - relLeft;
  const maxAnchorX = shellBounds.innerLeft + shellBounds.innerWidth - relRight;
  const minAnchorY = getDecorTopOverhangLimitY(relBounds, shellBounds) - relTop;
  const maxAnchorY = Math.min(
    shellBounds.innerTop + shellBounds.innerHeight - relBottom,
    layerBoundaryY - relBottom
  );
  const clampedX = minAnchorX <= maxAnchorX
    ? clamp(anchorX, minAnchorX, maxAnchorX)
    : (minAnchorX + maxAnchorX) / 2;
  const clampedY = minAnchorY <= maxAnchorY
    ? clamp(anchorY, minAnchorY, maxAnchorY)
    : maxAnchorY;

  const constrained = constrainNormalizedPointToTankShell(
    clamp(clampedX / TANK_WIDTH, minXNorm, maxXNorm),
    clamp(clampedY / TANK_HEIGHT, minYNorm, maxYNorm)
  );
  return {
    xNorm: clamp(constrained.xNorm, minXNorm, maxXNorm),
    yNorm: clamp(clampedY / TANK_HEIGHT, minYNorm, maxYNorm)
  };
}

function findPlacedDecorAtPoint(x, y) {
  const sorted = [...state.placedDecor].sort(comparePlacedDecorHitOrder);
  for (const item of sorted) {
    if (isCustomBubblerDecorKey(item.decorKey)) {
      const hitBounds = getCustomBubblerHitBounds(item);
      if (pointInSimpleBounds(x, y, hitBounds)) {
        return item;
      }
    }

    const descriptor = getDecorShapeDescriptor(item);
    if (descriptor && pointHitsShapeDescriptor(descriptor, x, y)) {
      return item;
    }
  }

  return null;
}

function getCustomBubblerHitBounds(item) {
  if (!item || !isCustomBubblerDecorKey(item.decorKey)) {
    return null;
  }

  return expandBoundsAroundCenter(getPlacedDecorBounds(item), CUSTOM_BUBBLER_HIT_SCALE);
}

function getPlacedDecorBounds(item) {
  const decor = runtime.decorMap.get(item.decorKey);
  if (!decor) {
    return null;
  }

  const image = runtime.images.get(decor.path);
  const width = getDecorDisplayWidth(decor, item);
  const height = width * (image ? image.height / image.width : 1);
  const x = item.xNorm * TANK_WIDTH;
  const y = item.yNorm * TANK_HEIGHT;

  return {
    left: x - width / 2,
    right: x + width / 2,
    top: y - height,
    bottom: y
  };
}

function getDecorVisibleImagePaths(decor) {
  if (!decor) {
    return [];
  }

  return [...new Set([
    decor.bgPath,
    decor.path,
    decor.midPath
  ].filter(Boolean))];
}

function getPlacedDecorOpaqueBoundsForImagePath(item, decor, imagePath) {
  const image = runtime.images.get(imagePath);
  const mask = getImageAlphaMask(imagePath);
  if (!image || !mask) {
    return null;
  }

  const width = getDecorDisplayWidth(decor, item);
  const height = width * (image.height / image.width);
  const x = item.xNorm * TANK_WIDTH;
  const y = item.yNorm * TANK_HEIGHT;
  const left = x - width / 2;
  const top = y - height;
  const minU = mask.bounds.minX / image.width;
  const maxU = (mask.bounds.maxX + 1) / image.width;
  const mappedMinU = resolveDecorHorizontalUnit(item, minU);
  const mappedMaxU = resolveDecorHorizontalUnit(item, maxU);

  return {
    left: left + Math.min(mappedMinU, mappedMaxU) * width,
    right: left + Math.max(mappedMinU, mappedMaxU) * width,
    top: top + (mask.bounds.minY / image.height) * height,
    bottom: top + ((mask.bounds.maxY + 1) / image.height) * height
  };
}

function getPlacedDecorOpaqueBounds(item, imagePathOverride = null) {
  const decor = runtime.decorMap.get(item?.decorKey);
  if (!decor) {
    return null;
  }

  const imagePaths = imagePathOverride
    ? [imagePathOverride]
    : getDecorVisibleImagePaths(decor);
  if (!imagePaths.length) {
    return getPlacedDecorBounds(item);
  }

  let mergedBounds = null;
  for (const imagePath of imagePaths) {
    const bounds = getPlacedDecorOpaqueBoundsForImagePath(item, decor, imagePath);
    if (!bounds) {
      continue;
    }

    if (!mergedBounds) {
      mergedBounds = { ...bounds };
      continue;
    }

    mergedBounds.left = Math.min(mergedBounds.left, bounds.left);
    mergedBounds.right = Math.max(mergedBounds.right, bounds.right);
    mergedBounds.top = Math.min(mergedBounds.top, bounds.top);
    mergedBounds.bottom = Math.max(mergedBounds.bottom, bounds.bottom);
  }

  return mergedBounds || getPlacedDecorBounds(item);
}

function getDecorShapeDescriptor(item, imagePathOverride = null) {
  const decor = runtime.decorMap.get(item?.decorKey);
  if (!decor) {
    return null;
  }

  const imagePath = imagePathOverride || decor.path;
  const image = runtime.images.get(imagePath);
  const mask = getImageAlphaMask(imagePath);
  if (!image || !mask) {
    return null;
  }

  return createDecorShapeDescriptorFromMask(item, decor, imagePath, mask);
}

function localDecorPointToTankNorm(item, localX, localY) {
  const bounds = getPlacedDecorBounds(item);
  if (!bounds) {
    return null;
  }

  const clampedX = resolveDecorHorizontalUnit(item, clamp(localX, 0.02, 0.98));
  const clampedY = clamp(localY, 0.02, 0.98);
  const worldX = bounds.left + (bounds.right - bounds.left) * clampedX;
  const worldY = bounds.top + (bounds.bottom - bounds.top) * clampedY;

  return {
    x: worldX,
    y: worldY,
    xNorm: clamp(worldX / TANK_WIDTH, 0.08, 0.92),
    yNorm: clamp(worldY / TANK_HEIGHT, 0.14, 0.8)
  };
}

function resolveOpenCavePoint(
  item,
  seedX,
  seedY,
  frontDescriptor,
  barrierDescriptor,
  fish = null,
  species = null,
  now = Date.now(),
  options = {}
) {
  const rangeX = Math.max(0.02, Number(options.rangeX) || 0.12);
  const rangeY = Math.max(0.02, Number(options.rangeY) || 0.1);
  const step = Math.max(0.01, Number(options.step) || 0.02);
  const allowFallback = options.allowFallback !== false;
  const barrierMode = options.barrierMode === "hit"
    ? "hit"
    : options.barrierMode === "clear"
      ? "clear"
      : "either";
  let bestPoint = null;
  let bestScore = Number.POSITIVE_INFINITY;

  for (let dy = -rangeY; dy <= rangeY + 0.0001; dy += step) {
    for (let dx = -rangeX; dx <= rangeX + 0.0001; dx += step) {
      const localX = clamp(seedX + dx, 0.08, 0.92);
      const localY = clamp(seedY + dy, 0.18, 0.9);
      const point = localDecorPointToTankNorm(item, localX, localY);
      if (!point) {
        continue;
      }

      if (frontDescriptor && pointHitsShapeDescriptor(frontDescriptor, point.x, point.y, ALPHA_COLLISION_THRESHOLD)) {
        continue;
      }

      const hitsBarrier = barrierDescriptor
        ? pointHitsShapeDescriptor(barrierDescriptor, point.x, point.y, ALPHA_COLLISION_THRESHOLD)
        : false;

      if (barrierMode === "hit" && !hitsBarrier) {
        continue;
      }

      if (barrierMode === "clear" && hitsBarrier) {
        continue;
      }

      if (fish && species) {
        const direction = Math.abs(point.xNorm - fish.xNorm) > 0.001
          ? (point.xNorm >= fish.xNorm ? 1 : -1)
          : (fish.direction || 1);
        const pose = getFishCollisionPose(fish, species, now, point.xNorm, point.yNorm, direction);
        const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
        if (!fishDescriptor) {
          continue;
        }

        if (
          (frontDescriptor && shapesOverlapByMaskStrict(fishDescriptor, frontDescriptor, CAVE_STRICT_SAMPLE_STEP_PX)) ||
          (barrierMode === "clear" && barrierDescriptor && shapesOverlapByMaskStrict(fishDescriptor, barrierDescriptor, CAVE_STRICT_SAMPLE_STEP_PX))
        ) {
          continue;
        }

        if (barrierMode === "hit" && barrierDescriptor && !shapeContainedByMaskStrict(barrierDescriptor, fishDescriptor, CAVE_STRICT_SAMPLE_STEP_PX)) {
          continue;
        }
      }

      const score = Math.abs(dx) + Math.abs(dy) * 1.35 + Math.hypot(dx, dy) * 0.4;
      if (score < bestScore) {
        bestScore = score;
        bestPoint = point;
      }
    }
  }

  return bestPoint || (allowFallback ? localDecorPointToTankNorm(item, seedX, seedY) : null);
}

function resolveCaveInteriorPoint(item, fish, species, now, frontDescriptor, barrierDescriptor) {
  if (!item || !fish || !species || !barrierDescriptor?.bounds) {
    return null;
  }

  const centerX = (barrierDescriptor.bounds.left + barrierDescriptor.bounds.right) / 2;
  const centerY = (barrierDescriptor.bounds.top + barrierDescriptor.bounds.bottom) / 2;
  const half = CAVE_CENTER_TARGET_SIZE_PX / 2;
  const minX = Math.max(barrierDescriptor.bounds.left, centerX - half);
  const maxX = Math.min(barrierDescriptor.bounds.right, centerX + half);
  const minY = Math.max(barrierDescriptor.bounds.top, centerY - half);
  const maxY = Math.min(barrierDescriptor.bounds.bottom, centerY + half);
  let bestPoint = null;
  let bestScore = Number.POSITIVE_INFINITY;

  for (let y = minY; y <= maxY + 0.1; y += 5) {
    for (let x = minX; x <= maxX + 0.1; x += 5) {
      const xNorm = clamp(x / TANK_WIDTH, 0.08, 0.92);
      const yNorm = clamp(y / TANK_HEIGHT, 0.14, 0.8);
      const direction = Math.abs(xNorm - fish.xNorm) > 0.001
        ? (xNorm >= fish.xNorm ? 1 : -1)
        : (fish.direction || 1);
      const pose = getFishCollisionPose(fish, species, now, xNorm, yNorm, direction);
      const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
      if (!fishDescriptor) {
        continue;
      }

      if (frontDescriptor && shapesOverlapByMask(fishDescriptor, frontDescriptor, 5)) {
        continue;
      }

      if (!shapeContainedByMask(barrierDescriptor, fishDescriptor, 5)) {
        continue;
      }

      const score = Math.hypot(x - centerX, y - centerY);
      if (score >= bestScore) {
        continue;
      }

      bestScore = score;
      bestPoint = {
        x,
        y,
        xNorm,
        yNorm
      };
    }
  }

  return bestPoint;
}

function retargetFishCaveBehavior(fish, species, now = Date.now()) {
  if (!fish?.caveState || !fish.caveDecorId || !species || species.behavior === "sucker") {
    return false;
  }

  const decor = getCaveBehaviorDecorById(fish.caveDecorId);
  if (!decor) {
    return false;
  }

  const plan = buildCaveNavigationPlan(decor, fish, now);
  if (!plan) {
    return false;
  }

  fish.cavePortalId = plan.portalId;
  fish.caveFrontLayer = clampTankLayer(plan.frontLayer);
  fish.caveBackLayer = clampTankLayer(plan.backLayer);
  fish.caveApproachXNorm = plan.approach.xNorm;
  fish.caveApproachYNorm = plan.approach.yNorm;
  fish.caveEntryXNorm = plan.mouth.xNorm;
  fish.caveEntryYNorm = plan.mouth.yNorm;
  fish.caveInsideXNorm = plan.inside.xNorm;
  fish.caveInsideYNorm = plan.inside.yNorm;
  fish.caveInsideUntil = Math.max(Number(fish.caveInsideUntil) || 0, now + 2600);
  fish.hangoutDecorId = plan.decorId;

  if (fish.caveState === "approach") {
    fish.targetXNorm = plan.approach.xNorm;
    fish.targetYNorm = plan.approach.yNorm;
    fish.targetAt = now + 1800 + Math.hypot(fish.xNorm - plan.approach.xNorm, fish.yNorm - plan.approach.yNorm) * 16000;
    setFishDesiredTankLayer(fish, plan.frontLayer);
    return true;
  }

  if (fish.caveState === "align") {
    fish.targetXNorm = plan.mouth.xNorm;
    fish.targetYNorm = plan.mouth.yNorm;
    fish.targetAt = now + 1800 + Math.hypot(fish.xNorm - plan.mouth.xNorm, fish.yNorm - plan.mouth.yNorm) * 14000;
    setFishDesiredTankLayer(fish, plan.frontLayer);
    return true;
  }

  if (fish.caveState === "enter") {
    const nodeIndex = Number.isFinite(fish.cavePathIndex) ? fish.cavePathIndex : 0;
    const node = plan.entryPathNodes[nodeIndex] || plan.inside;
    fish.targetXNorm = node.xNorm;
    fish.targetYNorm = node.yNorm;
    fish.targetAt = now + 2200 + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 14000;
    setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, plan.backLayer));
    return true;
  }

  if (fish.caveState === "inside") {
    fish.targetXNorm = plan.inside.xNorm;
    fish.targetYNorm = plan.inside.yNorm;
    fish.targetAt = Math.max(Number(fish.caveInsideUntil) || 0, now + 2200);
    setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, plan.backLayer));
    return true;
  }

  if (fish.caveState === "exit") {
    const nodeIndex = Number.isFinite(fish.cavePathIndex) ? fish.cavePathIndex : 0;
    const node = plan.exitPathNodes[nodeIndex] || plan.mouth;
    fish.targetXNorm = node.xNorm;
    fish.targetYNorm = node.yNorm;
    fish.targetAt = now + 2200 + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 14000;
    setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, plan.backLayer));
    return true;
  }

  if (fish.caveState === "depart") {
    fish.targetXNorm = plan.mouth.xNorm;
    fish.targetYNorm = plan.mouth.yNorm;
    fish.targetAt = now + 1800 + Math.hypot(fish.xNorm - plan.mouth.xNorm, fish.yNorm - plan.mouth.yNorm) * 14000;
    setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, plan.backLayer));
    return true;
  }

  if (fish.caveState === "leave") {
    fish.targetXNorm = plan.approach.xNorm;
    fish.targetYNorm = plan.approach.yNorm;
    fish.targetAt = now + 1800 + Math.hypot(fish.xNorm - plan.approach.xNorm, fish.yNorm - plan.approach.yNorm) * 14000;
    setFishDesiredTankLayer(fish, plan.frontLayer);
    return true;
  }

  return false;
}

function buildCaveNavigationPlan(item, fish, now = Date.now()) {
  if (!item || !isCaveDecorKey(item.decorKey)) {
    return null;
  }

  const species = fish ? getSpeciesForFish(fish) : null;
  const nav = getCaveNavigationData(item);
  if (!nav || !species || species.behavior === "sucker") {
    return null;
  }

  const span = getDecorLayerSpan(item.decorKey, getDecorTankLayer(item));
  const profile = getCaveBehaviorProfileForItem(item);
  const portals = [];

  for (const portal of profile.portals) {
    const approach = resolveOpenCavePoint(
      item,
      portal.approachX,
      portal.approachY,
      nav.frontDescriptor,
      nav.barrierDescriptor,
      fish,
      species,
      now,
      { rangeX: 0.14, rangeY: 0.1, step: 0.02, allowFallback: true, barrierMode: "clear" }
    );
    if (!approach) {
      continue;
    }

    const mouth = resolveOpenCavePoint(
      item,
      portal.mouthX,
      portal.mouthY,
      nav.frontDescriptor,
      null,
      fish,
      species,
      now,
      { rangeX: 0.1, rangeY: 0.1, step: 0.02, allowFallback: false, barrierMode: "clear" }
    );
    if (!mouth) {
      continue;
    }

    const fitCache = new Int8Array(nav.cols * nav.rows);
    fitCache.fill(-1);
    const interiorCandidates = collectCaveNavCandidatesNearWorldPoint(
      nav,
      mouth.x,
      mouth.y,
      Math.max(CAVE_PORTAL_SCAN_RADIUS_PX * 4, 120),
      (index, point, distancePx) => {
        if (!canFishOccupyCaveNavIndex(nav, index, fish, species, now, fitCache)) {
          return false;
        }

        return distancePx;
      }
    );
    if (!interiorCandidates.length) {
      continue;
    }

    const interiorStart = interiorCandidates[0];
    const reachable = buildReachableCaveRegion(nav, interiorStart.index, fish, species, now, fitCache);
    if (!reachable) {
      continue;
    }

    const centerCandidate = findReachableCaveInteriorTarget(nav, reachable, fish, species, now, fitCache);
    if (!centerCandidate) {
      continue;
    }

    const pathIndices = buildCavePathIndices(reachable.parents, interiorStart.index, centerCandidate.index);
    if (!pathIndices.length) {
      continue;
    }

    const pathNodes = compressCavePathNodes(
      pathIndices.map((index) => {
        const col = index % nav.cols;
        const row = Math.floor(index / nav.cols);
        return getCaveNavCellCenter(nav, col, row);
      })
    );
    if (!pathNodes.length) {
      continue;
    }

    const distanceNorm = fish
      ? Math.hypot(fish.xNorm - approach.xNorm, fish.yNorm - approach.yNorm)
      : 0;

    portals.push({
      id: portal.id,
      approach,
      mouth,
      inside: centerCandidate.point,
      entryPathNodes: pathNodes,
      exitPathNodes: [...pathNodes].reverse(),
      outsideLayer: clampTankLayer(Number.isFinite(Number(portal.outsideLayer)) ? Number(portal.outsideLayer) : Math.max(1, span.front - 1)),
      insideLayer: clampTankLayer(Number.isFinite(Number(portal.insideLayer)) ? Number(portal.insideLayer) : (span.back || span.front)),
      distanceNorm
    });
  }

  if (!portals.length) {
    return null;
  }

  portals.sort((left, right) => left.distanceNorm - right.distanceNorm);
  const bestPortal = portals[0];

  return {
    decorId: item.id,
    portalId: bestPortal.id,
    frontLayer: clampTankLayer(bestPortal.outsideLayer),
    backLayer: clampTankLayer(bestPortal.insideLayer),
    approach: bestPortal.approach,
    mouth: bestPortal.mouth,
    inside: bestPortal.inside,
    entryPathNodes: bestPortal.entryPathNodes,
    exitPathNodes: bestPortal.exitPathNodes,
    lingerMs: profile.lingerMinMs + Math.random() * Math.max(200, profile.lingerMaxMs - profile.lingerMinMs)
  };
}

function pickCaveEntryBehavior(species, fish, now = Date.now()) {
  if (
    !fish ||
    species?.behavior === "sucker" ||
    species?.caveEnabled === false ||
    (Number.isFinite(fish.caveTriggerCooldownUntil) && now < fish.caveTriggerCooldownUntil)
  ) {
    return null;
  }

  if (Math.random() > getCaveBehaviorChance(species, now)) {
    return null;
  }

  const candidates = collectCaveBehaviorPlansForFish(fish, now);
  if (!candidates.length) {
    return null;
  }

  return candidates[0];
}

function setFishTargetToCaveNode(fish, node, now = Date.now(), extraMs = 1800) {
  if (!fish || !node) {
    return false;
  }

  fish.targetXNorm = clamp(node.xNorm, 0.08, 0.92);
  fish.targetYNorm = clamp(node.yNorm, 0.14, 0.8);
  fish.targetAt = now + extraMs + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 18000;
  return true;
}

function getDebugCaveSeatSequence(item, fish, species, now = Date.now(), anchorPoint = null) {
  if (!item || !fish || !species) {
    return [];
  }

  const origin = anchorPoint || {
    xNorm: fish.xNorm,
    yNorm: fish.yNorm
  };

  return getCaveSeatRegions(item)
    .filter((seat) => !isCaveSeatOccupied(item.id, seat.id, fish.id))
    .filter((seat) => doesFishFitCaveRegionSize(seat, fish, species, 0.45))
    .map((seat) => {
      const fallbackDirection = Math.abs(seat.xNorm - origin.xNorm) > 0.001
        ? (seat.xNorm >= origin.xNorm ? 1 : -1)
        : (fish.direction || 1);
      const direction = getCaveSeatFacingDirection(seat, fallbackDirection);
      const idlePoint = pickCaveSeatIdleTarget(item, seat, fish, species, now, direction) || {
        xNorm: seat.xNorm,
        yNorm: seat.yNorm
      };
      if (!doesFishFitAtCavePoint(item, fish, species, now, idlePoint, direction, CAVE_PLAN_SAMPLE_STEP_PX)) {
        return null;
      }

      return {
        id: seat.id,
        distance: Math.hypot(idlePoint.xNorm - origin.xNorm, idlePoint.yNorm - origin.yNorm),
        xNorm: idlePoint.xNorm,
        yNorm: idlePoint.yNorm
      };
    })
    .filter(Boolean)
    .sort((left, right) => {
      if (Math.abs(left.distance - right.distance) > 0.0005) {
        return left.distance - right.distance;
      }

      if (Math.abs(left.yNorm - right.yNorm) > 0.0005) {
        return left.yNorm - right.yNorm;
      }

      return left.xNorm - right.xNorm;
    })
    .map((seat) => seat.id);
}

function findClosestCaveNavCandidate(nav, point, fish, species, now, fitCache, radiusPx = 96) {
  if (!nav || !point || !fish || !species) {
    return null;
  }

  const worldX = Number.isFinite(Number(point.x))
    ? Number(point.x)
    : (Number.isFinite(Number(point.xNorm)) ? Number(point.xNorm) * TANK_WIDTH : Number.NaN);
  const worldY = Number.isFinite(Number(point.y))
    ? Number(point.y)
    : (Number.isFinite(Number(point.yNorm)) ? Number(point.yNorm) * TANK_HEIGHT : Number.NaN);

  if (!Number.isFinite(worldX) || !Number.isFinite(worldY)) {
    return null;
  }

  return collectCaveNavCandidatesNearWorldPoint(nav, worldX, worldY, radiusPx, (index, candidatePoint, distancePx) => {
    if (!canFishOccupyCaveNavIndex(nav, index, fish, species, now, fitCache)) {
      return false;
    }

    return distancePx;
  })[0] || null;
}

function buildCaveInteriorRouteNodes(item, fish, species, fromPoint, toPoint, now = Date.now()) {
  if (!item || !fish || !species || !fromPoint || !toPoint) {
    return null;
  }

  const startPoint = {
    xNorm: clamp(fromPoint.xNorm, 0.08, 0.92),
    yNorm: clamp(fromPoint.yNorm, 0.14, 0.8)
  };
  const endPoint = {
    xNorm: clamp(toPoint.xNorm, 0.08, 0.92),
    yNorm: clamp(toPoint.yNorm, 0.14, 0.8)
  };

  if (pathStaysInsideCave(item, fish, species, now, startPoint, endPoint, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX)) {
    return [endPoint];
  }

  const nav = getCaveNavigationData(item);
  if (!nav) {
    return null;
  }

  const fitCache = new Int8Array(nav.cols * nav.rows);
  fitCache.fill(-1);
  const scanRadius = Math.max(CAVE_PORTAL_SCAN_RADIUS_PX * 6, 96);
  const startCandidate = findClosestCaveNavCandidate(nav, startPoint, fish, species, now, fitCache, scanRadius);
  if (!startCandidate) {
    return null;
  }

  const reachable = buildReachableCaveRegion(nav, startCandidate.index, fish, species, now, fitCache);
  if (!reachable) {
    return null;
  }

  const endCandidate = collectCaveNavCandidatesNearWorldPoint(
    nav,
    endPoint.xNorm * TANK_WIDTH,
    endPoint.yNorm * TANK_HEIGHT,
    scanRadius,
    (index, candidatePoint, distancePx) => {
      if (!reachable.visited[index] || !canFishOccupyCaveNavIndex(nav, index, fish, species, now, fitCache)) {
        return false;
      }

      return distancePx;
    }
  )[0] || null;
  if (!endCandidate) {
    return null;
  }

  const pathIndices = buildCavePathIndices(reachable.parents, startCandidate.index, endCandidate.index);
  if (!pathIndices.length) {
    return null;
  }

  let nodes = compressCavePathNodes(
    pathIndices.map((index) => {
      const col = index % nav.cols;
      const row = Math.floor(index / nav.cols);
      return getCaveNavCellCenter(nav, col, row);
    })
  );
  if (!nodes.length) {
    nodes = [{ ...endCandidate.point }];
  }

  while (
    nodes.length > 1 &&
    Math.hypot(nodes[0].xNorm - startPoint.xNorm, nodes[0].yNorm - startPoint.yNorm) <= 0.012
  ) {
    nodes.shift();
  }

  const lastNode = nodes[nodes.length - 1];
  if (!lastNode) {
    return null;
  }

  if (
    Math.hypot(lastNode.xNorm - endPoint.xNorm, lastNode.yNorm - endPoint.yNorm) > 0.006 &&
    pathStaysInsideCave(item, fish, species, now, lastNode, endPoint, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX)
  ) {
    nodes.push(endPoint);
  } else if (Math.hypot(lastNode.xNorm - endPoint.xNorm, lastNode.yNorm - endPoint.yNorm) <= 0.006) {
    nodes[nodes.length - 1] = endPoint;
  }

  return nodes;
}

function clearDebugCavePathState(plan) {
  if (!plan) {
    return;
  }

  plan.debugPathNodes = [];
  plan.debugPathIndex = null;
}

function appendUniqueDebugCaveNodes(targetNodes, nodes) {
  if (!Array.isArray(targetNodes) || !Array.isArray(nodes)) {
    return targetNodes;
  }

  for (const node of nodes) {
    if (!node) {
      continue;
    }

    const nextNode = {
      xNorm: clamp(node.xNorm, 0.08, 0.92),
      yNorm: clamp(node.yNorm, 0.14, 0.8)
    };
    const previousNode = targetNodes[targetNodes.length - 1] || null;
    if (previousNode && Math.hypot(previousNode.xNorm - nextNode.xNorm, previousNode.yNorm - nextNode.yNorm) <= 0.003) {
      continue;
    }

    targetNodes.push(nextNode);
  }

  return targetNodes;
}

function buildCheapDebugCaveSegmentNodes(item, fish, species, fromPoint, toPoint, now = Date.now(), viaPoint = null) {
  if (!item || !fish || !species || !fromPoint || !toPoint) {
    return [];
  }

  const startPoint = {
    xNorm: clamp(fromPoint.xNorm, 0.08, 0.92),
    yNorm: clamp(fromPoint.yNorm, 0.14, 0.8)
  };
  const endPoint = {
    xNorm: clamp(toPoint.xNorm, 0.08, 0.92),
    yNorm: clamp(toPoint.yNorm, 0.14, 0.8)
  };

  if (Math.hypot(startPoint.xNorm - endPoint.xNorm, startPoint.yNorm - endPoint.yNorm) <= 0.0035) {
    return [endPoint];
  }

  if (pathStaysInsideCave(item, fish, species, now, startPoint, endPoint, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX)) {
    return [endPoint];
  }

  const normalizedViaPoint = viaPoint
    ? {
      xNorm: clamp(viaPoint.xNorm, 0.08, 0.92),
      yNorm: clamp(viaPoint.yNorm, 0.14, 0.8)
    }
    : null;
  if (
    normalizedViaPoint &&
    Math.hypot(startPoint.xNorm - normalizedViaPoint.xNorm, startPoint.yNorm - normalizedViaPoint.yNorm) > 0.004 &&
    Math.hypot(normalizedViaPoint.xNorm - endPoint.xNorm, normalizedViaPoint.yNorm - endPoint.yNorm) > 0.004 &&
    pathStaysInsideCave(item, fish, species, now, startPoint, normalizedViaPoint, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX) &&
    pathStaysInsideCave(item, fish, species, now, normalizedViaPoint, endPoint, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX)
  ) {
    return [normalizedViaPoint, endPoint];
  }

  const fallbackNodes = buildDebugFallbackCavePathNodes(item, startPoint, endPoint);
  if (!fallbackNodes.length) {
    return [];
  }

  const validatedNodes = [];
  let previousPoint = startPoint;
  for (const node of fallbackNodes) {
    const normalizedNode = {
      xNorm: clamp(node.xNorm, 0.08, 0.92),
      yNorm: clamp(node.yNorm, 0.14, 0.8)
    };
    if (Math.hypot(previousPoint.xNorm - normalizedNode.xNorm, previousPoint.yNorm - normalizedNode.yNorm) <= 0.0035) {
      continue;
    }

    if (!pathStaysInsideCave(item, fish, species, now, previousPoint, normalizedNode, CAVE_PLAN_SAMPLE_STEP_PX, CAVE_PLAN_SEGMENT_STEP_PX)) {
      return [];
    }

    validatedNodes.push(normalizedNode);
    previousPoint = normalizedNode;
  }

  return validatedNodes;
}

function collectCheapDebugCaveRoamCandidates(item, fish, species, plan, seatRegions, now = Date.now()) {
  if (!item || !fish || !species || !plan) {
    return [];
  }

  const profile = getCaveBehaviorProfileForItem(item);
  const seen = new Set();
  const candidates = [];
  const interiorCenter = plan.inside || plan.mouth || {
    xNorm: fish.xNorm,
    yNorm: fish.yNorm
  };
  const seatList = Array.isArray(seatRegions) ? seatRegions : [];
  const addCandidate = (point, weight = 0) => {
    if (!point || !Number.isFinite(point.xNorm) || !Number.isFinite(point.yNorm)) {
      return;
    }

    const candidatePoint = {
      xNorm: clamp(point.xNorm, 0.08, 0.92),
      yNorm: clamp(point.yNorm, 0.14, 0.8)
    };
    const cacheKey = `${candidatePoint.xNorm.toFixed(4)}|${candidatePoint.yNorm.toFixed(4)}`;
    if (seen.has(cacheKey)) {
      return;
    }
    seen.add(cacheKey);

    const candidateDirection = Math.abs(candidatePoint.xNorm - interiorCenter.xNorm) > 0.001
      ? (candidatePoint.xNorm >= interiorCenter.xNorm ? 1 : -1)
      : (fish.direction || 1);
    if (!doesFishFitAtCavePoint(item, fish, species, now, candidatePoint, candidateDirection, CAVE_PLAN_SAMPLE_STEP_PX)) {
      return;
    }

    const distanceFromSeat = seatList.length
      ? seatList.reduce((bestDistance, seat) => Math.min(bestDistance, Math.hypot(candidatePoint.xNorm - seat.xNorm, candidatePoint.yNorm - seat.yNorm)), Number.POSITIVE_INFINITY)
      : Number.POSITIVE_INFINITY;
    if (distanceFromSeat < 0.018) {
      return;
    }

    const distanceFromCenter = Math.hypot(candidatePoint.xNorm - interiorCenter.xNorm, candidatePoint.yNorm - interiorCenter.yNorm);
    if (distanceFromCenter < 0.012) {
      return;
    }

    candidates.push({
      point: candidatePoint,
      score: distanceFromCenter + weight + Math.random() * 0.002
    });
  };

  if (Array.isArray(profile?.interiorZones)) {
    for (const zone of profile.interiorZones) {
      addCandidate(mapDecorLocalPointToTankNorm(item, (zone.xMin + zone.xMax) / 2, (zone.yMin + zone.yMax) / 2), 0.05);
      addCandidate(mapDecorLocalPointToTankNorm(item, zone.xMin + (zone.xMax - zone.xMin) * 0.22, (zone.yMin + zone.yMax) / 2), 0.03);
      addCandidate(mapDecorLocalPointToTankNorm(item, zone.xMin + (zone.xMax - zone.xMin) * 0.78, (zone.yMin + zone.yMax) / 2), 0.03);
    }
  }

  for (const slot of getCaveInsideSlots(profile)) {
    addCandidate(mapDecorLocalPointToTankNorm(item, slot.x, slot.y), 0.04);
  }

  const interiorDescriptor = getCaveInteriorContainmentDescriptor(item);
  if (interiorDescriptor?.bounds) {
    const spanXNorm = clamp(((interiorDescriptor.bounds.right - interiorDescriptor.bounds.left) / TANK_WIDTH) * 0.18, 0.014, 0.06);
    const spanYNorm = clamp(((interiorDescriptor.bounds.bottom - interiorDescriptor.bounds.top) / TANK_HEIGHT) * 0.16, 0.012, 0.045);
    const offsets = [
      [-1, 0],
      [1, 0],
      [0, -1],
      [0, 0.8],
      [-0.65, -0.55],
      [0.65, -0.55]
    ];
    for (const [offsetX, offsetY] of offsets) {
      addCandidate({
        xNorm: interiorCenter.xNorm + spanXNorm * offsetX,
        yNorm: interiorCenter.yNorm + spanYNorm * offsetY
      }, 0.02);
    }
  }

  candidates.sort((left, right) => right.score - left.score);
  const selectedPoints = [];
  for (const candidate of candidates) {
    if (selectedPoints.some((point) => Math.hypot(point.xNorm - candidate.point.xNorm, point.yNorm - candidate.point.yNorm) < 0.015)) {
      continue;
    }

    selectedPoints.push(candidate.point);
    if (selectedPoints.length >= 3) {
      break;
    }
  }

  return selectedPoints;
}

function ensureDebugCaveSequencePrepared(fish, species, decorItem, plan, mouthNode, now = Date.now()) {
  if (!fish || !species || !decorItem || !plan) {
    return false;
  }

  if (plan.debugPrepared) {
    return true;
  }

  const seatRegions = getCaveSeatRegions(decorItem);
  if (!Array.isArray(plan.debugSeatOrder)) {
    plan.debugSeatOrder = getDebugCaveSeatSequence(decorItem, fish, species, now, plan.inside || mouthNode);
  }

  const interiorCenter = plan.inside || mouthNode || {
    xNorm: fish.xNorm,
    yNorm: fish.yNorm
  };
  const roamPathNodes = [];
  let anchorPoint = interiorCenter;
  for (const roamPoint of collectCheapDebugCaveRoamCandidates(decorItem, fish, species, plan, seatRegions, now)) {
    const segmentNodes = buildCheapDebugCaveSegmentNodes(decorItem, fish, species, anchorPoint, roamPoint, now, interiorCenter);
    if (!segmentNodes.length) {
      continue;
    }

    appendUniqueDebugCaveNodes(roamPathNodes, segmentNodes);
    anchorPoint = roamPathNodes[roamPathNodes.length - 1] || anchorPoint;
  }

  if (!roamPathNodes.length && interiorCenter) {
    roamPathNodes.push({
      xNorm: clamp(interiorCenter.xNorm, 0.08, 0.92),
      yNorm: clamp(interiorCenter.yNorm, 0.14, 0.8)
    });
  }

  const seatSteps = [];
  for (const seatId of plan.debugSeatOrder) {
    const seatRegion = findRegionById(seatRegions, seatId);
    if (!seatRegion || !doesFishFitCaveRegionSize(seatRegion, fish, species, 0.45)) {
      continue;
    }

    const seatDirection = Math.abs(seatRegion.xNorm - anchorPoint.xNorm) > 0.001
      ? (seatRegion.xNorm >= anchorPoint.xNorm ? 1 : -1)
      : (fish.direction || 1);
    const configuredSeatDirection = getCaveSeatFacingDirection(seatRegion, seatDirection);
    const seatPoint = pickCaveSeatIdleTarget(decorItem, seatRegion, fish, species, now, configuredSeatDirection) || {
      xNorm: seatRegion.xNorm,
      yNorm: seatRegion.yNorm
    };
    if (!doesFishFitAtCavePoint(decorItem, fish, species, now, seatPoint, configuredSeatDirection, CAVE_PLAN_SAMPLE_STEP_PX)) {
      continue;
    }

    const pathNodes = buildCheapDebugCaveSegmentNodes(decorItem, fish, species, anchorPoint, seatPoint, now, interiorCenter);
    seatSteps.push({
      id: seatRegion.id,
      direction: configuredSeatDirection,
      point: {
        xNorm: clamp(seatPoint.xNorm, 0.08, 0.92),
        yNorm: clamp(seatPoint.yNorm, 0.14, 0.8)
      },
      pathNodes: pathNodes.length ? pathNodes : [{
        xNorm: clamp(seatPoint.xNorm, 0.08, 0.92),
        yNorm: clamp(seatPoint.yNorm, 0.14, 0.8)
      }]
    });
    anchorPoint = seatSteps[seatSteps.length - 1].point;
  }

  plan.debugPrepared = true;
  plan.debugRoamStarted = false;
  plan.debugRoamPathNodes = roamPathNodes;
  plan.debugSeatSteps = seatSteps;
  return true;
}

function startDebugCavePath(fish, plan, nodes, now = Date.now(), extraMs = 900) {
  clearDebugCavePathState(plan);
  if (!fish || !plan || !Array.isArray(nodes) || !nodes.length) {
    return false;
  }

  plan.debugPathNodes = nodes.map((node) => ({
    xNorm: clamp(node.xNorm, 0.08, 0.92),
    yNorm: clamp(node.yNorm, 0.14, 0.8)
  }));
  plan.debugPathIndex = 0;
  return setFishTargetToCaveNode(fish, plan.debugPathNodes[0], now, extraMs);
}

function advanceDebugCavePath(fish, plan, now = Date.now(), extraMs = 900) {
  const nodes = Array.isArray(plan?.debugPathNodes) ? plan.debugPathNodes : [];
  if (!fish || !plan || !nodes.length) {
    return false;
  }

  const nodeIndex = Number.isFinite(plan.debugPathIndex)
    ? clamp(Math.floor(plan.debugPathIndex), 0, nodes.length - 1)
    : 0;
  const node = nodes[nodeIndex];
  if (!node) {
    clearDebugCavePathState(plan);
    return false;
  }

  if (
    !Number.isFinite(fish.targetXNorm) ||
    !Number.isFinite(fish.targetYNorm) ||
    Math.hypot(fish.targetXNorm - node.xNorm, fish.targetYNorm - node.yNorm) > 0.0005
  ) {
    setFishTargetToCaveNode(fish, node, now, extraMs);
  }

  if (Math.hypot(fish.xNorm - node.xNorm, fish.yNorm - node.yNorm) > CAVE_GENERAL_REACHED_DISTANCE_NORM) {
    return true;
  }

  const nextIndex = nodeIndex + 1;
  if (nextIndex < nodes.length) {
    plan.debugPathIndex = nextIndex;
    setFishTargetToCaveNode(fish, nodes[nextIndex], now, extraMs);
    return true;
  }

  clearDebugCavePathState(plan);
  return false;
}

function pickDebugCaveRoamPathNodes(item, fish, species, plan, now = Date.now()) {
  if (!item || !fish || !species || !plan) {
    return null;
  }

  const nav = getCaveNavigationData(item);
  if (!nav) {
    return plan.inside
      ? buildCaveInteriorRouteNodes(item, fish, species, { xNorm: fish.xNorm, yNorm: fish.yNorm }, plan.inside, now)
      : null;
  }

  const fitCache = new Int8Array(nav.cols * nav.rows);
  fitCache.fill(-1);
  const startCandidate = findClosestCaveNavCandidate(
    nav,
    { xNorm: fish.xNorm, yNorm: fish.yNorm },
    fish,
    species,
    now,
    fitCache,
    Math.max(CAVE_PORTAL_SCAN_RADIUS_PX * 7, 120)
  );
  if (!startCandidate) {
    return null;
  }

  const reachable = buildReachableCaveRegion(nav, startCandidate.index, fish, species, now, fitCache);
  if (!reachable) {
    return null;
  }

  const clearanceMap = buildReachableCaveClearanceMap(nav, reachable);
  const seatRegions = getCaveSeatRegions(item);
  let bestPoint = null;
  let bestScore = Number.NEGATIVE_INFINITY;

  for (let index = 0; index < reachable.visited.length; index += 1) {
    if (!reachable.visited[index] || !canFishOccupyCaveNavIndex(nav, index, fish, species, now, fitCache)) {
      continue;
    }

    const col = index % nav.cols;
    const row = Math.floor(index / nav.cols);
    const point = getCaveNavCellCenter(nav, col, row);
    const distanceFromFish = Math.hypot(point.xNorm - fish.xNorm, point.yNorm - fish.yNorm);
    if (distanceFromFish < 0.018) {
      continue;
    }

    const distanceFromLastTarget = plan.debugLastRoamTarget
      ? Math.hypot(point.xNorm - plan.debugLastRoamTarget.xNorm, point.yNorm - plan.debugLastRoamTarget.yNorm)
      : distanceFromFish;
    if (plan.debugLastRoamTarget && distanceFromLastTarget < 0.012) {
      continue;
    }

    const distanceFromSeat = seatRegions.length
      ? seatRegions.reduce((bestDistance, seat) => Math.min(bestDistance, Math.hypot(point.xNorm - seat.xNorm, point.yNorm - seat.yNorm)), Number.POSITIVE_INFINITY)
      : Number.POSITIVE_INFINITY;
    if (distanceFromSeat < 0.018) {
      continue;
    }

    const clearance = clearanceMap ? Math.max(0, clearanceMap[index]) : 0;
    const distanceFromInside = plan.inside
      ? Math.hypot(point.xNorm - plan.inside.xNorm, point.yNorm - plan.inside.yNorm)
      : 0;
    const score =
      distanceFromFish * 85 +
      distanceFromLastTarget * 60 +
      clearance * nav.cellSize * 2 +
      Math.min(distanceFromInside, 0.06) * 24 +
      Math.random() * 18;
    if (score > bestScore) {
      bestScore = score;
      bestPoint = point;
    }
  }

  if (!bestPoint) {
    const fallbackTarget = findReachableCaveInteriorTarget(nav, reachable, fish, species, now, fitCache);
    bestPoint = fallbackTarget?.point || plan.inside || null;
  }

  if (!bestPoint) {
    return null;
  }

  const pathNodes = buildCaveInteriorRouteNodes(
    item,
    fish,
    species,
    { xNorm: fish.xNorm, yNorm: fish.yNorm },
    bestPoint,
    now
  );
  if (!pathNodes?.length) {
    return null;
  }

  plan.debugLastRoamTarget = {
    xNorm: bestPoint.xNorm,
    yNorm: bestPoint.yNorm
  };
  return pathNodes;
}

function beginFishDebugCaveExit(fish, plan, mouthNode, now = Date.now()) {
  if (!fish || !plan || !mouthNode) {
    return false;
  }

  clearDebugCavePathState(plan);
  plan.debugPhase = "exit";
  plan.debugSeatId = null;
  plan.debugSeatPoint = null;
  plan.debugSeatDirection = null;
  plan.debugSeatHoldUntil = null;
  fish.caveSeatId = null;
  fish.caveState = "exit";
  fish.cavePathIndex = 0;
  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;
  setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS));

  if (!setFishTargetToCaveNode(fish, plan.exitPathNodes[0] || mouthNode, now, 1300)) {
    abortFishCaveBehavior(fish, now, true);
    return false;
  }

  return true;
}

function updateDebugFishCaveInsideBehavior(fish, species, decorItem, plan, mouthNode, now = Date.now()) {
  if (!fish || !species || !decorItem || !plan || !mouthNode) {
    return false;
  }

  ensureDebugCaveSequencePrepared(fish, species, decorItem, plan, mouthNode, now);
  if (!Number.isFinite(plan.debugRoamUntil)) {
    plan.debugRoamUntil = now + CAVE_DEBUG_TEST_ROAM_MS;
  }
  if (!Number.isFinite(plan.debugSeatIndex)) {
    plan.debugSeatIndex = 0;
  }
  if (!plan.debugPhase) {
    plan.debugPhase = "roam";
  }

  fish.caveInsideUntil = Math.max(
    Number(fish.caveInsideUntil) || 0,
    plan.debugRoamUntil + plan.debugSeatOrder.length * CAVE_DEBUG_TEST_SEAT_MS + 1200
  );
  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;

  if (plan.debugPhase === "roam") {
    fish.caveSeatId = null;

    if (now >= plan.debugRoamUntil) {
      clearDebugCavePathState(plan);
      plan.debugPhase = "seat-move";
    } else {
      if (!plan.debugRoamStarted) {
        plan.debugRoamStarted = true;
        if (Array.isArray(plan.debugRoamPathNodes) && plan.debugRoamPathNodes.length) {
          startDebugCavePath(fish, plan, plan.debugRoamPathNodes, now, 850);
        }
      }

      if (advanceDebugCavePath(fish, plan, now, 850)) {
        return true;
      }

      if (plan.inside) {
        const holdPoint = Array.isArray(plan.debugRoamPathNodes) && plan.debugRoamPathNodes.length
          ? plan.debugRoamPathNodes[plan.debugRoamPathNodes.length - 1]
          : plan.inside;
        fish.targetXNorm = holdPoint.xNorm;
        fish.targetYNorm = holdPoint.yNorm;
        fish.targetAt = Math.min(plan.debugRoamUntil, now + 900);
      }
      return true;
    }
  }

  if (plan.debugPhase === "seat-hold") {
    const holdPoint = plan.debugSeatPoint || plan.inside || mouthNode;
    if (holdPoint) {
      fish.targetXNorm = holdPoint.xNorm;
      fish.targetYNorm = holdPoint.yNorm;
    }
    if (Number.isFinite(Number(plan.debugSeatDirection))) {
      setFishDirection(fish, normalizeCaveSeatFacing(plan.debugSeatDirection), species, now);
    }
    fish.targetAt = Math.max(Number(plan.debugSeatHoldUntil) || 0, now + 200);
    if (Number.isFinite(plan.debugSeatHoldUntil) && now < plan.debugSeatHoldUntil) {
      return true;
    }

    plan.debugSeatIndex += 1;
    plan.debugSeatId = null;
    plan.debugSeatPoint = null;
    plan.debugSeatDirection = null;
    plan.debugSeatHoldUntil = null;
    fish.caveSeatId = null;
    plan.debugPhase = "seat-move";
  }

  if (plan.debugPhase === "seat-move") {
    const seatSteps = Array.isArray(plan.debugSeatSteps) ? plan.debugSeatSteps : [];
    let activeSeatStep = seatSteps[plan.debugSeatIndex] || null;
    while (activeSeatStep && isCaveSeatOccupied(plan.decorId, activeSeatStep.id, fish.id)) {
      plan.debugSeatIndex += 1;
      plan.debugSeatId = null;
      plan.debugSeatPoint = null;
      plan.debugSeatDirection = null;
      fish.caveSeatId = null;
      activeSeatStep = seatSteps[plan.debugSeatIndex] || null;
    }
    if (!activeSeatStep) {
      return beginFishDebugCaveExit(fish, plan, mouthNode, now);
    }

    if (plan.debugSeatId !== activeSeatStep.id) {
      plan.debugSeatId = activeSeatStep.id;
      plan.debugSeatPoint = activeSeatStep.point;
      plan.debugSeatDirection = normalizeCaveSeatFacing(activeSeatStep.direction, fish.direction || 1);
      fish.caveSeatId = activeSeatStep.id;
      startDebugCavePath(fish, plan, activeSeatStep.pathNodes, now, 850);
    } else if (advanceDebugCavePath(fish, plan, now, 850)) {
      return true;
    }

    const seatReached = Boolean(
      plan.debugSeatPoint &&
      Math.hypot(fish.xNorm - plan.debugSeatPoint.xNorm, fish.yNorm - plan.debugSeatPoint.yNorm) <= CAVE_DEBUG_TEST_SEAT_SETTLE_DISTANCE_NORM
    );
    if (seatReached) {
      plan.debugPhase = "seat-hold";
      plan.debugSeatHoldUntil = now + CAVE_DEBUG_TEST_SEAT_MS;
      if (plan.debugSeatPoint) {
        fish.targetXNorm = plan.debugSeatPoint.xNorm;
        fish.targetYNorm = plan.debugSeatPoint.yNorm;
      }
      if (Number.isFinite(Number(plan.debugSeatDirection))) {
        setFishDirection(fish, normalizeCaveSeatFacing(plan.debugSeatDirection), species, now);
      }
      fish.targetAt = plan.debugSeatHoldUntil;
      return true;
    }

    if (plan.debugSeatPoint) {
      fish.targetXNorm = plan.debugSeatPoint.xNorm;
      fish.targetYNorm = plan.debugSeatPoint.yNorm;
      fish.targetAt = now + 900;
      return true;
    }

    plan.debugSeatIndex += 1;
    plan.debugSeatId = null;
    plan.debugSeatPoint = null;
    plan.debugSeatDirection = null;
    fish.caveSeatId = null;
    return true;
  }

  return beginFishDebugCaveExit(fish, plan, mouthNode, now);
}

function clearNormalCavePathState(plan) {
  if (!plan) {
    return;
  }

  plan.normalPathNodes = [];
  plan.normalPathIndex = null;
}

function buildNormalCaveInsideTravelNodes(item, fish, species, fromPoint, toPoint, now = Date.now(), viaPoint = null) {
  if (!item || !fish || !species || !fromPoint || !toPoint) {
    return [];
  }

  const routeNodes = buildCaveInteriorRouteNodes(item, fish, species, fromPoint, toPoint, now);
  if (Array.isArray(routeNodes) && routeNodes.length) {
    return routeNodes;
  }

  return buildCheapDebugCaveSegmentNodes(item, fish, species, fromPoint, toPoint, now, viaPoint);
}

function pickNormalCaveRoamAssignment(item, fish, species, plan, mouthNode, now = Date.now()) {
  if (!item || !fish || !species || !plan) {
    return null;
  }

  const origin = {
    xNorm: clamp(fish.xNorm, 0.08, 0.92),
    yNorm: clamp(fish.yNorm, 0.14, 0.8)
  };
  const interiorAnchor = plan.inside || mouthNode || origin;
  const seatRegions = getCaveSeatRegions(item);
  const candidates = collectCheapDebugCaveRoamCandidates(item, fish, species, plan, seatRegions, now);
  const lastRoamTarget = plan.normalLastRoamTarget || null;
  const pickCandidatePool = (excludeLastTarget = true) => candidates.filter((point) => (
    Math.hypot(point.xNorm - origin.xNorm, point.yNorm - origin.yNorm) > 0.012
    && (!excludeLastTarget || !lastRoamTarget || Math.hypot(point.xNorm - lastRoamTarget.xNorm, point.yNorm - lastRoamTarget.yNorm) > 0.014)
  ));
  let pool = pickCandidatePool(true);
  if (!pool.length) {
    pool = pickCandidatePool(false);
  }
  if (!pool.length && interiorAnchor) {
    pool = [interiorAnchor];
  }
  if (!pool.length) {
    return null;
  }

  const targetPoint = pool[Math.floor(Math.random() * Math.min(pool.length, 3))];
  if (!targetPoint) {
    return null;
  }

  const pathNodes = buildNormalCaveInsideTravelNodes(item, fish, species, origin, targetPoint, now, interiorAnchor);
  if (!pathNodes.length && Math.hypot(targetPoint.xNorm - origin.xNorm, targetPoint.yNorm - origin.yNorm) > 0.012) {
    return null;
  }

  return {
    point: {
      xNorm: clamp(targetPoint.xNorm, 0.08, 0.92),
      yNorm: clamp(targetPoint.yNorm, 0.14, 0.8)
    },
    pathNodes
  };
}

function startNormalCavePath(fish, plan, nodes, now = Date.now(), extraMs = 900) {
  clearNormalCavePathState(plan);
  if (!fish || !plan || !Array.isArray(nodes) || !nodes.length) {
    return false;
  }

  plan.normalPathNodes = nodes.map((node) => ({
    xNorm: clamp(node.xNorm, 0.08, 0.92),
    yNorm: clamp(node.yNorm, 0.14, 0.8)
  }));
  plan.normalPathIndex = 0;
  return setFishTargetToCaveNode(fish, plan.normalPathNodes[0], now, extraMs);
}

function advanceNormalCavePath(fish, plan, now = Date.now(), extraMs = 900) {
  const nodes = Array.isArray(plan?.normalPathNodes) ? plan.normalPathNodes : [];
  if (!fish || !plan || !nodes.length) {
    return false;
  }

  const nodeIndex = Number.isFinite(plan.normalPathIndex)
    ? clamp(Math.floor(plan.normalPathIndex), 0, nodes.length - 1)
    : 0;
  const node = nodes[nodeIndex];
  if (!node) {
    clearNormalCavePathState(plan);
    return false;
  }

  if (
    !Number.isFinite(fish.targetXNorm) ||
    !Number.isFinite(fish.targetYNorm) ||
    Math.hypot(fish.targetXNorm - node.xNorm, fish.targetYNorm - node.yNorm) > 0.0005
  ) {
    setFishTargetToCaveNode(fish, node, now, extraMs);
  }

  if (Math.hypot(fish.xNorm - node.xNorm, fish.yNorm - node.yNorm) > CAVE_GENERAL_REACHED_DISTANCE_NORM) {
    return true;
  }

  const nextIndex = nodeIndex + 1;
  if (nextIndex < nodes.length) {
    plan.normalPathIndex = nextIndex;
    setFishTargetToCaveNode(fish, nodes[nextIndex], now, extraMs);
    return true;
  }

  clearNormalCavePathState(plan);
  return false;
}

function beginFishNormalCaveExit(fish, plan, mouthNode, now = Date.now()) {
  if (!fish || !plan || !mouthNode) {
    return false;
  }

  clearNormalCavePathState(plan);
  plan.normalInsideMode = null;
  plan.normalTargetPoint = null;
  plan.normalSeatPoint = null;
  plan.normalSeatDirection = null;
  plan.normalSeatHoldUntil = null;
  plan.seatId = null;
  fish.caveSeatId = null;
  fish.caveState = "exit";
  fish.cavePathIndex = 0;
  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;
  setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS));

  if (!setFishTargetToCaveNode(fish, plan.exitPathNodes[0] || mouthNode, now, 1300)) {
    abortFishCaveBehavior(fish, now, true);
    return false;
  }

  return true;
}

function updateNormalFishCaveInsideBehavior(fish, species, decorItem, plan, mouthNode, now = Date.now()) {
  if (!fish || !species || !decorItem || !plan || !mouthNode) {
    return false;
  }

  const currentPoint = {
    xNorm: clamp(fish.xNorm, 0.08, 0.92),
    yNorm: clamp(fish.yNorm, 0.14, 0.8)
  };
  const interiorAnchor = plan.inside || mouthNode || currentPoint;
  const setInsideTarget = (point) => {
    if (!point) {
      return;
    }

    const normalizedPoint = {
      xNorm: clamp(point.xNorm, 0.08, 0.92),
      yNorm: clamp(point.yNorm, 0.14, 0.8)
    };
    plan.normalTargetPoint = normalizedPoint;
    fish.caveInsideXNorm = normalizedPoint.xNorm;
    fish.caveInsideYNorm = normalizedPoint.yNorm;
  };
  const clearSeatReservation = () => {
    plan.seatId = null;
    plan.normalSeatPoint = null;
    plan.normalSeatDirection = null;
    plan.normalSeatHoldUntil = null;
    fish.caveSeatId = null;
  };
  const configuredPoints = Boolean(plan.configuredPoints);
  const beginRoam = () => {
    if (configuredPoints) {
      return beginFishNormalCaveExit(fish, plan, mouthNode, now);
    }

    clearSeatReservation();
    const roamAssignment = pickNormalCaveRoamAssignment(decorItem, fish, species, plan, mouthNode, now);
    if (!roamAssignment?.point) {
      return beginFishNormalCaveExit(fish, plan, mouthNode, now);
    }

    plan.normalInsideMode = "roam";
    plan.normalLastRoamTarget = roamAssignment.point;
    setInsideTarget(roamAssignment.point);
    if (!startNormalCavePath(fish, plan, roamAssignment.pathNodes, now, 900) && plan.normalTargetPoint) {
      setFishTargetToCaveNode(fish, plan.normalTargetPoint, now, 900);
    }
    return true;
  };
  const beginSeatMove = (seatAssignment) => {
    if (!seatAssignment?.seatId || !seatAssignment?.point) {
      return beginRoam();
    }

    const pathNodes = configuredPoints
      ? []
      : buildNormalCaveInsideTravelNodes(
        decorItem,
        fish,
        species,
        currentPoint,
        seatAssignment.point,
        now,
        interiorAnchor
      );
    if (!configuredPoints && !pathNodes.length && Math.hypot(currentPoint.xNorm - seatAssignment.point.xNorm, currentPoint.yNorm - seatAssignment.point.yNorm) > 0.012) {
      return beginRoam();
    }

    plan.normalInsideMode = "seat-move";
    plan.seatId = seatAssignment.seatId;
    plan.normalSeatPoint = {
      xNorm: clamp(seatAssignment.point.xNorm, 0.08, 0.92),
      yNorm: clamp(seatAssignment.point.yNorm, 0.14, 0.8)
    };
    plan.normalSeatDirection = Number.isFinite(Number(seatAssignment.direction))
      ? normalizeCaveSeatFacing(seatAssignment.direction)
      : getCaveSeatFacingDirection(seatAssignment.seatRegion, fish.direction || 1);
    plan.normalSeatHoldUntil = null;
    fish.caveSeatId = null;
    setInsideTarget(plan.normalSeatPoint);
    if (!startNormalCavePath(fish, plan, pathNodes, now, 900) && plan.normalSeatPoint) {
      setFishTargetToCaveNode(fish, plan.normalSeatPoint, now, 900);
    }
    return true;
  };
  const chooseNextAction = () => {
    if (configuredPoints) {
      const seatAssignment = pickAvailableCaveSeatAssignment(decorItem, fish, species, now, currentPoint);
      const canLeaveCave = now >= (fish.caveTriggerCooldownUntil || 0);
      if (seatAssignment && Math.random() < 0.82) {
        return beginSeatMove(seatAssignment);
      }
      return canLeaveCave
        ? beginFishNormalCaveExit(fish, plan, mouthNode, now)
        : (seatAssignment ? beginSeatMove(seatAssignment) : true);
    }

    if (!plan.normalHasRoamed) {
      plan.normalHasRoamed = true;
      return beginRoam();
    }

    const seatAssignment = pickAvailableCaveSeatAssignment(decorItem, fish, species, now, currentPoint);
    const sitChance = isCaveNightWindow(now) ? CAVE_NORMAL_ROAM_SIT_CHANCE_NIGHT : CAVE_NORMAL_ROAM_SIT_CHANCE_DAY;
    const leaveChance = isCaveNightWindow(now) ? CAVE_NORMAL_ROAM_LEAVE_CHANCE_NIGHT : CAVE_NORMAL_ROAM_LEAVE_CHANCE_DAY;
    const canLeaveCave = now >= (fish.caveTriggerCooldownUntil || 0);
    const roll = Math.random();

    if (roll < leaveChance) {
      return canLeaveCave
        ? beginFishNormalCaveExit(fish, plan, mouthNode, now)
        : beginRoam();
    }

    if (roll < leaveChance + sitChance && seatAssignment) {
      return beginSeatMove(seatAssignment);
    }

    return beginRoam();
  };

  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;

  if (plan.normalInsideMode === "seat-hold") {
    if (plan.seatId && isCaveSeatOccupied(plan.decorId, plan.seatId, fish.id)) {
      clearNormalCavePathState(plan);
      clearSeatReservation();
      plan.normalInsideMode = null;
      return chooseNextAction();
    }

    if (!plan.seatId || !plan.normalSeatPoint) {
      clearNormalCavePathState(plan);
      clearSeatReservation();
      plan.normalInsideMode = null;
      return chooseNextAction();
    }

    fish.caveSeatId = plan.seatId;
    setInsideTarget(plan.normalSeatPoint);
    if (Number.isFinite(Number(plan.normalSeatDirection))) {
      setFishDirection(fish, normalizeCaveSeatFacing(plan.normalSeatDirection), species, now);
    } else {
      applyFishCaveSeatFacingById(fish, species, decorItem, plan.seatId, now, fish.direction || 1);
    }
    fish.targetXNorm = plan.normalSeatPoint.xNorm;
    fish.targetYNorm = plan.normalSeatPoint.yNorm;
    fish.targetAt = Math.max(Number(plan.normalSeatHoldUntil) || 0, now + 250);
    if (Number.isFinite(plan.normalSeatHoldUntil) && now < plan.normalSeatHoldUntil) {
      return true;
    }

    clearSeatReservation();
    plan.normalInsideMode = null;
    return chooseNextAction();
  }

  if (plan.normalInsideMode === "seat-move") {
    if (!plan.seatId || !plan.normalSeatPoint) {
      clearNormalCavePathState(plan);
      clearSeatReservation();
      plan.normalInsideMode = null;
      return chooseNextAction();
    }

    if (isCaveSeatOccupied(plan.decorId, plan.seatId, fish.id)) {
      clearNormalCavePathState(plan);
      clearSeatReservation();
      plan.normalInsideMode = null;
      return chooseNextAction();
    }

    if (advanceNormalCavePath(fish, plan, now, 900)) {
      return true;
    }

    fish.targetXNorm = plan.normalSeatPoint.xNorm;
    fish.targetYNorm = plan.normalSeatPoint.yNorm;
    fish.targetAt = now + 900;
    if (Math.hypot(fish.xNorm - plan.normalSeatPoint.xNorm, fish.yNorm - plan.normalSeatPoint.yNorm) > CAVE_NORMAL_SEAT_SETTLE_DISTANCE_NORM) {
      return true;
    }

    fish.caveSeatId = plan.seatId;
    if (Number.isFinite(Number(plan.normalSeatDirection))) {
      setFishDirection(fish, normalizeCaveSeatFacing(plan.normalSeatDirection), species, now);
    } else {
      applyFishCaveSeatFacingById(fish, species, decorItem, plan.seatId, now, fish.direction || 1);
    }
    plan.normalSeatHoldUntil = now + randomBetween(CAVE_NORMAL_SEAT_HOLD_MIN_MS, CAVE_NORMAL_SEAT_HOLD_MAX_MS);
    plan.normalInsideMode = "seat-hold";
    fish.targetAt = plan.normalSeatHoldUntil;
    return true;
  }

  if (plan.normalInsideMode === "roam") {
    clearSeatReservation();
    if (advanceNormalCavePath(fish, plan, now, 900)) {
      return true;
    }

    if (plan.normalTargetPoint) {
      fish.targetXNorm = plan.normalTargetPoint.xNorm;
      fish.targetYNorm = plan.normalTargetPoint.yNorm;
      fish.targetAt = now + 800;
      if (Math.hypot(fish.xNorm - plan.normalTargetPoint.xNorm, fish.yNorm - plan.normalTargetPoint.yNorm) > CAVE_GENERAL_REACHED_DISTANCE_NORM) {
        return true;
      }
    }

    plan.normalInsideMode = null;
    plan.normalTargetPoint = null;
    return chooseNextAction();
  }

  clearNormalCavePathState(plan);
  clearSeatReservation();
  plan.normalInsideMode = null;
  return chooseNextAction();
}

function beginFishCaveBehavior(fish, plan, now = Date.now()) {
  if (!fish || !plan) {
    return false;
  }

  const debugTestLoop = isDebugCaveTestFish(fish);
  const debugForced = debugTestLoop || plan.debugForced === true;
  const decorItem = getCaveBehaviorDecorById(plan.decorId);
  const species = getSpeciesForFish(fish);
  const debugSeatOrder = debugTestLoop && decorItem && species
    ? getDebugCaveSeatSequence(decorItem, fish, species, now, plan.inside || plan.mouth || plan.approach)
    : [];

  runtime.activeFishCavePlans.set(fish.id, {
    decorId: plan.decorId,
    portalId: plan.portalId,
    triggerId: plan.triggerId || plan.portalId,
    seatId: plan.seatId || null,
    seatDirection: Number.isFinite(Number(plan.seatDirection))
      ? normalizeCaveSeatFacing(plan.seatDirection)
      : null,
    configuredPoints: plan.configuredPoints === true,
    debugForced,
    frontLayer: clampTankLayer(plan.frontLayer),
    backLayer: clampTankLayer(plan.backLayer),
    approach: { ...plan.approach },
    mouth: { ...plan.mouth },
    inside: { ...plan.inside },
    entryPathNodes: Array.isArray(plan.entryPathNodes) ? plan.entryPathNodes.map((node) => ({ ...node })) : [],
    exitPathNodes: Array.isArray(plan.exitPathNodes) ? plan.exitPathNodes.map((node) => ({ ...node })) : [],
    debugTestLoop,
    debugPhase: debugTestLoop ? "roam" : null,
    debugRoamUntil: debugTestLoop ? now + CAVE_DEBUG_TEST_ROAM_MS : null,
    debugPrepared: false,
    debugRoamStarted: false,
    debugRoamPathNodes: [],
    debugSeatSteps: [],
    debugPathNodes: [],
    debugPathIndex: null,
    debugLastRoamTarget: null,
    debugSeatOrder,
    debugSeatIndex: 0,
    debugSeatId: null,
    debugSeatPoint: null,
    debugSeatDirection: null,
    debugSeatHoldUntil: null,
    normalInsideMode: null,
    normalPathNodes: [],
    normalPathIndex: null,
    normalTargetPoint: null,
    normalSeatPoint: plan.configuredPoints && plan.inside ? { ...plan.inside } : null,
    normalSeatDirection: Number.isFinite(Number(plan.seatDirection))
      ? normalizeCaveSeatFacing(plan.seatDirection)
      : null,
    normalSeatHoldUntil: null,
    normalLastRoamTarget: null,
    normalHasRoamed: plan.configuredPoints === true
  });
  fish.caveState = "approach";
  fish.caveDecorId = plan.decorId;
  fish.cavePortalId = plan.portalId;
  fish.caveTriggerId = plan.triggerId || plan.portalId || null;
  fish.caveSeatId = null;
  fish.caveFrontLayer = clampTankLayer(plan.frontLayer);
  fish.caveBackLayer = clampTankLayer(plan.backLayer);
  fish.caveApproachXNorm = plan.approach.xNorm;
  fish.caveApproachYNorm = plan.approach.yNorm;
  fish.caveEntryXNorm = plan.mouth.xNorm;
  fish.caveEntryYNorm = plan.mouth.yNorm;
  fish.caveInsideXNorm = plan.inside.xNorm;
  fish.caveInsideYNorm = plan.inside.yNorm;
  fish.caveInsideUntil = now + Math.max(
    Number(plan.lingerMs) || 0,
    debugTestLoop ? CAVE_DEBUG_TEST_ROAM_MS + debugSeatOrder.length * CAVE_DEBUG_TEST_SEAT_MS + 1200 : 0
  );
  fish.cavePathIndex = null;
  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;
  fish.hangoutDecorId = plan.decorId;
  fish.targetXNorm = plan.approach.xNorm;
  fish.targetYNorm = plan.approach.yNorm;
  fish.targetAt = now + 2200 + Math.hypot(fish.xNorm - plan.approach.xNorm, fish.yNorm - plan.approach.yNorm) * 18000;
  setFishTankLayers(fish, plan.frontLayer, plan.frontLayer);

  if (debugTestLoop) {
    const activePlan = runtime.activeFishCavePlans.get(fish.id) || null;
    if (activePlan && decorItem && species) {
      ensureDebugCaveSequencePrepared(fish, species, decorItem, activePlan, activePlan.mouth, now);
    }
  }

  return true;
}

function abortFishCaveBehavior(fish, now = Date.now(), blockCurrentDecor = false) {
  if (!fish) {
    return;
  }

  const priorState = fish.caveState;
  const wasInsideCave = ["enter", "inside", "exit", "depart"].includes(priorState);
  const fallbackFrontLayer = clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER);
  const fallbackXNorm = clamp(
    Number.isFinite(fish.caveApproachXNorm)
      ? fish.caveApproachXNorm
      : fish.xNorm,
    0.08,
    0.92
  );
  const fallbackYNorm = clamp(
    Number.isFinite(fish.caveApproachYNorm)
      ? fish.caveApproachYNorm
      : fish.yNorm,
    0.14,
    0.8
  );

  if (blockCurrentDecor && fish.caveDecorId) {
    fish.blockedDecorId = fish.caveDecorId;
    fish.blockedDecorUntil = now + 4200;
  }

  clearFishCaveBehavior(fish);
  fish.hangoutDecorId = null;

  if (wasInsideCave) {
    setFishTankLayers(fish, fallbackFrontLayer, fallbackFrontLayer);
    setFishDesiredTankLayer(fish, fallbackFrontLayer);
    fish.targetXNorm = fallbackXNorm;
    fish.targetYNorm = fallbackYNorm;
    fish.targetAt = now + 1200 + Math.hypot(fish.xNorm - fallbackXNorm, fish.yNorm - fallbackYNorm) * 14000;
  }
}

function isFishWithinCaveCenterTarget(fish) {
  const seatRegion = getActiveFishCaveSeatRegion(fish);
  if (seatRegion) {
    return isFishWithinRegionBounds(fish, seatRegion, 10);
  }

  if (!fish || !Number.isFinite(fish.caveInsideXNorm) || !Number.isFinite(fish.caveInsideYNorm)) {
    return false;
  }

  const toleranceX = (CAVE_CENTER_TARGET_SIZE_PX / 2) / TANK_WIDTH;
  const toleranceY = (CAVE_CENTER_TARGET_SIZE_PX / 2) / TANK_HEIGHT;
  return (
    Math.abs(fish.xNorm - fish.caveInsideXNorm) <= toleranceX &&
    Math.abs(fish.yNorm - fish.caveInsideYNorm) <= toleranceY
  );
}

function fishShapeLeavesActiveCaveInterior(fish, species, now, xNorm, yNorm) {
  if (!fish?.caveState || !["enter", "inside", "exit", "depart"].includes(fish.caveState) || !fish.caveDecorId || !species) {
    return false;
  }

  const plan = getActiveFishCavePlan(fish);
  if (!plan) {
    return true;
  }
  if (plan.configuredPoints) {
    return false;
  }

  const decor = getCaveBehaviorDecorById(plan.decorId);
  if (!decor) {
    return false;
  }

  const direction = Math.abs(xNorm - fish.xNorm) > 0.001
    ? (xNorm >= fish.xNorm ? 1 : -1)
    : (fish.direction || 1);
  const pose = getFishCollisionPose(fish, species, now, xNorm, yNorm, direction);
  const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
  if (!fishDescriptor) {
    return true;
  }

  if (fish.caveState === "enter") {
    return false;
  }

  const interiorDescriptor = getCaveInteriorContainmentDescriptor(decor);
  if (interiorDescriptor && !shapeContainedByMaskStrict(interiorDescriptor, fishDescriptor, CAVE_STRICT_SAMPLE_STEP_PX)) {
    return true;
  }

  const barrierDescriptor = getCaveBarrierDescriptor(decor);
  if (barrierDescriptor && shapesOverlapByMaskStrict(fishDescriptor, barrierDescriptor, CAVE_STRICT_SAMPLE_STEP_PX)) {
    return true;
  }

  return false;
}

function forceFishToCaveFrontLayer(fish, species, now = Date.now()) {
  if (!fish || !species) {
    return false;
  }

  const plan = getActiveFishCavePlan(fish);
  const frontLayer = clampTankLayer(fish.caveFrontLayer || plan?.frontLayer || 2);
  const fallbackXNorm = clamp(
    Number.isFinite(fish.caveApproachXNorm)
      ? fish.caveApproachXNorm
      : (plan?.approach?.xNorm ?? fish.xNorm),
    0.08,
    0.92
  );
  const fallbackYNorm = clamp(
    Number.isFinite(fish.caveApproachYNorm)
      ? fish.caveApproachYNorm
      : (plan?.approach?.yNorm ?? fish.yNorm),
    0.14,
    0.8
  );

  abortFishCaveBehavior(fish, now, true);
  setFishTankLayers(fish, frontLayer, frontLayer);
  setFishDesiredTankLayer(fish, frontLayer);
  fish.targetXNorm = fallbackXNorm;
  fish.targetYNorm = fallbackYNorm;
  fish.targetAt = now + 1400 + Math.hypot(fish.xNorm - fallbackXNorm, fish.yNorm - fallbackYNorm) * 14000;
  fish.hangoutDecorId = null;

  if (Math.abs(fallbackXNorm - fish.xNorm) > 0.001) {
    setFishDirection(fish, fallbackXNorm >= fish.xNorm ? 1 : -1, species, now);
  }

  return true;
}

function retargetFishToSafeCaveInteriorPoint(fish, species, point, now = Date.now(), stateOverride = "enter") {
  if (!fish || !species || !point) {
    return false;
  }

  if (stateOverride) {
    fish.caveState = stateOverride;
  }
  const backLayer = getFishActiveCaveInsideLayer(fish, DEFAULT_TANK_LAYER);
  fish.cavePathIndex = null;
  fish.caveIdleTargetXNorm = null;
  fish.caveIdleTargetYNorm = null;
  fish.caveIdleTargetAt = null;
  fish.targetXNorm = clamp(point.xNorm, 0.08, 0.92);
  fish.targetYNorm = clamp(point.yNorm, 0.14, 0.8);
  fish.targetAt = now + 900 + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 14000;
  setFishTankLayers(fish, backLayer, backLayer);
  setFishDesiredTankLayer(fish, backLayer);

  if (Math.abs(fish.targetXNorm - fish.xNorm) > FISH_DIRECTION_TARGET_DEADZONE_NORM) {
    setFishDirection(fish, fish.targetXNorm >= fish.xNorm ? 1 : -1, species, now);
  }

  return true;
}

function enforceActiveCaveMaskRule(fish, species, now = Date.now()) {
  if (!fish?.caveState || !species || species.behavior === "sucker") {
    return false;
  }

  const activePlan = getActiveFishCavePlan(fish);
  if (activePlan?.debugForced && isDebugCaveTestFish(fish)) {
    return false;
  }

  if (!["enter", "inside", "exit", "depart"].includes(fish.caveState)) {
    return false;
  }

  if (!fishShapeLeavesActiveCaveInterior(fish, species, now, fish.xNorm, fish.yNorm)) {
    return false;
  }

  const decor = getCaveBehaviorDecorById(fish.caveDecorId);
  if (decor && fish.caveState === "inside") {
    const seatRegion = getActiveFishCaveSeatRegion(fish);
    const seatDirection = seatRegion ? getCaveSeatFacingDirection(seatRegion, fish.direction || 1) : null;
    const settlePoint = seatRegion
      ? (pickCaveSeatIdleTarget(decor, seatRegion, fish, species, now, seatDirection) || {
        xNorm: seatRegion.xNorm,
        yNorm: seatRegion.yNorm
      })
      : (
        Number.isFinite(fish.caveInsideXNorm) && Number.isFinite(fish.caveInsideYNorm)
          ? { xNorm: fish.caveInsideXNorm, yNorm: fish.caveInsideYNorm }
          : null
      );

    if (settlePoint) {
      if (seatRegion && Number.isFinite(Number(seatDirection))) {
        setFishDirection(fish, normalizeCaveSeatFacing(seatDirection), species, now);
      }
      return retargetFishToSafeCaveInteriorPoint(fish, species, settlePoint, now, "enter");
    }
  }

  return forceFishToCaveFrontLayer(fish, species, now);
}

function updateFishCaveBehavior(fish, species, now = Date.now()) {
  if (!fish?.caveState || !fish.caveDecorId || species?.behavior === "sucker" || fish.activity !== "roam") {
    return false;
  }

  const plan = getActiveFishCavePlan(fish);
  if (!plan || plan.decorId !== fish.caveDecorId) {
    abortFishCaveBehavior(fish, now, false);
    return false;
  }

  const decorItem = getCaveBehaviorDecorById(plan.decorId);
  if (!decorItem) {
    abortFishCaveBehavior(fish, now, false);
    return false;
  }
  const debugForcedPlan = Boolean(plan.debugForced) && isDebugCaveTestFish(fish);
  const debugTestLoop = Boolean(plan.debugTestLoop) && isDebugCaveTestFish(fish);

  const triggerRegion = getActiveFishCaveTriggerRegion(fish);
  let seatRegion = getActiveFishCaveSeatRegion(fish);
  const mouthNode = triggerRegion || plan.mouth;
  let insideNode = seatRegion || plan.inside;
  const distanceToTarget = Math.hypot(fish.targetXNorm - fish.xNorm, fish.targetYNorm - fish.yNorm);
  const distanceToMouth = mouthNode
    ? Math.hypot(fish.xNorm - mouthNode.xNorm, fish.yNorm - mouthNode.yNorm)
    : Number.POSITIVE_INFINITY;
  const reachedTarget = distanceToTarget <= CAVE_GENERAL_REACHED_DISTANCE_NORM;
  const reachedMouth = distanceToTarget <= CAVE_MOUTH_REACHED_DISTANCE_NORM;
  const reachedTrigger = triggerRegion ? isFishWithinRegionBounds(fish, triggerRegion, 8) : reachedMouth;
  const stalledAtTrigger = (
    Number.isFinite(fish.targetAt) &&
    now >= fish.targetAt + CAVE_TRIGGER_STALL_FORCE_MS &&
    distanceToMouth <= CAVE_TRIGGER_STALL_FORCE_DISTANCE_NORM
  );

  if (fish.caveState === "approach") {
    fish.hangoutDecorId = fish.caveDecorId;
    setFishTankLayers(
      fish,
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
    );
    if (reachedTarget) {
      fish.caveState = "align";
      fish.cavePathIndex = null;
      setFishTankLayers(
        fish,
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
      );
      if (!setFishTargetToCaveNode(fish, mouthNode, now, 1200)) {
        abortFishCaveBehavior(fish, now, true);
        return false;
      }
      return true;
    }

    return true;
  }

  if (fish.caveState === "align") {
    fish.hangoutDecorId = fish.caveDecorId;
    setFishTankLayers(
      fish,
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
    );
    if (reachedTrigger || stalledAtTrigger) {
      fish.xNorm = clamp(mouthNode.xNorm, 0.08, 0.92);
      fish.yNorm = clamp(mouthNode.yNorm, 0.14, 0.8);
      fish.targetXNorm = fish.xNorm;
      fish.targetYNorm = fish.yNorm;
      const mouthPose = getFishCollisionPose(fish, species, now, fish.xNorm, fish.yNorm, fish.direction || 1);
      if (!plan.configuredPoints && !debugForcedPlan && !stalledAtTrigger && !canFishChangeToLayer(fish, species, now, clampTankLayer(fish.caveBackLayer || DEFAULT_TANK_LAYER), mouthPose)) {
        setFishTankLayers(
          fish,
          clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
          clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
        );
        setFishDesiredTankLayer(fish, clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER));
        fish.targetAt = now + 900;
        return true;
      }
      fish.caveTriggerCooldownUntil = now + CAVE_TRIGGER_COOLDOWN_MS;
      fish.caveIdleTargetXNorm = null;
      fish.caveIdleTargetYNorm = null;
      fish.caveIdleTargetAt = null;
      fish.caveState = "enter";
      const interiorLayer = getFishActiveCaveInsideLayer(fish, DEFAULT_TANK_LAYER);
      setFishTankLayers(fish, interiorLayer, interiorLayer);
      fish.cavePathIndex = 0;

      if (!setFishTargetToCaveNode(fish, plan.entryPathNodes[0] || insideNode, now, 1200)) {
        abortFishCaveBehavior(fish, now, true);
        return false;
      }
      return true;
    }

    return true;
  }

  if (fish.caveState === "enter") {
    fish.hangoutDecorId = fish.caveDecorId;
    const interiorLayer = getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS);
    setFishTankLayers(
      fish,
      interiorLayer,
      interiorLayer
    );
    if (reachedTarget) {
      const nextIndex = (Number.isFinite(fish.cavePathIndex) ? fish.cavePathIndex : 0) + 1;
      if (nextIndex < plan.entryPathNodes.length) {
        fish.cavePathIndex = nextIndex;
        setFishTargetToCaveNode(fish, plan.entryPathNodes[nextIndex], now, 1300);
        return true;
      }

      fish.caveState = "inside";
      fish.cavePathIndex = null;
      if (!plan.configuredPoints) {
        plan.seatId = null;
      }
      plan.normalInsideMode = null;
      plan.normalTargetPoint = null;
      plan.normalSeatPoint = plan.configuredPoints && plan.inside ? { ...plan.inside } : null;
      plan.normalSeatHoldUntil = null;
      plan.normalLastRoamTarget = null;
      plan.normalHasRoamed = plan.configuredPoints === true;
      clearNormalCavePathState(plan);
      fish.caveSeatId = plan.configuredPoints ? (plan.seatId || null) : null;
      fish.caveInsideUntil = Math.max(Number(fish.caveInsideUntil) || 0, now + CAVE_TRIGGER_COOLDOWN_MS);
      fish.caveIdleTargetXNorm = null;
      fish.caveIdleTargetYNorm = null;
      fish.caveIdleTargetAt = null;
      fish.targetXNorm = fish.xNorm;
      fish.targetYNorm = fish.yNorm;
      fish.targetAt = Math.max(fish.caveInsideUntil || 0, now + 1200);
      if (Number.isFinite(Number(plan.seatDirection))) {
        setFishDirection(fish, normalizeCaveSeatFacing(plan.seatDirection), species, now);
      } else if (fish.caveSeatId) {
        applyFishCaveSeatFacingById(fish, species, decorItem, fish.caveSeatId, now, fish.direction || 1);
      }
      setFishDesiredTankLayer(fish, getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS));
      return true;
    }

    return true;
  }

  if (fish.caveState === "inside") {
    const insideLayer = getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS);
    fish.hangoutDecorId = fish.caveDecorId;
    setFishTankLayers(
      fish,
      insideLayer,
      insideLayer
    );
    if (debugTestLoop) {
      return updateDebugFishCaveInsideBehavior(fish, species, decorItem, plan, mouthNode, now);
    }
    return updateNormalFishCaveInsideBehavior(fish, species, decorItem, plan, mouthNode, now);
  }

  if (fish.caveState === "exit") {
    fish.hangoutDecorId = fish.caveDecorId;
    const interiorLayer = getFishActiveCaveInsideLayer(fish, TANK_DEPTH_LAYERS);
    setFishTankLayers(
      fish,
      interiorLayer,
      interiorLayer
    );
    if (reachedTrigger || reachedTarget || stalledAtTrigger) {
      const nextIndex = (Number.isFinite(fish.cavePathIndex) ? fish.cavePathIndex : 0) + 1;
      if (nextIndex < plan.exitPathNodes.length) {
        fish.cavePathIndex = nextIndex;
        setFishTargetToCaveNode(fish, plan.exitPathNodes[nextIndex], now, 1300);
        return true;
      }

      fish.xNorm = clamp(mouthNode.xNorm, 0.08, 0.92);
      fish.yNorm = clamp(mouthNode.yNorm, 0.14, 0.8);
      fish.targetXNorm = fish.xNorm;
      fish.targetYNorm = fish.yNorm;
      const mouthPose = getFishCollisionPose(fish, species, now, fish.xNorm, fish.yNorm, fish.direction || 1);
      if (!plan.configuredPoints && !debugForcedPlan && !stalledAtTrigger && !canFishChangeToLayer(fish, species, now, clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER), mouthPose)) {
        fish.targetAt = now + 900;
        return true;
      }
      fish.caveState = "leave";
      fish.cavePathIndex = null;
      fish.caveTriggerCooldownUntil = now + CAVE_TRIGGER_COOLDOWN_MS;
      fish.targetXNorm = fish.caveApproachXNorm;
      fish.targetYNorm = fish.caveApproachYNorm;
      fish.targetAt = now + 5000;
      setFishTankLayers(
        fish,
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
      );
      return true;
    }

    return true;
  }

  if (fish.caveState === "depart") {
    fish.hangoutDecorId = fish.caveDecorId;
    const interiorLayer = getFishActiveCaveInsideLayer(fish, DEFAULT_TANK_LAYER);
    setFishTankLayers(
      fish,
      interiorLayer,
      interiorLayer
    );
    if (reachedMouth) {
      fish.xNorm = clamp(plan.mouth.xNorm, 0.08, 0.92);
      fish.yNorm = clamp(plan.mouth.yNorm, 0.14, 0.8);
      fish.targetXNorm = fish.xNorm;
      fish.targetYNorm = fish.yNorm;
      fish.caveState = "leave";
      fish.targetXNorm = fish.caveApproachXNorm;
      fish.targetYNorm = fish.caveApproachYNorm;
      fish.targetAt = now + 5000;
      setFishTankLayers(
        fish,
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
        clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
      );
      return true;
    }

    return true;
  }

  if (fish.caveState === "leave") {
    fish.hangoutDecorId = fish.caveDecorId;
    setFishTankLayers(
      fish,
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER),
      clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
    );
    if (reachedTarget || now > fish.targetAt + 2400) {
      fish.caveTriggerCooldownUntil = Math.max(
        Number(fish.caveTriggerCooldownUntil) || 0,
        now + CAVE_POST_EXIT_COOLDOWN_MS
      );
      abortFishCaveBehavior(fish, now, false);
      fish.targetAt = now;
      return false;
    }

    return true;
  }

  abortFishCaveBehavior(fish, now, false);
  return false;
}



function getCaveBarrierDescriptor(item) {
  if (!item || !isCaveDecorKey(item.decorKey)) {
    return null;
  }

  const span = getDecorLayerSpan(item.decorKey, getDecorTankLayer(item));
  const descriptor = getCaveShellDescriptor(item);
  if (!descriptor) {
    return null;
  }

  return {
    ...descriptor,
    decorId: item.id,
    frontLayer: span.front,
    barrierLayer: span.back,
    backLayer: span.back,
    minLayer: span.front,
    maxLayer: span.back
  };
}

function segmentHitsShapeDescriptor(
  descriptor,
  fromX,
  fromY,
  toX,
  toY,
  threshold = ALPHA_COLLISION_THRESHOLD,
  sampleStepPx = 8
) {
  if (!descriptor) {
    return false;
  }

  if (
    !boundsIntersect(
      descriptor.bounds,
      {
        left: Math.min(fromX, toX),
        right: Math.max(fromX, toX),
        top: Math.min(fromY, toY),
        bottom: Math.max(fromY, toY)
      }
    )
  ) {
    return false;
  }

  const dx = toX - fromX;
  const dy = toY - fromY;
  const distance = Math.hypot(dx, dy);
  const steps = Math.max(1, Math.ceil(distance / Math.max(2, sampleStepPx)));

  for (let index = 0; index <= steps; index += 1) {
    const t = index / steps;
    const x = fromX + dx * t;
    const y = fromY + dy * t;

    if (pointHitsShapeDescriptor(descriptor, x, y, threshold)) {
      return true;
    }
  }

  return false;
}

function getFishCollisionPose(fish, species, now, xNorm, yNorm, directionOverride = null) {
  const pose = getFishPose(fish, species, now);
  const direction = directionOverride == null
    ? (Math.abs(fish.targetXNorm - fish.xNorm) > 0.0001 ? (fish.targetXNorm >= fish.xNorm ? 1 : -1) : (fish.direction || 1))
    : directionOverride;

  return {
    ...pose,
    x: xNorm * TANK_WIDTH,
    y: yNorm * TANK_HEIGHT,
    direction,
    facingScaleX: direction < 0 ? -1 : 1
  };
}

function fishPoseHitsCaveBarrier(fish, species, now, pose, barrierDescriptor) {
  const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
  if (!fishDescriptor || !barrierDescriptor) {
    return false;
  }

  return shapesOverlapByMaskStrict(fishDescriptor, barrierDescriptor, CAVE_STRICT_SAMPLE_STEP_PX);
}

function getFishFootprintBoundsAtPose(fish, species, now, pose) {
  const image = runtime.images.get(getFishDisplayAssetPath(fish, species, now) || species?.asset);
  if (!fish || !species || !pose || !image) {
    return null;
  }

  const width = getFishDisplayWidth(fish, species, now);
  const height = width * (image.height / image.width);
  const centerX = pose.x + (pose.swayX || 0);
  const centerY = pose.y;
  const radiusX = width * 0.38;
  const radiusY = height * 0.32;

  return {
    left: centerX - radiusX,
    right: centerX + radiusX,
    top: centerY - radiusY,
    bottom: centerY + radiusY
  };
}

function getBlockingCaveFootprint(item) {
  if (!item || !isCaveDecorKey(item.decorKey)) {
    return null;
  }

  return getPlacedDecorOpaqueBounds(item);
}

function findBlockingCaveForFishPose(fish, species, now, pose, layerOverride = null) {
  if (!fish || !species || species.behavior === "sucker") {
    return null;
  }

  const testLayer = clampTankLayer(layerOverride ?? getFishTankLayer(fish));
  if (testLayer < 3) {
    return null;
  }

  const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
  if (!fishDescriptor) {
    return null;
  }

  for (const item of state.placedDecor) {
    if (!isCaveDecorKey(item.decorKey)) {
      continue;
    }

    if (isFishUsingOwnCavePath(fish, item)) {
      continue;
    }

    const descriptor = getCaveBlockingDescriptorForLayer(item, testLayer);
    if (!descriptor) {
      continue;
    }

    if (boundsIntersect(fishDescriptor.bounds, descriptor.bounds) && shapesOverlapByMaskStrict(fishDescriptor, descriptor, CAVE_STRICT_SAMPLE_STEP_PX)) {
      return {
        item,
        span: getDecorLayerSpan(item.decorKey, getDecorTankLayer(item)),
        descriptor
      };
    }
  }

  return null;
}

function pushFishOutOfBlockingCave(fish, species, now) {
  if (!fish || !species || fish.caveState) {
    return false;
  }

  const pose = getFishPose(fish, species, now);
  const blocking = findBlockingCaveForFishPose(fish, species, now, pose);
  if (!blocking) {
    return false;
  }

  const fishX = fish.xNorm * TANK_WIDTH;
  const fishY = fish.yNorm * TANK_HEIGHT;
  const footprint = blocking.descriptor?.bounds;
  if (!footprint) {
    return false;
  }
  const leftEscapePx = Math.abs(fishX - footprint.left);
  const rightEscapePx = Math.abs(footprint.right - fishX);
  const escapeLeft = leftEscapePx <= rightEscapePx;
  const targetX = escapeLeft ? footprint.left - 36 : footprint.right + 36;
  const targetY = Math.min(footprint.bottom + 18, TANK_HEIGHT * 0.79);

  const safeFrontLayer = Math.max(1, clampTankLayer((blocking.span?.front || 3) - 1));
  setFishTankLayers(fish, safeFrontLayer, safeFrontLayer);
  fish.targetXNorm = clamp(targetX / TANK_WIDTH, 0.08, 0.92);
  fish.targetYNorm = clamp(targetY / TANK_HEIGHT, 0.14, 0.8);
  fish.targetAt = now + 1800 + Math.hypot(fish.xNorm - fish.targetXNorm, fish.yNorm - fish.targetYNorm) * 14000;
  fish.hangoutDecorId = null;
  fish.blockedDecorId = blocking.item.id;
  fish.blockedDecorUntil = now + 5200;
  if (Math.abs(fish.targetXNorm - fish.xNorm) > 0.002) {
    setFishDirection(fish, fish.targetXNorm >= fish.xNorm ? 1 : -1, species, now);
  }
  return true;
}

function pathHitsShapeAtLayer(fish, species, fromXNorm, fromYNorm, toXNorm, toYNorm, now, descriptor) {
  if (!descriptor) {
    return false;
  }

  const direction = Math.abs(toXNorm - fromXNorm) > 0.0001
    ? (toXNorm >= fromXNorm ? 1 : -1)
    : (fish.direction || 1);
  const fullDx = toXNorm - fromXNorm;
  const fullDy = toYNorm - fromYNorm;
  const fullDistancePx = Math.hypot(fullDx * TANK_WIDTH, fullDy * TANK_HEIGHT);
  const samples = Math.max(2, Math.ceil(fullDistancePx / 4));

  for (let i = 1; i <= samples; i += 1) {
    const t = i / samples;
    const sampleXNorm = fromXNorm + fullDx * t;
    const sampleYNorm = fromYNorm + fullDy * t;
    const pose = getFishCollisionPose(fish, species, now, sampleXNorm, sampleYNorm, direction);
    const fishDescriptor = getFishShapeDescriptor(fish, species, now, pose);
    if (fishDescriptor && shapesOverlapByMask(fishDescriptor, descriptor, 5)) {
      return true;
    }
  }

  return false;
}

function pathHitsActiveCaveFront(fish, species, fromXNorm, fromYNorm, toXNorm, toYNorm, now) {
  if (!fish?.caveState || ["approach", "align", "leave"].includes(fish.caveState) || !fish.caveDecorId) {
    return false;
  }

  const decor = getCaveBehaviorDecorById(fish.caveDecorId);
  if (!decor) {
    return false;
  }

  const frontDescriptor = getDecorShapeDescriptor(decor);
  return pathHitsShapeAtLayer(fish, species, fromXNorm, fromYNorm, toXNorm, toYNorm, now, frontDescriptor);
}

function pathHitsAnyCaveBarrierAtLayer(fish, species, fromXNorm, fromYNorm, toXNorm, toYNorm, now, testLayer) {
  const direction = Math.abs(toXNorm - fromXNorm) > 0.0001
    ? (toXNorm >= fromXNorm ? 1 : -1)
    : (fish.direction || 1);
  const checkedLayer = clampTankLayer(testLayer);

  for (const item of state.placedDecor) {
    const barrier = getCaveBarrierDescriptor(item);
    if (!barrier) {
      continue;
    }

    if (isFishUsingOwnCavePath(fish, item)) {
      continue;
    }

    if (checkedLayer < barrier.frontLayer || checkedLayer > barrier.backLayer) {
      continue;
    }

    const fullDx = toXNorm - fromXNorm;
    const fullDy = toYNorm - fromYNorm;
    const fullDistancePx = Math.hypot(fullDx * TANK_WIDTH, fullDy * TANK_HEIGHT);
    const samples = Math.max(2, Math.ceil(fullDistancePx / 4));

    for (let i = 1; i <= samples; i += 1) {
      const t = i / samples;
      const sampleXNorm = fromXNorm + fullDx * t;
      const sampleYNorm = fromYNorm + fullDy * t;
      const pose = getFishCollisionPose(fish, species, now, sampleXNorm, sampleYNorm, direction);

      if (fishPoseHitsCaveBarrier(fish, species, now, pose, barrier)) {
        return true;
      }
    }
  }

  return false;
}

function resolveFishCaveCollision(fish, nextXNorm, nextYNorm, now = Date.now()) {
  const species = getSpeciesForFish(fish);
  if (!species || species.behavior === "sucker") {
    return {
      xNorm: nextXNorm,
      yNorm: nextYNorm,
      blocked: false
    };
  }

  const currentLayer = getFishTankLayer(fish);
  const effectiveLayer = currentLayer;
  const startXNorm = fish.xNorm;
  const startYNorm = fish.yNorm;
  let resolvedXNorm = clamp(nextXNorm, 0.08, 0.92);
  let resolvedYNorm = clamp(nextYNorm, 0.14, 0.8);

  if (effectiveLayer < 3) {
    return {
      xNorm: resolvedXNorm,
      yNorm: resolvedYNorm,
      blocked: false
    };
  }

  const nextPose = getFishCollisionPose(
    fish,
    species,
    now,
    resolvedXNorm,
    resolvedYNorm,
    Math.abs(resolvedXNorm - startXNorm) > 0.0001
      ? (resolvedXNorm >= startXNorm ? 1 : -1)
      : (fish.direction || 1)
  );
  const blockingCave = findBlockingCaveForFishPose(fish, species, now, nextPose, effectiveLayer);
  if (!blockingCave) {
    return {
      xNorm: resolvedXNorm,
      yNorm: resolvedYNorm,
      blocked: false,
      blockingCave: null
    };
  }

  const activePlan = fish.caveState ? getActiveFishCavePlan(fish) : null;
  if (
    activePlan?.debugForced &&
    isDebugCaveTestFish(fish) &&
    blockingCave.item?.id === fish.caveDecorId
  ) {
    return {
      xNorm: resolvedXNorm,
      yNorm: resolvedYNorm,
      blocked: false,
      blockingCave: null
    };
  }

  if (!fish.caveState) {
    return {
      xNorm: startXNorm,
      yNorm: startYNorm,
      blocked: true,
      blockingCave
    };
  }

  return {
    xNorm: startXNorm,
    yNorm: startYNorm,
    blocked: true,
    blockingCave
  };
}

function getFishShapeDescriptor(fish, species, now, poseOverride = null) {
  const fishAsset = getFishDisplayAssetPath(fish, species, now) || species?.asset;
  const image = runtime.images.get(fishAsset);
  const mask = fishAsset ? getImageAlphaMask(fishAsset) : null;
  if (!species || !image || !mask) {
    return null;
  }

  const pose = poseOverride || getFishPose(fish, species, now);
  const width = getFishDisplayWidth(fish, species, now);
  const height = width * (image.height / image.width);
  const centerX = pose.x + pose.swayX;
  const centerY = pose.y;
  const facingScaleX = pose.facingScaleX ?? (pose.direction < 0 ? -1 : 1);
  const bodyScaleX = pose.bodyScaleX || 1;
  const bodyScaleY = pose.bodyScaleY || 1;
  const tilt = pose.tilt || 0;
  const drawX = -width / 2 + pose.wiggle * width * 0.018;
  const drawY = -height / 2;
  const cos = Math.cos(-tilt);
  const sin = Math.sin(-tilt);
  const worldCos = Math.cos(tilt);
  const worldSin = Math.sin(tilt);
  const localToWorld = (localX, localY) => {
    const sx = localX * bodyScaleX;
    const sy = localY * bodyScaleY;
    const rx = sx * worldCos - sy * worldSin;
    const ry = sx * worldSin + sy * worldCos;
    return {
      x: centerX + rx * facingScaleX,
      y: centerY + ry
    };
  };
  const corners = [
    localToWorld(drawX, drawY),
    localToWorld(drawX + width, drawY),
    localToWorld(drawX + width, drawY + height),
    localToWorld(drawX, drawY + height)
  ];

  return {
    mask,
    bounds: {
      left: Math.min(...corners.map((corner) => corner.x)),
      right: Math.max(...corners.map((corner) => corner.x)),
      top: Math.min(...corners.map((corner) => corner.y)),
      bottom: Math.max(...corners.map((corner) => corner.y))
    },
    worldToUv(worldX, worldY) {
      let localX = worldX - centerX;
      let localY = worldY - centerY;
      localX /= Math.abs(facingScaleX) < 0.0001 ? 1 : facingScaleX;
      const rotatedX = localX * cos - localY * sin;
      const rotatedY = localX * sin + localY * cos;
      localX = rotatedX / (Math.abs(bodyScaleX) < 0.0001 ? 1 : bodyScaleX);
      localY = rotatedY / (Math.abs(bodyScaleY) < 0.0001 ? 1 : bodyScaleY);
      return {
        u: (localX - drawX) / width,
        v: (localY - drawY) / height
      };
    }
  };
}

function getOverlappingDecorForFish(fish, species, now, poseOverride = null, options = null) {
  const fishDescriptor = getFishShapeDescriptor(fish, species, now, poseOverride);
  if (!fishDescriptor) {
    return [];
  }

  const minLayer = Number.isFinite(options?.minLayer) ? clampTankLayer(options.minLayer) : 1;
  const maxLayer = Number.isFinite(options?.maxLayer) ? clampTankLayer(options.maxLayer) : TANK_DEPTH_LAYERS;
  const overlaps = [];
  for (const item of state.placedDecor) {
    const itemLayer = getDecorTankLayer(item);
    if (itemLayer < minLayer || itemLayer > maxLayer) {
      continue;
    }

    const opaqueBounds = getPlacedDecorOpaqueBounds(item);
    if (opaqueBounds && !boundsIntersect(fishDescriptor.bounds, opaqueBounds)) {
      continue;
    }

    const decorDescriptor = getDecorShapeDescriptor(item);
    if (!decorDescriptor || !shapesOverlapByMask(fishDescriptor, decorDescriptor, 10)) {
      continue;
    }

    overlaps.push({
      item,
      layer: itemLayer,
      descriptor: decorDescriptor
    });
  }

  return overlaps;
}

function getOverlappingFishForLayerChange(fish, species, now, poseOverride = null, options = null) {
  const fishDescriptor = getFishShapeDescriptor(fish, species, now, poseOverride);
  if (!fishDescriptor) {
    return [];
  }

  const minLayer = Number.isFinite(options?.minLayer) ? clampTankLayer(options.minLayer) : 1;
  const maxLayer = Number.isFinite(options?.maxLayer) ? clampTankLayer(options.maxLayer) : TANK_DEPTH_LAYERS;
  const overlaps = [];

  for (const otherFish of state.fish) {
    if (!otherFish || otherFish.id === fish.id || isFishDead(otherFish)) {
      continue;
    }

    const otherLayer = getFishTankLayer(otherFish);
    if (otherLayer < minLayer || otherLayer > maxLayer) {
      continue;
    }

    const otherSpecies = runtime.fishMap.get(otherFish.speciesId);
    if (!otherSpecies) {
      continue;
    }

    const otherPose = getFishPose(otherFish, otherSpecies, now);
    const otherBounds = getFishOcclusionBounds(otherFish, otherSpecies, otherPose);
    if (otherBounds && !boundsIntersect(fishDescriptor.bounds, otherBounds)) {
      continue;
    }

    const otherDescriptor = getFishShapeDescriptor(otherFish, otherSpecies, now, otherPose);
    if (!otherDescriptor || !shapesOverlapByMask(fishDescriptor, otherDescriptor, 10)) {
      continue;
    }

    overlaps.push({
      fish: otherFish,
      layer: otherLayer,
      descriptor: otherDescriptor
    });
  }

  return overlaps;
}

function canFishChangeToLayer(fish, species, now, desiredLayer, poseOverride = null) {
  const currentLayer = getFishTankLayer(fish);
  const targetLayer = clampTankLayer(desiredLayer);
  if (targetLayer === currentLayer) {
    return true;
  }

  const pose = poseOverride || getFishPose(fish, species, now);
  if (findBlockingCaveForFishPose(fish, species, now, pose, targetLayer)) {
    return false;
  }

  const minLayer = Math.min(currentLayer, targetLayer);
  const maxLayer = Math.max(currentLayer, targetLayer);
  const decorOverlaps = getOverlappingDecorForFish(fish, species, now, pose, {
    minLayer,
    maxLayer
  });
  const fishOverlaps = getOverlappingFishForLayerChange(fish, species, now, pose, {
    minLayer,
    maxLayer
  });

  if (targetLayer > currentLayer) {
    return !decorOverlaps.some(({ layer }) => layer >= currentLayer && layer <= targetLayer) &&
      !fishOverlaps.some(({ layer }) => layer >= currentLayer && layer <= targetLayer);
  }

  return !decorOverlaps.some(({ layer }) => layer <= currentLayer && layer >= targetLayer) &&
    !fishOverlaps.some(({ layer }) => layer <= currentLayer && layer >= targetLayer);
}

function syncFishDrawLayer(fish, species, now) {
  if (getEffectiveFishBehavior(fish, species) === "sucker") {
    setFishTankLayers(fish, TANK_DEPTH_LAYERS, TANK_DEPTH_LAYERS);
    return;
  }

  if (fish.caveState) {
    const lockedLayer = ["approach", "align", "leave"].includes(fish.caveState)
      ? clampTankLayer(fish.caveFrontLayer || DEFAULT_TANK_LAYER)
      : getFishActiveCaveInsideLayer(fish, DEFAULT_TANK_LAYER);
    setFishTankLayers(fish, lockedLayer, lockedLayer);
    return;
  }

  const currentLayer = getFishTankLayer(fish);
  const desiredLayer = getDesiredFishTankLayer(fish);
  setFishTankLayers(fish, currentLayer, desiredLayer);
  if (desiredLayer === currentLayer) {
    return;
  }

  const pose = getFishPose(fish, species, now);
  if (canFishChangeToLayer(fish, species, now, desiredLayer, pose)) {
    setFishTankLayers(fish, desiredLayer, desiredLayer);
  }
}

function isFishInsideTargetDecor(fish, species, pose) {
  const currentLayer = getFishTankLayer(fish);
  if (!fish.hangoutDecorId) {
    return !isFishOccludedByDecor(fish, species, pose);
  }

  const overlap = getOverlappingDecorForFish(fish, species, Date.now(), pose).find(({ item }) => item.id === fish.hangoutDecorId);
  return Boolean(overlap && currentLayer > overlap.layer);
}

function isFishOccludedByDecor(fish, species, pose) {
  const currentLayer = getFishTankLayer(fish);
  return getOverlappingDecorForFish(fish, species, Date.now(), pose).some(({ layer }) => layer < currentLayer);
}

function getFishOcclusionBounds(fish, species, pose) {
  const image = runtime.images.get(getFishDisplayAssetPath(fish, species) || species.asset);
  const width = getFishDisplayWidth(fish, species);
  const height = width * (image ? image.height / image.width : 0.65);
  const bodyWidth = width * 0.52;
  const bodyHeight = height * 0.36;

  return {
    left: pose.x - bodyWidth / 2,
    right: pose.x + bodyWidth / 2,
    top: pose.y - bodyHeight / 2,
    bottom: pose.y + bodyHeight / 2
  };
}

function boundsIntersect(leftBounds, rightBounds) {
  return !(
    leftBounds.right <= rightBounds.left ||
    leftBounds.left >= rightBounds.right ||
    leftBounds.bottom <= rightBounds.top ||
    leftBounds.top >= rightBounds.bottom
  );
}

function isTankOverlayTarget(target) {
  return (
    target instanceof Element &&
    Boolean(target.closest("#tankSidebar, .tank-display, .tank-bottom-dock, #editDecorTray, #editFishTray, #foodTray, #medicineTray, .tank-overlay-hints, .store-overlay, .settings-overlay, .fish-inspector, .decor-settings-badge-button, .decor-action-float-button, .tab-buttons"))
  );
}

function randomSwimX() {
  return 0.08 + Math.random() * 0.84;
}

function randomSwimY(layer = DEFAULT_TANK_LAYER, fish = null, species = getSpeciesForFish(fish), options = {}) {
  const range = getLayerSwimYRange(layer, fish, species, options);
  return range.min + Math.random() * Math.max(0, range.max - range.min);
}

function getFishFacingDirection(fish) {
  return Number(fish?.displayDirection) < 0 ? -1 : 1;
}

function normalizeAngle(angle) {
  let next = Number.isFinite(Number(angle)) ? Number(angle) : 0;
  while (next > Math.PI) {
    next -= Math.PI * 2;
  }
  while (next <= -Math.PI) {
    next += Math.PI * 2;
  }
  return next;
}

function getFishFacingAngle(fish) {
  return Number.isFinite(Number(fish?.displayAngle))
    ? normalizeAngle(Number(fish.displayAngle))
    : (getFishFacingDirection(fish) < 0 ? Math.PI : 0);
}

function getDirectedAngleDelta(fromAngle, toAngle, spinDirection = 1) {
  const start = normalizeAngle(fromAngle);
  const end = normalizeAngle(toAngle);
  const clockwiseDelta = (end - start + Math.PI * 2) % (Math.PI * 2);
  const counterClockwiseDelta = clockwiseDelta - Math.PI * 2;
  const shortestDelta = Math.abs(clockwiseDelta) <= Math.abs(counterClockwiseDelta)
    ? clockwiseDelta
    : counterClockwiseDelta;
  if (Math.abs(shortestDelta) <= Math.PI * 0.55) {
    return shortestDelta;
  }
  return spinDirection < 0 ? counterClockwiseDelta : clockwiseDelta;
}

function updateFishTurnState(fish, species, now) {
  if (species.behavior !== "sucker") {
    const liveDirection = Number(fish.direction) < 0 ? -1 : 1;
    if (!fish.turnStartedAt || fish.turnDurationMs <= 0) {
      fish.displayDirection = liveDirection;
      fish.displayAngle = liveDirection < 0 ? Math.PI : 0;
      fish.turnStartedAt = null;
      fish.turnDurationMs = 0;
      fish.turnFromDirection = fish.displayDirection;
      fish.turnToDirection = fish.displayDirection;
      fish.turnFromAngle = fish.displayAngle;
      fish.turnToAngle = fish.displayAngle;
      fish.turnSpinDirection = fish.displayDirection < 0 ? 1 : -1;
      return;
    }

    const progress = clamp((now - fish.turnStartedAt) / fish.turnDurationMs, 0, 1);
    const fromDirection = Number(fish.turnFromDirection) < 0 ? -1 : 1;
    const toDirection = Number(fish.turnToDirection) < 0 ? -1 : 1;
    const visibleDirection = progress < 0.5 ? fromDirection : toDirection;
    fish.displayDirection = visibleDirection;
    fish.displayAngle = visibleDirection < 0 ? Math.PI : 0;

    if (progress >= 1) {
      fish.displayDirection = liveDirection;
      fish.displayAngle = liveDirection < 0 ? Math.PI : 0;
      fish.turnStartedAt = null;
      fish.turnDurationMs = 0;
      fish.turnFromDirection = fish.displayDirection;
      fish.turnToDirection = fish.displayDirection;
      fish.turnFromAngle = fish.displayAngle;
      fish.turnToAngle = fish.displayAngle;
      fish.turnSpinDirection = fish.displayDirection < 0 ? 1 : -1;
    }
    return;
  }

  if (!fish.turnStartedAt || fish.turnDurationMs <= 0) {
    fish.displayAngle = getFishFacingAngle(fish);
    fish.displayDirection = Math.cos(fish.displayAngle) < 0 ? -1 : 1;
    return;
  }

  if (now >= fish.turnStartedAt + fish.turnDurationMs) {
    fish.displayAngle = Number.isFinite(Number(fish.turnToAngle))
      ? normalizeAngle(Number(fish.turnToAngle))
      : getFishFacingAngle(fish);
    fish.displayDirection = Math.cos(fish.displayAngle) < 0 ? -1 : 1;
    fish.turnStartedAt = null;
    fish.turnDurationMs = 0;
    fish.turnFromDirection = fish.displayDirection;
    fish.turnToDirection = fish.displayDirection;
    fish.turnFromAngle = fish.displayAngle;
    fish.turnToAngle = fish.displayAngle;
    fish.turnSpinDirection = fish.displayDirection < 0 ? 1 : -1;
  }
}

function setSuckerFishAngle(fish, desiredAngle, now) {
  const nextAngle = normalizeAngle(desiredAngle);
  const currentAngle = getFishFacingAngle(fish);
  if (Math.abs(getDirectedAngleDelta(currentAngle, nextAngle, fish.turnSpinDirection || 1)) < 0.06) {
    fish.displayAngle = nextAngle;
    fish.displayDirection = Math.cos(nextAngle) < 0 ? -1 : 1;
    fish.direction = fish.displayDirection;
    return;
  }

  const pendingAngle = fish.turnStartedAt && fish.turnDurationMs > 0
    ? normalizeAngle(Number.isFinite(Number(fish.turnToAngle)) ? Number(fish.turnToAngle) : currentAngle)
    : currentAngle;
  if (Math.abs(getDirectedAngleDelta(pendingAngle, nextAngle, fish.turnSpinDirection || 1)) < 0.08) {
    return;
  }

  if (fish.turnStartedAt && fish.turnDurationMs > 0) {
    return;
  }

  const spinDirection = Math.random() < 0.5 ? -1 : 1;
  const turnDelta = getDirectedAngleDelta(currentAngle, nextAngle, spinDirection);
  fish.turnStartedAt = now;
  fish.turnDurationMs = 900 + Math.abs(turnDelta) * 620 + Math.random() * 420;
  fish.turnFromAngle = currentAngle;
  fish.turnToAngle = nextAngle;
  fish.turnSpinDirection = spinDirection;
  fish.turnFromDirection = Math.cos(currentAngle) < 0 ? -1 : 1;
  fish.turnToDirection = Math.cos(nextAngle) < 0 ? -1 : 1;
  fish.direction = fish.turnToDirection;
}

function setFishDirection(fish, desiredDirection, species, now) {
  const nextDirection = Number(desiredDirection) < 0 ? -1 : 1;
  if (species.behavior !== "sucker") {
    const currentDisplayDirection = getFishFacingDirection(fish);
    const currentDisplayAngle = currentDisplayDirection < 0 ? Math.PI : 0;
    fish.direction = nextDirection;

    if (fish.turnStartedAt && fish.turnDurationMs > 0) {
      const pendingDirection = Number(fish.turnToDirection) < 0 ? -1 : 1;
      if (nextDirection === pendingDirection) {
        return;
      }

      if (nextDirection === currentDisplayDirection) {
        fish.displayDirection = nextDirection;
        fish.displayAngle = currentDisplayAngle;
        fish.turnStartedAt = null;
        fish.turnDurationMs = 0;
        fish.turnFromDirection = nextDirection;
        fish.turnToDirection = nextDirection;
        fish.turnFromAngle = currentDisplayAngle;
        fish.turnToAngle = currentDisplayAngle;
        fish.turnSpinDirection = nextDirection < 0 ? 1 : -1;
      }
      return;
    }

    if (nextDirection === currentDisplayDirection) {
      fish.displayDirection = nextDirection;
      fish.displayAngle = currentDisplayAngle;
      fish.turnStartedAt = null;
      fish.turnDurationMs = 0;
      fish.turnFromDirection = nextDirection;
      fish.turnToDirection = nextDirection;
      fish.turnFromAngle = currentDisplayAngle;
      fish.turnToAngle = currentDisplayAngle;
      fish.turnSpinDirection = nextDirection < 0 ? 1 : -1;
      return;
    }

    fish.displayDirection = currentDisplayDirection;
    fish.displayAngle = currentDisplayAngle;
    fish.turnStartedAt = now;
    fish.turnDurationMs = getFishTurnDurationMs(fish, species);
    fish.turnFromDirection = currentDisplayDirection;
    fish.turnToDirection = nextDirection;
    fish.turnFromAngle = currentDisplayAngle;
    fish.turnToAngle = nextDirection < 0 ? Math.PI : 0;
    fish.turnSpinDirection = Math.random() < 0.5 ? -1 : 1;
    return;
  }

  fish.direction = nextDirection;
  setSuckerFishAngle(fish, nextDirection < 0 ? Math.PI : 0, now);
}

function getActiveGravelContour() {
  if (runtime.scene?.gravelSurfaceContour?.length) {
    return runtime.scene.gravelSurfaceContour;
  }
  return runtime.scene?.substrateContour || [0, 0];
}

function getVisibleTankVirtualBounds() {
  const dpr = Math.max(1, window.devicePixelRatio || 1);
  const scale = Math.max(0.0001, Number(runtime.stageRenderScale) || dpr);
  const offsetX = Number(runtime.stageRenderOffsetX) || 0;
  const offsetY = Number(runtime.stageRenderOffsetY) || 0;
  const width = Math.max(1, dom.tankCanvas?.width || TANK_WIDTH * scale);
  const height = Math.max(1, dom.tankCanvas?.height || TANK_HEIGHT * scale);

  return {
    left: clamp((0 - offsetX) / scale, 0, TANK_WIDTH),
    top: clamp((0 - offsetY) / scale, 0, TANK_HEIGHT),
    right: clamp((width - offsetX) / scale, 0, TANK_WIDTH),
    bottom: clamp((height - offsetY) / scale, 0, TANK_HEIGHT)
  };
}

function getTargetVisibleGravelHeightPx() {
  const dpr = Math.max(1, window.devicePixelRatio || 1);
  const viewportHeight = Math.max(
    1,
    dom.tankStage?.getBoundingClientRect().height || ((dom.tankCanvas?.height || TANK_HEIGHT) / dpr)
  );
  return clamp(
    viewportHeight * GRAVEL_VIEWPORT_HEIGHT_RATIO,
    GRAVEL_VISIBLE_HEIGHT_MIN_PX,
    GRAVEL_VISIBLE_HEIGHT_MAX_PX
  );
}

function getTargetVisibleGravelHeightVirtual() {
  const dpr = Math.max(1, window.devicePixelRatio || 1);
  const scale = Math.max(0.0001, Number(runtime.stageRenderScale) || dpr);
  return (getTargetVisibleGravelHeightPx() * dpr) / scale;
}

function getVisibleTankFloorBottomY() {
  const visibleBounds = getVisibleTankVirtualBounds();
  const tankBottom = TANK_HEIGHT - GLASS_MARGIN_BOTTOM;
  return clamp(
    Math.min(tankBottom, visibleBounds.bottom),
    WATER_SURFACE_Y + 90,
    tankBottom
  );
}

function getDynamicGravelSurfaceBaseY() {
  const bottom = getVisibleTankFloorBottomY();
  const targetHeight = getTargetVisibleGravelHeightVirtual();
  return clamp(
    bottom - targetHeight,
    WATER_SURFACE_Y + 80,
    bottom - 40
  );
}

function getGravelFloorLayoutKey() {
  return [
    WATER_SURFACE_Y.toFixed(2),
    getVisibleTankFloorBottomY().toFixed(2),
    getTargetVisibleGravelHeightVirtual().toFixed(2)
  ].join(":");
}

function getGravelSurfacePointY(point) {
  return getDynamicGravelSurfaceBaseY() + point * 11;
}

function traceTankFloorPath(context = tankContext, ridge = getActiveGravelContour()) {
  context.beginPath();
  context.moveTo(GLASS_MARGIN_X, TANK_HEIGHT - GLASS_MARGIN_BOTTOM);
  context.lineTo(GLASS_MARGIN_X, getGravelSurfacePointY(ridge[0]));
  ridge.forEach((point, index) => {
    const x = GLASS_MARGIN_X + (index / (ridge.length - 1)) * (TANK_WIDTH - GLASS_MARGIN_X * 2);
    const y = getGravelSurfacePointY(point);
    context.lineTo(x, y);
  });
  context.lineTo(TANK_WIDTH - GLASS_MARGIN_X, TANK_HEIGHT - GLASS_MARGIN_BOTTOM);
  context.closePath();
}

function traceTankFloorSurfaceBandPath(context = tankContext, ridge = getActiveGravelContour(), bandDepthPx = GRAVEL_SURFACE_CAP_DEPTH_PX + 7) {
  const points = ridge.map((point, index) => ({
    x: GLASS_MARGIN_X + (index / (ridge.length - 1)) * (TANK_WIDTH - GLASS_MARGIN_X * 2),
    y: getGravelSurfacePointY(point)
  }));

  context.beginPath();
  context.moveTo(points[0].x, points[0].y - 2);
  points.forEach((point) => {
    context.lineTo(point.x, point.y - 2);
  });
  for (let index = points.length - 1; index >= 0; index -= 1) {
    const point = points[index];
    context.lineTo(point.x, point.y + bandDepthPx);
  }
  context.closePath();
}

function getTankFloorSurfaceYAtX(x) {
  const ridge = getActiveGravelContour();
  const width = TANK_WIDTH - GLASS_MARGIN_X * 2;
  const normalized = clamp((x - GLASS_MARGIN_X) / width, 0, 1) * (ridge.length - 1);
  const leftIndex = Math.floor(normalized);
  const rightIndex = Math.min(ridge.length - 1, leftIndex + 1);
  const blend = normalized - leftIndex;
  const heightPoint = ridge[leftIndex] * (1 - blend) + ridge[rightIndex] * blend;
  return getGravelSurfacePointY(heightPoint);
}

function buildGravelSurfaceContour(seed = 1) {
  const rand = mulberry32((Math.abs(Math.floor(seed || 1)) || 1) ^ 0x3c6ef35f);
  const contour = Array.from({ length: SUBSTRATE_CONTOUR_POINTS }, (_, index) => {
    const t = index / Math.max(1, SUBSTRATE_CONTOUR_POINTS - 1);
    const longWave = Math.sin(t * Math.PI * (1.12 + rand() * 0.26) + rand() * Math.PI * 2) * 0.3;
    const midWave = Math.sin(t * Math.PI * (2.45 + rand() * 0.9) + rand() * Math.PI * 2) * 0.11;
    const ripple = Math.sin(t * Math.PI * (5.4 + rand() * 1.1) + rand() * Math.PI * 2) * 0.035;
    return longWave + midWave + ripple + (rand() - 0.5) * 0.05;
  });

  for (let pass = 0; pass < 2; pass += 1) {
    for (let index = 1; index < contour.length - 1; index += 1) {
      contour[index] = contour[index - 1] * 0.24 + contour[index] * 0.52 + contour[index + 1] * 0.24;
    }
  }

  contour[0] *= 0.3;
  contour[contour.length - 1] *= 0.3;
  return contour.map((value) => clamp(value, -0.42, 0.42));
}

function createSceneSeeds() {
  const rand = mulberry32(34127);
  const contour = Array.from({ length: SUBSTRATE_CONTOUR_POINTS }, (_, index) => {
    const t = index / (SUBSTRATE_CONTOUR_POINTS - 1);
    const longWave = Math.sin(t * Math.PI * 1.12 + 0.3) * 0.18;
    const shortWave = Math.sin(t * Math.PI * 3.4 + 1.1) * 0.06;
    return longWave + shortWave + (rand() - 0.5) * 0.04;
  });
  return {
    bubbles: Array.from({ length: 34 }, () => {
      const styleRoll = rand();
      return {
        x: 0.08 + rand() * 0.84,
        size: 3.2 + rand() * 9.2,
        speed: 0.03 + rand() * 0.08,
        offset: rand(),
        wobble: 6 + rand() * 18,
        wave: 4 + rand() * 6,
        stretch: 0.84 + rand() * 0.42,
        alpha: 0.18 + rand() * 0.32,
        spriteScale: 2.8 + rand() * 2.6,
        spriteIndex: Math.floor(rand() * Math.max(1, runtime.bubbleCatalog.length || 3)),
        count: 2 + Math.floor(rand() * 3),
        style: styleRoll < 0.22 ? "sprite" : styleRoll < 0.52 ? "cluster" : styleRoll < 0.78 ? "fizz" : "ring",
        layer: 1 + Math.min(AMBIENT_BUBBLE_DEPTH_LAYERS - 1, Math.floor(Math.pow(rand(), 0.86) * AMBIENT_BUBBLE_DEPTH_LAYERS))
      };
    }),
    substrateContour: contour,
    grimeMarks: Array.from({ length: 70 }, () => ({
      x: rand(),
      y: rand(),
      rx: 36 + rand() * 120,
      ry: 10 + rand() * 46,
      rotation: rand() * Math.PI,
      color: rand() > 0.5 ? "rgba(124, 173, 74, 0.36)" : "rgba(96, 148, 69, 0.28)"
    }))
  };
}

function buildFishName(speciesId, takenNames) {
  const pool = runtime.fishMap.get(speciesId)?.defaultNames || [];
  const unused = pool.find((name) => !takenNames.includes(name));
  if (unused) {
    return unused;
  }

  const species = runtime.fishMap.get(speciesId);
  const count = takenNames.filter((name) => name.startsWith(species?.name || "Fish")).length + 1;
  return `${species?.name || "Fish"} ${count}`;
}

function renderHearts(units, maxUnits = Math.max(2, Math.round(Number(units) || 0))) {
  const clampedUnits = Math.max(0, Math.round(Number(units) || 0));
  const heartCount = Math.max(1, Math.ceil(Math.max(0, Number(maxUnits) || clampedUnits) / 2));
  return Array.from({ length: heartCount }, (_, index) => {
    const remaining = clampedUnits - index * 2;
    const klass = remaining >= 2 ? "full" : remaining === 1 ? "half" : "";
    return `<span class="heart ${klass}">&#9829;</span>`;
  }).join("");
}

function createId(prefix) {
  if (window.crypto?.randomUUID) {
    return `${prefix}-${window.crypto.randomUUID()}`;
  }

  return `${prefix}-${Date.now()}-${Math.floor(Math.random() * 100000)}`;
}

function formatNumber(value) {
  return new Intl.NumberFormat().format(value);
}

function formatDuration(ms) {
  if (ms <= 0) {
    return "0m";
  }

  const totalMinutes = Math.ceil(ms / 60000);
  const days = Math.floor(totalMinutes / 1440);
  const hours = Math.floor((totalMinutes % 1440) / 60);
  const minutes = totalMinutes % 60;

  if (days > 0) {
    return `${days}d ${hours}h`;
  }
  if (hours > 0) {
    return `${hours}h ${minutes}m`;
  }
  return `${minutes}m`;
}

function timeAgo(timestamp) {
  const diff = Date.now() - timestamp;
  const minutes = Math.floor(diff / 60000);
  if (minutes < 1) {
    return "Just now";
  }
  if (minutes < 60) {
    return `${minutes}m ago`;
  }
  const hours = Math.floor(minutes / 60);
  if (hours < 24) {
    return `${hours}h ago`;
  }
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}

function titleFromFile(fileName) {
  return fileName
    .replace(/\.[^.]+$/, "")
    .replace(/_bubbler$/i, "")
    .split(/[-_]/g)
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function pluralize(word, amount) {
  return amount === 1 ? word : `${word}s`;
}

function getMessageAnchorRect() {
  return dom.tankDisplay?.getBoundingClientRect?.() || document.querySelector(".tank-display")?.getBoundingClientRect?.() || null;
}

function getTransientMessageAnchor(gap = 14) {
  const stageRect = dom.tankStage?.getBoundingClientRect?.() || null;
  const anchorRect = getMessageAnchorRect();
  if (anchorRect?.width && anchorRect?.height) {
    const viewportLeft = Math.round(anchorRect.left);
    const viewportTop = Math.round(anchorRect.bottom + gap);
    const stageLeft = stageRect ? Math.round(anchorRect.left - stageRect.left) : 8;
    const stageTop = stageRect ? Math.round(anchorRect.bottom - stageRect.top + gap) : viewportTop;
    return {
      viewportLeft,
      viewportTop,
      stageLeft,
      stageTop,
      toastMaxWidth: Math.max(220, Math.min(420, Math.round(window.innerWidth - viewportLeft - 12))),
      hintMaxWidth: Math.max(220, Math.min(420, Math.round((stageRect?.width || window.innerWidth) - stageLeft - 12)))
    };
  }

  return {
    viewportLeft: 12,
    viewportTop: 86,
    stageLeft: 8,
    stageTop: 86,
    toastMaxWidth: Math.max(220, Math.min(420, window.innerWidth - 24)),
    hintMaxWidth: Math.max(220, Math.min(420, Math.round((stageRect?.width || window.innerWidth) - 16)))
  };
}

function positionToast() {
  if (!dom.toast) {
    return;
  }

  const anchor = getTransientMessageAnchor();
  dom.toast.style.left = `${anchor.viewportLeft}px`;
  dom.toast.style.top = `${anchor.viewportTop}px`;
  dom.toast.style.bottom = "auto";
  dom.toast.style.maxWidth = `${anchor.toastMaxWidth}px`;
}

function positionPlacementHint() {
  if (!dom.placementHintContainer) {
    return;
  }

  if (shouldShowDecorSwimGuide()) {
    const stageRect = dom.tankStage?.getBoundingClientRect?.() || null;
    const trayRect = dom.editDecorTray && !dom.editDecorTray.hidden
      ? dom.editDecorTray.getBoundingClientRect?.() || null
      : null;
    if (stageRect?.width && trayRect?.width) {
      const hintWidth = Math.max(260, Math.min(520, Math.round(trayRect.width - 28)));
      const hintHeight = Math.max(
        dom.placementHintContainer.offsetHeight || 0,
        dom.placementHint?.offsetHeight || 0,
        44
      );
      const maxLeft = Math.max(8, Math.round(stageRect.width - hintWidth - 8));
      const centeredLeft = Math.round(trayRect.left - stageRect.left + (trayRect.width - hintWidth) / 2);
      dom.placementHintContainer.style.left = `${clamp(centeredLeft, 8, maxLeft)}px`;
      dom.placementHintContainer.style.top = `${Math.max(12, Math.round(trayRect.top - stageRect.top - hintHeight - 12))}px`;
      dom.placementHintContainer.style.right = "auto";
      dom.placementHintContainer.style.bottom = "auto";
      dom.placementHintContainer.style.transform = "none";
      dom.placementHintContainer.style.maxWidth = `${hintWidth}px`;
      dom.placementHintContainer.style.width = `${hintWidth}px`;
      return;
    }
  }

  const anchor = getTransientMessageAnchor();
  dom.placementHintContainer.style.left = `${anchor.stageLeft}px`;
  dom.placementHintContainer.style.top = `${anchor.stageTop}px`;
  dom.placementHintContainer.style.right = "auto";
  dom.placementHintContainer.style.bottom = "auto";
  dom.placementHintContainer.style.transform = "none";
  dom.placementHintContainer.style.maxWidth = `${anchor.hintMaxWidth}px`;
  dom.placementHintContainer.style.width = `${anchor.hintMaxWidth}px`;
}

function positionTransientMessages() {
  positionPlacementHint();
  positionToast();
}

function showToast(message) {
  dom.toast.textContent = message;
  positionToast();
  dom.toast.classList.add("is-visible");

  if (runtime.toastHandle) {
    clearTimeout(runtime.toastHandle);
  }

  runtime.toastHandle = setTimeout(() => {
    dom.toast.classList.remove("is-visible");
  }, 2200);
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function randomBetween(min, max) {
  return min + Math.random() * (max - min);
}

function randomBetweenWith(rand, min, max) {
  const sample = typeof rand === "function" ? rand() : Math.random();
  return min + sample * (max - min);
}

function distance(x1, y1, x2, y2) {
  return Math.hypot(x1 - x2, y1 - y2);
}

function mulberry32(seed) {
  let current = seed;
  return () => {
    current |= 0;
    current = (current + 0x6d2b79f5) | 0;
    let t = Math.imul(current ^ (current >>> 15), 1 | current);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
